def _ensure_dotenv_file():
    if _DOTENV_PATH.exists():
        return
    template = (
        "DATABASE_URL=\n"
        "SECRET_KEY=mi_clave_secreta\n"
    )
    try:
        _DOTENV_PATH.write_text(template, encoding="utf-8")
        print(f"[CONFIG] Archivo .env creado en: {_DOTENV_PATH}")
    except OSError as exc:
        print(f"[CONFIG] AVISO: no se pudo crear .env en {_DOTENV_PATH}: {exc}")


def _normalize_database_url(raw_value):
    value = str(raw_value or "").strip()
    if not value:
        return ""
    if value.lower() in ("null", "none", "undefined"):
        return ""
    if value == _DEFAULT_PLACEHOLDER_DATABASE_URL:
        return ""
    return value


