# Zona horaria fija: República Dominicana (todo el sistema; no usar hora del navegador/teléfono).
TZ_RD = ZoneInfo("America/Santo_Domingo")
tz_rd = pytz.timezone("America/Santo_Domingo")
RD_TZ = TZ_RD

# Tras registrar números en `resultados`, tiempo mínimo antes de permitir pagar premio (misma zona RD).
PREMIO_PAGO_ESPERA_SEGUNDOS = int(os.environ.get("PREMIO_PAGO_ESPERA_SEGUNDOS", "600"))


def _premio_pay_espera_td():
    """Misma ventana temporal que espera después del instante del sorteo (America/Santo_Domingo)."""
    return timedelta(seconds=max(1, PREMIO_PAGO_ESPERA_SEGUNDOS))


def _premio_ticket_far_future_pay_ms():
    """Epoch ms lejano: el botón Pagar debe seguir bloqueado en cliente hasta nueva carga desde backend."""
    try:
        return int((ahora_rd() + timedelta(days=3650)).timestamp() * 1000)
    except Exception:
        return (1 << 62)


def _premio_ticket_eval_habilitar_pago_ui(lineas, ticket_id=None, imprimir_debug=False):
    """
    Regla única botón/traza «Pagar» (backend también valida igual):
      - debe haber líneas pendientes con premio > 0 (acierto económico);
      - debe haber pasado PREMIO_PAGO_ESPERA_SEGUNDOS desde el **último** instante de sorteo conocido
        entre esas líneas (RD). Si falta fecha/hora de sorteo, se usa ganador_detectado_en + espera como respaldo legado.

    imprimir_debug: True en rutas POST pago / diagnóstico; en listado usar DEBUG_PAGO_PREMIO=1.
    Devuelve dict con habilitar_pago, tiempo_ok y pago_habilitar_unix_ms (countdown servidor).
    """
    ahora = obtener_fecha_rd()
    premio_lines = [ln for ln in (lineas or []) if float(ln.get("premio") or 0) > 0]

    try:
        acierto_f = round(sum(float(ln.get("premio") or 0) for ln in premio_lines), 2)
    except (TypeError, ValueError):
        acierto_f = None
    acierto = acierto_f
    tiene_ganador = acierto is not None and acierto > 0

    fin_espera_candidatos = []
    ultimo_sorteo = None

    espera_td = _premio_pay_espera_td()
    for ln in premio_lines:
        fecha_linea = ln.get("fecha_sorteo_linea")
        if fecha_linea is None:
            fecha_linea = ln.get("fecha_sorteo")
        d_cal = _parse_iso_date_only(fecha_linea)
        dr_raw = (
            normalizar_sorteo(_draw_efectivo_jugada(ln.get("lottery"), ln.get("draw")))
            or str(_draw_efectivo_jugada(ln.get("lottery"), ln.get("draw")) or "").strip()
        )
        sorteo_inst = (
            _sorteo_instante_rd_en_fecha(dr_raw, d_cal) if (dr_raw and d_cal) else None
        )
        if sorteo_inst is not None:
            if ultimo_sorteo is None or sorteo_inst > ultimo_sorteo:
                ultimo_sorteo = sorteo_inst
            fin_espera_candidatos.append(sorteo_inst + espera_td)
        else:
            gd = valor_guardado_a_rd_dt(ln.get("ganador_detectado_en"))
            if gd is not None:
                fin_espera_candidatos.append(gd + espera_td)

    tiempo_ok = False
    habilita_en_rd = None
    sec_rest = None
    if tiene_ganador and fin_espera_candidatos:
        habilita_en_rd = max(fin_espera_candidatos)
        tiempo_ok = ahora >= habilita_en_rd
        if not tiempo_ok:
            sec_rest = max(0, int((habilita_en_rd - ahora).total_seconds()))
    elif tiene_ganador and not fin_espera_candidatos:
        # Sin horario de sorteo parseable → no bloquear pago de premios ya persistidos pendientes.
        tiempo_ok = True

    habilitar_pago = bool(tiene_ganador and tiempo_ok)
    ms = (
        int(habilita_en_rd.timestamp() * 1000)
        if (habilita_en_rd is not None)
        else _premio_ticket_far_future_pay_ms()
    )

    if imprimir_debug or os.environ.get("DEBUG_PAGO_PREMIO", "").strip().lower() in (
        "1",
        "true",
        "yes",
    ):
        print("acierto:", acierto)
        print("tiene_ganador:", tiene_ganador)
        print("hora_sorteo:", ultimo_sorteo)
        print("hora_actual:", ahora)
        print("tiempo_ok:", tiempo_ok)
        print("habilitar_pago:", habilitar_pago)

    return {
        "acierto": acierto,
        "tiene_ganador": tiene_ganador,
        "hora_sorteo": ultimo_sorteo,
        "hora_actual_rd": ahora,
        "habilita_en_rd": habilita_en_rd,
        "tiempo_ok": tiempo_ok,
        "habilitar_pago": habilitar_pago,
        "pago_habilitar_unix_ms": ms,
        "seconds_until_pay": sec_rest,
    }


def obtener_fecha_rd():
    """Hora actual en America/Santo_Domingo (reloj del servidor, zona RD)."""
    return ahora_rd()


def ahora_rd():
    """Instante aware en America/Santo_Domingo. Única fuente para lógica crítica de fecha/hora."""
    return datetime.now(TZ_RD)


def fecha_hoy_rd_iso():
    """YYYY-MM-DD calendario RD (servidor)."""
    return ahora_rd().date().strftime("%Y-%m-%d")


def timestamp_rd_iso():
    """YYYY-MM-DD HH:MM:SS en RD (servidor), para persistir en SQLite."""
    return ahora_rd().strftime("%Y-%m-%d %H:%M:%S")


def _fecha_sorteo_calendario_linea_rd(lottery, draw):
    """
    Día calendario del sorteo al guardar ticket_lines (servidor RD).
    No acepta fecha enviada por el cliente.
    """
    _ = lottery, draw
    return fecha_hoy_rd_iso()


def _parse_fecha_iso_cliente_o_none(raw):
    """Parsea YYYY-MM-DD enviado por cliente solo para consultas/filtros."""
    s = str(raw or "").strip()[:10]
    if len(s) != 10 or not re.match(r"^\d{4}-\d{2}-\d{2}$", s):
        return None
    return _parse_iso_date_only(s)


def _fecha_consulta_cliente_acotada(
    raw,
    *,
    default_hoy=True,
    max_dias_atras=366,
    max_dias_adelante=2,
):
    """
    Fecha de calendario para reportes o navegación en UI.
    Valida formato y acota al rango; nunca usa reloj del dispositivo.
    """
    hoy = ahora_rd().date()
    d = _parse_fecha_iso_cliente_o_none(raw)
    if not d:
        return hoy.strftime("%Y-%m-%d") if default_hoy else None
    if d > hoy + timedelta(days=max(0, int(max_dias_adelante))):
        d = hoy + timedelta(days=max(0, int(max_dias_adelante)))
    if d < hoy - timedelta(days=max(1, int(max_dias_atras))):
        d = hoy - timedelta(days=max(1, int(max_dias_atras)))
    return d.strftime("%Y-%m-%d")


def formatear_fecha_rd(fecha):
    """Formato profesional para recibos y pantallas: DD-MM-YYYY hh:mm AM/PM (RD)."""
    if fecha is None:
        return "—"
    if isinstance(fecha, str):
        s = fecha.strip()
        if not s:
            return "—"
        try:
            fecha = datetime.fromisoformat(s.replace("Z", "+00:00"))
        except ValueError:
            return s + ("" if "(RD)" in s else " (RD)")
    if isinstance(fecha, datetime):
        if fecha.tzinfo is None:
            try:
                fecha = tz_rd.localize(fecha)
            except (ValueError, OverflowError):
                fecha = fecha.replace(tzinfo=tz_rd)
        else:
            fecha = fecha.astimezone(tz_rd)
        return fecha.strftime("%d-%m-%Y %I:%M %p") + " (RD)"
    if isinstance(fecha, date):
        return fecha.strftime("%d-%m-%Y") + " (RD)"
    return str(fecha)


def _parse_texto_fecha_rd(s):
    """Interpreta textos guardados (naive) como instante en calendario RD."""
    if s is None:
        return None
    t = str(s).strip()
    if not t or t == "—":
        return None
    for fmt, mx in (
        ("%Y-%m-%d %H:%M:%S", 19),
        ("%Y-%m-%d %H:%M", 16),
        ("%Y-%m-%d", 10),
    ):
        if len(t) < mx:
            continue
        try:
            d = datetime.strptime(t[:mx], fmt)
            return tz_rd.localize(d)
        except ValueError:
            continue
    return None


def valor_guardado_a_rd_dt(val):
    """datetime/str desde la BD → aware en America/Santo_Domingo (interpretación RD)."""
    if val is None:
        return None
    if isinstance(val, datetime):
        if val.tzinfo is None:
            try:
                return tz_rd.localize(val)
            except (ValueError, OverflowError):
                return val.replace(tzinfo=tz_rd)
        return val.astimezone(tz_rd)
    return _parse_texto_fecha_rd(val)


# Ventana para eliminar una línea de jugada (historial_jugadas.created_at o ticket.created_at), en segundos.
JUGADA_ELIMINAR_MAX_SEGUNDOS = int(
    os.environ.get("JUGADA_ELIMINAR_MAX_SEGUNDOS")
    or os.environ.get("JUGADA_ELIMINAR_EDITAR_MAX_SEGUNDOS")
    or "300"
)

MSG_ELIMINAR_JUGADA_TIEMPO_EXPIRADO = (
    "No se puede eliminar este ticket. Pasaron más de 5 minutos desde la venta."
)

# Límite diario por número / lotería / sorteo / banca cuando no hay fila en limites_numeros.
LIMITE_NUMERO_DIARIO_DEFAULT = float(os.environ.get("LIMITE_NUMERO_DIARIO_DEFAULT", "250"))


def historial_jugada_created_at_rd(val):
    """created_at de historial_jugadas → datetime aware RD (None si no parseable)."""
    if val is None:
        return None
    if isinstance(val, datetime):
        if val.tzinfo is None:
            try:
                return tz_rd.localize(val)
            except (ValueError, OverflowError):
                return val.replace(tzinfo=tz_rd)
        return val.astimezone(tz_rd)
    return _parse_texto_fecha_rd(val)


def jugada_linea_dentro_ventana_acciones(created_val, ticket_created_val=None):
    """True si aún está dentro de JUGADA_ELIMINAR_MAX_SEGUNDOS desde la venta (jugada o ticket)."""
    dt = historial_jugada_created_at_rd(created_val)
    if not dt and ticket_created_val is not None:
        dt = historial_jugada_created_at_rd(ticket_created_val)
    if not dt:
        return False
    try:
        return (ahora_rd() - dt).total_seconds() <= float(JUGADA_ELIMINAR_MAX_SEGUNDOS)
    except (TypeError, ValueError, OverflowError):
        return False


def _fecha_venta_para_eliminar_jugada(jugada_created_at, ticket_created_at=None):
    """Momento de venta en RD: prioriza historial_jugadas.created_at, luego tickets.created_at."""
    dt = historial_jugada_created_at_rd(jugada_created_at)
    if dt:
        return dt
    return historial_jugada_created_at_rd(ticket_created_at)


def _log_eliminar_jugada_tiempo(*, ticket_id, jugada_id, fecha_venta, permitido, source=None):
    ahora = ahora_rd()
    minutos = None
    if fecha_venta:
        try:
            minutos = (ahora - fecha_venta).total_seconds() / 60.0
        except (TypeError, ValueError, OverflowError):
            minutos = None
    log.info(
        "[ELIMINAR_JUGADA_TIEMPO] ticket_id=%s jugada_id=%s fecha_venta=%s ahora=%s "
        "minutos_pasados=%s permitido=%s source=%s",
        ticket_id if ticket_id is not None else "-",
        jugada_id if jugada_id is not None else "-",
        fecha_venta.isoformat() if fecha_venta else "-",
        ahora.isoformat(),
        ("%.2f" % minutos) if minutos is not None else "-",
        "true" if permitido else "false",
        source or (_eliminar_jugada_client_source() if has_request_context() else "api"),
    )


def _validar_tiempo_eliminar_jugada(jugada_created_at, ticket_created_at, *, ticket_id=None, jugada_id=None, source=None):
    """Backend: bloquea eliminación si pasaron más de JUGADA_ELIMINAR_MAX_SEGUNDOS desde la venta."""
    fecha_venta = _fecha_venta_para_eliminar_jugada(jugada_created_at, ticket_created_at)
    if not fecha_venta:
        _log_eliminar_jugada_tiempo(
            ticket_id=ticket_id,
            jugada_id=jugada_id,
            fecha_venta=None,
            permitido=False,
            source=source,
        )
        return False, MSG_ELIMINAR_JUGADA_TIEMPO_EXPIRADO
    try:
        segundos = (ahora_rd() - fecha_venta).total_seconds()
    except (TypeError, ValueError, OverflowError):
        segundos = float(JUGADA_ELIMINAR_MAX_SEGUNDOS) + 1
    permitido = segundos <= float(JUGADA_ELIMINAR_MAX_SEGUNDOS)
    _log_eliminar_jugada_tiempo(
        ticket_id=ticket_id,
        jugada_id=jugada_id,
        fecha_venta=fecha_venta,
        permitido=permitido,
        source=source,
    )
    if not permitido:
        return False, MSG_ELIMINAR_JUGADA_TIEMPO_EXPIRADO
    return True, None


def _eliminar_jugada_request_snapshot():
    """Headers y body útiles para diagnóstico Web/APK (sin cookies completas)."""
    if not has_request_context():
        return {"headers": "", "body": ""}
    hdrs = {
        "X-Requested-With": (request.headers.get("X-Requested-With") or "").strip(),
        "Accept": (request.headers.get("Accept") or "").strip()[:80],
        "Content-Type": (request.headers.get("Content-Type") or "").strip()[:80],
        "X-Client-Source": (request.headers.get("X-Client-Source") or "").strip(),
        "X-Banca-Client": (request.headers.get("X-Banca-Client") or "").strip(),
        "User-Agent": (request.headers.get("User-Agent") or "").strip()[:120],
        "has_session_cookie": "session=" in (request.headers.get("Cookie") or "").lower(),
    }
    body_txt = ""
    try:
        if request.is_json:
            body_txt = json.dumps(request.get_json(silent=True) or {}, ensure_ascii=False)[:500]
        else:
            raw = request.get_data(cache=True, as_text=True) or ""
            body_txt = str(raw).strip()[:500]
    except Exception:
        body_txt = ""
    if not body_txt:
        body_txt = "(vacío)"
    return {
        "headers": json.dumps(hdrs, ensure_ascii=False)[:600],
        "body": body_txt,
    }


def _log_eliminar_jugada_request(
    phase,
    jugada_id,
    *,
    ticket_id=None,
    http_status=None,
    error_msg=None,
    extra=None,
    endpoint=None,
    resultado=None,
    monto=None,
    source=None,
    body=None,
    headers_importantes=None,
):
    """Diagnóstico Web/APK: URL, HTTP, usuario, rol, ticket_id y headers útiles en Logcat/Render."""
    if not has_request_context():
        return
    snap = _eliminar_jugada_request_snapshot()
    ua = (request.headers.get("User-Agent") or "")[:160]
    xrw = (request.headers.get("X-Requested-With") or "").strip()
    accept = (request.headers.get("Accept") or "")[:80]
    referer = (request.headers.get("Referer") or "")[:200]
    cookie_hdr = request.headers.get("Cookie") or ""
    has_session_cookie = "session=" in cookie_hdr.lower()
    user = (session.get("u") or session.get("user") or "").strip()
    role = (session.get("role") or "").strip()
    ep = endpoint or request.path
    src = source or _eliminar_jugada_client_source()
    body_log = body if body is not None else snap.get("body")
    hdrs_log = headers_importantes if headers_importantes is not None else snap.get("headers")
    log.info(
        "[ELIMINAR_JUGADA_API] phase=%s source=%s endpoint=%s method=%s jugada_id=%s ticket_id=%s "
        "usuario=%s rol=%s monto=%s http_status=%s resultado=%s error=%s "
        "headers_importantes=%s body=%s "
        "x_requested_with=%s accept=%s has_session_cookie=%s ua=%s referer=%s extra=%s",
        phase,
        src,
        ep,
        request.method,
        jugada_id,
        ticket_id if ticket_id is not None else "-",
        user or "(anon)",
        role or "(sin_rol)",
        monto if monto is not None else "-",
        http_status if http_status is not None else "-",
        (resultado or "-")[:80],
        (error_msg or "")[:240],
        hdrs_log or "-",
        (body_log or "-")[:500],
        xrw or "-",
        accept or "-",
        has_session_cookie,
        ua,
        referer or "-",
        (extra or "")[:240],
    )


def _eliminar_jugada_client_source():
    """web | apk | api según ruta y User-Agent (WebView Android)."""
    if not has_request_context():
        return "api"
    path = (request.path or "").strip()
    if path.startswith("/api/eliminar_jugada"):
        ua = (request.headers.get("User-Agent") or "").lower()
        if "android" in ua or "; wv)" in ua:
            return "apk"
        hdr = (request.headers.get("X-Client-Source") or "").strip().lower()
        if hdr in ("apk", "android", "webview"):
            return "apk"
        return "api"
    if path.startswith("/eliminar_jugada/"):
        return "apk" if "android" in (request.headers.get("User-Agent") or "").lower() else "api"
    hdr = (request.headers.get("X-Client-Source") or request.headers.get("X-Banca-Client") or "").strip().lower()
    if hdr in ("apk", "android", "webview"):
        return "apk"
    ua = (request.headers.get("User-Agent") or "").lower()
    if "android" in ua and "; wv)" in ua:
        return "apk"
    return "web"


def _wants_json_eliminar_jugada(force_json=False):
    """Web fetch, API /api/eliminar_jugada y WebView Android siempre reciben JSON."""
    if force_json:
        return True
    if has_request_context():
        path = (request.path or "").strip()
        if path.startswith("/api/eliminar_jugada") or path.startswith("/eliminar_jugada/"):
            return True
        ua = (request.headers.get("User-Agent") or "").lower()
        if "android" in ua or "; wv)" in ua:
            return True
    return bool(
        (request.headers.get("X-Requested-With") or "").strip() == "XMLHttpRequest"
        or "application/json" in (request.headers.get("Accept") or "").lower()
    )


def _validar_ticket_estado_eliminar_jugada(cur, ticket_id):
    """Bloquea si el ticket ya fue eliminado o pagado. Retorna (msg, code) o (None, None)."""
    try:
        tid = int(ticket_id or 0)
    except (TypeError, ValueError):
        return "Ticket inválido.", 400
    if tid <= 0:
        return "Ticket inválido.", 400
    is_pg = bool(os.environ.get("DATABASE_URL"))
    log.info("[ELIMINAR_JUGADA_FIX] antes validar ticket_id=%s is_pg=%s", tid, is_pg)
    if is_pg:
        # eliminado=INTEGER, pagado=BOOLEAN|INTEGER según migración: CAST unifica ambos.
        cur.execute(
            """
            SELECT id,
                   COALESCE(CAST(eliminado AS INTEGER), 0) AS eliminado,
                   COALESCE(CAST(pagado AS INTEGER), 0) AS pagado
            FROM tickets WHERE id = %s
            """,
            (tid,),
        )
    else:
        cur.execute(
            _sql(
                """
            SELECT id, COALESCE(eliminado, 0) AS eliminado, COALESCE(pagado, 0) AS pagado
            FROM tickets WHERE id = %s
            """
            ),
            (tid,),
        )
    row = cur.fetchone()
    if not row:
        log.info("[ELIMINAR_JUGADA_FIX] despues validar ticket_id=%s resultado=not_found", tid)
        return "Ticket no encontrado.", 404
    rd = dict(row) if hasattr(row, "keys") else {
        "id": row[0],
        "eliminado": row[1] if len(row) > 1 else 0,
        "pagado": row[2] if len(row) > 2 else 0,
    }
    eliminado = _ticket_row_eliminado(rd)
    pagado = _pago_premio_es_truthy_pagado(rd.get("pagado"))
    log.info(
        "[ELIMINAR_JUGADA_FIX] tipos normalizados eliminado=%s pagado=%s raw_eliminado=%r raw_pagado=%r",
        eliminado,
        pagado,
        rd.get("eliminado"),
        rd.get("pagado"),
    )
    if eliminado:
        return "Este ticket ya fue eliminado.", 409
    if pagado:
        return "No se puede eliminar: el ticket ya fue pagado.", 409
    if _ticket_tiene_pagos_premios_activos(cur, tid) or _ticket_tiene_pagos_legacy_activos(cur, tid):
        log.info("[ELIMINAR_JUGADA_FIX] despues validar ticket_id=%s resultado=premio_pagado_activo", tid)
        return "No se puede eliminar: el ticket tiene premio pagado.", 409
    log.info("[ELIMINAR_JUGADA_FIX] despues validar ticket_id=%s resultado=ok", tid)
    return None, None


