STATIC_ASSET_VERSION = "20260634"


def _session_username_raw():
    if not has_request_context():
        return ""
    return (session.get("u") or session.get("user") or "").strip()


def _session_display_name_raw():
    if not has_request_context():
        return ""
    for key in ("nombre_completo", "display_name", "nombre"):
        val = session.get(key)
        if val and str(val).strip():
            return str(val).strip()
    return ""


def session_usuario_autenticado():
    """Nombre visible del usuario logueado: nombre completo o username en MAYÚSCULAS."""
    full = _session_display_name_raw()
    if full:
        return full
    user = _session_username_raw()
    return user.upper() if user else ""


def session_usuario_display_raw():
    """Nombre para venta/cajero: nombre completo o username tal cual en sesión (0303, Solibel)."""
    full = _session_display_name_raw()
    if full:
        return full
    return _session_username_raw()


def session_usuario_bienvenida():
    """Texto estándar de bienvenida reutilizable en todos los dashboards."""
    name = session_usuario_autenticado()
    return ("Bienvenido, " + name) if name else ""


def session_usuario_bienvenida_venta():
    """Bienvenida en encabezado /venta (conserva capitalización del username)."""
    name = session_usuario_display_raw()
    return ("Bienvenido, " + name) if name else ""


def _inject_session_user_context(context):
    context.setdefault("usuario_autenticado", session_usuario_autenticado())
    context.setdefault("usuario_bienvenida", session_usuario_bienvenida())
    context.setdefault("usuario_autenticado_venta", session_usuario_display_raw())
    context.setdefault("usuario_bienvenida_venta", session_usuario_bienvenida_venta())


def render_template_string(source, **context):
    """Inyecta siempre `fecha` en RD para plantillas ({{ fecha }})."""
    context.setdefault("fecha", formatear_fecha_rd(obtener_fecha_rd()))
    context.setdefault("static_v", STATIC_ASSET_VERSION)
    context.setdefault("static_asset_version", STATIC_ASSET_VERSION)
    _inject_session_user_context(context)
    return _flask_render_template_string(source, **context)


def render_template(template_name_or_list, **context):
    """Inyecta siempre `fecha` en RD para plantillas ({{ fecha }})."""
    context.setdefault("fecha", formatear_fecha_rd(obtener_fecha_rd()))
    context.setdefault("static_v", STATIC_ASSET_VERSION)
    context.setdefault("static_asset_version", STATIC_ASSET_VERSION)
    _inject_session_user_context(context)
    return _flask_render_template(template_name_or_list, **context)

