_ttl_cache_store = {}
_ttl_cache_lock = threading.Lock()


def _dashboard_cache_ttl_seconds():
    """0 = sin caché in-process; por defecto 45s."""
    try:
        return max(0, min(600, int(os.environ.get("DASHBOARD_CACHE_TTL", "45"))))
    except (TypeError, ValueError):
        return 45


def _dashboard_snapshot_cache_ttl_seconds():
    """Snapshot caliente para /admin (KPI ya calculados). 0 = desactivado."""
    try:
        return max(0.0, min(120.0, float(os.environ.get("DASHBOARD_SNAPSHOT_CACHE_TTL", "15"))))
    except (TypeError, ValueError):
        return 15.0


def _balance_ciclo_cache_ttl_seconds():
    """
    TTL in-process sólo sobre el «núcleo» Ventas/Premios/Entregado del ciclo (_compute_totales_periodo_*).
    0 = sin caché (siempre consulta fresco). Vacío/no definido → mismo TTL que DASHBOARD_CACHE_TTL.
    Los ajustes contables siguen calcularse después del hit (siempre fresco).
    """
    raw = (os.environ.get("BALANCE_CICLO_CACHE_TTL") or "").strip()
    if not raw:
        return _dashboard_cache_ttl_seconds()
    try:
        return max(0, min(600, int(raw)))
    except (TypeError, ValueError):
        return _dashboard_cache_ttl_seconds()


def _ttl_shallow_clone(val):
    if isinstance(val, list):
        out = []
        for x in val:
            out.append(dict(x) if isinstance(x, dict) else x)
        return out
    if isinstance(val, dict):
        return dict(val)
    return val


def _ttl_cache_peek(bucket, key):
    if not bucket or key is None:
        return None
    now_m = time.monotonic()
    with _ttl_cache_lock:
        buck = _ttl_cache_store.get(bucket) or {}
        ent = buck.get(key)
        if not ent:
            return None
        exp, payload = ent
        if exp < now_m:
            try:
                del buck[key]
            except Exception:
                pass
            return None
        return _ttl_shallow_clone(payload)


def _ttl_cache_store_put(bucket, key, payload, ttl_sec):
    if ttl_sec <= 0 or bucket is None or key is None:
        return
    until = time.monotonic() + float(ttl_sec)
    cloned = _ttl_shallow_clone(payload)
    with _ttl_cache_lock:
        b = _ttl_cache_store.setdefault(bucket, {})
        b[key] = (until, cloned)


def _ttl_cache_invalidate_bucket(bucket):
    with _ttl_cache_lock:
        _ttl_cache_store.pop(bucket or "", None)


