def _premios_count_ganadores_lineas_fecha(cur, fecha_rd, cajero_username=None):
    """COUNT DISTINCT line_id con premio > 0 del día (lectura rápida)."""
    fr = str(fecha_rd or "").strip()[:10]
    if len(fr) != 10:
        return 0
    params = [fr, fr]
    caj_sql = ""
    if (cajero_username or "").strip():
        caj_sql = " AND lower(trim(COALESCE(p.cajero, ''))) = lower(trim(%s))"
        params.append((cajero_username or "").strip())
    try:
        cur.execute(
            _sql(
                """
                SELECT COUNT(DISTINCT p.line_id) AS c
                FROM premios p
                WHERE p.line_id IS NOT NULL
                  AND COALESCE(p.premio, 0) > 0.004
                  AND lower(trim(COALESCE(p.estado, ''))) IN ('pendiente', 'pagado')
                  AND (
                    substr(trim(COALESCE(p.fecha_dia, '')), 1, 10) = %s
                    OR EXISTS (
                        SELECT 1 FROM ticket_lines tl
                        WHERE tl.id = p.line_id
                          AND substr(trim(COALESCE(tl.fecha_sorteo, '')), 1, 10) = %s
                    )
                  )
                """
                + caj_sql
            ),
            tuple(params),
        )
        row = cur.fetchone()
        return int((row["c"] if hasattr(row, "keys") else (row[0] if row else 0)) or 0)
    except Exception as e:
        log.warning("_premios_count_ganadores_lineas_fecha(%s): %s", fr, e, exc_info=True)
        _rollback_pg_cursor(cur)
        return 0


def _premios_dia_tiene_ganadores_persistidos(cur, fecha_rd, cajero_username=None):
    """True si ya hay al menos un premio ganador persistido para líneas del día."""
    return _premios_count_ganadores_lineas_fecha(cur, fecha_rd, cajero_username) > 0


def _premios_sync_hecho_para_fecha(fecha_rd):
    fr = str(fecha_rd or "").strip()[:10]
    if len(fr) != 10:
        return False
    return _ttl_cache_peek("premios_sync_done", fr) is not None


def _premios_marcar_sync_hecho(fecha_rd):
    fr = str(fecha_rd or "").strip()[:10]
    if len(fr) != 10:
        return
    _ttl_cache_store_put("premios_sync_done", fr, True, ttl_sec=86400)


def _ganadores_count_tickets_fecha(cur, fecha_rd, cajero_username=None):
    fr = str(fecha_rd or "").strip()[:10]
    if len(fr) != 10:
        return 0
    params = [fr]
    caj_sql = ""
    if (cajero_username or "").strip():
        caj_sql = " AND lower(trim(COALESCE(tk.cajero, ''))) = lower(trim(%s))"
        params.append((cajero_username or "").strip())
    try:
        cur.execute(
            _sql(
                """
                SELECT COUNT(DISTINCT tl.ticket_id) AS c
                FROM ticket_lines tl
                INNER JOIN tickets tk ON tk.id = tl.ticket_id
                WHERE substr(trim(COALESCE(tl.fecha_sorteo, '')), 1, 10) = %s
                  AND COALESCE(tl.estado, 'activo') <> 'cancelado'
                """
                + caj_sql
            ),
            tuple(params),
        )
        row = cur.fetchone()
        return int((row["c"] if hasattr(row, "keys") else (row[0] if row else 0)) or 0)
    except Exception:
        _rollback_pg_cursor(cur)
        return 0


def _ganadores_count_resultados_fecha(cur, fecha_rd):
    fr = str(fecha_rd or "").strip()[:10]
    if len(fr) != 10:
        return 0
    try:
        if os.environ.get("DATABASE_URL"):
            cur.execute(
                """
                SELECT COUNT(*) AS c FROM resultados r
                WHERE r.publicado IS TRUE
                  AND lower(trim(COALESCE(NULLIF(trim(CAST(r.estado AS TEXT)), ''), 'cerrado'))) = 'cerrado'
                  AND """
                + _sql_expr_resultados_fecha_calendario_rd_pg("r.fecha")
                + """ = (%s)::date
                """,
                (fr,),
            )
        else:
            cur.execute(
                _sql(
                    """
                SELECT COUNT(*) AS c FROM resultados r
                WHERE COALESCE(r.publicado, 0) != 0
                  AND lower(trim(COALESCE(NULLIF(trim(r.estado), ''), 'cerrado'))) = 'cerrado'
                  AND """
                    + _sql_expr_resultados_fecha_calendario_rd_sqlite("r.fecha")
                    + """ = %s
                    """
                ),
                (fr,),
            )
        row = cur.fetchone()
        return int((row["c"] if hasattr(row, "keys") else (row[0] if row else 0)) or 0)
    except Exception:
        _rollback_pg_cursor(cur)
        return 0


def _premios_sync_necesario(cur, fecha_rd, cajero_username=None, force=False):
    """
    ¿Ejecutar cruce+UPSERT? No si premios del día ya existen, ya se sincronizó o no hay jugadas/resultados.
    """
    if force:
        return True
    if not _ganadores_skip_sync_si_materializados():
        return True
    fr = str(fecha_rd or "").strip()[:10]
    if len(fr) != 10:
        return False
    if _premios_dia_tiene_ganadores_persistidos(cur, fr, cajero_username):
        return False
    if _premios_sync_hecho_para_fecha(fr):
        return False
    return True


