def _ganadores_paginacion_params():
    """?page=1&limit=100 para la tabla de pendientes en /ganadores."""
    try:
        page = max(1, int(request.args.get("page") or 1))
    except (TypeError, ValueError):
        page = 1
    try:
        raw_lim = request.args.get("limit") or os.environ.get("GANADORES_PAGE_LIMIT") or "100"
        limit = max(10, min(200, int(raw_lim)))
    except (TypeError, ValueError):
        limit = 100
    return page, limit, (page - 1) * limit


