def _req_trace(step, path=None, **extra):
    """Log de diagnóstico para rutas que el usuario reporta colgadas."""
    try:
        p = path if path is not None else getattr(request, "path", None)
    except RuntimeError:
        p = path
    if p not in REQ_TRACE_PATHS:
        return
    parts = ["[REQ_TRACE]", "path=%s" % p, "step=%s" % step]
    for k, v in extra.items():
        parts.append("%s=%s" % (k, v))
    log.info(" ".join(parts))
