@app.route("/create-admin")
def create_admin():
    if not _DB_SCHEMA_READY and _initializing_db:
        return render_template_string("""
        <!DOCTYPE html><html lang="es"><head>
        <meta charset="utf-8"><meta http-equiv="refresh" content="4">
        <title>Inicializando base de datos</title>
        </head><body style="font-family:system-ui,sans-serif;text-align:center;padding:72px 24px;background:#0f172a;color:#e2e8f0">
        <h2 style="color:#fbbf24;margin:0 0 12px">⏳ Base de datos inicializando</h2>
        <p style="color:#94a3b8;max-width:420px;margin:0 auto;line-height:1.5">
          La primera vez puede tardar unos minutos (migraciones SQLite).
          Esta página se recargará sola en unos segundos.
        </p>
        </body></html>
        """), 503

    if not _wait_db_schema_ready(timeout_sec=900):
        return render_template_string("""
        <!DOCTYPE html><html lang="es"><head><meta charset="utf-8"><title>BD ocupada</title></head>
        <body style="font-family:system-ui,sans-serif;text-align:center;padding:72px 24px">
        <h2>Base de datos aún ocupada</h2>
        <p>Espera 1–2 minutos e intenta de nuevo.</p>
        <p><a href="/create-admin">Reintentar</a></p>
        </body></html>
        """), 503

    pwd_hash = generate_password_hash("Moose555@")
    last_err = None
    for attempt in range(14):
        conn = None
        cur = None
        creado = False
        try:
            conn = _open_db_connection_retry(max_attempts=3)
            if not conn:
                raise sqlite3.OperationalError("database is locked")
            try:
                if os.environ.get("DATABASE_URL"):
                    conn.autocommit = True
            except Exception:
                pass
            cur = conn.cursor()
            for col_sql in [
                "ALTER TABLE users ADD COLUMN created_by INTEGER",
                "ALTER TABLE users ADD COLUMN is_approved BOOLEAN DEFAULT FALSE",
                "ALTER TABLE users ADD COLUMN is_blocked BOOLEAN DEFAULT FALSE",
                "ALTER TABLE users ADD COLUMN pago_activo BOOLEAN DEFAULT TRUE",
                "ALTER TABLE users ADD COLUMN fecha_vencimiento DATE",
                "ALTER TABLE users ADD COLUMN telefono TEXT",
            ]:
                try:
                    cur.execute(col_sql)
                except Exception:
                    pass

            cur.execute(_sql("SELECT id FROM users WHERE username=%s"), ("jose0219",))
            row = cur.fetchone()
            if row:
                uid = row["id"] if isinstance(row, dict) else row[0]
                cur.execute(
                    _sql("""
                        UPDATE users
                        SET password_hash=%s,
                            role=%s,
                            approved=true,
                            is_approved=true,
                            is_blocked=false,
                            pago_activo=true
                        WHERE id=%s
                    """),
                    (pwd_hash, ROLE_SUPER_ADMIN, uid),
                )
                _db_commit(conn)
                creado = True
            else:
                cur.execute(
                    _sql("""
                        INSERT INTO users
                            (username, password_hash, role, created_by, approved, is_approved, is_blocked, pago_activo, fecha_vencimiento, telefono, created_at)
                        VALUES (%s, %s, %s, NULL, true, true, false, true, NULL, NULL, CURRENT_TIMESTAMP)
                    """),
                    ("jose0219", pwd_hash, ROLE_SUPER_ADMIN),
                )
                _db_commit(conn)
                creado = True
            if creado:
                try:
                    _invalidate_super_admin_probe_cache()
                except Exception:
                    pass
            return render_template_string(IOS + """
            <div class="card text-center" style="max-width:520px;margin:110px auto;padding:26px;border-radius:16px;">
              <h2 style="color:#002D62;margin-bottom:10px;">Listo para iniciar sesión</h2>
              <p style="color:#555;margin:8px 0;">Credenciales:</p>
              <p style="font-weight:900;color:#002D62;margin:6px 0;">jose0219</p>
              <p style="font-weight:900;color:#CE1126;margin:6px 0;">Moose555@</p>
              <p style="color:#555;margin:12px 0;">Usuario con rol: <b>super_admin</b></p>
              <a href="/" style="display:inline-block;margin-top:14px;background:#002D62;color:white;padding:10px 20px;border-radius:10px;text-decoration:none;font-weight:900;">Ir a Login</a>
            </div>
            """)
        except Exception as e:
            last_err = e
            if _sqlite_error_is_locked(e) and attempt < 13:
                time.sleep(min(3.0, 0.25 * (2 ** min(attempt, 6))))
                continue
            log.exception("create-admin falló")
            if _sqlite_error_is_locked(e):
                return render_template_string("""
                <!DOCTYPE html><html lang="es"><head>
                <meta charset="utf-8"><meta http-equiv="refresh" content="5">
                <title>BD ocupada</title></head>
                <body style="font-family:system-ui,sans-serif;text-align:center;padding:72px 24px">
                <h2>Base de datos ocupada</h2>
                <p>Migraciones en curso. Reintentando en 5 segundos…</p>
                <p><a href="/create-admin">Reintentar ahora</a></p>
                </body></html>
                """), 503
            if app.debug:
                return "ERROR REAL: %s" % (e,), 500
            return "No se pudo crear el super_admin. Intente de nuevo en un minuto.", 500
        finally:
            _db_close(conn, cur)
    if app.debug and last_err:
        return "ERROR REAL: %s" % (last_err,), 500
    return "Base de datos ocupada. Espere e intente de nuevo.", 503


