ABR_PLAY = {
    "Quiniela": "QL",
    "Pale": "PL",
    "Tripleta": "TP",
    "Super Pale": "SP"
}

ABR_LOTERIA = {
    "La Primera": "P",
    "Lotedom": "LD",
    "La Suerte Dominicana": "SD",
    "Lotería Real": "LR",
    "Loteria Nacional": "LN",
    "Loteka": "LT",
    "Leidsa": "LE",
    "La Anguila": "AN",
    "King Lottery": "KL",
    "Florida": "FL",
    "New York": "NY",
    "Quiniela Real": "QR",
}

def abr_play(nombre):
    return ABR_PLAY.get(nombre, nombre[:2].upper())


def normalizar_loteria(nombre):
    """
    Punto único de verdad: alias → nombre oficial en BD / POS (misma grafía que sorteos_por_loteria.js).
    Trim + espacios colapsados; comparación case-insensitive para alias conocidos.
    """
    if not nombre:
        return ""
    s_raw = str(nombre).strip()
    s = " ".join(s_raw.split())
    # Quitar hora embebida antes de alias (ej. «La Primera 12:00 PM» → «La Primera»).
    s_sin_hora = re.sub(
        r"[0-9]{1,2}:[0-9]{2}\s*(a\.?m\.?|p\.?m\.?)",
        " ",
        s,
        flags=re.IGNORECASE,
    )
    s_sin_hora = " ".join(s_sin_hora.split()).strip()
    if s_sin_hora:
        s = s_sin_hora
    sl = s.lower()

    # Lotedom (histórico: scraper Conectate, imports, mayúsculas mixtas)
    if (
        sl in ("lotedom", "lote dom", "lote-dom", "lottedóm", "lote dom.")
        or s_raw in ("LoteDom", "Lote Dom", "LOTEDOM", "lotedom")
    ):
        return "Lotedom"

    oficiales_case = {
        "florida": "Florida",
        "king lottery": "King Lottery",
        "kinglottery": "King Lottery",
        "la suerte dominicana": "La Suerte Dominicana",
        "lasuertedominicana": "La Suerte Dominicana",
        "leidsa": "Leidsa",
        "loteka": "Loteka",
        "quiniela real": "Quiniela Real",
        "quinielareal": "Quiniela Real",
    }
    if sl in oficiales_case:
        return oficiales_case[sl]

    # New York — solo nombre de lotería en jugadas (no claves compuestas tipo "New York 2:30 PM")
    if sl in ("new york", "newyork", "nueva york", "new york lottery", "ny lottery"):
        return "New York"

    # Anguila — Conectate / variantes
    if sl in ("anguila", "anguilla", "la anguilla", "la anguila") or s_raw in (
        "Anguila",
        "Anguilla",
        "La Anguilla",
    ):
        return "La Anguila"

    # La Primera — en BD solo "La Primera" + hora (12:00 PM / 7:00 PM); no "La Primera Día" ni "Primera Noche"
    if sl in ("la primera", "primera") or "primera noche" in sl:
        return "La Primera"
    if "primera día" in sl or "primera dia" in sl:
        return "La Primera"

    # Lotería Nacional — alias cortos y etiquetas Conectate / POS (no confundir con otras loterías)
    if sl in ("nacional", "nac"):
        return "Loteria Nacional"
    if sl in ("gana más", "gana mas", "ganamas"):
        return "Loteria Nacional"
    if "nacional tarde" in sl:
        return "Loteria Nacional"

    incorrectos = (
        "Lotería Nacional",
        "Loteria Nacional",
        "Loter!a Nacional",
        "Loter¡a Nacional",
        "Loterja Nacional",
        "Loterja Nac",
    )
    if s in incorrectos:
        return "Loteria Nacional"
    # Cualquier otra variante con "loter" típica de nacional (después de excluir lotedom arriba)
    if "loter" in sl:
        return "Loteria Nacional"

    return s_raw


def normalizar_nombre_loteria(nombre):
    """Compatibilidad: delega en normalizar_loteria."""
    return normalizar_loteria(nombre)


def _ganadores_es_clave_loteria_nacional(s: str) -> bool:
    """True si la clave ya normalizada (minúsculas, sin hora) es Lotería Nacional o alias común en RD."""
    if not s:
        return False
    if s == "loteria nacional":
        return True
    if s in ("nacional", "nac", "gana mas", "ganamas"):
        return True
    if "nacional tarde" in s:
        return True
    if "gana mas" in s:
        return True
    return False


def clave_loteria(nombre):
    """
    Clave estable para comparar nombres de lotería (JOIN ticket_lines/resultados, validaciones):
    minúsculas, sin tildes/diacríticos, espacios colapsados, sin hora embebida tipo «9:00 pm» en el texto.
    Ej.: «Lotería Nacional», «Loteria Nacional», «La Loteria Nacional», «Loteria Nacional 9:00 PM» → «loteria nacional».
    """
    if nombre is None:
        return ""
    s = " ".join(str(nombre).strip().split())
    if not s:
        return ""
    s = s.lower()
    s = "".join(
        c for c in unicodedata.normalize("NFD", s) if unicodedata.category(c) != "Mn"
    )
    s = re.sub(
        r"[0-9]{1,2}:[0-9]{2}\s*(a\.?m\.?|p\.?m\.?)",
        " ",
        s,
        flags=re.IGNORECASE,
    )
    s = " ".join(s.split())
    s = s.strip()
    if _ganadores_es_clave_loteria_nacional(s):
        return "loteria nacional"
    # "La Loteria Nacional" en resultados/import vs "Loteria Nacional" en tickets — misma clave
    s_sin_art = re.sub(r"^(la|el)\s+", "", s, count=1, flags=re.I).strip()
    if _ganadores_es_clave_loteria_nacional(s_sin_art):
        return "loteria nacional"
    # «Anguila» sin artículo en tickets POS vs «La Anguila» en resultados (scraper) — misma clave que el JOIN PG.
    if s_sin_art in ("anguila", "anguilla"):
        return "la anguila"
    if s in ("anguila", "anguilla", "la anguila", "la anguilla"):
        return "la anguila"
    return s


def _strip_accents(s):
    """Quita marcas diacríticas (NFD) para comparar lotería/sorteo."""
    return "".join(
        c for c in unicodedata.normalize("NFD", str(s or "")) if unicodedata.category(c) != "Mn"
    )


# =====================================================
# Horarios de sorteo
# — Formato oficial en BD (columnas draw) y en pantalla/recibos: 12 h con AM/PM (ej. 9:00 PM).
# — normalizar_hora() devuelve HH:MM en 24 h solo para claves lógicas (sorteo_key) y parseo;
#   no es el formato que debe persistirse en ticket_lines / resultados.
# =====================================================
_RE_HORA_FORMATO_ESTANDAR = re.compile(
    r"\b\d{1,2}:\d{2}\s*(AM|PM)\b",
    re.IGNORECASE,
)

_RE_HORA_COMPACTA_AMPM = re.compile(
    r"(?<![:\d])(\d{1,4})\s*(am|pm)\b",
    re.IGNORECASE,
)

_RE_HORA_COLON_AMPM = re.compile(
    r"(?<![:\d])(\d{1,2}):(\d{2})\s*(am|pm)\b",
    re.IGNORECASE,
)


def normalizar_hora(hora_str):
    """
    Hora interna «HH:MM» en 24 h (solo para claves y comparaciones, p. ej. sorteo_key).
    Para guardar en BD usar siempre draw_almacen_canonico() → formato 12 h (AM/PM).
    Acepta: 9:00 PM, 21:00, 9:00 PM, etc. (primero expande compactos vía formatear_hora_estandar).
    """
    if hora_str is None:
        return ""
    s0 = str(hora_str).strip()
    if not s0:
        return ""
    s = (formatear_hora_estandar(s0) or s0).strip()
    if not s:
        return ""
    s_am = (
        s.upper()
        .replace("A.M.", "AM")
        .replace("P.M.", "PM")
    ).strip()
    try:
        return datetime.strptime(s_am, "%I:%M %p").strftime("%H:%M")
    except ValueError:
        pass
    try:
        return datetime.strptime(s.strip(), "%H:%M").strftime("%H:%M")
    except ValueError:
        pass
    return s0


def _hora_hhmm24_a_ampm(h24: str) -> str:
    """«HH:MM» 24h → «H:MM AM/PM» (misma grafía que sorteos_por_loteria.js y recibos)."""
    if not h24 or len(h24) != 5 or h24[2] != ":":
        return ""
    try:
        hh = int(h24[:2])
        mi = int(h24[3:5])
    except ValueError:
        return ""
    if not (0 <= hh <= 23 and 0 <= mi <= 59):
        return ""
    if hh == 0:
        return f"12:{mi:02d} AM"
    if hh < 12:
        return f"{hh}:{mi:02d} AM"
    if hh == 12:
        return f"12:{mi:02d} PM"
    return f"{hh - 12}:{mi:02d} PM"


def draw_almacen_canonico(val):
    """
    Valor a guardar en columnas draw (ticket_lines, resultados, lotteries, premios, limites_numeros):
    siempre «H:MM AM/PM» (p. ej. 9:00 PM) o '' — compactos tipo se expanden antes.
    """
    if val is None:
        return ""
    s = str(val).strip()
    if not s:
        return ""
    if s.lower().startswith("domingos "):
        s = s[9:].strip()
    s2 = (formatear_hora_estandar(s) or s).strip()
    h24 = normalizar_hora(s2)
    if h24 and len(h24) == 5 and h24[2] == ":":
        disp = _hora_hhmm24_a_ampm(h24)
        if disp:
            return disp
    return (formatear_hora_estandar(s2) or s2).strip()


def sorteo_key(loteria, hora):
    """
    Clave estable «clave_lotería|HH:MM» usando hora en 24 h solo en esta cadena (normalizar_hora).
    En BD las columnas draw siguen en formato 12 h (AM/PM); esta clave unifica 9:00 PM y 21:00.
    """
    lk = clave_loteria(loteria)
    eff = _draw_efectivo_jugada(loteria, hora)
    hk = normalizar_hora(eff) if eff else ""
    if hk:
        return f"{lk}|{hk}"
    return lk


def sorteo_key_compound(lottery, draw):
    """Misma clave que sorteo_key con columnas lottery + draw (hora extraída si viene en el nombre)."""
    return sorteo_key(lottery, draw)


def formatear_hora_estandar(texto):
    """
    Convierte fragmentos tipo 9:00 PM, 1230pm, 100am, 6:00pm a «H:MM AM/PM» (ej. 9:00 PM, 12:30 PM, 1:00 AM).
    Útil en texto mixto («Loteria Nacional 9:00 PM, columnas draw, nombres con hora embebida).
    """
    if texto is None:
        return texto
    s = str(texto)
    if not s.strip():
        return s

    tstrip = s.strip().lower()
    m_anchor = re.match(r"^(\d{1,2})(\d{2})(am|pm)$", tstrip)
    if m_anchor:
        try:
            hhi = int(m_anchor.group(1), 10)
            mmi = int(m_anchor.group(2), 10)
        except ValueError:
            pass
        else:
            ap = m_anchor.group(3).upper()
            if 1 <= hhi <= 12 and 0 <= mmi <= 59:
                return f"{hhi}:{m_anchor.group(2)} {ap}"

    def _repl(m):
        digits = m.group(1)
        ampm = m.group(2).upper()
        n = len(digits)
        try:
            if n <= 2:
                hour = int(digits, 10)
                minute = 0
            elif n == 3:
                hour = int(digits[0], 10)
                minute = int(digits[1:3], 10)
            else:
                hour = int(digits[0:2], 10)
                minute = int(digits[2:4], 10)
        except ValueError:
            return m.group(0)
        if not (1 <= hour <= 12) or not (0 <= minute <= 59):
            return m.group(0)
        return f"{hour}:{minute:02d} {ampm}"

    def _repl_colon(m):
        try:
            hour = int(m.group(1), 10)
            minute = int(m.group(2), 10)
        except ValueError:
            return m.group(0)
        ampm = m.group(3).upper()
        if not (1 <= hour <= 12) or not (0 <= minute <= 59):
            return m.group(0)
        return f"{hour}:{minute:02d} {ampm}"

    s = _RE_HORA_COMPACTA_AMPM.sub(_repl, s)
    s = _RE_HORA_COLON_AMPM.sub(_repl_colon, s)
    return s


def normalizar_hora_compacta_en_texto(texto):
    """Alias de formatear_hora_estandar (compatibilidad con código previo)."""
    return formatear_hora_estandar(texto)


@app.template_filter("hora_estandar")
def _jinja_filter_hora_estandar(t):
    """Plantillas Jinja: {{ valor|hora_estandar }}"""
    if t is None:
        return ""
    return formatear_hora_estandar(t) or ""


def _sql_expr_translate_rd_lower(inner_expr: str) -> str:
    """translate(lower(...)) alineado con tildes RD (misma tabla que clave_lotería PG)."""
    tr_f = (
        "ÁÀÄÂÅÃÉÈËÊÍÌÏÎÓÒÖÔÚÙÜÛÑÇ"
        "áàäâåãéèëêíìïîóòöôúùüûñç"
    )
    tr_t = (
        "AAAAAAEEEEIIIIOOOOUUUUNC"
        "aaaaaaeeeeiiiioooouuuunc"
    )
    return f"translate(lower(({inner_expr})), '{tr_f}', '{tr_t}')"


def _sql_expr_clave_loteria_pg(col_sql):
    """Expresión SQL PostgreSQL alineada con clave_loteria(col) para JOIN sin depender de extensión unaccent."""
    tr_f = (
        "ÁÀÄÂÅÃÉÈËÊÍÌÏÎÓÒÖÔÚÙÜÛÑÇ"
        "áàäâåãéèëêíìïîóòöôúùüûñç"
    )
    tr_t = (
        "AAAAAAEEEEIIIIOOOOUUUUNC"
        "aaaaaaeeeeiiiioooouuuunc"
    )
    c = f"trim(CAST(COALESCE({col_sql}, '') AS text))"
    inner = (
        f"trim(regexp_replace(regexp_replace(translate(lower({c}), '{tr_f}', '{tr_t}'), "
        f"'[0-9]{{1,2}}:[0-9]{{2}}[[:space:]]*(a\\.?m\\.?|p\\.?m\\.?)', ' ', 'gi'), "
        f"'[[:space:]]+', ' ', 'g'))"
    )
    inner_la = f"trim(regexp_replace(({inner}), '^la\\\\s+', '', 'i'))"
    return (
        "(CASE "
        f"WHEN ({inner}) IN ('nacional', 'nac', 'gana mas', 'ganamas', 'loteria nacional') "
        f"OR ({inner_la}) IN ('nacional', 'nac', 'gana mas', 'ganamas', 'loteria nacional') "
        f"OR strpos({inner}, 'gana mas') > 0 OR strpos({inner_la}, 'gana mas') > 0 "
        f"OR strpos({inner}, 'nacional tarde') > 0 OR strpos({inner_la}, 'nacional tarde') > 0 "
        f"OR strpos({inner}, 'loteria nacional') > 0 OR strpos({inner_la}, 'loteria nacional') > 0 "
        f"THEN 'loteria nacional' "
        f"WHEN ({inner_la}) IN ('anguila', 'anguilla') OR ({inner}) IN ('anguila', 'anguilla') "
        f"THEN 'la anguila' "
        f"ELSE {inner} END)"
    )


def _sql_expr_draw_column_eq_pg(left_draw_col: str, right_draw_col: str) -> str:
    """
    Igualdad de columnas draw: mismo texto (lower+btrim) O forma compacta sin ':' ni espacios
    (ej. '9:00 PM' y '900pm'). Equivalencias 21:00 ↔ 9:00 PM siguen en Python (_ganadores_fila_coincide_hora_sorteo).
    """
    a = f"lower(btrim(cast(coalesce({left_draw_col}, '') as text)))"
    b = f"lower(btrim(cast(coalesce({right_draw_col}, '') as text)))"
    ca = f"regexp_replace(replace({a}, ':', ''), E'\\\\s+', '', 'g')"
    cb = f"regexp_replace(replace({b}, ':', ''), E'\\\\s+', '', 'g')"
    return f"(({a} = {b}) OR ({ca} = {cb}))"


def _sql_expr_draw_column_eq_sqlite(left_draw_col: str, right_draw_col: str) -> str:
    """Igual que _sql_expr_draw_column_eq_pg para SQLite (ticket_lines.draw ↔ resultados.draw)."""
    a = f"lower(trim(ifnull(cast({left_draw_col} as text), '')))"
    b = f"lower(trim(ifnull(cast({right_draw_col} as text), '')))"
    ca = f"replace(replace({a}, ':', ''), ' ', '')"
    cb = f"replace(replace({b}, ':', ''), ' ', '')"
    return f"(({a} = {b}) OR ({ca} = {cb}))"


def _sql_expr_draw_col_eq_param_pg(draw_col: str) -> str:
    """Igualdad draw_col ↔ %s (PostgreSQL) con normalización compacta."""
    a = f"lower(btrim(cast(coalesce({draw_col}, '') as text)))"
    b = "lower(btrim(cast(coalesce(%s, '') as text)))"
    ca = f"regexp_replace(replace({a}, ':', ''), E'\\\\s+', '', 'g')"
    cb = f"regexp_replace(replace({b}, ':', ''), E'\\\\s+', '', 'g')"
    return f"(({a} = {b}) OR ({ca} = {cb}))"


def _sql_expr_draw_col_eq_param_sqlite(draw_col: str) -> str:
    """Igualdad draw_col ↔ %s (SQLite) con normalización compacta."""
    a = f"lower(trim(ifnull(cast({draw_col} as text), '')))"
    b = "lower(trim(ifnull(cast(%s as text), '')))"
    ca = f"replace(replace({a}, ':', ''), ' ', '')"
    cb = f"replace(replace({b}, ':', ''), ' ', '')"
    return f"(({a} = {b}) OR ({ca} = {cb}))"


def _sql_expr_draw_effective_pg(lottery_col: str, draw_col: str) -> str:
    """
    Hora efectiva para JOIN en PostgreSQL:
    - si draw_col tiene valor, usarlo
    - si está vacío, extraer «H:MM AM/PM» desde lottery_col (mismo criterio que _draw_efectivo_jugada en Python)
    """
    d = f"trim(CAST(COALESCE({draw_col}, '') AS text))"
    lot = f"CAST(COALESCE({lottery_col}, '') AS text)"
    # extrae un fragmento tipo 10:00 AM / 6:00 pm / 9:00 P.M.
    extracted = f"substring({lot} from '([0-9]{{1,2}}:[0-9]{{2}}\\s*(a\\.?m\\.?|p\\.?m\\.?))')"
    return f"COALESCE(NULLIF({d}, ''), {extracted})"


def _sql_expr_draw_effective_sqlite(lottery_col: str, draw_col: str) -> str:
    """
    Hora efectiva para JOIN en SQLite:
    - si draw_col tiene valor, usarlo
    - si está vacío, extraer desde lottery_col con una aproximación (se usa solo en modo SQLite local).
    """
    d = f"trim(ifnull(cast({draw_col} as text), ''))"
    lot = f"lower(ifnull(cast({lottery_col} as text), ''))"
    # Intento simple: si aparece 'am' o 'pm' con patrón X:YY, conservar el string original lottery_col.
    # (SQLite no tiene regex nativo estándar; el match exacto final igual lo valida Python con normalizar_hora)
    return f"CASE WHEN {d} <> '' THEN {d} ELSE {lot} END"


def normalizar_sorteo(loteria: object, hora=None):
    """
    Normaliza hora de sorteo al formato de almacenamiento en 12 h: «H:MM AM/PM» (columnas draw).
    - Un argumento: solo texto de hora (9:00 PM,
    - Dos argumentos: concatena «lotería hora» (legado) y extrae con draw_almacen_canonico.
    """
    if hora is not None:
        return draw_almacen_canonico(f"{loteria or ''} {hora or ''}".strip())
    return draw_almacen_canonico(loteria)


def _sorteo_compound_join_key(lottery, draw):
    """
    Clave única lotería+hora para JOIN y validación; delega en sorteo_key_compound().
    """
    return sorteo_key_compound(lottery, draw)


def _debug_match_sorteo(t_lot, t_draw, r_lot, r_draw):
    if os.environ.get("DEBUG_MATCH_SORTEO") != "1" and os.environ.get("DEBUG_SORTEO_KEY") != "1":
        return
    tk = _sorteo_compound_join_key(t_lot, t_draw)
    rk = _sorteo_compound_join_key(r_lot, r_draw)
    print("DEBUG MATCH SORTEO")
    print("Ticket key:", tk, "| raw:", t_lot, t_draw)
    print("Resultado key:", rk, "| raw:", r_lot, r_draw)
    print(("IGUAL" if tk == rk else "DISTINTO") + ":", tk, "vs", rk)


def normalizar_texto(t):
    """Normalización simple para comparar lotería/hora sin depender de mayúsculas ni espacios."""
    return str(t or "").strip().lower().replace(" ", "")


def _numeros_resultado_bd(primero, segundo, tercero):
    return numeros_resultado_bd(primero, segundo, tercero)


def _debug_sorteo_plano(s):
    """Alias legado: misma colisión que normalizar_sorteo (solo lectura en logs antiguos)."""
