def _debug_cruce_imprime(d):
    """
    Log detallado del cruce ticket↔resultado antes del resto de validaciones.
    Activar: DEBUG_CRUCE_COMPLETO=1 o DEBUG_AISLAR_GANADORES=1 (este último activa también fecha/catálogo relajados).
    """
    if os.environ.get("DEBUG_CRUCE_COMPLETO") != "1" and os.environ.get("DEBUG_AISLAR_GANADORES") != "1":
        return
    p1, p2, p3 = d.get("primero"), d.get("segundo"), d.get("tercero")
    numeros_resultado = _numeros_resultado_bd(p1, p2, p3)
    lt = d.get("lottery")
    lr = d.get("res_lottery")
    loteria_ticket = lt
    loteria_resultado = lr
    clave_ticket = clave_loteria(lt)
    clave_resultado = clave_loteria(lr)
    ticket_id = d.get("ticket_id")
    fecha_ticket = _ganadores_fecha_sorteo_efectiva_str(d)
    fecha_resultado = d.get("resultado_fecha")
    rn = d.get("number")
    if rn is None or (isinstance(rn, str) and str(rn).strip() == ""):
        numero = ""
    else:
        numero = str(rn).zfill(2)
    print("---- DEBUG CRUCE ----")
    print("Ticket ID:", ticket_id)
    print("Loteria Ticket:", loteria_ticket, "→", clave_ticket)
    print("Loteria Resultado:", loteria_resultado, "→", clave_resultado)
    print("Ticket sorteo (draw):", d.get("draw"))
    print("Resultado draw:", d.get("res_draw"))
    print(
        "normalizar_hora:",
        normalizar_hora(str(_draw_efectivo_jugada(d.get("lottery"), d.get("draw")) or "").strip()),
        "==",
        normalizar_hora(str(_draw_efectivo_jugada(d.get("res_lottery"), d.get("res_draw")) or "").strip()),
    )
    ticket_key = _sorteo_compound_join_key(lt, d.get("draw"))
    resultado_key = _sorteo_compound_join_key(lr, d.get("res_draw"))
    print("DEBUG MATCH SORTEO")
    print("TICKET:", loteria_ticket, d.get("draw"), "=>", ticket_key)
    print("RESULTADO:", loteria_resultado, d.get("res_draw"), "=>", resultado_key)
    if ticket_key != resultado_key:
        print("❌ Sorteo no coincide")
    print("Fecha Ticket:", fecha_ticket)
    print("Fecha Resultado:", fecha_resultado)
    print("Primero/Segundo/Tercero (columnas BD):", p1, p2, p3)
    print("Numeros BD:", numeros_resultado)
    print("Numero Jugado:", numero)
    if numero and numero in numeros_resultado:
        print("🔥 MATCH REAL DETECTADO")
    else:
        print("❌ NO MATCH")


def _draw_efectivo_jugada(lottery, draw):
    """
    Hora de sorteo para cruce ganadores: columna `draw`; si viene vacía, intenta leerla del nombre
    (p. ej. ticket con lottery = «Loteria Nacional 9:00 PM» y draw vacío).
    """
    d = str(draw or "").strip()
    if d:
        return d
    lot = str(lottery or "")
    m = re.search(r"[0-9]{1,2}:[0-9]{2}\s*(a\.?m\.?|p\.?m\.?)", lot, re.I)
    if m:
        return m.group(0).strip()
    return ""


def _clave_sorteo_join(lottery, draw):
    """Misma noción que el JOIN (PG/SQLite): clave_loteria + draw en 12 h almacenado (= sorteo_key_compound)."""
    try:
        return sorteo_key_compound(lottery, draw)
    except Exception:
        return ""


def abr_loteria(nombre):
    nombre = normalizar_loteria(nombre)
    return ABR_LOTERIA.get(nombre, nombre[:2].upper() if nombre else "")


