def _nc_hist_state_update(**fields):
    now_iso = ahora_rd().strftime("%Y-%m-%d %H:%M:%S")
    with _NC_HIST_IMPORT_LOCK:
        _NC_HIST_IMPORT_STATE.update(fields)
        _NC_HIST_IMPORT_STATE["updated_at"] = now_iso
