def _nc_hist_fecha_iso_desde_texto(txt, fallback_iso=""):
    s = str(txt or "").strip()
    if not s:
        return (fallback_iso or "")[:10]
    m_iso = re.search(r"(\d{4})-(\d{2})-(\d{2})", s)
    if m_iso:
        return m_iso.group(0)
    m_dd = re.search(r"(\d{2})-(\d{2})-(\d{4})", s)
    if m_dd:
        d, mm, yy = m_dd.groups()
        return f"{yy}-{mm}-{d}"
    return (fallback_iso or "")[:10]


def _nc_hist_parse_ultimos_resultados(fecha_iso, html_text):
    soup = BeautifulSoup(html_text or "", "html.parser")
    rows = []
    for block in soup.select("div.game-block"):
        title_el = block.select_one(".game-title")
        if not title_el:
            continue
        title = title_el.get_text(" ", strip=True)
        internal = _conectate_label_to_internal_key(title)
        if not internal:
            continue
        lot_db, draw_db = RESULT_LOTTERY_TO_TICKET.get(internal, (None, None))
        if not lot_db:
            continue
        if lot_db not in NC_CANON_TO_PROGRESS:
            continue
        scores = []
        for sc in block.select(".score"):
            m_num = re.search(r"(\d{1,2})", sc.get_text(" ", strip=True))
            if not m_num:
                continue
            scores.append(m_num.group(1).zfill(2))
            if len(scores) >= 3:
                break
        if len(scores) < 3:
            continue
        dt_txt = ""
        dt_el = block.select_one(".session-date")
        if dt_el:
            dt_txt = dt_el.get_text(" ", strip=True)
        fecha_row = _nc_hist_fecha_iso_desde_texto(dt_txt, fallback_iso=fecha_iso)
        if not fecha_row:
            continue
        rows.append(
            {
                "lottery": lot_db,
                "draw": draw_db,
                "fecha": fecha_row[:10],
                "primero": scores[0],
                "segundo": scores[1],
                "tercero": scores[2],
                "title": title,
            }
        )
    dedup = {}
    for r in rows:
        dedup[(r["lottery"], r["draw"], r["fecha"])] = r
    return list(dedup.values())


def _nc_hist_fetch_day(fecha_iso):
    fecha_iso = (fecha_iso or "")[:10]
    try:
        dt = datetime.strptime(fecha_iso, "%Y-%m-%d").date()
    except Exception:
        return {"ok": False, "rows": [], "error": "fecha_invalida"}
    params = {"date": dt.strftime("%d-%m-%Y"), "_ts": str(int(time.time()))}
    headers = {
        "User-Agent": (
            "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 "
            "(KHTML, like Gecko) Chrome/126.0.0.0 Safari/537.36"
        ),
        "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
        "Accept-Language": "es-DO,es;q=0.9,en;q=0.8",
        "Referer": "https://www.conectate.com.do/loterias/",
        "Cache-Control": "no-cache",
        "Pragma": "no-cache",
    }
    try:
        resp = requests.get(NC_HISTORICO_URL, params=params, headers=headers, timeout=24)
        resp.raise_for_status()
        rows = _nc_hist_parse_ultimos_resultados(fecha_iso, resp.text)
        return {"ok": True, "rows": rows, "error": ""}
    except Exception as e:
        return {"ok": False, "rows": [], "error": str(e)}


def _nc_hist_progress_map(counts_by_label, dias_proc, dias_tot, final=False):
    out = _nc_hist_progress_defaults()
    dias_proc = max(0, int(dias_proc or 0))
    dias_tot = max(1, int(dias_tot or 1))
    for label, count in (counts_by_label or {}).items():
        if label not in out:
            continue
        c = int(count or 0)
        if final or dias_proc <= 0:
            total = c
        else:
            total = max(c, int(round((c / float(max(1, dias_proc))) * float(dias_tot))))
        out[label] = {"procesados": c, "total": total}
    return out


def _resultado_validar_loteria_sorteo(lottery_db, draw_db):
    """True si el par lotería/sorteo puede persistirse (catálogo oficial, NY, etc.)."""
    lottery_db = (lottery_db or "").strip()
    nd = normalizar_sorteo(draw_db) or str(draw_db or "").strip()
    if lottery_db == "New York":
        return _resultado_new_york_draw_valido(draw_db)
    if lottery_db in SORTEOS_POR_LOTERIA:
        allowed = {
            normalizar_sorteo(d) or str(d).strip()
            for d in SORTEOS_POR_LOTERIA[lottery_db]
        }
        return bool(nd) and nd in allowed
    return True


def _norm_resultado_tres_digitos(r1, r2, r3):
    out = []
    for v in (r1, r2, r3):
        s = str(v or "").strip()
        if re.match(r"^\d{1,2}$", s):
            out.append(s.zfill(2))
        else:
            out.append(s)
    return out[0], out[1], out[2]


def _resultado_fila_tiene_numeros(p1, p2, p3):
    return bool(
        str(p1 or "").strip() or str(p2 or "").strip() or str(p3 or "").strip()
    )


def _resultado_row_val(row, key, idx=0, default=None):
    """Lee columna de fila SQLite/PostgreSQL (dict, sqlite3.Row o tupla). Row tiene keys() pero no .get()."""
    if row is None:
        return default
    if isinstance(row, dict):
        return row.get(key, default)
    if hasattr(row, "keys"):
        try:
            if hasattr(row, "get"):
                return row.get(key, default)
            return row[key]
        except (KeyError, IndexError, TypeError):
            return default
    try:
        return row[idx]
    except (IndexError, TypeError, KeyError):
        return default


def _resultado_draw_normalizado_guardado(hora_o_draw):
    """Mismo pipeline que _resultado_upsert para comparar columnas draw en SQL."""
    s = formatear_hora_estandar(str(draw_almacen_canonico(hora_o_draw) or "").strip())
    return (normalizar_sorteo(s) or str(s or "").strip()) or ""


def _resultado_fetch_numeros(cur, lottery_db: str, draw_val: str, fecha: str):
    """
    Lee números oficiales existentes en BD para (lottery, draw, fecha).
    Devuelve tuple (p1,p2,p3) normalizados a 2 dígitos cuando aplica, o None si no existe.
    """
    try:
        dv = formatear_hora_estandar(str(draw_val or "").strip())
        dv = normalizar_sorteo(dv) or str(dv or "").strip()
        cur.execute(
            _sql(
                """
                SELECT primero, segundo, tercero
                FROM resultados
                WHERE lottery = %s AND COALESCE(draw, '') = COALESCE(%s, '') AND fecha = %s
                """
            ),
            (lottery_db, dv, str(fecha or "")[:10]),
        )
        row = cur.fetchone()
        if not row:
            return None
        p1 = _resultado_row_val(row, "primero", 0)
        p2 = _resultado_row_val(row, "segundo", 1)
        p3 = _resultado_row_val(row, "tercero", 2)
        return _norm_resultado_tres_digitos(p1, p2, p3)
    except Exception:
        return None


