def _client_ip_actual():
    """IP del cliente si hay request activo (respeta X-Forwarded-For)."""
    try:
        if has_request_context() and request:
            xf = (request.headers.get("X-Forwarded-For") or "").split(",")[0].strip()
            return (xf or (request.remote_addr or "") or None)[:64] or None
    except Exception:
        pass
    return None


def _row_to_audit_dict(row):
    """Serializa una fila de cursor (sqlite.Row / RealDictRow) a dict JSON-friendly."""
    if row is None:
        return None
    d = dict(row) if hasattr(row, "keys") else {}
    out = {}
    for k, v in d.items():
        if v is None:
            out[k] = None
        elif isinstance(v, datetime):
            out[k] = v.isoformat()
        elif isinstance(v, date):
            out[k] = v.isoformat()
        elif isinstance(v, bytes):
            out[k] = v.decode("utf-8", errors="replace")
        elif isinstance(v, (int, float, str, bool)):
            out[k] = v
        elif type(v).__name__ == "Decimal":
            try:
                out[k] = float(v)
            except Exception:
                out[k] = str(v)
        else:
            out[k] = str(v)
    return out


def registrar_auditoria(cur, usuario, accion, tabla, registro_id, antes, despues):
    """Inserta un registro en auditoria_logs (PostgreSQL JSONB / SQLite TEXT)."""
    u = str(usuario or "sistema")[:200]
    aj = json.dumps(antes, ensure_ascii=False) if antes is not None else None
    dj = json.dumps(despues, ensure_ascii=False) if despues is not None else None
    if os.environ.get("DATABASE_URL"):
        cur.execute(
            """
            INSERT INTO auditoria_logs (usuario, accion, tabla, registro_id, antes, despues)
            VALUES (%s, %s, %s, %s, CAST(%s AS JSONB), CAST(%s AS JSONB))
            """,
            (u, accion, tabla, registro_id, aj, dj),
        )
    else:
        cur.execute(
            _sql(
                """
                INSERT INTO auditoria_logs (usuario, accion, tabla, registro_id, antes, despues)
                VALUES (%s, %s, %s, %s, %s, %s)
                """
            ),
            (u, accion, tabla, registro_id, aj, dj),
        )


def _auditoria_format_campo_json(v):
    if v is None:
        return "—"
    if isinstance(v, (dict, list)):
        return json.dumps(v, ensure_ascii=False, indent=2)
    if isinstance(v, str):
        t = v.strip()
        if not t:
            return "—"
        try:
            return json.dumps(json.loads(t), ensure_ascii=False, indent=2)
        except Exception:
            return v
    return str(v)


def _auditoria_parse_json_campo(v):
    """Normaliza columnas antes/despues (JSONB dict, texto JSON o None) a dict/list o None."""
    if v is None:
        return None
    if isinstance(v, (dict, list)):
        return v
    if isinstance(v, str):
        t = v.strip()
        if not t:
            return None
        try:
            return json.loads(t)
        except Exception:
            return None
    return None


def _auditoria_money_rd(v):
    """Formato RD$ con separador de miles y dos decimales."""
    if v is None:
        return "—"
    try:
        n = float(v)
    except (TypeError, ValueError):
        return "—"
    s = f"{abs(n):,.2f}"
    sign = "-" if n < 0 else ""
    return "RD$ " + sign + s


def _aud_float_get(d, *keys):
    if not isinstance(d, dict):
        return None
    for k in keys:
        if k not in d or d.get(k) is None:
            continue
        try:
            return float(d[k])
        except (TypeError, ValueError):
            continue
    return None


def _auditoria_balance_final_en(obj):
    if not isinstance(obj, dict):
        return None
    for k in ("balance_final", "balance_real"):
        n = _aud_float_get(obj, k)
        if n is not None:
            return n
    return None


def _auditoria_enriquecer_log_display(d):
    """
    Añade claves de presentación (badge, montos, balances, cajero, icono, objetos JSON).
    Modifica el dict d in-place.
    """
    antes = _auditoria_parse_json_campo(d.get("antes"))
    despues = _auditoria_parse_json_campo(d.get("despues"))
    acc = (str(d.get("accion") or "")).strip().upper()

    if "ELIMINAR" in acc or "DELETE" in acc or acc.startswith("BORR"):
        badge = "aud-badge aud-badge--red"
        icon = "fa-trash-can"
    elif "AJUST" in acc or "AJUSTAR_BALANCE" in acc:
        badge = "aud-badge aud-badge--blue"
        icon = "fa-sliders"
    elif any(x in acc for x in ("CREAR", "INSERT", "REGISTR", "NUEVO")):
        badge = "aud-badge aud-badge--green"
        icon = "fa-circle-plus"
    elif "PAGAR" in acc:
        badge = "aud-badge aud-badge--green"
        icon = "fa-money-bill-wave"
    elif "EDITAR" in acc or "UPDATE" in acc or "MODIF" in acc:
        badge = "aud-badge aud-badge--amber"
        icon = "fa-pen-to-square"
    elif "REVERS" in acc or "ANUL" in acc:
        badge = "aud-badge aud-badge--purple"
        icon = "fa-rotate-left"
    elif "ENTREG" in acc:
        badge = "aud-badge aud-badge--teal"
        icon = "fa-hand-holding-dollar"
    else:
        badge = "aud-badge aud-badge--muted"
        icon = "fa-clipboard-list"

    monto = None
    for src in (despues, antes):
        if not isinstance(src, dict):
            continue
        for key in (
            "monto_entrega_fisica",
            "monto_ajuste_contable",
            "monto_pagado",
            "monto_ingresado_total",
            "monto_ingresado",
            "monto",
            "pagos_premios_monto_revertido",
            "monto_entrega",
        ):
            n = _aud_float_get(src, key)
            if n is not None:
                monto = n
                break
        if monto is not None:
            break

    bal_ant = None
    bal_dsp = None
    if isinstance(despues, dict):
        n = _aud_float_get(despues, "balance_final_antes")
        if n is not None:
            bal_ant = n
        nested = despues.get("despues")
        if isinstance(nested, dict):
            b = _auditoria_balance_final_en(nested)
            if b is not None:
                bal_dsp = b
        res = despues.get("despues_resumen")
        if bal_dsp is None and isinstance(res, dict):
            b = _auditoria_balance_final_en(res)
            if b is not None:
                bal_dsp = b
        if bal_dsp is None:
            b = _auditoria_balance_final_en(despues)
            if b is not None:
                bal_dsp = b

    if isinstance(antes, dict):
        if bal_ant is None:
            b = _auditoria_balance_final_en(antes)
            if b is not None:
                bal_ant = b
        if bal_ant is None:
            n = _aud_float_get(antes, "saldo_pendiente")
            if n is not None:
                bal_ant = n

    cajero = "—"
    for src in (despues, antes):
        if not isinstance(src, dict):
            continue
        cx = src.get("cajero")
        if cx is not None and str(cx).strip():
            cajero = str(cx).strip()
            break
        cid = src.get("cajero_id")
        if cid is not None and str(cid).strip():
            try:
                cajero = "Cajero #" + str(int(cid))
            except (TypeError, ValueError):
                cajero = str(cid)
            break
        tk = src.get("ticket")
        if isinstance(tk, dict):
            cx = tk.get("cajero")
            if cx is not None and str(cx).strip():
                cajero = str(cx).strip()
                break

    d["ui_badge_class"] = badge
    d["ui_icon"] = icon
    d["ui_monto"] = _auditoria_money_rd(monto)
    d["ui_balance_antes"] = _auditoria_money_rd(bal_ant)
    d["ui_balance_despues"] = _auditoria_money_rd(bal_dsp)
    d["ui_cajero"] = cajero

    if isinstance(antes, (dict, list)):
        d["antes_obj"] = antes
    elif antes is not None:
        d["antes_obj"] = {"_valor": str(antes)[:8000]}
    else:
        d["antes_obj"] = None

    if isinstance(despues, (dict, list)):
        d["despues_obj"] = despues
    elif despues is not None:
        d["despues_obj"] = {"_valor": str(despues)[:8000]}
    else:
        d["despues_obj"] = None

    fv = d.get("fecha")
    dt_rd = valor_guardado_a_rd_dt(fv)
    d["fecha_fmt"] = formatear_fecha_rd(dt_rd if dt_rd else fv)
    return d


def get_ticket(cur, ticket_group):
    """
    Todas las jugadas y el total de un ticket lógico por ticket_group.
    En este proyecto las líneas viven en ticket_lines; el padre en tickets comparte el mismo ticket_group.
    Tickets antiguos (ticket_group NULL) no se consultan aquí; usar /ticket/<id>.
    """
    if ticket_group is None:
        return [], 0.0
    cur.execute(
        _sql(
            "SELECT id FROM tickets WHERE ticket_group = %s ORDER BY id DESC LIMIT 1"
        ),
        (ticket_group,),
    )
    row = cur.fetchone()
    if not row:
        return [], 0.0
    tid = row["id"] if hasattr(row, "keys") else row[0]
    cur.execute(
        _sql(
            """
            SELECT number AS numero, amount AS monto, lottery, draw
            FROM ticket_lines
            WHERE ticket_id = %s AND COALESCE(estado, 'activo') != 'cancelado'
            ORDER BY id ASC
            """
        ),
        (tid,),
    )
    lineas = cur.fetchall()
    cur.execute(
        _sql(
            """
            SELECT COALESCE(SUM(amount), 0) AS total
            FROM ticket_lines
            WHERE ticket_id = %s AND COALESCE(estado, 'activo') != 'cancelado'
            """
        ),
        (tid,),
    )
    tr = cur.fetchone()
    if tr is None:
        return lineas, 0.0
    if hasattr(tr, "keys"):
        total = float(list(tr.values())[0] or 0)
    else:
        total = float(tr[0] or 0)
    return lineas, total


