# DEFAULT ADMIN (si no hay usuarios — permite login admin/admin)
# =====================================================
def ensure_default_admin():
    """Create initial SUPER_ADMIN (jose0219 / Moose555@) if users table is empty."""
    conn = db()
    if not conn:
        return
    cur = None
    try:
        cur = conn.cursor()
        cur.execute("SELECT COUNT(*) FROM users")
        row = cur.fetchone()
        n = list(row.values())[0] if hasattr(row, "values") else row[0]
        if n == 0:
            cur.execute(_sql("""
                INSERT INTO users (username, password_hash, role, approved, is_approved, is_blocked, pago_activo, created_at)
                VALUES (%s, %s, %s, true, true, false, true, CURRENT_TIMESTAMP)
            """), ("jose0219", generate_password_hash("Moose555@"), ROLE_SUPER_ADMIN))
            _db_commit(conn)
    except Exception as e:
        print("ensure_default_admin:", e)
    finally:
        _db_close(conn, cur)


# =====================================================
# BEFORE_REQUEST: solo sesión / tiempo (sin BD ni init_db)
# Esquema: primer db() → _ensure_app_db_initialized()
# =====================================================
@app.before_request
def light_before_request():
    g.request_started_at = time.perf_counter()
    if request.path in REQ_TRACE_PATHS:
        _req_trace(
            "before_request inicio",
            session_u=bool(session.get("u")),
            schema_ready=_DB_SCHEMA_READY,
            initializing=_initializing_db,
        )
    if request.path in ("/health", "/healthz", "/admin_ping", "/api/hora_servidor"):
        return None

    rutas_sin_auth = ("/", "/login", "/create-admin")
    if request.path in rutas_sin_auth:
        return None

    # PWA / estáticos: nunca obligar sesión aquí (un 302 a HTML rompe SW, manifest, JS y CSP).
    if request.path.startswith("/static/"):
        return None
    if request.path in ("/manifest.json", "/sw.js", "/favicon.ico"):
        return None

    now_ts = time.time()
    last = session.get("last_activity", 0)

    def _api_session_invalid():
        if not session.get("u") and not session.get("user"):
            return True
        if now_ts - last > INACTIVITY_TIMEOUT_SECONDS:
            session.clear()
            return True
        return False

    # Rutas JSON: jamás responder 302 HTML (los fetch esperan JSON).
    if request.path.startswith("/api/"):
        if _api_session_invalid():
            return jsonify({"error": "unauthorized"}), 401
        if now_ts - float(session.get("last_activity_touch", 0) or 0) >= SESSION_TOUCH_INTERVAL_SECONDS:
            session["last_activity"] = now_ts
            session["last_activity_touch"] = now_ts
        return None

    if not session.get("u") and not session.get("user"):
        return redirect("/")

    if now_ts - last > INACTIVITY_TIMEOUT_SECONDS:
        session.clear()
        return redirect("/")
    if now_ts - float(session.get("last_activity_touch", 0) or 0) >= SESSION_TOUCH_INTERVAL_SECONDS:
        session["last_activity"] = now_ts
        session["last_activity_touch"] = now_ts

    _sync_session_role_from_db()

    role_block = _enforce_role_route_access()
    if role_block is not None:
        return role_block

    return None


@app.after_request
def log_request_timing(response):
    start = getattr(g, "request_started_at", None)
    if start is not None:
        elapsed_s = time.perf_counter() - start
        elapsed_ms = round(elapsed_s * 1000, 2)
        response.headers["X-Response-Time-ms"] = str(elapsed_ms)
        if request.path not in ("/health", "/healthz", "/admin_ping"):
            print(
                "Tiempo:",
                round(elapsed_s, 4),
                "s",
                request.method,
                request.path,
                response.status_code,
            )
        if elapsed_ms >= REQUEST_SLOW_MS:
            log.warning(
                "request_slow method=%s path=%s status=%s ms=%s",
                request.method,
                request.path,
                response.status_code,
                elapsed_ms,
            )
        else:
            log.info(
                "request method=%s path=%s status=%s ms=%s",
                request.method,
                request.path,
                response.status_code,
                elapsed_ms,
            )
        if request.path in REQ_TRACE_PATHS:
            _req_trace(
                "after_request fin",
                status=response.status_code,
                ms=elapsed_ms,
            )
    return response


