def _upsert_official_lottery_draws(cur):
    """Garantiza filas en `lotteries` para cada (lotería oficial, hora) sin duplicar."""
    for lottery, draws in SORTEOS_POR_LOTERIA.items():
        for draw in draws:
            dnorm = normalizar_sorteo(draw) or str(draw).strip()
            if not dnorm:
                continue
            cur.execute(
                _sql(
                    """
                    INSERT INTO lotteries (lottery, draw)
                    SELECT %s, %s
                    WHERE NOT EXISTS (
                        SELECT 1 FROM lotteries x
                        WHERE x.lottery = %s AND TRIM(COALESCE(x.draw, '')) = %s
                    )
                    """
                ),
                (lottery, dnorm, lottery, dnorm),
            )


def _resolver_loteria_id_venta(cur, lottery_txt, draw_txt):
    """
    FK lógico hacia ``lotteries.id`` usando el mismo (lottery, draw) que el POS guarda en ``ticket_lines``.
    Devuelve None si no encuentra coincidencia (ej. texto antiguo no canónico).
    """
    lot = normalizar_loteria(lottery_txt) or str(lottery_txt or "").strip()
    if not lot:
        return None
    if str(draw_txt or "").strip():
        dr = draw_almacen_canonico(draw_txt)
    else:
        dr = normalizar_sorteo(draw_txt) or str(draw_txt or "").strip()
    dr = dr or ""
    try:
        cur.execute(
            _sql(
                "SELECT id FROM lotteries WHERE lottery = %s "
                "AND TRIM(COALESCE(draw, '')) = TRIM(%s) LIMIT 1"
            ),
            (lot, dr),
        )
        row = cur.fetchone()
        if row:
            rid = row["id"] if hasattr(row, "keys") else row[0]
            return int(rid) if rid is not None else None
    except Exception:
        pass
    return None


def _backfill_ticket_lines_loteria_id(cur, is_pg):
    """Rellena ``ticket_lines.loteria_id`` legacy matcheando texto con ``lotteries``."""
    try:
        if is_pg:
            cur.execute(
                """
                UPDATE ticket_lines tl
                SET loteria_id = lo.id
                FROM lotteries lo
                WHERE tl.loteria_id IS NULL
                  AND tl.lottery = lo.lottery
                  AND TRIM(COALESCE(tl.draw, '')) = TRIM(COALESCE(lo.draw, ''))
                """
            )
        else:
            cur.execute("""
                UPDATE ticket_lines SET loteria_id = (
                  SELECT lo.id FROM lotteries lo
                  WHERE ticket_lines.lottery = lo.lottery
                    AND TRIM(COALESCE(ticket_lines.draw, '')) = TRIM(COALESCE(lo.draw, ''))
                  LIMIT 1
                )
                WHERE loteria_id IS NULL AND EXISTS (
                  SELECT 1 FROM lotteries lo
                  WHERE ticket_lines.lottery = lo.lottery
                    AND TRIM(COALESCE(ticket_lines.draw, '')) = TRIM(COALESCE(lo.draw, ''))
                )
                """)
    except Exception as e:
        log.warning("_backfill_ticket_lines_loteria_id: %s", e, exc_info=True)
        try:
            _rollback_pg_cursor(cur)
        except Exception:
            pass


def _ticket_lines_sql_and_params_loteria_id(loteria_sel_id=None):
    """
    Fragmento de filtro (alias tabla ``ticket_lines``) + tuple de parámetros.
    Solo aplica igualdad cuando el id es un entero > 0.
    """
    try:
        lid = int(loteria_sel_id or 0)
    except (TypeError, ValueError):
        lid = 0
    if lid <= 0:
        return "", ()
    return " AND ticket_lines.loteria_id = %s", (lid,)


def _loteria_id_desde_querystring():
    try:
        lr = (request.args.get("loteria_id") or "").strip()
        x = int(lr) if lr else 0
        return x if x > 0 else None
    except (TypeError, ValueError):
        return None


def _allowed_lottery_draw_pairs():
    """Pares (lotería, hora) permitidos en `lotteries`, alineados con SORTEOS_POR_LOTERIA."""
    s = set()
    for lottery, draws in SORTEOS_POR_LOTERIA.items():
        for d in draws:
            dn = normalizar_sorteo(d) or str(d).strip()
            if dn:
                s.add((lottery, dn))
    return s


def _purge_lotteries_to_official_catalog(cur):
    """
    Limpia la tabla `lotteries` (catálogo de sorteos en POS):
    - Elimina filas sin hora efectiva y pares (lotería, hora) no oficiales (p. ej. New York 2:20 PM).
    - Elimina duplicados por misma lotería + misma hora normalizada (conserva el id más bajo).
    - Normaliza texto de columnas lottery/draw en las filas que permanecen.
    - Vuelve a insertar cualquier par oficial faltante.
    El índice único lotteries_lottery_draw_unique equivale a UNIQUE (lotería, hora) con draw vacío unificado.
    """
    allowed = _allowed_lottery_draw_pairs()
    try:
        cur.execute(_sql("SELECT id, lottery, draw FROM lotteries"))
        raw_rows = cur.fetchall()
    except Exception as e:
        print("_purge_lotteries_to_official_catalog: SELECT", e)
        return

    def _cell(r, key, i):
        if isinstance(r, dict):
            return r.get(key)
        try:
            return r[key]
        except Exception:
            pass
        try:
            return r[i]
        except Exception:
            return None

    to_delete = set()
    canonical_min_id = {}
    for r in raw_rows:
        rid = _cell(r, "id", 0)
        if rid is None:
            continue
        nlot = normalizar_loteria(_cell(r, "lottery", 1)) or str(_cell(r, "lottery", 1) or "").strip()
        ndr = normalizar_sorteo(_cell(r, "draw", 2)) or str(_cell(r, "draw", 2) or "").strip()
        if not ndr or (nlot, ndr) not in allowed:
            to_delete.add(rid)
            continue
        key = (nlot, ndr)
        if key not in canonical_min_id:
            canonical_min_id[key] = rid
        else:
            keep = min(canonical_min_id[key], rid)
            drop = max(canonical_min_id[key], rid)
            canonical_min_id[key] = keep
            to_delete.add(drop)

    for rid in to_delete:
        try:
            cur.execute(_sql("DELETE FROM lotteries WHERE id = %s"), (rid,))
        except Exception as e:
            print("_purge_lotteries_to_official_catalog DELETE", rid, e)

    for r in raw_rows:
        rid = _cell(r, "id", 0)
        if rid is None or rid in to_delete:
            continue
        nlot = normalizar_loteria(_cell(r, "lottery", 1)) or str(_cell(r, "lottery", 1) or "").strip()
        ndr = normalizar_sorteo(_cell(r, "draw", 2)) or str(_cell(r, "draw", 2) or "").strip()
        olot = str(_cell(r, "lottery", 1) or "").strip()
        odr = str(_cell(r, "draw", 2) or "").strip()
        if olot != nlot or odr != ndr:
            try:
                cur.execute(
                    _sql("UPDATE lotteries SET lottery = %s, draw = %s WHERE id = %s"),
                    (nlot, ndr, rid),
                )
            except Exception as e:
                print("_purge_lotteries_to_official_catalog UPDATE", rid, e)

    _upsert_official_lottery_draws(cur)

    try:
        if os.environ.get("DATABASE_URL"):
            cur.execute("""
                DELETE FROM lotteries a
                USING lotteries b
                WHERE a.id > b.id
                  AND a.lottery = b.lottery
                  AND COALESCE(TRIM(a.draw), '') = COALESCE(TRIM(b.draw), '')
            """)
        else:
            cur.execute("""
                DELETE FROM lotteries
                WHERE EXISTS (
                    SELECT 1 FROM lotteries l2
                    WHERE l2.lottery = lotteries.lottery
                      AND COALESCE(TRIM(l2.draw), '') = COALESCE(TRIM(lotteries.draw), '')
                      AND l2.id < lotteries.id
                )
            """)
    except Exception as e:
        print("_purge_lotteries_to_official_catalog dedup final:", e)


