def _pago_premio_es_truthy_pagado(raw):
    return raw in (True, 1, "t", "true", "1", "T", "True")


def _premio_max_ganador_detectado_dt(join_rows, ticket_id):
    """Mayor instante ganador_detectado_en entre filas join del ticket (RD aware)."""
    max_dt = None
    tid = int(ticket_id or 0)
    for r in join_rows or []:
        if int(r.get("ticket_id") or 0) != tid:
            continue
        dt = valor_guardado_a_rd_dt(r.get("res_ganador_detectado_en"))
        if dt is None:
            continue
        if max_dt is None or dt > max_dt:
            max_dt = dt
    return max_dt


def _premio_pago_espera_ganador_ok(cur, ticket_id, hoy):
    """
    True sólo si ya pasó PREMIO_PAGO_ESPERA desde el último instante de sorteo conocido (America/Santo_Domingo)
    o, en su defecto, desde ganador_detectado_en (fallback). Nunca autoriza con «True» por ausencia de datos
    si existe premio pendiente sin ventana resuelta.
    Retorna (permitido, segundos_restantes o None).
    hoy: parámetro legado; el cálculo usa fecha_sorteo guardada en «premios».
    """
    cur.execute(
        _sql(
            """
            SELECT premio, lottery, draw, fecha_sorteo, ganador_detectado_en
            FROM premios
            WHERE ticket_id = %s AND estado = %s
            """
        ),
        (int(ticket_id), "pendiente"),
    )
    lineas_sql = []
    for row in cur.fetchall() or []:
        d = dict(row) if hasattr(row, "keys") else {
            "premio": row[0],
            "lottery": row[1],
            "draw": row[2],
            "fecha_sorteo": row[3],
            "ganador_detectado_en": row[4],
        }
        lineas_sql.append(
            {
                "premio": float(d.get("premio") or 0),
                "lottery": d.get("lottery"),
                "draw": d.get("draw"),
                "fecha_sorteo_linea": d.get("fecha_sorteo"),
                "fecha_sorteo": d.get("fecha_sorteo"),
                "ganador_detectado_en": d.get("ganador_detectado_en"),
            }
        )

    info = _premio_ticket_eval_habilitar_pago_ui(
        lineas_sql,
        ticket_id=int(ticket_id),
        imprimir_debug=True,
    )

    if not lineas_sql:
        return True, None

    if not info.get("tiene_ganador"):
        return False, info.get("seconds_until_pay")

    if info.get("tiempo_ok"):
        return True, None

    return False, info.get("seconds_until_pay")


def _premio_devengado_por_ticket_hoy(cur, ticket_id, hoy):
    """Suma premios de todas las líneas ganadoras del ticket (misma lógica que /ganadores). Propaga errores SQL."""
    join_rows = _ganadores_fetch_lineas_vs_resultados(cur, hoy, ticket_id=ticket_id)
    sub = join_rows or []
    if not sub:
        return 0.0
    cfg = _ganadores_try_load_pagos_config(cur) or {}
    pagos_efectivo = {**PAGOS, **cfg}
    lista = _ganadores_procesar_filas(sub, pagos=pagos_efectivo, hoy_rd_str=hoy, cur=cur)
    total_acc = float(sum(float(x.get("premio") or 0) for x in lista))
    if os.environ.get("DEBUG_TRACE_PAGO_PREMIO", "").strip().lower() in ("1", "true", "yes"):
        print("ticket:", ticket_id)
        for x in lista or []:
            print(
                "numero jugado:",
                repr(x.get("number")),
                "resultado oficial:",
                repr(x.get("resultado")),
                "premio encontrado:",
                x.get("premio"),
            )
        print("total acumulado:", total_acc)
    return total_acc


def _total_premio_ganadores_devengado_lista_hoy(cur, hoy_str, cajero_username=None):
    """
    Suma premios de líneas ganadoras del día (misma lista que /ganadores). No usa tickets.premio.
    """
    uname_raw = (cajero_username or "").strip()
    join_rows = _ganadores_fetch_lineas_vs_resultados(
        cur, hoy_str, cajero_username=uname_raw if uname_raw else None
    )
    cfg = _ganadores_try_load_pagos_config(cur) or {}
    lista = _ganadores_procesar_filas(
        join_rows, pagos={**PAGOS, **cfg}, hoy_rd_str=hoy_str, cur=cur
    )
    un = uname_raw.lower()
    if not un:
        return float(sum(float(x.get("premio") or 0) for x in lista))
    return float(
        sum(
            float(x.get("premio") or 0)
            for x in lista
            if str(x.get("cajero") or "").strip().lower() == un
        )
    )


def _pendiente_premios_ganadores_hoy_rd(cur, hoy_str, conn=None):
    """
    Suma económica pendiente del día (RD), alineada a `/ganadores`.
    Preferir `_ganadores_pendientes_dashboard_resumen` cuando haya `conn`.
    """
    hs = str(hoy_str or "").strip()[:10]
    cn = conn or getattr(cur, "connection", None)
    if cn is not None and len(hs) == 10:
        try:
            return float(
                (_ganadores_pendientes_dashboard_resumen(cur, cn, hs)).get("pendiente_hoy") or 0
            )
        except Exception:
            try:
                cn.rollback()
            except Exception:
                pass
    try:
        if len(hs) == 10:
            st = _premios_pendientes_aggregate(
                cur, None, fecha_ref=None, fecha_hasta=hs, omit_integridad_fecha=True
            )
            return float(st.get("sum_premio") or 0)
    except Exception:
        try:
            _cx = getattr(cur, "connection", None)
            if _cx is not None:
                _cx.rollback()
        except Exception:
            pass
    try:
        cur.execute(
            _sql(
                """SELECT COALESCE(SUM(premio), 0) AS s FROM premios WHERE estado = %s
                AND (substr(trim(COALESCE(fecha_dia,'')), 1, 10) = %s
                OR substr(trim(COALESCE(fecha_resultado,'')), 1, 10) = %s
                OR substr(trim(COALESCE(fecha_sorteo,'')), 1, 10) = %s)"""
            ),
            tuple(["pendiente", hs, hs, hs]),
        )
        row = cur.fetchone()
        return float((row.get("s") if hasattr(row, "get") else (row[0] if row else 0)) or 0)
    except Exception:
        try:
            cur.execute("SELECT COALESCE(SUM(premio), 0) AS s FROM premios WHERE estado = %s", ("pendiente",))
            row = cur.fetchone()
            return float((row.get("s") if hasattr(row, "get") else (row[0] if row else 0)) or 0)
        except Exception:
            return 0.0


def _pendiente_premios_todos_ganadores_no_pagados(cur, conn=None):
    cn = conn or getattr(cur, "connection", None)
    if cn is not None:
        hs = str(ahora_rd().date().strftime("%Y-%m-%d"))
        try:
            return float((_ganadores_pendientes_dashboard_resumen(cur, cn, hs)).get("pendiente_total") or 0)
        except Exception:
            try:
                cn.rollback()
            except Exception:
                pass
    try:
        st = _premios_pendientes_aggregate(cur, None, fecha_ref=None)
        return float(st.get("sum_premio") or 0)
    except Exception:
        pass
    try:
        cur.execute(_sql("SELECT COALESCE(SUM(premio), 0) AS s FROM premios WHERE estado = %s"), ("pendiente",))
        row = cur.fetchone()
        return float((row.get("s") if hasattr(row, "get") else (row[0] if row else 0)) or 0)
    except Exception:
        return 0.0


def _pago_premio_ya_registrado_premio_id(cur, premio_id):
    try:
        pid = int(premio_id)
    except (TypeError, ValueError):
        return False
    if pid <= 0:
        return False
    cur.execute(
        _sql(
            "SELECT 1 FROM pagos_premios WHERE premio_id = %s AND "
            + _pp_sin_revertir_sql("pagos_premios")
            + " LIMIT 1"
        ),
        (pid,),
    )
    return cur.fetchone() is not None


def _premio_pago_espera_ganador_ok_premio(cur, premio_id):
    """Igual que la espera post-sorteo, pero evaluando solo la fila `premios.id`."""
    cur.execute(
        _sql(
            """
            SELECT ticket_id, premio, lottery, draw, fecha_sorteo, ganador_detectado_en
            FROM premios WHERE id = %s
            """
        ),
        (int(premio_id),),
    )
    row = cur.fetchone()
    if not row:
        return False, None
    d = dict(row) if hasattr(row, "keys") else {}
    tid = int(d.get("ticket_id") or (row[0] if row else 0) or 0)
    fe = d.get("fecha_sorteo") or ""
    lineas_sql = [
        {
            "premio": float(d.get("premio") or 0),
            "lottery": d.get("lottery"),
            "draw": d.get("draw"),
            "fecha_sorteo_linea": fe,
            "fecha_sorteo": fe,
            "ganador_detectado_en": d.get("ganador_detectado_en"),
        }
    ]
    info = _premio_ticket_eval_habilitar_pago_ui(lineas_sql, ticket_id=tid)
    if not lineas_sql or float(lineas_sql[0].get("premio") or 0) <= 0:
        return True, None
    if not info.get("tiene_ganador"):
        return False, info.get("seconds_until_pay")
    if info.get("tiempo_ok"):
        return True, None
    return False, info.get("seconds_until_pay")


def _premio_eval_habilitar_pago_ui_por_premio_id(cur, premio_id):
    """Misma salida que `_premio_ticket_eval_habilitar_pago_ui` para una fila `premios`."""
    try:
        pid = int(premio_id)
    except (TypeError, ValueError):
        return {
            "tiene_ganador": False,
            "habilitar_pago": False,
            "pago_habilitar_unix_ms": _premio_ticket_far_future_pay_ms(),
        }
    if pid <= 0:
        return {
            "tiene_ganador": False,
            "habilitar_pago": False,
            "pago_habilitar_unix_ms": _premio_ticket_far_future_pay_ms(),
        }
    cur.execute(
        _sql(
            """
            SELECT ticket_id, premio, lottery, draw, fecha_sorteo, ganador_detectado_en
            FROM premios WHERE id = %s
            """
        ),
        (pid,),
    )
    row = cur.fetchone()
    if not row:
        return {
            "tiene_ganador": False,
            "habilitar_pago": False,
            "pago_habilitar_unix_ms": _premio_ticket_far_future_pay_ms(),
        }
    d = dict(row) if hasattr(row, "keys") else {}
    tid = int(d.get("ticket_id") or 0)
    fe = d.get("fecha_sorteo") or ""
    lineas_sql = [
        {
            "premio": float(d.get("premio") or 0),
            "lottery": d.get("lottery"),
            "draw": d.get("draw"),
            "fecha_sorteo_linea": fe,
            "fecha_sorteo": fe,
            "ganador_detectado_en": d.get("ganador_detectado_en"),
        }
    ]
    return _premio_ticket_eval_habilitar_pago_ui(lineas_sql, ticket_id=tid)


def _sync_linea_si_todas_premios_linea_pagados(cur, line_id, is_pg):
    if not line_id:
        return
    try:
        lid = int(line_id)
    except (TypeError, ValueError):
        return
    if lid <= 0:
        return
    cur.execute(
        _sql(
            "SELECT COUNT(*) AS c FROM premios WHERE line_id = %s AND lower(trim(COALESCE(estado,''))) = %s"
        ),
        (lid, "pendiente"),
    )
    rw = cur.fetchone()
    c = int((rw.get("c") if hasattr(rw, "keys") else (rw[0] if rw else 0)) or 0)
    if c > 0:
        return
    if is_pg:
        cur.execute(
            "UPDATE ticket_lines SET premio_linea_pagada = 1, pagado = TRUE WHERE id = %s",
            (lid,),
        )
    else:
        cur.execute(
            _sql("UPDATE ticket_lines SET premio_linea_pagada = 1, pagado = 1 WHERE id = ?"),
            (lid,),
        )


def _sync_ticket_si_todos_premios_ticket_pagados(cur, ticket_id, is_pg):
    tid = int(ticket_id)
    cur.execute(
        _sql(
            "SELECT COUNT(*) AS c FROM premios WHERE ticket_id = %s AND lower(trim(COALESCE(estado,''))) = %s"
        ),
        (tid, "pendiente"),
    )
    rw = cur.fetchone()
    c = int((rw.get("c") if hasattr(rw, "keys") else (rw[0] if rw else 0)) or 0)
    if c > 0:
        return
    _ts_pago_rd = timestamp_rd_iso()
    if is_pg:
        cur.execute(
            """
            UPDATE tickets
            SET pagado = TRUE, ganador = TRUE,
                fecha_pago = COALESCE(fecha_pago, (NOW() AT TIME ZONE 'America/Santo_Domingo'))
            WHERE id = %s
            """,
            (tid,),
        )
    else:
        cur.execute(
            _sql(
                """
            UPDATE tickets
            SET pagado = 1, ganador = 1,
                fecha_pago = COALESCE(fecha_pago, ?)
            WHERE id = ?
            """
            ),
            (_ts_pago_rd, tid),
        )


# =====================================================
# BANCO GENERAL + SUBCUENTAS POR CAJERO
# =====================================================
BANCO_TIPO_BALANCE_INICIAL = "balance_inicial"
BANCO_TIPO_VENTA = "venta_ticket"
BANCO_TIPO_PREMIO = "premio_pagado"
BANCO_TIPO_ENTREGA = "entrega_cajero_admin"
BANCO_TIPO_FONDO = "fondo_entregado_cajero"
BANCO_TIPO_RETIRO = "retiro_banco"
BANCO_TIPO_AJUSTE = "ajuste_manual"
BANCO_TIPO_ANULACION = "anulacion"
BANCO_TIPO_REVERSA_PAGO_PREMIO = "reversa_pago_premio"

_BANCO_TIPOS_VALIDOS = frozenset(
    {
        BANCO_TIPO_BALANCE_INICIAL,
        BANCO_TIPO_VENTA,
        BANCO_TIPO_PREMIO,
        BANCO_TIPO_ENTREGA,
        BANCO_TIPO_FONDO,
        BANCO_TIPO_RETIRO,
        BANCO_TIPO_AJUSTE,
        BANCO_TIPO_ANULACION,
        BANCO_TIPO_REVERSA_PAGO_PREMIO,
    }
)


def _banco_row_val(row, key, idx=0, default=None):
    if row is None:
        return default
    if hasattr(row, "keys"):
        try:
            if hasattr(row, "get"):
                return row.get(key, default)
            d = dict(row)
            return d.get(key, default)
        except Exception:
            pass
    try:
        return row[idx]
    except (IndexError, TypeError, KeyError):
        return default


def _banco_is_pg():
    return bool(os.environ.get("DATABASE_URL"))


def _banco_bool_from_row(val):
    """Lee afecta_banco desde fila (PG boolean o SQLite 0/1)."""
    if val is None:
        return False
    if isinstance(val, bool):
        return val
    if isinstance(val, (int, float)):
        return bool(int(val))
    return str(val).strip().lower() in ("1", "true", "t", "yes", "si", "sí")


def _banco_bool_for_db(val):
    """Valor para INSERT en banco_movimientos.afecta_banco (INTEGER en app schema)."""
    if isinstance(val, bool):
        b = val
    elif isinstance(val, (int, float)):
        b = bool(int(val))
    else:
        b = _banco_bool_from_row(val)
    return 1 if b else 0


def _banco_resolve_cajero_id(cur, cajero_ref):
    """Convierte username o id numérico al id de users."""
    if cajero_ref is None:
        return None
    try:
        if isinstance(cajero_ref, int) or (isinstance(cajero_ref, str) and str(cajero_ref).strip().isdigit()):
            cid = int(cajero_ref)
            if cid > 0:
                cur.execute(_sql("SELECT id FROM users WHERE id = %s"), (cid,))
                r = cur.fetchone()
                if r:
                    return int(_banco_row_val(r, "id", 0))
    except (TypeError, ValueError):
        pass
    un = str(cajero_ref or "").strip()
    if not un:
        return None
    cur.execute(_sql("SELECT id FROM users WHERE lower(trim(username)) = lower(trim(%s))"), (un,))
    r = cur.fetchone()
    if r:
        return int(_banco_row_val(r, "id", 0))
    return None


def _banco_cajero_username(cur, cajero_id):
    try:
        cid = int(cajero_id or 0)
    except (TypeError, ValueError):
        return ""
    if cid <= 0:
        return ""
    cur.execute(_sql("SELECT username FROM users WHERE id = %s"), (cid,))
    r = cur.fetchone()
    return str(_banco_row_val(r, "username", 0) or "").strip()


def _banco_pg_txn(cur):
    """PostgreSQL: FOR UPDATE y escrituras requieren transacción activa."""
    if os.environ.get("DATABASE_URL"):
        _pg_ensure_transaction_for_savepoints(cur)


def _banco_has_referencia_col(cur):
    """True si la columna referencia_movimiento_id existe (migración aplicada)."""
    try:
        if _banco_is_pg():
            cur.execute(
                """
                SELECT 1 FROM information_schema.columns
                WHERE table_schema = 'public'
                  AND table_name = 'banco_movimientos'
                  AND column_name = 'referencia_movimiento_id'
                LIMIT 1
                """
            )
            return cur.fetchone() is not None
        cur.execute(_sql("SELECT referencia_movimiento_id FROM banco_movimientos LIMIT 0"))
        return True
    except Exception:
        return False


def _banco_get_general_row(cur, for_update=False):
    if for_update:
        _banco_pg_txn(cur)
    sql = "SELECT id, balance_inicial, balance_actual, creado_por, updated_by FROM banco_general ORDER BY id ASC LIMIT 1"
    if for_update and os.environ.get("DATABASE_URL"):
        sql += " FOR UPDATE"
    cur.execute(_sql(sql))
    return cur.fetchone()


def _banco_ensure_general_row(cur, creado_por=None):
    row = _banco_get_general_row(cur)
    if row:
        return row
    admin_txt = (str(creado_por or "").strip() or "sistema")[:200]
    if os.environ.get("DATABASE_URL"):
        cur.execute(
            """
            INSERT INTO banco_general (balance_inicial, balance_actual, creado_por, updated_by)
            VALUES (0, 0, %s, %s)
            RETURNING id, balance_inicial, balance_actual, creado_por, updated_by
            """,
            (admin_txt, admin_txt),
        )
        return cur.fetchone()
    cur.execute(
        _sql(
            "INSERT INTO banco_general (balance_inicial, balance_actual, creado_por, updated_by) VALUES (%s, %s, %s, %s)"
        ),
        (0, 0, admin_txt, admin_txt),
    )
    cur.execute(_sql("SELECT id, balance_inicial, balance_actual, creado_por, updated_by FROM banco_general ORDER BY id DESC LIMIT 1"))
    return cur.fetchone()


def banco_get_balance_general(cur):
    row = _banco_get_general_row(cur)
    if not row:
        return 0.0
    return round(float(_banco_row_val(row, "balance_actual", 2, 0) or 0), 2)


def banco_get_balance_cajero(cur, cajero_id):
    """Balance virtual del cajero desde movimientos (no columna fija en users)."""
    try:
        cid = int(cajero_id or 0)
    except (TypeError, ValueError):
        return 0.0
    if cid <= 0:
        return 0.0
    cur.execute(
        _sql(
            """
            SELECT COALESCE(SUM(CASE WHEN suma_o_resta = '+' THEN monto ELSE -monto END), 0) AS bal
            FROM banco_movimientos
            WHERE cajero_id = %s
            """
        ),
        (cid,),
    )
    r = cur.fetchone()
    return round(float(_banco_row_val(r, "bal", 0, 0) or 0), 2)


def _banco_movimiento_duplicado(cur, tipo, ticket_id=None, pago_id=None):
    if ticket_id and tipo == BANCO_TIPO_VENTA:
        cur.execute(
            _sql("SELECT id FROM banco_movimientos WHERE tipo = %s AND ticket_id = %s LIMIT 1"),
            (BANCO_TIPO_VENTA, int(ticket_id)),
        )
        return cur.fetchone() is not None
    if pago_id and tipo == BANCO_TIPO_PREMIO:
        cur.execute(
            _sql("SELECT id FROM banco_movimientos WHERE tipo = %s AND pago_id = %s LIMIT 1"),
            (BANCO_TIPO_PREMIO, int(pago_id)),
        )
        return cur.fetchone() is not None
    return False


def _banco_registrar_movimiento(
    cur,
    tipo,
    monto,
    afecta_banco,
    suma_o_resta,
    cajero_id=None,
    usuario_admin_id=None,
    ticket_id=None,
    pago_id=None,
    descripcion=None,
    referencia_movimiento_id=None,
):
    """
    Inserta movimiento y actualiza balance_actual del banco general si aplica.
    No hace commit. Lanza ValueError si tipo inválido o monto <= 0.
    """
    tipo = str(tipo or "").strip().lower()
    if tipo not in _BANCO_TIPOS_VALIDOS:
        raise ValueError("tipo_movimiento_invalido")
    monto = round(float(monto or 0), 2)
    if monto <= 0:
        raise ValueError("monto_invalido")
    sign = str(suma_o_resta or "+").strip()
    if sign not in ("+", "-"):
        raise ValueError("signo_invalido")
    afecta = _banco_bool_for_db(afecta_banco)

    _banco_pg_txn(cur)
    _banco_ensure_general_row(cur)
    gen = _banco_get_general_row(cur, for_update=True)
    bal_gen_antes = round(float(_banco_row_val(gen, "balance_actual", 2, 0) or 0), 2)
    bal_gen_despues = bal_gen_antes
    if afecta:
        bal_gen_despues = round(bal_gen_antes + monto if sign == "+" else bal_gen_antes - monto, 2)

    cid = None
    if cajero_id is not None:
        cid = _banco_resolve_cajero_id(cur, cajero_id)
    bal_caj_antes = None
    bal_caj_despues = None
    if cid:
        bal_caj_antes = banco_get_balance_cajero(cur, cid)
        bal_caj_despues = round(bal_caj_antes + monto if sign == "+" else bal_caj_antes - monto, 2)

    desc_txt = (str(descripcion or "").strip() or tipo)[:500]
    admin_uid = None
    if usuario_admin_id is not None:
        try:
            admin_uid = int(usuario_admin_id) or None
        except (TypeError, ValueError):
            admin_uid = None

    ref_id = int(referencia_movimiento_id) if referencia_movimiento_id else None
    ins_params = (
        tipo,
        monto,
        afecta,
        sign,
        bal_gen_antes,
        bal_gen_despues,
        bal_caj_antes,
        bal_caj_despues,
        cid,
        admin_uid,
        int(ticket_id) if ticket_id else None,
        int(pago_id) if pago_id else None,
        desc_txt,
    )
    if _banco_has_referencia_col(cur):
        cur.execute(
            _sql(
                """
            INSERT INTO banco_movimientos (
                tipo, monto, afecta_banco, suma_o_resta,
                balance_general_antes, balance_general_despues,
                cajero_balance_antes, cajero_balance_despues,
                cajero_id, usuario_admin_id, ticket_id, pago_id,
                descripcion, referencia_movimiento_id
            ) VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
            """
            ),
            ins_params + (ref_id,),
        )
    else:
        cur.execute(
            _sql(
                """
            INSERT INTO banco_movimientos (
                tipo, monto, afecta_banco, suma_o_resta,
                balance_general_antes, balance_general_despues,
                cajero_balance_antes, cajero_balance_despues,
                cajero_id, usuario_admin_id, ticket_id, pago_id,
                descripcion
            ) VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
            """
            ),
            ins_params,
        )

    if afecta:
        gen_id = int(_banco_row_val(gen, "id", 0) or 0)
        try:
            _aud_u = _auditoria_usuario_actual()
        except Exception:
            _aud_u = "sistema"
        upd_by = (str(usuario_admin_id or "") or _aud_u or "sistema")[:200]
        cur.execute(
            _sql("UPDATE banco_general SET balance_actual = %s, updated_by = %s, updated_at = CURRENT_TIMESTAMP WHERE id = %s"),
            (bal_gen_despues, upd_by, gen_id),
        )
    _banco_log(
        "movimiento",
        tipo=tipo,
        monto=monto,
        signo=sign,
        afecta_banco=bool(afecta if isinstance(afecta, bool) else int(afecta or 0)),
        banco_antes=bal_gen_antes,
        banco_despues=bal_gen_despues,
        cajero_id=cid,
    )

    if os.environ.get("DATABASE_URL"):
        cur.execute(_sql("SELECT id FROM banco_movimientos ORDER BY id DESC LIMIT 1"))
    else:
        cur.execute("SELECT last_insert_rowid()")
    rr = cur.fetchone()
    mov_id = int(_banco_row_val(rr, "id", 0) or (rr[0] if rr else 0) or 0)
    return {
        "movimiento_id": mov_id,
        "balance_general": bal_gen_despues,
        "balance_cajero": bal_caj_despues,
    }


def banco_configurar_inicial(cur, monto, nota=None, usuario_admin_id=None):
    """Solo admin: registra balance inicial (una sola vez; ventas posteriores suman encima)."""
    monto = round(float(monto or 0), 2)
    if monto < 0:
        raise ValueError("monto_invalido")
    cur.execute(
        _sql("SELECT COUNT(*) AS c FROM banco_movimientos WHERE tipo = %s"),
        (BANCO_TIPO_BALANCE_INICIAL,),
    )
    rw = cur.fetchone()
    if int(_banco_row_val(rw, "c", 0, 0) or 0) > 0:
        raise ValueError("balance_inicial_ya_existe")
    _banco_pg_txn(cur)
    try:
        _aud_ini = _auditoria_usuario_actual()
    except Exception:
        _aud_ini = "admin"
    admin_txt = str(usuario_admin_id or _aud_ini or "admin")[:200]
    _banco_ensure_general_row(cur, creado_por=admin_txt)
    gen = _banco_get_general_row(cur, for_update=True)
    gen_id = int(_banco_row_val(gen, "id", 0) or 0)
    cur.execute(
        _sql("UPDATE banco_general SET balance_inicial = %s, creado_por = %s, updated_by = %s WHERE id = %s"),
        (monto, admin_txt, admin_txt, gen_id),
    )
    if monto > 0.005:
        return _banco_registrar_movimiento(
            cur,
            BANCO_TIPO_BALANCE_INICIAL,
            monto,
            True,
            "+",
            usuario_admin_id=usuario_admin_id,
            descripcion=nota or "Balance inicial del banco general",
        )
    cur.execute(
        _sql("UPDATE banco_general SET balance_actual = 0, updated_at = CURRENT_TIMESTAMP WHERE id = %s"),
        (gen_id,),
    )
    return {"movimiento_id": None, "balance_general": 0.0, "balance_cajero": None}


def banco_registrar_venta(cur, ticket_id, cajero_id, monto, descripcion=None):
    tid = int(ticket_id)
    m = round(float(monto or 0), 2)
    if _banco_movimiento_duplicado(cur, BANCO_TIPO_VENTA, ticket_id=tid):
        log.info(
            "[BANCO_SYNC_VENTA] ticket_id=%s monto=%.2f ya_existia=1 creado=0",
            tid,
            m,
        )
        return {"duplicado": True, "balance_general": banco_get_balance_general(cur)}
    banco_antes = banco_get_balance_general(cur)
    desc = descripcion or ("Venta ticket #%s" % tid)
    out = _banco_registrar_movimiento(
        cur,
        BANCO_TIPO_VENTA,
        monto,
        True,
        "+",
        cajero_id=cajero_id,
        ticket_id=tid,
        descripcion=desc,
    )
    log.info(
        "[BANCO_SYNC_VENTA] ticket_id=%s monto=%.2f ya_existia=0 creado=1 banco_antes=%.2f banco_despues=%.2f",
        tid,
        m,
        banco_antes,
        float(out.get("balance_general") or banco_get_balance_general(cur)),
    )
    return out


def banco_registrar_pago(cur, pago_id, cajero_id, monto, ticket_id=None, descripcion=None, premio_id=None):
    pid_pago = int(pago_id)
    m = round(float(monto or 0), 2)
    if _banco_movimiento_duplicado(cur, BANCO_TIPO_PREMIO, pago_id=pid_pago):
        log.info(
            "[BANCO_PAGO_PREMIO] premio_id=%s pago_id=%s ticket_id=%s monto=%.2f duplicado=1",
            premio_id,
            pid_pago,
            ticket_id,
            m,
        )
        return {"duplicado": True, "balance_general": banco_get_balance_general(cur)}
    cid = _banco_resolve_cajero_id(cur, cajero_id)
    banco_antes = banco_get_balance_general(cur)
    caj_antes = banco_get_balance_cajero(cur, cid) if cid else 0.0
    desc = descripcion or ("Premio pagado (pago #%s)" % pid_pago)
    out = _banco_registrar_movimiento(
        cur,
        BANCO_TIPO_PREMIO,
        monto,
        True,
        "-",
        cajero_id=cajero_id,
        pago_id=pid_pago,
        ticket_id=ticket_id,
        descripcion=desc,
    )
    caj_despues = banco_get_balance_cajero(cur, cid) if cid else 0.0
    log.info(
        "[BANCO_PAGO_PREMIO] premio_id=%s pago_id=%s ticket_id=%s monto=%.2f "
        "banco_antes=%.2f banco_despues=%.2f cajero_antes=%.2f cajero_despues=%.2f",
        premio_id,
        pid_pago,
        ticket_id,
        m,
        banco_antes,
        float(out.get("balance_general") or banco_get_balance_general(cur)),
        caj_antes,
        caj_despues,
    )
    return out


