# UTILIDAD: ¿CAJA CERRADA HOY?
# =====================================================
def caja_cerrada_hoy():
    c = db()
    if not c:
        return False
    cur = None
    try:
        cur = c.cursor()
        hoy = ahora_rd().strftime("%Y-%m-%d")
        cur.execute(_sql("""
            SELECT COUNT(*) AS n
            FROM cash_closings
            WHERE date = %s
        """), (hoy,))
        row = cur.fetchone()
        n = _row_sum_scalar(row)
        return float(n or 0) > 0
    except Exception as e:
        log.warning("caja_cerrada_hoy: %s", e, exc_info=True)
        return False
    finally:
        _db_close(c, cur)


