# CONFIGURACION LIMITES DESDE ADMIN (AUTO)
# =====================================================

def init_config():
    c = db()
    if not c:
        return
    cur = None
    try:
        cur = c.cursor()
        cur.execute("""
        CREATE TABLE IF NOT EXISTS config (
            key TEXT PRIMARY KEY,
            value TEXT
        )
        """)
        defaults = {
            "usar_limites": "0",
            "limite_sorteo": "5000",
            "limite_numero": "100",
            "meta_diaria": "0",
            "nc_auto_activo": "0",
            "nc_dias_analisis": "30",
            "nc_riesgo_minimo": "alto",
            "nc_limite_alto": "0",
            "nc_limite_medio": "50",
            "nc_limite_bajo": "100",
        }
        for k, v in defaults.items():
            cur.execute(
                _sql("SELECT 1 FROM config WHERE key=%s"),
                (k,),
            )
            if not cur.fetchone():
                cur.execute(
                    _sql("INSERT INTO config (key, value) VALUES (%s, %s)"),
                    (k, v),
                )
        c.commit()
    except Exception as e:
        print("ERROR init_config:", e)
        traceback.print_exc()
        try:
            c.rollback()
        except Exception:
            pass
    finally:
        _db_close(c, cur)
    
# =====================================================
# OBTENER CONFIG
# =====================================================
def get_config(key):
    c = db()
    if not c:
        return None
    cur = None
    try:
        cur = c.cursor()
        cur.execute(_sql("SELECT value FROM config WHERE key=%s"), (key,))
        r = cur.fetchone()
        if r is None:
            return None
        return r.get("value") if hasattr(r, "get") else (r[0] if isinstance(r, (list, tuple)) else getattr(r, "value", None))
    except Exception as e:
        print("ERROR get_config:", e)
        try:
            c.rollback()
        except Exception:
            pass
        return None
    finally:
        _db_close(c, cur)

# ===============================
# NORMALIZAR NUMERO
# ===============================
def normalizar_jugada(valor):
    """Valor canónico de jugada, independiente del formato visual del ticket."""
    if valor is None:
        return None
    s = str(valor).replace("\xa0", " ").replace("\u200b", "")
    s = re.sub(r"[\r\n\t]+", " ", s)
    s = re.sub(r"\s+", " ", s).strip()
    if not s:
        return None

    # Línea impresa: "56 - RD$25.00" / "56-RD$25". No confundir con Pale "12-34".
    m = re.match(r"^(\d{1,4})\s*[-–—]\s*(?:RD\$|\$)\s*\d+(?:[.,]\d+)?\s*$", s, re.I)
    if m:
        return m.group(1).strip()

    # Variante sin moneda: "56 - 25.00". Requiere espacios o decimal para no tocar "12-34".
    m = re.match(r"^(\d{1,4})\s+[-–—]\s*\d+[.,]\d+\s*$", s)
    if m:
        return m.group(1).strip()

    return s


def _limpiar_texto_numero_ticket(numero):
    limpio = normalizar_jugada(numero)
    return limpio if limpio is not None else ""


def _jugada_simple_int(valor):
    """Convierte una Quiniela/Super Pale simple a entero 0-99; rechaza Pale/Tripleta."""
    s = normalizar_jugada(valor)
    if not s or "-" in s:
        return None
    try:
        return int(s) % 100
    except (TypeError, ValueError):
        return None


