def normalizar_numero(numero):

    if numero is None:
        return ""

    numero = _limpiar_texto_numero_ticket(numero)
    if not numero:
        return ""

    # 1202 -> 12-02
    if len(numero) == 4 and numero.isdigit():
        return numero[:2] + "-" + numero[2:]

    # Quiniela u otro número de 1–2 cifras → dos dígitos ("3"/"03" → "03", "30" → "30")
    if re.match(r"^\d{1,2}$", numero):
        return str(int(numero, 10)).zfill(2)

    return numero


def _norm_sorteo_dos_digitos(val):
    """
    Unifica números de sorteo para comparar jugadas vs resultados (Quiniela / componentes de Pale).
    - "30", 30, 30.0, Decimal(30), "030", "30.0" → "30"
    - PostgreSQL/SQLite pueden devolver NUMERIC/float: str(30.0) es "30.0" y antes rompía el match con "30".
    - Pale/Tripleta: componentes numéricos; si no aplica, se deja el string recortado.
    """
    if val is None:
        return ""
    # Tipos numéricos del driver (int, float, Decimal) — no pasar por regex solo-dígitos
    if not isinstance(val, str):
        try:
            if isinstance(val, float) and val != val:  # NaN
                return ""
            n = int(round(float(val))) % 100
            return str(n).zfill(2)
        except (TypeError, ValueError, OverflowError):
            pass
    s = _limpiar_texto_numero_ticket(val)
    if not s:
        return ""
    # "30.0" / "06.00" desde Excel o columnas REAL
    if re.match(r"^\d+\.\d+$", s):
        try:
            n = int(round(float(s))) % 100
            return str(n).zfill(2)
        except (TypeError, ValueError):
            pass
    if re.match(r"^\d+$", s):
        try:
            n = int(s, 10) % 100
            return str(n).zfill(2)
        except (TypeError, ValueError):
            return s
    return s


def numeros_resultado_bd(primero, segundo, tercero):
    """
    Números oficiales (1.er, 2.do, 3.er) desde columnas primero, segundo, tercero.
    Cada valor se normaliza a dos dígitos (str); no concatenar como \"23-77-78\".
    """
    out = []
    for n in (primero, segundo, tercero):
        x = _norm_sorteo_dos_digitos(n)
        if x != "":
            out.append(str(x).strip().zfill(2))
    return out


def _ganadores_hay_match_numeros(jugados, r1, r2, r3):
    """True si algún número jugado (quiniela) está en el resultado oficial (3 posiciones)."""
    if not jugados:
        return False
    # Comparación exacta por token de 2 dígitos (evita cualquier match parcial/substring).
    jug_set = {str(j).strip().zfill(2) for j in jugados if str(j).strip() != ""}
    res_set = set(numeros_resultado_bd(r1, r2, r3))
    return bool(jug_set and res_set and (jug_set & res_set))


def _quiniela_jugados_desde_campo(numero):
    """
    Uno o varios números de quiniela en el mismo campo (coma, punto y coma, espacios).
    Devuelve lista de strings '00'..'99'.
    Formato Pale (05-50) y Tripleta (05-12-30) no se descomponen aquí: usan su propia rama.
    """
    raw = normalizar_jugada(numero)
    if not raw:
        return []
    if _es_formato_tripleta_numero(raw):
        return []
    if _es_formato_pale_numero(raw):
        return []
    s = raw.strip()
    s = s.replace("\u200b", "").replace("\ufeff", "")
    _uq = {
        "\uff0c": ",",
        "\u3001": ",",
        "\uff1b": ";",
        "\u00a0": " ",
        "\u2013": "-",
        "\u2014": "-",
        "\xb7": " ",
    }
    s = s.translate(str.maketrans(_uq))
    s = re.sub(r"\s+", " ", s).strip()
    # "21 - 78 - 87" / "73-78" / "21-78-87" → unificar guiones y separar tokens.
    s = re.sub(r"\s*-\s*", ",", s)
    toks = [p for p in re.split(r"[,\s;|]+", s) if p and str(p).strip()]
    vals = []
    for t in toks:
        t = str(t).strip()
        if re.fullmatch(r"\d{1,4}", t):
            vals.append(str(int(t, 10) % 100).zfill(2))
    return list(dict.fromkeys(vals))


def _quiniela_premio_fragmentos(numero_campo, monto, r1, r2, r3, pagos_merge):
    """
    Desglose de premios Quiniela por acierto (1.er / 2.do / 3.er), mismo criterio que calcular_premio.
    Cada ítem lleva premio_shard estable (único por línea+acierto) para persistir varias filas en `premios`.
    pagos_merge: dict devuelto por _merge_pagos_calc (claves lowercase).

    Evalúa cada posición del resultado por separado: si el mismo número aparece en 2.do y 3.er,
    se emiten dos fragmentos (q2:NN y q3:NN) con el multiplicador de cada posición.
    Varios números distintos en el mismo campo (lista) siguen sumando premios independientes.
    """
    try:
        m = float(monto)
    except (TypeError, ValueError):
        return []
    if m <= 0:
        return []
    if not isinstance(pagos_merge, dict):
        return []
    if _es_formato_tripleta_numero(numero_campo) or _es_formato_pale_numero(numero_campo):
        return []
    r1s = _norm_sorteo_dos_digitos(r1)
    r2s = _norm_sorteo_dos_digitos(r2)
    r3s = _norm_sorteo_dos_digitos(r3)
    numero_raw = normalizar_numero(numero_campo)
    jugados = _quiniela_jugados_desde_campo(numero_campo)
    if not jugados:
        n_one = _jugada_simple_int(numero_raw)
        if n_one is not None:
            jugados = [str(n_one).zfill(2)]
    if not jugados:
        return []
    m1 = _p_mul(pagos_merge, "quiniela_1")
    m2 = _p_mul(pagos_merge, "quiniela_2")
    m3 = _p_mul(pagos_merge, "quiniela_3")
    # (etiqueta shard, posición normalizada, multiplicador)
    slots = (("q1", r1s, m1), ("q2", r2s, m2), ("q3", r3s, m3))
    out = []
    for j in jugados:
        jj = str(j).strip().zfill(2)
        for qtag, rs_k, mk in slots:
            if not rs_k:
                continue
            if jj != rs_k:
                continue
            out.append(
                {
                    "premio_shard": "%s:%s" % (qtag, jj),
                    "premio": round(float(m * float(mk)), 2),
                    "jugado_norm": jj,
                }
            )
    return out


def _ganadores_play_canonical_premio(play):
    play_in = (play or "").strip()
    play_l = play_in.lower().replace("_", " ")
    if play_l == "quiniela" or play_l.startswith("quiniela"):
        return "Quiniela"
    if play_l == "pale" or play_l.startswith("pale"):
        return "Pale"
    if play_l == "tripleta":
        return "Tripleta"
    if play_l in ("super pale", "superpale"):
        return "Super Pale"
    return play_in


def _premio_shard_norm(g):
    if isinstance(g, dict):
        v = g.get("premio_shard")
    else:
        v = g
    if v is None:
        return "0"
    s = str(v).strip()
    return s if s else "0"


