def _premios_normalize_business_fields(g, fecha_sorteo_txt="", fecha_resultado_txt="", fecha_dia_txt=""):
    """Valores canónicos para clave única de negocio (misma forma en INSERT y ON CONFLICT)."""
    lot_raw = g.get("lottery") if isinstance(g, dict) else None
    drw_raw = g.get("draw") if isinstance(g, dict) else None
    num_raw = g.get("number") if isinstance(g, dict) else None
    if isinstance(g, dict) and not num_raw:
        num_raw = g.get("numero")
    lot_u = (normalizar_loteria(lot_raw) or str(lot_raw or "")).strip()
    drw_eff = _draw_efectivo_jugada(lot_raw, drw_raw)
    draw_u = (
        formatear_hora_estandar(str(drw_eff or "").strip())
        or str(drw_eff or "").strip()
    )
    num_u = _norm_sorteo_dos_digitos(num_raw) or str(num_raw or "").strip()
    fe_res = (
        str(
            fecha_resultado_txt
            or (g.get("resultado_fecha_iso") if isinstance(g, dict) else "")
            or fecha_dia_txt
            or fecha_sorteo_txt
            or ""
        ).strip()[:10]
    )
    shard_s = _premio_shard_norm(g)
    return {
        "lottery": lot_u,
        "draw": draw_u,
        "numero": num_u,
        "fecha_resultado": fe_res,
        "premio_shard": shard_s,
    }


def _premios_migrate_unique_constraints(cur):
    """
    Quita UNIQUE legado solo por line_id (p. ej. unique_pago_linea en Render)
    y crea índice único de negocio (ticket + línea + lotería + sorteo + fecha + número + posición).
    """
    is_pg = bool(os.environ.get("DATABASE_URL"))
    if is_pg:
        for cname in (
            "unique_pago_linea",
            "premios_line_id_key",
            "premios_line_id_unique",
            "unique_premio_linea",
            "premios_pkey_line_id",
        ):
            try:
                cur.execute("ALTER TABLE premios DROP CONSTRAINT IF EXISTS %s" % cname)
            except Exception as _de:
                log.warning("premios migrate DROP CONSTRAINT %s: %s", cname, _de)
    for drop_ix in (
        "DROP INDEX IF EXISTS unique_pago_linea",
        "DROP INDEX IF EXISTS idx_premios_line_id_unique",
        "DROP INDEX IF EXISTS idx_premios_line_shard_unique",
        "DROP INDEX IF EXISTS premios_line_id_key",
    ):
        try:
            cur.execute(drop_ix)
        except Exception as _die:
            log.warning("premios migrate %s: %s", drop_ix, _die)
    ix_sql = (
        "CREATE UNIQUE INDEX IF NOT EXISTS idx_premios_ganador_business_unique "
        "ON premios (ticket_id, line_id, lottery, draw, fecha_resultado, numero, premio_shard)"
    )
    try:
        cur.execute(ix_sql)
        log.info("premios: índice único de negocio idx_premios_ganador_business_unique OK")
    except Exception as _ce:
        log.warning("premios migrate CREATE UNIQUE business: %s", _ce, exc_info=True)


def _ganadores_lista_clave_unica(g):
    """
    Clave única de negocio: no colapsa dos tickets por mismo número/lotería/sorteo.
    ticket_id + line_id + lottery + draw + fecha_resultado + numero + premio_shard.
    """
    if not isinstance(g, dict):
        return None
    try:
        tid = int(g.get("ticket_id") or 0)
    except (TypeError, ValueError):
        tid = 0
    lid = _ganadores_line_id_key(g.get("line_id"))
    if lid is None:
        return None
    lot = (
        normalizar_loteria(g.get("lottery")) or str(g.get("lottery") or "").strip()
    ).strip().lower()
    drw = (
        formatear_hora_estandar(str(g.get("draw") or "").strip())
        or str(g.get("draw") or "").strip()
    ).strip().lower()
    fe = str(
        g.get("resultado_fecha_iso")
        or g.get("fecha_sorteo_linea")
        or g.get("fecha_sorteo")
        or g.get("fecha_resultado")
        or g.get("fecha_dia")
        or ""
    ).strip()[:10]
    num = _norm_sorteo_dos_digitos(g.get("number") or g.get("numero") or "")
    return (tid, int(lid), lot, drw, fe, num, _premio_shard_norm(g))


def _ganadores_lista_seen_tuple(g):
    """Clave estable para deduplicar filas Lista de Ganadores (sin fusionar tickets distintos)."""
    return _ganadores_lista_clave_unica(g)


def normalizar_numero_sorteo(val):
    """Alias explícito: un valor numérico de sorteo → cadena de 2 dígitos (ver _norm_sorteo_dos_digitos)."""
    return _norm_sorteo_dos_digitos(val)


