def _ganador_eval_detalle(play_decl, numero, r1, r2, r3, premio=0.0):
    """Resumen de evaluación para logs y diagnóstico (Quiniela / Pale / Tripleta)."""
    play_eff = _play_efectivo_cruce(play_decl, numero)
    res_txt = _ganadores_resultado_str(r1, r2, r3)
    num = str(numero or "").strip()
    coincidencias = []
    gana_premio = float(premio or 0) > 0.005
    gana = False
    motivo = "sin_premio"

    if play_eff == "Tripleta":
        coincidencias, gana_triple = _tripleta_coincidencias_eval(num, r1, r2, r3)
        gana = bool(gana_triple and gana_premio)
        motivo = "tripleta_completa" if gana else "tripleta_incompleta"
    elif play_eff == "Pale":
        coincidencias, gana_pale = _pale_coincidencias_eval(num, r1, r2, r3)
        gana = bool(gana_pale and gana_premio)
        if gana:
            motivo = "pale_par_completo"
        elif coincidencias:
            motivo = "pale_solo_un_numero"
        else:
            motivo = "pale_sin_acierto"
    elif play_eff == "Super Pale":
        n_int = _jugada_simple_int(num)
        r1_int = _jugada_simple_int(_norm_sorteo_dos_digitos(r1))
        gana = n_int is not None and r1_int is not None and n_int == r1_int and gana_premio
        if gana:
            coincidencias = [str(n_int).zfill(2)]
            motivo = "super_pale_primer_premio"
        else:
            motivo = "super_pale_sin_acierto"
    else:
        jugados = _quiniela_jugados_desde_campo(num) or []
        if not jugados:
            ji = _jugada_simple_int(num)
            if ji is not None:
                jugados = [str(int(ji) % 100).zfill(2)]
        res_set = set(numeros_resultado_bd(r1, r2, r3))
        coincidencias = sorted(set(jugados) & res_set)
        gana = bool(coincidencias) and gana_premio
        motivo = "quiniela_acierto" if gana else "quiniela_sin_acierto"

    return play_eff, res_txt, coincidencias, gana, motivo


def _tripleta_eval_log(ticket, jugada, resultado, coincidencias, gana, play_decl=None):
    log.info(
        "[TRIPLETA_EVAL] ticket=%s jugada=%s resultado=%s coincidencias=%s gana=%s play=%s",
        ticket,
        jugada,
        resultado,
        coincidencias,
        "true" if gana else "false",
        play_decl or "",
    )


def _play_efectivo_cruce(play, numero):
    """
    Tipo de jugada para cruce/premio. Formato con guiones define el tipo real:
    - 3 números → Tripleta
    - 2 números → Pale
    aunque el campo play venga mal guardado como Quiniela.
    """
    num = str(numero or "").strip()
    if _es_formato_tripleta_numero(num):
        return "Tripleta"
    if _es_formato_pale_numero(num):
        return "Pale"
    canon = _ganadores_play_canonical_premio(play)
    if canon in ("Tripleta", "Pale", "Quiniela", "Super Pale"):
        return canon
    return "Quiniela"


def _display_2d_sorteo_val(val):
    """Texto breve para ticket (dos cifras coherentes con el sorteo)."""
    xs = _norm_sorteo_dos_digitos(val)
    if xs:
        return xs.zfill(2) if xs.isdigit() else xs
    if val is None:
        return ""
    s = str(val).strip()
    return s


def _resultados_fila_recibo_pago(cur, lottery, draw, fecha_iso):
    """
    Devuelve (primero, segundo, tercero) desde `resultados` para lotería + sorteo + fecha de sorteo.
    Misma clave que el panel de premios / ganadores (sin hardcodear números).
    """
    if not lottery or not fecha_iso:
        return (None, None, None)
    fecha = str(fecha_iso).strip()[:10]
    if len(fecha) < 10:
        return (None, None, None)
    loteria = str(lottery).strip()
    if not loteria:
        return (None, None, None)
    draw_j = normalizar_sorteo(draw) or str(draw or "").strip()
    try:
        if os.environ.get("DATABASE_URL"):
            _fdg = _sql_expr_resultados_fecha_calendario_rd_pg("fecha")
            cur.execute(
                f"""
                SELECT primero, segundo, tercero
                FROM resultados
                WHERE lottery = %s
                  AND {_fdg} = CAST(%s AS date)
                  AND lower(replace(trim(COALESCE(draw, '')), ' ', ''))
                    = lower(replace(trim(COALESCE(%s, '')), ' ', ''))
                ORDER BY id DESC
                LIMIT 1
                """,
                (loteria, fecha, draw_j),
            )
        else:
            _fdgs = _sql_expr_resultados_fecha_calendario_rd_sqlite("fecha")
            cur.execute(
                _sql(
                    """
                SELECT primero, segundo, tercero
                FROM resultados
                WHERE lottery = %s
                  AND """
                    + _fdgs
                    + """ = %s
                  AND lower(replace(trim(ifnull(draw, '')), ' ', ''))
                    = lower(replace(trim(ifnull(%s, '')), ' ', ''))
                ORDER BY id DESC
                LIMIT 1
                    """
                ),
                (loteria, fecha, draw_j),
            )
        row = cur.fetchone()
        if not row:
            return (None, None, None)
        if hasattr(row, "get"):
            return (row.get("primero"), row.get("segundo"), row.get("tercero"))
        return (row[0], row[1], row[2])
    except Exception as e:
        log.warning("_resultados_fila_recibo_pago: %s", e, exc_info=True)
        _rollback_pg_cursor(cur)
        return (None, None, None)


def _texto_numero_ganador_recibo_pago(play, numero_linea, primero, segundo, tercero):
    """
    Etiqueta para ticket térmico: número(s) oficial(es) del sorteo según tipo de jugada.
    Usa los valores de `resultados` (primero/segundo/tercero), no literales.
    """
    if primero is None and segundo is None and tercero is None:
        return ""
    r1s = _norm_sorteo_dos_digitos(primero)
    r2s = _norm_sorteo_dos_digitos(segundo)
    r3s = _norm_sorteo_dos_digitos(tercero)
    d1 = _display_2d_sorteo_val(primero)
    d2 = _display_2d_sorteo_val(segundo)
    d3 = _display_2d_sorteo_val(tercero)

    play_l = (play or "").strip().lower().replace("_", " ")
    if play_l in ("super pale", "superpale"):
        return d1 or "—"

    if play_l == "tripleta":
        if r1s and r2s and r3s:
            return f"{d1} · {d2} · {d3}"
        return ""

    if play_l == "pale":
        par = _parse_pale_par(str(numero_linea or "").strip())
        if par and r1s and r2s and r3s:
            n1, n2 = par
            nums = {n1, n2}
            rs12 = {r1s, r2s}
            rs13 = {r1s, r3s}
            rs23 = {r2s, r3s}
            if nums == rs12:
                return f"{d1}-{d2}"
            if nums == rs13:
                return f"{d1}-{d3}"
            if nums == rs23:
                return f"{d2}-{d3}"
        parts = [x for x in (d1, d2, d3) if x]
        return " · ".join(parts) if parts else ""

    # Quiniela (y default)
    nq = _norm_sorteo_dos_digitos(normalizar_numero(numero_linea) or numero_linea)
    if nq and r1s and nq == r1s:
        return d1
    if nq and r2s and nq == r2s:
        return d2
    if nq and r3s and nq == r3s:
        return d3
    parts = [x for x in (d1, d2, d3) if x]
    return " · ".join(parts) if parts else ""


# ===============================
# CALCULAR PREMIO AUTOMATICO (PRO)
# ===============================
def calcular_premio(play, numero, monto, r1, r2, r3, pagos=None):
    """
    Quiniela: uno o varios números de 2 cifras en el mismo campo; suma un premio por cada
    acierto (1er / 2do / 3er) — cada número jugado puede pagar hasta una vez por posición.
    Pale: par de números distintos; debe coincidir con el par del sorteo (1º-2º, 1º-3º o 2º-3º).
    Tripleta: tres números distintos; deben coincidir con el trío {1º,2º,3º} (orden libre).
    Super Pale: acierta el 1er premio con el número jugado (cupón de un solo número).
    """
    P = _merge_pagos_calc(pagos)

    try:
        monto = float(monto)
    except Exception:
        return 0

    if monto <= 0 or numero is None or str(numero).strip() == "":
        return 0

    play = _play_efectivo_cruce(play, numero)
    play = (play or "").strip()
    play_l = play.lower().replace("_", " ")
    if play_l == "quiniela" or play_l.startswith("quiniela"):
        play = "Quiniela"
    elif play_l == "pale":
        play = "Pale"
    elif play_l == "tripleta":
        play = "Tripleta"
    elif play_l in ("super pale", "superpale"):
        play = "Super Pale"

    numero_raw = normalizar_numero(numero)
    r1s = _norm_sorteo_dos_digitos(r1)
    r2s = _norm_sorteo_dos_digitos(r2)
    r3s = _norm_sorteo_dos_digitos(r3)
    resultados_raw = [r1, r2, r3]
    resultados_norm = [r1s, r2s, r3s]

    if _verbose_premios_debug():
        print("DEBUG calcular_premio ENTRADA play=", repr(play), "monto=", repr(monto))
        _debug_ganadores_real(numero, resultados_norm)

    if os.environ.get("DEBUG_CALCULAR_PREMIO") == "1":
        log.debug(
            "calcular_premio play=%s Ticket:%s Resultados:%s norm=%s,%s,%s",
            play,
            numero_raw,
            resultados_raw,
            r1s,
            r2s,
            r3s,
        )

    # ===============================
    # QUINIELA: uno o varios números (coma/espacio); suma premios por cada acierto 1er/2do/3er.
    # ===============================
    if play == "Quiniela":
        frags = _quiniela_premio_fragmentos(numero, monto, r1, r2, r3, P)
        if not frags:
            if os.environ.get("DEBUG_VALIDACION_PREMIOS") == "1":
                print("DEBUG VALIDACION calcular_premio: Quiniela sin tokens", repr(numero_raw))
            if _verbose_premios_debug():
                print(
                    "DEBUG calcular_premio RETORNA 0: Quiniela no convertible",
                    repr(numero_raw),
                )
            return 0
        total = float(sum(float(f.get("premio") or 0) for f in frags))
        if os.environ.get("DEBUG_VALIDACION_PREMIOS") == "1":
            print("DEBUG VALIDACION calcular_premio Quiniela")
            print("Fragmentos:", frags)
            print("Resultados 1/2/3:", r1s, r2s, r3s)
            print("numeros_resultado_bd:", numeros_resultado_bd(r1, r2, r3))
            print("Premio suma:", total)
        if total > 0:
            if _verbose_premios_debug():
                print(
                    "DEBUG calcular_premio PREMIO Quiniela:",
                    total,
                    "fragmentos=",
                    frags,
                )
            return total
        if _verbose_premios_debug():
            print(
                "DEBUG calcular_premio RETORNA 0: Quiniela no coincide",
                frags,
                [r1s, r2s, r3s],
            )
        return 0

    # ===============================
    # PALE (12-34): par contra pares del sorteo
    # Gana si el conjunto {n1,n2} coincide con {1er,2do}, {1er,3er} o {2do,3er} (orden del cupón no importa).
    # pale_12 / pale_13: siempre PAGO_PALE (1500× monto); pale_23 sigue en PAGOS / pagos_config.
    # ===============================
    if play == "Pale":
        par = _parse_pale_par(numero_raw)
        if not par:
            if _verbose_premios_debug():
                print("DEBUG calcular_premio RETORNA 0: Pale no parsea", repr(numero_raw))
            return 0
        if not (r1s and r2s and r3s):
            if _verbose_premios_debug():
                print(
                    "DEBUG calcular_premio RETORNA 0: Pale resultados incompletos",
                    resultados_norm,
                )
            return 0
        n1, n2 = par
        nums = {n1, n2}
        rs12 = {r1s, r2s}
        rs13 = {r1s, r3s}
        rs23 = {r2s, r3s}
        if nums == rs12:
            premio = monto * float(PAGO_PALE)
            if _verbose_premios_debug():
                print("DEBUG calcular_premio PREMIO:", premio, "motivo=pale_12")
            return premio
        if nums == rs13:
            premio = monto * float(PAGO_PALE)
            if _verbose_premios_debug():
                print("DEBUG calcular_premio PREMIO:", premio, "motivo=pale_13")
            return premio
        if nums == rs23:
            premio = monto * _p_mul(P, "pale_23")
            if _verbose_premios_debug():
                print("DEBUG calcular_premio PREMIO:", premio, "motivo=pale_23")
            return premio
        if _verbose_premios_debug():
            print(
                "DEBUG calcular_premio RETORNA 0: Pale no coincide",
                nums,
                [rs12, rs13, rs23],
            )
        return 0

    # ===============================
    # TRIPLETA (12-34-56): trío = {1º,2º,3º}
    # ===============================
    if play == "Tripleta":
        tnums = _parse_tripleta_nums(numero_raw)
        res_txt = _ganadores_resultado_str(r1, r2, r3)
        coincidencias, gana = _tripleta_coincidencias_eval(numero_raw, r1, r2, r3)
        _tripleta_eval_log(
            "",
            numero_raw,
            res_txt,
            coincidencias,
            gana,
            play_decl=play,
        )
        if not tnums:
            if _verbose_premios_debug():
                print("DEBUG calcular_premio RETORNA 0: Tripleta no parsea", repr(numero_raw))
            return 0
        if not (r1s and r2s and r3s):
            if _verbose_premios_debug():
                print(
                    "DEBUG calcular_premio RETORNA 0: Tripleta resultados incompletos",
                    resultados_norm,
                )
            return 0
        if gana:
            premio = monto * _p_mul(P, "tripleta")
            if _verbose_premios_debug():
                print("DEBUG calcular_premio PREMIO:", premio, "motivo=tripleta")
            return premio
        if _verbose_premios_debug():
            print(
                "DEBUG calcular_premio RETORNA 0: Tripleta no coincide",
                tnums,
                resultados_norm,
            )
        return 0

    # ===============================
    # SUPER PALE (acierto 1er con número simple)
    # ===============================
    if play == "Super Pale":
        ns_int = _jugada_simple_int(numero_raw)
        r1_int = _jugada_simple_int(r1s)
        if _verbose_premios_debug():
            print("LINEA:", numero)
            print("NORMALIZADO:", ns_int)
            print("RESULTADOS:", [r1_int, _jugada_simple_int(r2s), _jugada_simple_int(r3s)])
        if ns_int is not None and r1_int is not None and ns_int == r1_int:
            premio = monto * _p_mul(P, "super_pale")
            if _verbose_premios_debug():
                print("DEBUG calcular_premio PREMIO:", premio, "motivo=super_pale")
            return premio
        if _verbose_premios_debug():
            print(
                "DEBUG calcular_premio RETORNA 0: Super Pale no coincide",
                ns_int,
                r1_int,
            )
        return 0

    if _verbose_premios_debug():
        print("DEBUG calcular_premio RETORNA 0: tipo no reconocido", repr(play))
    return 0


def _ganadores_acierto_presentacion(play, numero, r1, r2, r3, premio_f, pagos=None, premio_shard=None):
    """
    Textos para UI /ganadores: qué jugó, qué salió en el sorteo y por qué ganó.
    Replica criterios de calcular_premio (sin recalcular multiplicadores en plantilla).
    premio_shard (p. ej. q2:23) fija la posición mostrada cuando el mismo número repite en el resultado.
    """
    premio_f = float(premio_f or 0)
    numero_raw = normalizar_numero(numero)
    r1s = _norm_sorteo_dos_digitos(r1)
    r2s = _norm_sorteo_dos_digitos(r2)
    r3s = _norm_sorteo_dos_digitos(r3)
    res_tres = "-".join(x for x in (r1s, r2s, r3s) if x)

    play_in = (play or "").strip()
    play_eff = _play_efectivo_cruce(play, numero)
    play_l = play_eff.lower().replace("_", " ")
    if play_l == "quiniela" or play_l.startswith("quiniela"):
        play = "Quiniela"
    elif play_l == "pale":
        play = "Pale"
    elif play_l == "tripleta":
        play = "Tripleta"
    elif play_l in ("super pale", "superpale"):
        play = "Super Pale"
    else:
        play = play_eff or play_in

    def _out(jugado, oficial, detalle, ok):
        return {
            "numero_jugado_display": jugado,
            "numero_oficial_display": oficial,
            "resultado_sorteo": res_tres,
            "detalle": detalle,
            "acierto_ok": bool(ok and premio_f > 0),
        }

    if play == "Quiniela":
        jugados_vals = list(_quiniela_jugados_desde_campo(numero) or [])
        if not jugados_vals:
            n_one = _jugada_simple_int(numero_raw)
            if n_one is not None:
                jugados_vals = [str(n_one).zfill(2)]
        # Varios números en la misma celda ("78, 73", ticket impreso tipo lista): reflejar todos los aciertos.
        if len(jugados_vals) > 1:
            hits = []
            _seen_slot = set()
            for j in jugados_vals:
                if not j:
                    continue
                jj = str(j).strip().zfill(2)
                if r1s and jj == str(r1s).strip().zfill(2):
                    sig = ("1", jj)
                    if sig not in _seen_slot:
                        hits.append((jj, r1s, "1er premio"))
                        _seen_slot.add(sig)
                if r2s and jj == str(r2s).strip().zfill(2):
                    sig = ("2", jj)
                    if sig not in _seen_slot:
                        hits.append((jj, r2s, "2do premio"))
                        _seen_slot.add(sig)
                if r3s and jj == str(r3s).strip().zfill(2):
                    sig = ("3", jj)
                    if sig not in _seen_slot:
                        hits.append((jj, r3s, "3er premio"))
                        _seen_slot.add(sig)
            jugado_show = ", ".join(jugados_vals)
            if not hits:
                return _out(jugado_show, "—", "", False)
            oficial_show = ", ".join(str(h[1]) for h in hits)
            detalle = "; ".join("%s (%s)" % (h[2], h[0]) for h in hits)
            return _out(jugado_show, oficial_show, detalle, premio_f > 0.004)
        nq_int = _jugada_simple_int(numero_raw)
        if nq_int is None:
            return _out(numero_raw, "—", "", False)
        jugado_show = _norm_sorteo_dos_digitos(nq_int)
        r1_int = _jugada_simple_int(r1s)
        r2_int = _jugada_simple_int(r2s)
        r3_int = _jugada_simple_int(r3s)
        shard_pos = ""
        if premio_shard:
            m_sh = re.match(r"^q([123]):", str(premio_shard).strip(), re.I)
            if m_sh:
                shard_pos = m_sh.group(1)
        if shard_pos == "1" and r1_int is not None and nq_int == r1_int:
            return _out(jugado_show, r1s, "1er premio", True)
        if shard_pos == "2" and r2_int is not None and nq_int == r2_int:
            return _out(jugado_show, r2s, "2do premio", True)
        if shard_pos == "3" and r3_int is not None and nq_int == r3_int:
            return _out(jugado_show, r3s, "3er premio", True)
        if not shard_pos:
            if r1_int is not None and nq_int == r1_int:
                return _out(jugado_show, r1s, "1er premio", True)
            if r2_int is not None and nq_int == r2_int:
                return _out(jugado_show, r2s, "2do premio", True)
            if r3_int is not None and nq_int == r3_int:
                return _out(jugado_show, r3s, "3er premio", True)
        return _out(jugado_show, "—", "", False)

    if play == "Pale":
        par = _parse_pale_par(numero_raw)
        if not par or not (r1s and r2s and r3s):
            return _out(numero_raw, res_tres, "", False)
        n1, n2 = par
        nums = {n1, n2}
        if nums == {r1s, r2s}:
            return _out(numero_raw, "%s-%s" % (r1s, r2s), "Pale 1er–2do", True)
        if nums == {r1s, r3s}:
            return _out(numero_raw, "%s-%s" % (r1s, r3s), "Pale 1er–3er", True)
        if nums == {r2s, r3s}:
            return _out(numero_raw, "%s-%s" % (r2s, r3s), "Pale 2do–3er", True)
        return _out(numero_raw, res_tres, "", False)

    if play == "Tripleta":
        tnums = _parse_tripleta_nums(numero_raw)
        coincidencias, gana = _tripleta_coincidencias_eval(numero_raw, r1, r2, r3)
        _tripleta_eval_log("", numero_raw, res_tres, coincidencias, gana, play_decl=play_in)
        if not tnums or not (r1s and r2s and r3s):
            return _out(numero_raw, res_tres, "", False)
        if gana:
            return _out(numero_raw, res_tres, "Tripleta (1er+2do+3er)", True)
        return _out(numero_raw, res_tres, "", False)

    if play == "Super Pale":
        ns_int = _jugada_simple_int(numero_raw)
        jugado_show = _norm_sorteo_dos_digitos(ns_int) if ns_int is not None else numero_raw
        r1_int = _jugada_simple_int(r1s)
        if ns_int is not None and r1_int is not None and ns_int == r1_int:
            return _out(jugado_show, r1s, "1er premio (Super Pale)", True)
        return _out(jugado_show, "—", "", False)

    return _out(numero_raw, res_tres, "", False)


def _ganadores_premio_techo_legal(play, monto, pagos=None, numero=None):
    """
    Tope de premio reproducible sin sorteo específico: Quiniela usa cantidad de tokens × monto × max mult
    cuando se conoce el campo numero; si no, conserva el techo conservador de un solo acierto.
    """
    try:
        m = float(monto or 0)
    except (TypeError, ValueError):
        return None
    if m <= 0:
        return 0.0
    P = _merge_pagos_calc(pagos)
    play_eff = _play_efectivo_cruce(play, numero)
    pl = play_eff.strip().lower().replace("_", " ")
    if pl == "quiniela" or pl.startswith("quiniela"):
        mx = max(_p_mul(P, "quiniela_1"), _p_mul(P, "quiniela_2"), _p_mul(P, "quiniela_3"))
        if numero is None or str(numero).strip() == "":
            return m * mx
        num_raw = normalizar_numero(numero)
        jugados = _quiniela_jugados_desde_campo(numero)
        if not jugados:
            n_one = _jugada_simple_int(num_raw)
            if n_one is not None:
                jugados = [str(n_one).zfill(2)]
        k = max(1, len(jugados))
        return m * k * mx
    if pl == "pale":
        return m * max(float(PAGO_PALE), _p_mul(P, "pale_23"))
    if pl == "tripleta":
        return m * _p_mul(P, "tripleta")
    if pl in ("super pale", "superpale"):
        return m * _p_mul(P, "super_pale")
    return m * _p_mul(P, "quiniela_1")


def _ganadores_premio_integridad(play, numero, amount, r1, r2, r3, premio_declarado, pagos=None):
    """
    Doble paso por calcular_premio y comparación con tope legal.
    Descarta líneas si el premio no es reproducible o excede el máximo teórico.
    """
    try:
        amt = float(amount or 0)
        p0 = float(premio_declarado or 0)
    except (TypeError, ValueError):
        return False
    if p0 <= 0 or amt <= 0:
        return False
    try:
        p1 = float(calcular_premio(play, numero, amt, r1, r2, r3, pagos=pagos) or 0)
        p2 = float(calcular_premio(play, numero, amt, r1, r2, r3, pagos=pagos) or 0)
    except Exception:
        return False
    if round(p0, 2) != round(p1, 2) or round(p1, 2) != round(p2, 2):
        log.warning(
            "ganadores: premio_integridad rechazada (doble cálculo) play=%s line_amount=%s p0=%s p1=%s",
            play,
            amt,
            p0,
            p1,
        )
        return False
    techo = _ganadores_premio_techo_legal(play, amt, pagos=pagos, numero=numero)
    if techo is not None and p0 > float(techo) + 0.02:
        log.warning(
            "ganadores: premio_integridad rechazada (sobre tope) play=%s p0=%s techo=%s",
            play,
            p0,
            techo,
        )
        return False
    return True


def _selftest_ganador_quiniela_vs_resultado():
    """
    Prueba directa (activar TEST_GANADOR_MANUAL=1 al arrancar): normalización de ticket
    y Quiniela contra resultados con comparación numérica.
    """
    p_a = float(calcular_premio("Quiniela", "02", 10.0, "02", "43", "41") or 0)
    p_b = float(calcular_premio("Quiniela", "2", 10.0, "02", "43", "41") or 0)
    p_c = float(calcular_premio("Quiniela", "43", 10.0, "02", "43", "41") or 0)
    p_d = float(calcular_premio("Quiniela", "56 - RD$25.00", 10.0, "79", "56", "41") or 0)
    p_e = float(calcular_premio("Quiniela", "21, 78, 87", 10.0, "23", "77", "78") or 0)
    if _quiniela_jugados_desde_campo("21，78，87") != ["21", "78", "87"]:
        raise AssertionError("Unicode comma quiniela tokens: %r" % (_quiniela_jugados_desde_campo("21，78，87"),))
    p_e2 = float(calcular_premio("Quiniela", "21，78，87", 10.0, "23", "77", "78") or 0)
    if p_e <= 0 or p_e2 <= 0:
        raise AssertionError("Quiniela multi-campo: 78 en tercero debía premiar; premio=%s / %s" % (p_e, p_e2))
    if not _ganadores_numero_coincide_resultado("Quiniela", "21, 78, 87", "23", "77", "78"):
        raise AssertionError("coincide Quiniela multi falló")
    if _quiniela_jugados_desde_campo("73-78") != []:
        raise AssertionError(
            "Formato Pale (73-78) no debe descomponerse como Quiniela; got %r"
            % (_quiniela_jugados_desde_campo("73-78"),)
        )
    p_hyphen = float(calcular_premio("Quiniela", "73-78", 10.0, "78", "52", "73") or 0)
    if p_hyphen <= 0:
        raise AssertionError("Pale inferido 73-78 vs 78-52-73 debía premiar par 1er-3er; got %s" % p_hyphen)
    casos_56 = ("56", "56 ", " 56", "56\xa0", "56 - RD$25.00")
    normalizados = [normalizar_jugada(x) for x in casos_56]
    enteros = [_jugada_simple_int(normalizar_numero(x)) for x in casos_56]
    if normalizados != ["56", "56", "56", "56", "56"] or enteros != [56, 56, 56, 56, 56]:
        raise AssertionError("normalización 56 falló: %s / %s" % (normalizados, enteros))
    if not (p_a > 0 and p_b > 0 and p_c > 0 and p_d > 0 and p_e > 0 and p_e2 > 0 and p_hyphen > 0):
        raise AssertionError(
            "esperaba premios > 0 para 02/2/43/56-ticket/multi/guión; got %.2f %.2f %.2f %.2f %.2f %.2f %.2f"
            % (p_a, p_b, p_c, p_d, p_e, p_e2, p_hyphen)
        )
    log.warning(
        "TEST_GANADOR_MANUAL OK: quiniela/ticket normalizado premios %.2f %.2f %.2f %.2f %.2f %.2f %.2f",
        p_a,
        p_b,
        p_c,
        p_d,
        p_e,
        p_e2,
        p_hyphen,
    )


if os.environ.get("TEST_GANADOR_MANUAL") == "1":
    try:
        _selftest_ganador_quiniela_vs_resultado()
    except Exception as _ex:
        log.error("TEST_GANADOR_MANUAL falló: %s", _ex, exc_info=True)


def _selftest_join_manual_num():
    """Caso informe usuario: si la intersección existe pero no hay ganador, sospechar del JOIN."""
    resultado = ["23", "77", "78"]
    jugados = ["21", "78", "87"]
    assert "78" in resultado
    assert any(j in resultado for j in jugados)
    log.warning("TEST_JOIN_MANUAL OK: intersección jugados↔oficial (diagnóstico JOIN)")


if os.environ.get("TEST_JOIN_MANUAL") == "1":
    try:
        _selftest_join_manual_num()
    except Exception as _ex:
        log.error("TEST_JOIN_MANUAL falló: %s", _ex, exc_info=True)


