def _numeros_calientes_dashboard(cur, filtros=None):
    filtros = filtros or {}
    try:
        banca_id = int(filtros.get("banca_id") or 0)
    except (TypeError, ValueError):
        banca_id = 0
    cur.execute(
        _sql(
            """
            SELECT lottery, draw, fecha, primero, segundo, tercero
            FROM resultados
            WHERE COALESCE(TRIM(lottery), '') <> ''
              AND COALESCE(TRIM(fecha), '') <> ''
            ORDER BY fecha DESC, id DESC
            LIMIT 12000
            """
        )
    )
    rows = cur.fetchall() or []
    historial_total = 0
    hoy = ahora_rd().date()
    cut_30 = hoy - timedelta(days=29)
    por_loteria = Counter()
    freq = Counter()
    repeated = Counter()
    last_seen = {}
    num_dates = defaultdict(list)
    trend_daily = Counter()
    for r in rows:
        lot_raw = _limites_row_val(r, "lottery", 0, "")
        fecha_raw = _limites_row_val(r, "fecha", 2, "")
        lot_n = normalizar_loteria(lot_raw) or str(lot_raw or "").strip()
        d = _parse_iso_date_only(fecha_raw)
        if not lot_n or not d:
            continue
        historial_total += 1
        por_loteria[lot_n] += 1
        nums = []
        for idx, key in ((3, "primero"), (4, "segundo"), (5, "tercero")):
            nn = normalizar_numero(_limites_row_val(r, key, idx, ""))
            if re.match(r"^\d{2}$", nn or ""):
                nums.append(nn)
        if not nums:
            continue
        cnums = Counter(nums)
        if d >= cut_30:
            trend_daily[d.strftime("%Y-%m-%d")] += len(set(nums))
        for n in nums:
            freq[n] += 1
            last_seen[n] = max(last_seen.get(n, d), d) if last_seen.get(n) else d
            if len(num_dates[n]) < 20:
                num_dates[n].append(d)
        for dn, vv in cnums.items():
            if vv > 1:
                repeated[dn] += 1

    def _top_numbers(counter_obj, limit=10, by_recent=False):
        keys = list(counter_obj.keys())
        if by_recent:
            keys = sorted(
                keys,
                key=lambda n: (
                    -((last_seen.get(n) or date(1900, 1, 1)).toordinal()),
                    -int(freq.get(n, 0)),
                    n,
                ),
            )
        else:
            keys = sorted(
                keys,
                key=lambda n: (
                    -int(counter_obj.get(n, 0)),
                    -((last_seen.get(n) or date(1900, 1, 1)).toordinal()),
                    n,
                ),
            )
        out = []
        for n in keys[: max(1, int(limit or 10))]:
            ul = []
            seen_dates = set()
            for dd in num_dates.get(n, []):
                iso = dd.strftime("%Y-%m-%d")
                if iso in seen_dates:
                    continue
                seen_dates.add(iso)
                ul.append({"iso": iso, "mmdd": dd.strftime("%m/%d")})
                if len(ul) >= 4:
                    break
            out.append(
                {
                    "numero": n,
                    "frecuencia": int(counter_obj.get(n, 0)),
                    "veces_salio": int(freq.get(n, 0)),
                    "ultima_vez": (last_seen.get(n).strftime("%Y-%m-%d") if last_seen.get(n) else ""),
                    "ultimas_fechas": ul,
                }
            )
        return out

    top_frecuentes_10 = _top_numbers(freq, limit=10, by_recent=False)
    top_frecuentes_20 = _top_numbers(freq, limit=20, by_recent=False)
    top_recientes_10 = _top_numbers(freq, limit=10, by_recent=True)
    top_repetidos_10 = _top_numbers(repeated, limit=10, by_recent=False)
    cold_rows = _numeros_calientes_cold_rows(cur, {"max_por_par": 180})
    top_frios_10 = [
        {
            "numero": r.get("numero"),
            "lottery": r.get("lottery"),
            "draw": r.get("draw"),
            "sorteos_sin_salir": int(r.get("sorteos_sin_salir") or 0),
            "ultima_vez": r.get("ultima_vez") or "",
        }
        for r in cold_rows[:10]
    ]
    cold_lottery = Counter()
    for r in cold_rows:
        if int(r.get("sorteos_sin_salir") or 0) >= 20:
            cold_lottery[r.get("lottery") or "—"] += 1

    per_lottery_rows = [
        {"lottery": k, "resultados_historicos": int(v)}
        for k, v in sorted(por_loteria.items(), key=lambda kv: (-int(kv[1]), kv[0]))
    ]

    cur.execute(
        _sql(
            """
            SELECT lottery, draw, numero, nivel_riesgo, veces_any_7, veces_any_15, veces_any_30
            FROM numeros_calientes_stats
            ORDER BY lottery ASC, draw ASC, numero ASC
            """
        )
    )
    trend_rows = []
    hot_lottery = Counter()
    for rr in cur.fetchall() or []:
        lot = _limites_row_val(rr, "lottery", 0, "") or ""
        dr = _limites_row_val(rr, "draw", 1, "") or ""
        num = _limites_row_val(rr, "numero", 2, "") or ""
        risk = _numeros_calientes_norm_riesgo(_limites_row_val(rr, "nivel_riesgo", 3, "bajo"))
        v7 = int(_limites_row_val(rr, "veces_any_7", 4, 0) or 0)
        v15 = int(_limites_row_val(rr, "veces_any_15", 5, 0) or 0)
        v30 = int(_limites_row_val(rr, "veces_any_30", 6, 0) or 0)
        pct = _nc_trend_pct(v7, v15, v30)
        if pct > 0 and v30 >= 3:
            trend_rows.append(
                {
                    "numero": num,
                    "lottery": lot,
                    "draw": dr,
                    "trend_pct": int(pct),
                    "riesgo": risk,
                    "veces_any_7": v7,
                    "veces_any_15": v15,
                    "veces_any_30": v30,
                }
            )
        hot_lottery[lot or "—"] += 1
    trend_rows.sort(key=lambda x: (-int(x.get("trend_pct") or 0), x.get("lottery") or "", x.get("numero") or ""))
    top_tendencia_10 = trend_rows[:10]

    cur.execute(
        _sql(
            """
            SELECT importados_nuevos, guardados, actualizados, omitidos, historial_total,
                   calientes_total, estado, detalle, created_at
            FROM numeros_calientes_import_runs
            ORDER BY created_at DESC, id DESC
            LIMIT 20
            """
        )
    )
    imports = []
    for rr in cur.fetchall() or []:
        imports.append(
            {
                "importados_nuevos": int(_limites_row_val(rr, "importados_nuevos", 0, 0) or 0),
                "guardados": int(_limites_row_val(rr, "guardados", 1, 0) or 0),
                "actualizados": int(_limites_row_val(rr, "actualizados", 2, 0) or 0),
                "omitidos": int(_limites_row_val(rr, "omitidos", 3, 0) or 0),
                "historial_total": int(_limites_row_val(rr, "historial_total", 4, 0) or 0),
                "calientes_total": int(_limites_row_val(rr, "calientes_total", 5, 0) or 0),
                "estado": _limites_row_val(rr, "estado", 6, "ok") or "ok",
                "detalle": _limites_row_val(rr, "detalle", 7, "") or "",
                "created_at": str(_limites_row_val(rr, "created_at", 8, "") or "")[:19],
            }
        )

    bloqueados_total = 0
    bloqueados_lottery = Counter()
    if banca_id > 0:
        cur.execute(
            _sql(
                """
                SELECT COUNT(*) AS c
                FROM (
                    SELECT lottery, draw, numero
                    FROM limites_numeros
                    WHERE banca_id = %s
                      AND COALESCE(activo, 1) = 1
                      AND COALESCE(limite, 0) <= 0
                      AND (COALESCE(fecha_rd, '') = '' OR fecha_rd = %s)
                    GROUP BY lottery, draw, numero
                ) z
                """
            ),
            (banca_id, ahora_rd().strftime("%Y-%m-%d")),
        )
        bloqueados_total = int(_limites_row_val(cur.fetchone(), "c", 0, 0) or 0)
        cur.execute(
            _sql(
                """
                SELECT lottery, COUNT(*) AS c
                FROM limites_numeros
                WHERE banca_id = %s
                  AND COALESCE(activo, 1) = 1
                  AND COALESCE(limite, 0) <= 0
                  AND (COALESCE(fecha_rd, '') = '' OR fecha_rd = %s)
                GROUP BY lottery
                ORDER BY c DESC
                """
            ),
            (banca_id, ahora_rd().strftime("%Y-%m-%d")),
        )
        for rr in cur.fetchall() or []:
            bloqueados_lottery[_limites_row_val(rr, "lottery", 0, "—") or "—"] = int(_limites_row_val(rr, "c", 1, 0) or 0)

    recomendacion = ""
    if historial_total < 100:
        recomendacion = (
            "Historial actual: %s sorteos. Se recomienda mínimo 100 sorteos para análisis avanzado."
            % int(historial_total)
        )

    chart_calientes_loteria = [{"label": k, "value": int(v)} for k, v in hot_lottery.most_common(20)]
    chart_frios_loteria = [{"label": k, "value": int(v)} for k, v in cold_lottery.most_common(20)]
    chart_bloqueados_loteria = [{"label": k, "value": int(v)} for k, v in bloqueados_lottery.most_common(20)]
    days30 = []
    for i in range(29, -1, -1):
        d = hoy - timedelta(days=i)
        iso = d.strftime("%Y-%m-%d")
        days30.append({"label": d.strftime("%m/%d"), "date": iso, "value": int(trend_daily.get(iso, 0))})

    return {
        "historial_total": int(historial_total),
        "recomendacion": recomendacion,
        "por_loteria": per_lottery_rows,
        "top_frecuentes_10": top_frecuentes_10,
        "top_recientes_10": top_recientes_10,
        "top_repetidos_10": top_repetidos_10,
        "top_frios_10": top_frios_10,
        "top_tendencia_10": top_tendencia_10,
        "chart_top20": top_frecuentes_20,
        "chart_calientes_loteria": chart_calientes_loteria,
        "chart_tendencia_30d": days30,
        "chart_frios_loteria": chart_frios_loteria,
        "chart_bloqueados_loteria": chart_bloqueados_loteria,
        "import_runs": imports,
        "bloqueados_total": int(bloqueados_total),
        "counts": _numeros_calientes_contadores(cur, banca_id=banca_id, fecha_ref=ahora_rd().strftime("%Y-%m-%d")),
    }


def _numeros_calientes_listar(cur, filtros=None):
    filtros = filtros or {}
    page = max(1, int(filtros.get("page") or 1))
    per_page = max(10, min(5000, int(filtros.get("per_page") or 50)))
    offset = (page - 1) * per_page
    tab = str(filtros.get("tab") or "mas_calientes").strip().lower()
    try:
        banca_id = int(filtros.get("banca_id") or 0)
    except (TypeError, ValueError):
        banca_id = 0
    fecha_ref = ahora_rd().strftime("%Y-%m-%d")
    where, params = ["1=1"], []
    lot = normalizar_loteria(filtros.get("lottery") or "")
    if lot:
        where.append("lottery = %s")
        params.append(lot)
    dr = normalizar_sorteo(filtros.get("draw") or filtros.get("sorteo") or "")
    if dr:
        where.append("draw = %s")
        params.append(dr)
    num = normalizar_numero(filtros.get("numero") or "")
    if re.match(r"^\d{2}$", num or ""):
        where.append("numero = %s")
        params.append(num)
    riesgo = _numeros_calientes_norm_riesgo(filtros.get("riesgo") or "")
    if (filtros.get("riesgo") or "").strip().lower() in ("bajo", "medio", "alto"):
        where.append("nivel_riesgo = %s")
        params.append(riesgo)
    if tab == "tendencia":
        where.append(
            "(COALESCE(veces_any_30, 0) > COALESCE(veces_any_7, 0) AND COALESCE(veces_any_15, 0) >= COALESCE(veces_any_7, 0) AND COALESCE(veces_any_30, 0) >= 3)"
        )
    if tab == "bloqueados":
        if banca_id <= 0:
            cfg = _numeros_calientes_get_config_cached(cur, force=False)
            return {
                "items": [],
                "total": 0,
                "page": 1,
                "per_page": per_page,
                "pages": 1,
                "config": cfg,
                "tab": tab,
                "warning": "Seleccione cajero/banca para ver bloqueados.",
                "counts": _numeros_calientes_contadores(cur, banca_id=0, fecha_ref=fecha_ref),
            }
        b_where, b_params = ["ln.banca_id = %s", "COALESCE(ln.activo, 1) = 1", "COALESCE(ln.limite, 0) <= 0"], [banca_id]
        b_where.append("(COALESCE(ln.fecha_rd, '') = '' OR ln.fecha_rd = %s)")
        b_params.append(fecha_ref)
        if lot:
            b_where.append("ln.lottery = %s")
            b_params.append(lot)
        if dr:
            b_where.append("ln.draw = %s")
            b_params.append(dr)
        if re.match(r"^\d{2}$", num or ""):
            b_where.append("ln.numero = %s")
            b_params.append(num)
        q = str(filtros.get("q") or "").strip()
        if q:
            qq = "%%%s%%" % q
            b_where.append("(ln.numero LIKE %s OR ln.lottery LIKE %s OR ln.draw LIKE %s)")
            b_params.extend([qq, qq, qq])
        b_sql = " AND ".join(b_where)
        # Una fila por (lotería, sorteo, número): el contador y la tabla deben coincidir.
        cur.execute(
            _sql(
                """
                SELECT COUNT(*) AS c
                FROM (
                    SELECT MAX(ln.id) AS id
                    FROM limites_numeros ln
                    WHERE """
                + b_sql
                + """
                    GROUP BY ln.lottery, ln.draw, ln.numero
                ) z
                """
            ),
            tuple(b_params),
        )
        total = int(_limites_row_val(cur.fetchone(), "c", 0, 0) or 0)
        cfg = _numeros_calientes_get_config_cached(cur, force=False)
        cur.execute(
            _sql(
                """
                SELECT
                    ln.numero, ln.lottery, ln.draw, ln.limite,
                    COALESCE(NULLIF(ln.fecha_rd, ''), substr(CAST(ln.updated_at AS TEXT), 1, 10), '') AS fecha_bloqueo,
                    CASE
                        WHEN ncs.numero IS NOT NULL THEN 'Número caliente'
                        ELSE 'Manual'
                    END AS origen,
                    ln.updated_at,
                    COALESCE(u.username, 'Sistema') AS usuario_bloqueo
                FROM limites_numeros ln
                INNER JOIN (
                    SELECT MAX(ln2.id) AS id
                    FROM limites_numeros ln2
                    WHERE """
                + b_sql.replace("ln.", "ln2.")
                + """
                    GROUP BY ln2.lottery, ln2.draw, ln2.numero
                ) latest ON latest.id = ln.id
                LEFT JOIN numeros_calientes_stats ncs
                  ON ncs.lottery = ln.lottery
                 AND ncs.draw = ln.draw
                 AND ncs.numero = ln.numero
                LEFT JOIN users u
                  ON u.id = ln.admin_id
                ORDER BY COALESCE(ln.updated_at, CURRENT_TIMESTAMP) DESC, ln.id DESC
                LIMIT %s OFFSET %s
                """
            ),
            tuple(list(b_params) + list(b_params) + [per_page, offset]),
        )
        items = []
        for rr in cur.fetchall() or []:
            items.append(
                {
                    "numero": _limites_row_val(rr, "numero", 0, ""),
                    "lottery": _limites_row_val(rr, "lottery", 1, ""),
                    "draw": _limites_row_val(rr, "draw", 2, ""),
                    "limite_auto": round(float(_limites_row_val(rr, "limite", 3, 0) or 0), 2),
                    "fecha_bloqueo": (_limites_row_val(rr, "fecha_bloqueo", 4, "") or "")[:10],
                    "origen": _limites_row_val(rr, "origen", 5, "Manual") or "Manual",
                    "updated_at": str(_limites_row_val(rr, "updated_at", 6, "") or "")[:19],
                    "usuario_bloqueo": _limites_row_val(rr, "usuario_bloqueo", 7, "Sistema") or "Sistema",
                    "estado": "Bloqueado",
                    "bloqueado": True,
                    "accion": "bloquear",
                }
            )
        pages = max(1, (total + per_page - 1) // per_page)
        items = _nc_enriquecer_items_banca(cur, banca_id, items, fecha_ref)
        return {
            "items": items,
            "total": total,
            "page": page,
            "per_page": per_page,
            "pages": pages,
            "config": cfg,
            "tab": tab,
            "counts": _numeros_calientes_contadores(cur, banca_id=banca_id, fecha_ref=fecha_ref),
        }
    if tab == "frios":
        cfg = _numeros_calientes_get_config_cached(cur, force=False)
        cold_all = _numeros_calientes_cold_rows(
            cur,
            {
                "lottery": lot,
                "draw": dr,
                "numero": num,
                "q": filtros.get("q") or "",
                "max_por_par": 220,
            },
        )
        total = len(cold_all)
        paged = cold_all[offset : offset + per_page]
        items = []
        for rr in paged:
            numero = rr.get("numero") or ""
            lottery = rr.get("lottery") or ""
            draw = rr.get("draw") or ""
            lim_info = _numeros_calientes_limite_manual_info(cur, banca_id, lottery, draw, numero, fecha_ref=fecha_ref)
            bloqueado = bool(lim_info.get("tiene_limite")) and float(lim_info.get("limite") or 0) <= 0
            estado_txt = "Bloqueado" if bloqueado else ("Limitado" if lim_info.get("tiene_limite") else "Activo")
            conf = {"score": 20, "label": "Normal"}
            items.append(
                {
                    "numero": numero,
                    "lottery": lottery,
                    "draw": draw,
                    "ultima_vez": rr.get("ultima_vez") or "",
                    "sorteos_sin_salir": int(rr.get("sorteos_sin_salir") or 0),
                    "nivel_riesgo": "bajo",
                    "semaforo": "verde",
                    "estado": estado_txt,
                    "bloqueado": bool(bloqueado),
                    "tiene_limite_manual": bool(lim_info.get("tiene_limite")),
                    "limite_manual": lim_info.get("limite"),
                    "limite_auto": round(float(lim_info.get("limite") or 0), 2) if lim_info.get("tiene_limite") else 0.0,
                    "confidence_score": int(conf.get("score") or 20),
                    "confidence_label": conf.get("label") or "Normal",
                    "accion": "vigilar",
                }
            )
        pages = max(1, (total + per_page - 1) // per_page)
        items = _nc_enriquecer_items_banca(cur, banca_id, items, fecha_ref)
        return {
            "items": items,
            "total": int(total),
            "page": page,
            "per_page": per_page,
            "pages": pages,
            "config": cfg,
            "tab": tab,
            "counts": _numeros_calientes_contadores(
                cur,
                banca_id=banca_id,
                fecha_ref=fecha_ref,
                skip_riesgo_count=bool(filtros.get("_skip_riesgo_count")),
            ),
        }
    if tab == "riesgo":
        if banca_id <= 0:
            cfg = _numeros_calientes_get_config_cached(cur, force=False)
            return {
                "items": [],
                "total": 0,
                "page": 1,
                "per_page": per_page,
                "pages": 1,
                "config": cfg,
                "tab": tab,
                "warning": "Seleccione cajero/banca para ver riesgo por lotería.",
                "counts": _numeros_calientes_contadores(cur, banca_id=0, fecha_ref=fecha_ref),
            }
        q_riesgo = str(filtros.get("q") or "").strip()
        if q_riesgo:
            qq = "%%%s%%" % q_riesgo
            where.append("(numero LIKE %s OR lottery LIKE %s OR draw LIKE %s)")
            params.extend([qq, qq, qq])
        where_sql = " AND ".join(where)
        cfg = _numeros_calientes_get_config_cached(cur, force=False)
        cur.execute(
            _sql(
                """
                SELECT
                    numero, lottery, draw, veces_salio, ultima_vez, nivel_riesgo,
                    veces_any_7, veces_any_15, veces_any_30, veces_any_100,
                    repetido_mismo_sorteo, racha_reciente
                FROM numeros_calientes_stats
                WHERE """
                + where_sql
            ),
            tuple(params),
        )
        items = []
        for r in cur.fetchall() or []:
            numero = _limites_row_val(r, "numero", 0, "")
            lottery = _limites_row_val(r, "lottery", 1, "")
            draw = _limites_row_val(r, "draw", 2, "")
            riesgo_row = _numeros_calientes_norm_riesgo(_limites_row_val(r, "nivel_riesgo", 5, "bajo"))
            limite_auto = _numeros_calientes_limite_por_riesgo(cfg, riesgo_row)
            lim_info = _numeros_calientes_limite_manual_info(cur, banca_id, lottery, draw, numero, fecha_ref=fecha_ref)
            bloqueado = bool(lim_info.get("tiene_limite")) and float(lim_info.get("limite") or 0) <= 0
            estado_txt = "Bloqueado" if bloqueado else ("Limitado" if lim_info.get("tiene_limite") else "Activo")
            trend_pct = _nc_trend_pct(
                _limites_row_val(r, "veces_any_7", 6, 0),
                _limites_row_val(r, "veces_any_15", 7, 0),
                _limites_row_val(r, "veces_any_30", 8, 0),
            )
            conf = _nc_confianza(
                riesgo_row,
                _limites_row_val(r, "veces_any_7", 6, 0),
                _limites_row_val(r, "veces_any_15", 7, 0),
                _limites_row_val(r, "veces_any_30", 8, 0),
                _limites_row_val(r, "racha_reciente", 11, 0),
            )
            items.append(
                {
                    "numero": numero,
                    "lottery": lottery,
                    "draw": draw,
                    "veces_salio": int(_limites_row_val(r, "veces_salio", 3, 0) or 0),
                    "ultima_vez": (_limites_row_val(r, "ultima_vez", 4, "") or "")[:10],
                    "nivel_riesgo": riesgo_row,
                    "limite_auto": round(float(limite_auto or 0), 2),
                    "accion": "bloquear" if float(limite_auto or 0) <= 0 else "limitar",
                    "veces_any_7": int(_limites_row_val(r, "veces_any_7", 6, 0) or 0),
                    "veces_any_15": int(_limites_row_val(r, "veces_any_15", 7, 0) or 0),
                    "veces_any_30": int(_limites_row_val(r, "veces_any_30", 8, 0) or 0),
                    "veces_any_100": int(_limites_row_val(r, "veces_any_100", 9, 0) or 0),
                    "repetido_mismo_sorteo": int(_limites_row_val(r, "repetido_mismo_sorteo", 10, 0) or 0),
                    "racha_reciente": int(_limites_row_val(r, "racha_reciente", 11, 0) or 0),
                    "estado": estado_txt,
                    "bloqueado": bool(bloqueado),
                    "tiene_limite_manual": bool(lim_info.get("tiene_limite")),
                    "limite_manual": lim_info.get("limite"),
                    "fecha_limite_manual": lim_info.get("fecha"),
                    "semaforo": "rojo" if riesgo_row == "alto" else ("amarillo" if riesgo_row == "medio" else "verde"),
                    "trend_pct": int(trend_pct),
                    "confidence_score": int(conf.get("score") or 20),
                    "confidence_label": conf.get("label") or "Normal",
                }
            )
        expos = _centro_riesgo_exposicion_banca(cur, banca_id, fecha_ref)
        seen = {(it.get("lottery"), it.get("draw"), it.get("numero")) for it in items}
        for key, exp in expos.items():
            lot_k, draw_k, num_k = key
            if (lot_k, draw_k, num_k) in seen:
                continue
            if float(exp.get("vendido") or 0) < 50:
                continue
            lim_info = _numeros_calientes_limite_manual_info(cur, banca_id, lot_k, draw_k, num_k, fecha_ref=fecha_ref)
            bloqueado = bool(lim_info.get("tiene_limite")) and float(lim_info.get("limite") or 0) <= 0
            estado_txt = "Bloqueado" if bloqueado else ("Limitado" if lim_info.get("tiene_limite") else "Activo")
            items.append(
                {
                    "numero": num_k,
                    "lottery": lot_k,
                    "draw": draw_k,
                    "veces_salio": 0,
                    "ultima_vez": "",
                    "nivel_riesgo": "bajo",
                    "limite_auto": 0.0,
                    "accion": "vigilar",
                    "veces_any_7": 0,
                    "veces_any_15": 0,
                    "veces_any_30": 0,
                    "veces_any_100": 0,
                    "repetido_mismo_sorteo": 0,
                    "racha_reciente": 0,
                    "estado": estado_txt,
                    "bloqueado": bool(bloqueado),
                    "tiene_limite_manual": bool(lim_info.get("tiene_limite")),
                    "limite_manual": lim_info.get("limite"),
                    "fecha_limite_manual": lim_info.get("fecha"),
                    "semaforo": "verde",
                    "trend_pct": 0,
                    "confidence_score": 20,
                    "confidence_label": "Normal",
                }
            )
            seen.add((lot_k, draw_k, num_k))
        items = _nc_enriquecer_items_banca(cur, banca_id, items, fecha_ref)
        items = _numeros_calientes_filtro_riesgo_banca(items)
        total = len(items)
        pages = max(1, (total + per_page - 1) // per_page)
        items = items[offset : offset + per_page]
        return {
            "items": items,
            "total": total,
            "page": page,
            "per_page": per_page,
            "pages": pages,
            "config": cfg,
            "tab": tab,
            "counts": _numeros_calientes_contadores(
                cur,
                banca_id=banca_id,
                fecha_ref=fecha_ref,
                skip_riesgo_count=bool(filtros.get("_skip_riesgo_count")),
            ),
        }
    if tab == "mas_calientes":
        cfg_mc = _numeros_calientes_get_config_cached(cur, force=False)
        where.append(_nc_sql_riesgo_minimo_clause(cfg_mc))
    q = str(filtros.get("q") or "").strip()
    if q:
        qq = "%%%s%%" % q
        where.append("(numero LIKE %s OR lottery LIKE %s OR draw LIKE %s)")
        params.extend([qq, qq, qq])
    where_sql = " AND ".join(where)
    cur.execute(_sql("SELECT COUNT(*) AS c FROM numeros_calientes_stats WHERE " + where_sql), tuple(params))
    total = int(_limites_row_val(cur.fetchone(), "c", 0, 0) or 0)
    cfg = _numeros_calientes_get_config_cached(cur, force=False)
    order_sql = """
            ORDER BY
                CASE nivel_riesgo WHEN 'alto' THEN 3 WHEN 'medio' THEN 2 ELSE 1 END DESC,
                veces_salio DESC,
                ultima_vez DESC,
                lottery ASC,
                draw ASC,
                numero ASC
            """
    if tab == "tendencia":
        order_sql = """
            ORDER BY
                COALESCE(racha_reciente, 0) DESC,
                COALESCE(repetido_mismo_sorteo, 0) DESC,
                COALESCE(veces_any_7, 0) DESC,
                ultima_vez DESC,
                lottery ASC,
                draw ASC,
                numero ASC
            """
    cur.execute(
        _sql(
            """
            SELECT
                numero, lottery, draw, veces_salio, ultima_vez, nivel_riesgo,
                veces_any_7, veces_any_15, veces_any_30, veces_any_100,
                repetido_mismo_sorteo, racha_reciente
            FROM numeros_calientes_stats
            WHERE """
            + where_sql
            + order_sql
            + """
            LIMIT %s OFFSET %s
            """
        ),
        tuple(list(params) + [per_page, offset]),
    )
    items = []
    for r in cur.fetchall() or []:
        numero = _limites_row_val(r, "numero", 0, "")
        lottery = _limites_row_val(r, "lottery", 1, "")
        draw = _limites_row_val(r, "draw", 2, "")
        riesgo_row = _numeros_calientes_norm_riesgo(_limites_row_val(r, "nivel_riesgo", 5, "bajo"))
        limite_auto = _numeros_calientes_limite_por_riesgo(cfg, riesgo_row)
        lim_info = _numeros_calientes_limite_manual_info(cur, banca_id, lottery, draw, numero, fecha_ref=fecha_ref)
        bloqueado = bool(lim_info.get("tiene_limite")) and float(lim_info.get("limite") or 0) <= 0
        estado_txt = "Bloqueado" if bloqueado else ("Limitado" if lim_info.get("tiene_limite") else "Activo")
        ultimas_fechas = _numeros_calientes_historial_numero(cur, lottery, draw, numero, limit=4)
        trend_pct = _nc_trend_pct(
            _limites_row_val(r, "veces_any_7", 6, 0),
            _limites_row_val(r, "veces_any_15", 7, 0),
            _limites_row_val(r, "veces_any_30", 8, 0),
        )
        conf = _nc_confianza(
            riesgo_row,
            _limites_row_val(r, "veces_any_7", 6, 0),
            _limites_row_val(r, "veces_any_15", 7, 0),
            _limites_row_val(r, "veces_any_30", 8, 0),
            _limites_row_val(r, "racha_reciente", 11, 0),
        )
        items.append(
            {
                "numero": numero,
                "lottery": lottery,
                "draw": draw,
                "veces_salio": int(_limites_row_val(r, "veces_salio", 3, 0) or 0),
                "ultima_vez": (_limites_row_val(r, "ultima_vez", 4, "") or "")[:10],
                "nivel_riesgo": riesgo_row,
                "limite_auto": round(float(limite_auto or 0), 2),
                "accion": "bloquear" if float(limite_auto or 0) <= 0 else "limitar",
                "veces_any_7": int(_limites_row_val(r, "veces_any_7", 6, 0) or 0),
                "veces_any_15": int(_limites_row_val(r, "veces_any_15", 7, 0) or 0),
                "veces_any_30": int(_limites_row_val(r, "veces_any_30", 8, 0) or 0),
                "veces_any_100": int(_limites_row_val(r, "veces_any_100", 9, 0) or 0),
                "repetido_mismo_sorteo": int(_limites_row_val(r, "repetido_mismo_sorteo", 10, 0) or 0),
                "racha_reciente": int(_limites_row_val(r, "racha_reciente", 11, 0) or 0),
                "estado": estado_txt,
                "bloqueado": bool(bloqueado),
                "tiene_limite_manual": bool(lim_info.get("tiene_limite")),
                "limite_manual": lim_info.get("limite"),
                "fecha_limite_manual": lim_info.get("fecha"),
                "semaforo": "rojo" if riesgo_row == "alto" else ("amarillo" if riesgo_row == "medio" else "verde"),
                "ultimas_fechas": ultimas_fechas,
                "ultimas_fechas_txt": " ".join([x.get("mmdd") for x in ultimas_fechas if x.get("mmdd")]),
                "trend_pct": int(trend_pct),
                "confidence_score": int(conf.get("score") or 20),
                "confidence_label": conf.get("label") or "Normal",
            }
        )
    pages = max(1, (total + per_page - 1) // per_page)
    counts = _numeros_calientes_contadores(
        cur,
        banca_id=banca_id,
        fecha_ref=fecha_ref,
        skip_riesgo_count=bool(filtros.get("_skip_riesgo_count")),
    )
    items = _nc_enriquecer_items_banca(cur, banca_id, items, fecha_ref)
    return {
        "items": items,
        "total": total,
        "page": page,
        "per_page": per_page,
        "pages": pages,
        "config": cfg,
        "tab": tab,
        "counts": counts,
    }


def _obtener_limite_numero_loteria(cur, banca_id, lottery, draw, num_02d, usuario_id=None, fecha_rd=None):
    """Límite en limites_numeros (por cajero si existe) o LIMITE_NUMERO_DIARIO_DEFAULT."""
    lottery_n, draw_n = _normalizar_clave_limite_loteria(lottery, draw)
    num_02d = str(num_02d or "").zfill(2)
    try:
        banca_id = int(banca_id)
    except (TypeError, ValueError):
        return float(LIMITE_NUMERO_DIARIO_DEFAULT)
    if banca_id <= 0 or not lottery_n or not num_02d:
        return float(LIMITE_NUMERO_DIARIO_DEFAULT)
    fecha_rd = (fecha_rd or ahora_rd().strftime("%Y-%m-%d"))[:10]
    uid = _limites_usuario_id_int(usuario_id)

    def _fetch(uid_filter):
        cur.execute(
            _sql(
                """
                SELECT limite FROM limites_numeros
                WHERE banca_id = %s AND lottery = %s AND draw = %s AND numero = %s
                  AND COALESCE(activo, 1) = 1
                  AND (COALESCE(fecha_rd, '') = '' OR fecha_rd = %s)
                  AND COALESCE(usuario_id, 0) = %s
                ORDER BY CASE WHEN COALESCE(fecha_rd, '') = '' THEN 1 ELSE 0 END, id DESC
                LIMIT 1
                """
            ),
            (banca_id, lottery_n, draw_n, num_02d, fecha_rd, uid_filter),
        )
        row = cur.fetchone()
        if not row:
            return None
        try:
            return float(_limites_row_val(row, "limite", 0, 0) or 0)
        except (TypeError, ValueError):
            return None

    if uid > 0:
        lim_u = _fetch(uid)
        if lim_u is not None:
            return lim_u
    lim_g = _fetch(0)
    if lim_g is not None:
        return lim_g
    return float(LIMITE_NUMERO_DIARIO_DEFAULT)


def _limites_disponible_numero(cur, banca_id, lottery, draw, numero, fecha_rd=None, usuario_id=None):
    """Retorna dict limite, vendido, disponible para un número."""
    lottery_n, draw_n = _normalizar_clave_limite_loteria(lottery, draw)
    fecha_rd = (fecha_rd or ahora_rd().strftime("%Y-%m-%d"))[:10]
    uid = _limites_usuario_id_int(usuario_id)
    num = str(numero or "").zfill(2) if re.match(r"^\d{1,2}$", str(numero or "").strip()) else str(numero or "")
    lim = _obtener_limite_numero_loteria(cur, banca_id, lottery_n, draw_n, num, usuario_id=uid, fecha_rd=fecha_rd)
    hot_rule = _numeros_calientes_regla_para_numero(cur, lottery_n, draw_n, num)
    lim_hot = None
    if hot_rule:
        try:
            lim_hot = round(float(hot_rule.get("limite_auto") or 0), 2)
            lim = min(float(lim), float(lim_hot))
        except (TypeError, ValueError):
            lim_hot = None
    vendido = _total_jugado_hoy_banca_loteria_numero(cur, banca_id, lottery_n, draw_n, fecha_rd, num)
    disp = max(0.0, float(lim) - float(vendido))
    return {
        "limite": round(float(lim), 2),
        "vendido": round(float(vendido), 2),
        "disponible": round(float(disp), 2),
        "limite_hot": lim_hot,
        "hot_rule": hot_rule,
    }


def _total_jugado_hoy_banca_loteria_numero(cur, banca_id, lottery, draw, fecha_rd, num_02d):
    """
    Suma de montos jugados hoy (fecha_sorteo = fecha_rd) para una banca, lotería, sorteo
    y número (incluye Quiniela y componentes de Pale / Tripleta según _componentes_limite_numero).
    """
    try:
        banca_id = int(banca_id)
    except (TypeError, ValueError):
        return 0.0
    lottery_n, draw_n = _normalizar_clave_limite_loteria(lottery, draw)
    fecha_rd = (fecha_rd or ahora_rd().strftime("%Y-%m-%d"))[:10]
    num_02d = str(num_02d or "").zfill(2)
    if banca_id <= 0 or not lottery_n or not fecha_rd or not num_02d:
        return 0.0
    cur.execute(
        _sql(
            """
            SELECT tl.play, tl.number, tl.amount
            FROM ticket_lines tl
            INNER JOIN tickets t ON t.id = tl.ticket_id
            WHERE COALESCE(tl.estado, 'activo') <> 'cancelado'
              AND COALESCE(t.banca_id, t.cajero_id) = %s
              AND tl.lottery = %s
              AND COALESCE(tl.draw, '') = %s
              AND COALESCE(tl.fecha_sorteo, '') = %s
            """
        ),
        (banca_id, lottery_n, draw_n, fecha_rd),
    )
    total = 0.0
    for row in cur.fetchall() or []:
        if hasattr(row, "keys"):
            r = dict(row)
            number = r.get("number")
            amt = r.get("amount")
        else:
            number = row[1] if row and len(row) > 1 else ""
            amt = row[2] if row and len(row) > 2 else 0
        try:
            amt_f = float(amt or 0)
        except (TypeError, ValueError):
            continue
        if num_02d in _componentes_limite_numero(number):
            total += amt_f
    return total


def validar_limite(cur, banca_id, lottery, draw, numero, monto, fecha_rd=None):
    """
    Valida el monto contra el límite diario por banca / lotería / sorteo / número.
    Retorna (ok, mensaje_error). Si ok es False, mensaje_error describe el rechazo.
    """
    if not banca_id:
        return True, ""
    try:
        banca_id = int(banca_id)
    except (TypeError, ValueError):
        return True, ""
    if banca_id <= 0:
        return True, ""
    if not _limites_diarios_activos(cur):
        return True, ""
    fecha_rd = (fecha_rd or ahora_rd().strftime("%Y-%m-%d"))[:10]
    try:
        monto_f = float(monto or 0)
    except (TypeError, ValueError):
        return False, "Monto inválido."
    if monto_f <= 0:
        return True, ""
    lottery_n, draw_n = _normalizar_clave_limite_loteria(lottery, draw)
    if not lottery_n:
        return True, ""
    uid = _limites_usuario_id_int(session.get("uid") if session else 0)
    for num in _componentes_limite_numero(numero):
        info = _limites_disponible_numero(cur, banca_id, lottery_n, draw_n, num, fecha_rd, usuario_id=uid)
        hot_rule = info.get("hot_rule") or {}
        lim = info["limite"]
        if lim <= 0:
            _numeros_calientes_log(
                loteria=lottery_n,
                sorteo=draw_n,
                numero=num,
                frecuencia=hot_rule.get("veces_salio"),
                riesgo=hot_rule.get("riesgo"),
                accion="bloquear",
            )
            return False, "Este número está bloqueado para esta lotería/sorteo."
        vendido = info["vendido"]
        disp = info["disponible"]
        if vendido + monto_f > lim + 0.005:
            if hot_rule:
                _numeros_calientes_log(
                    loteria=lottery_n,
                    sorteo=draw_n,
                    numero=num,
                    frecuencia=hot_rule.get("veces_salio"),
                    riesgo=hot_rule.get("riesgo"),
                    accion="limitar",
                )
                return False, (
                    "Número caliente bloqueado automáticamente para esta lotería/sorteo. "
                    "Riesgo %s, límite RD$ %.2f, disponible RD$ %.2f."
                ) % (str(hot_rule.get("riesgo") or "").upper(), lim, disp)
            _limites_log(
                "límite excedido",
                numero=num,
                lottery=lottery_n,
                draw=draw_n,
                limite=lim,
                vendido=vendido,
                monto=monto_f,
            )
            return False, (
                "⚠️ Número limitado: %s en %s (%s). "
                "Disponible restante RD$ %.2f (límite RD$ %.2f, jugado RD$ %.2f)."
            ) % (num, lottery_n, draw_n or "-", disp, lim, vendido)
    _limites_log("venta validada", banca_id=banca_id, lottery=lottery_n, draw=draw_n, monto=monto_f)
    return True, ""


def _validar_limites_banca_venta(cur, banca_id, jugadas):
    """
    Valida la venta completa: límites diarios independientes por (banca, lotería, sorteo, número).
    Super Pale cuenta el monto hacia ambas loterías de la jugada.
    """
    if not banca_id:
        return True, ""
    try:
        banca_id = int(banca_id)
    except (TypeError, ValueError):
        return True, ""
    if banca_id <= 0:
        return True, ""
    if not _limites_diarios_activos(cur):
        return True, ""
    uid = _limites_usuario_id_int(session.get("uid") if session else 0)
    acum = {}
    for j in jugadas or []:
        play = (j.get("play") or "").strip()
        l1, d1 = _normalizar_clave_limite_loteria(j.get("lottery"), j.get("draw"))
        if not l1:
            continue
        fecha_linea = (j.get("fecha_sorteo") or "").strip()[:10]
        if not fecha_linea:
            fecha_linea = _fecha_sorteo_calendario_linea_rd(j.get("lottery"), j.get("draw"))
        if not fecha_linea:
            fecha_linea = ahora_rd().strftime("%Y-%m-%d")
        l2 = None
        if play == "Super Pale":
            l2_raw = j.get("lottery2")
            if l2_raw:
                l2, _ = _normalizar_clave_limite_loteria(l2_raw, j.get("draw"))
                if not l2:
                    l2 = None
        try:
            amt = float(j.get("amount") or 0)
        except (TypeError, ValueError):
            continue
        if amt <= 0:
            continue
        for num in _componentes_limite_numero(j.get("number")):
            key1 = (fecha_linea, l1, d1, num)
            acum[key1] = acum.get(key1, 0.0) + amt
            if l2:
                key2 = (fecha_linea, l2, d1, num)
                acum[key2] = acum.get(key2, 0.0) + amt
    for (fecha_linea, lottery_n, draw_n, num), nuevo_total in acum.items():
        info = _limites_disponible_numero(
            cur, banca_id, lottery_n, draw_n, num, fecha_linea, usuario_id=uid
        )
        hot_rule = info.get("hot_rule") or {}
        lim = info["limite"]
        if lim <= 0:
            _numeros_calientes_log(
                loteria=lottery_n,
                sorteo=draw_n,
                numero=num,
                frecuencia=hot_rule.get("veces_salio"),
                riesgo=hot_rule.get("riesgo"),
                accion="bloquear",
            )
            return False, "Este número está bloqueado para esta lotería/sorteo."
        vendido = info["vendido"]
        disp = info["disponible"]
        if vendido + nuevo_total > lim + 0.005:
            if hot_rule:
                _numeros_calientes_log(
                    loteria=lottery_n,
                    sorteo=draw_n,
                    numero=num,
                    frecuencia=hot_rule.get("veces_salio"),
                    riesgo=hot_rule.get("riesgo"),
                    accion="limitar",
                )
                return False, (
                    "Número caliente bloqueado automáticamente para esta lotería/sorteo. "
                    "Riesgo %s, límite RD$ %.2f, disponible RD$ %.2f."
                ) % (str(hot_rule.get("riesgo") or "").upper(), lim, disp)
            _limites_log(
                "límite excedido venta",
                numero=num,
                lottery=lottery_n,
                fecha=fecha_linea,
                limite=lim,
                vendido=vendido,
                nuevo=nuevo_total,
            )
            return False, (
                "⚠️ Número limitado: %s en %s (%s). "
                "Disponible restante RD$ %.2f (límite RD$ %.2f, jugado RD$ %.2f, venta RD$ %.2f)."
            ) % (num, lottery_n, draw_n or "-", disp, lim, vendido, nuevo_total)
    _limites_log("venta validada batch", banca_id=banca_id, lineas=len(acum))
    return True, ""


LIMITES_TODAS_LOTERIAS = "__TODAS__"
LIMITES_TODOS_DRAWS = "__TODOS__"


def _limites_body_flag(val):
    if isinstance(val, bool):
        return val
    return str(val or "").strip().lower() in ("1", "true", "yes", "on", "si", "sí")


def _limites_pares_loteria_draw(cur):
    """Pares únicos (lottery, draw) activos en catálogo lotteries."""
    cur.execute(_sql("SELECT DISTINCT lottery, draw FROM lotteries ORDER BY lottery, draw"))
    pairs, seen = [], set()
    for r in cur.fetchall() or []:
        if hasattr(r, "keys"):
            rd = dict(r) if not hasattr(r, "get") else r
            lot_raw, dr_raw = rd.get("lottery"), rd.get("draw")
        else:
            lot_raw, dr_raw = (r[0] if r else ""), (r[1] if r and len(r) > 1 else "")
        lot_n, dr_n = _normalizar_clave_limite_loteria(lot_raw, dr_raw)
        if not lot_n or not dr_n:
            continue
        key = (lot_n, dr_n)
        if key in seen:
            continue
        seen.add(key)
        pairs.append({"lottery": lot_n, "draw": dr_n})
    return pairs


def _limites_expand_lottery_draw(cur, lottery="", draw="", all_lotteries=False, all_draws=False):
    """Resuelve combinaciones lotería/sorteo según flags masivos."""
    all_lotteries = _limites_body_flag(all_lotteries) or str(lottery or "").strip() == LIMITES_TODAS_LOTERIAS
    all_draws = _limites_body_flag(all_draws) or str(draw or "").strip() == LIMITES_TODOS_DRAWS
    pairs = _limites_pares_loteria_draw(cur)
    if not pairs:
        return []
    if all_lotteries:
        if all_draws:
            return pairs
        dr_n = normalizar_sorteo(draw) or (draw or "").strip()
        if dr_n and dr_n != LIMITES_TODOS_DRAWS:
            return [p for p in pairs if p["draw"] == dr_n]
        return pairs
    lot_n = normalizar_loteria(lottery) or (lottery or "").strip()
    if not lot_n:
        return []
    if all_draws:
        return [p for p in pairs if p["lottery"] == lot_n]
    dr_n = normalizar_sorteo(draw) or (draw or "").strip()
    if not dr_n:
        return []
    return [{"lottery": lot_n, "draw": dr_n}]


def _limites_numeros_from_body(body):
    if _limites_body_flag(body.get("aplicar_todos_numeros") or body.get("aplicar_todos")):
        return ["%02d" % i for i in range(100)]
    nums_in = body.get("numeros")
    if isinstance(nums_in, (list, tuple)) and nums_in:
        out = []
        for n in nums_in:
            nn = normalizar_numero(n)
            if re.match(r"^\d{2}$", nn or "") and nn not in out:
                out.append(nn)
        if out:
            return out
    nn = normalizar_numero(body.get("numero") or "")
    if re.match(r"^\d{2}$", nn or ""):
        return [nn]
    raise ValueError("numero_invalido")


def _limites_guardar_desde_api_body(cur, body, admin_uid):
    """Guarda límite(s) desde POST /api/admin/limites/global (upsert)."""
    try:
        banca_id = int(body.get("banca_id") or 0)
    except (TypeError, ValueError):
        banca_id = 0
    if banca_id <= 0:
        raise ValueError("banca_invalida")
    if not _limites_banca_permitida(cur, banca_id):
        raise ValueError("sin_permiso")
    limite = float(body.get("limite") or LIMITE_NUMERO_DIARIO_DEFAULT)
    usuario_id = body.get("usuario_id") or body.get("cajero_id") or 0
    fecha_rd = (body.get("fecha_rd") or "")[:10]
    activo = body.get("activo", 1)
    all_lot = _limites_body_flag(body.get("all_lotteries")) or str(body.get("lottery") or "") == LIMITES_TODAS_LOTERIAS
    all_dr = _limites_body_flag(body.get("all_draws")) or str(body.get("draw") or body.get("sorteo") or "") == LIMITES_TODOS_DRAWS
    aplicar_todos_nums = _limites_body_flag(body.get("aplicar_todos_numeros") or body.get("aplicar_todos"))
    numero_txt = str(body.get("numero") or "").strip()
    numero_nn = normalizar_numero(numero_txt) if numero_txt else ""
    # Número escrito en el formulario: solo ese dígito (ignora 00-99 accidental).
    if re.match(r"^\d{2}$", numero_nn or ""):
        numeros = [numero_nn]
        if all_lot or all_dr:
            res = _limites_aplicar_masivo(
                cur,
                banca_id,
                numeros,
                limite,
                admin_uid,
                usuario_id,
                fecha_rd,
                activo,
                all_lotteries=all_lot,
                all_draws=all_dr,
                lottery=body.get("lottery") or "",
                draw=body.get("draw") or body.get("sorteo") or "",
            )
            _limites_log(
                "guardar api masivo numero",
                banca_id=banca_id,
                numero=numero_nn,
                total=res.get("total"),
            )
            return res
        st = _limites_upsert_fila(
            cur,
            banca_id,
            body.get("lottery"),
            body.get("draw") or body.get("sorteo"),
            numero_nn,
            limite,
            admin_uid,
            usuario_id,
            fecha_rd,
            activo,
        )
        _limites_log("guardar api uno", banca_id=banca_id, numero=numero_nn, estado=st)
        return {
            "creados": 1 if st == "created" else 0,
            "actualizados": 1 if st == "updated" else 0,
            "total": 1,
        }
    if all_lot or all_dr or aplicar_todos_nums:
        numeros = _limites_numeros_from_body(body)
        res = _limites_aplicar_masivo(
            cur,
            banca_id,
            numeros,
            limite,
            admin_uid,
            usuario_id,
            fecha_rd,
            activo,
            all_lotteries=all_lot,
            all_draws=all_dr,
            lottery=body.get("lottery") or "",
            draw=body.get("draw") or body.get("sorteo") or "",
        )
        _limites_log("guardar api masivo", banca_id=banca_id, total=res.get("total"))
        return res
    raise ValueError("numero_invalido")


def _limites_build_masivo_valores(cur, banca_id, pairs, numeros, limite, admin_id, usuario_id, fecha_rd, activo):
    """Lista de tuplas para upsert masivo (banca, admin, usuario, lot, draw, num, limite, fecha, activo)."""
    banca_id = int(banca_id)
    limite_f = round(float(limite), 2)
    uid = _limites_usuario_id_int(usuario_id)
    fecha_rd = (fecha_rd or "")[:10]
    activo_i = 1 if str(activo).strip() not in ("0", "false", "False") else 0
    admin_id_i = int(admin_id) if admin_id else None
    valores = []
    for p in pairs:
        lottery_n, draw_n = _normalizar_clave_limite_loteria(p.get("lottery"), p.get("draw"))
        if not lottery_n or not draw_n:
            continue
        for num in numeros:
            nn = normalizar_numero(num)
            if not re.match(r"^\d{2}$", nn or ""):
                continue
            valores.append((banca_id, admin_id_i, uid, lottery_n, draw_n, nn, limite_f, fecha_rd, activo_i))
    return valores


def _limites_bulk_upsert_pg(cur, valores):
    """PostgreSQL: UPDATE masivo + INSERT masivo (2 consultas por lote, sin 2200 round-trips)."""
    from psycopg2.extras import execute_values

    _pg_ensure_transaction_for_savepoints(cur)
    template = "(%s::integer, %s::integer, %s::integer, %s::text, %s::text, %s::text, %s::numeric, %s::text, %s::integer)"
    upd_sql = """
        UPDATE limites_numeros AS ln SET
            limite = v.limite,
            activo = v.activo,
            admin_id = v.admin_id,
            usuario_id = v.usuario_id,
            fecha_rd = v.fecha_rd,
            updated_at = CURRENT_TIMESTAMP
        FROM (VALUES %s) AS v(
            banca_id, admin_id, usuario_id, lottery, draw, numero, limite, fecha_rd, activo
        )
        WHERE ln.banca_id = v.banca_id
          AND ln.lottery = v.lottery
          AND ln.draw = v.draw
          AND ln.numero = v.numero
    """
    ins_sql = """
        INSERT INTO limites_numeros
            (banca_id, admin_id, usuario_id, lottery, draw, numero, limite, fecha_rd, activo, updated_at)
        SELECT
            v.banca_id, v.admin_id, v.usuario_id, v.lottery, v.draw, v.numero,
            v.limite, v.fecha_rd, v.activo, CURRENT_TIMESTAMP
        FROM (VALUES %s) AS v(
            banca_id, admin_id, usuario_id, lottery, draw, numero, limite, fecha_rd, activo
        )
        WHERE NOT EXISTS (
            SELECT 1 FROM limites_numeros ln
            WHERE ln.banca_id = v.banca_id
              AND ln.lottery = v.lottery
              AND ln.draw = v.draw
              AND ln.numero = v.numero
        )
    """
    creados, actualizados = 0, 0
    page_size = 1000
    for i in range(0, len(valores), page_size):
        chunk = valores[i : i + page_size]
        execute_values(cur, upd_sql, chunk, template=template, page_size=len(chunk))
        n_upd = int(cur.rowcount or 0)
        if n_upd < 0:
            n_upd = 0
        actualizados += n_upd
        execute_values(cur, ins_sql, chunk, template=template, page_size=len(chunk))
        n_ins = int(cur.rowcount or 0)
        if n_ins < 0:
            n_ins = 0
        creados += n_ins
    if creados + actualizados < len(valores):
        creados = max(creados, len(valores) - actualizados)
    return creados, actualizados


def _limites_bulk_upsert_sqlite(cur, valores):
    """SQLite local/tests: executemany UPSERT o fallback fila a fila."""
    sql = """
        INSERT INTO limites_numeros
            (banca_id, admin_id, usuario_id, lottery, draw, numero, limite, fecha_rd, activo, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
        ON CONFLICT(banca_id, lottery, draw, numero) DO UPDATE SET
            limite = excluded.limite,
            activo = excluded.activo,
            admin_id = excluded.admin_id,
            usuario_id = excluded.usuario_id,
            fecha_rd = excluded.fecha_rd,
            updated_at = CURRENT_TIMESTAMP
    """
    try:
        page_size = 500
        for i in range(0, len(valores), page_size):
            cur.executemany(sql, valores[i : i + page_size])
        return 0, len(valores)
    except sqlite3.OperationalError:
        creados, actualizados = 0, 0
        for v in valores:
            st = _limites_upsert_fila(cur, v[0], v[3], v[4], v[5], v[6], v[1], v[2], v[7], v[8])
            if st == "created":
                creados += 1
            else:
                actualizados += 1
        return creados, actualizados


def _limites_aplicar_masivo(
    cur,
    banca_id,
    numeros,
    limite,
    admin_id=None,
    usuario_id=0,
    fecha_rd="",
    activo=1,
    all_lotteries=False,
    all_draws=False,
    lottery="",
    draw="",
):
    """Aplica límite a muchas combinaciones en una transacción (bulk upsert)."""
    pairs = _limites_expand_lottery_draw(cur, lottery, draw, all_lotteries, all_draws)
    if not pairs:
        raise ValueError("sin_loterias_activas")
    valores = _limites_build_masivo_valores(
        cur, banca_id, pairs, numeros, limite, admin_id, usuario_id, fecha_rd, activo
    )
    if not valores:
        raise ValueError("numero_invalido")
    n_rows = len(valores)
    t0 = time.monotonic()
    log.info("[LIMITES_BULK_START] banca_id=%s registros=%s", int(banca_id), n_rows)
    if n_rows == 1:
        v = valores[0]
        st = _limites_upsert_fila(
            cur, v[0], v[3], v[4], v[5], v[6], v[1], v[2], v[7], v[8]
        )
        creados = 1 if st == "created" else 0
        actualizados = 1 if st == "updated" else 0
    elif os.environ.get("DATABASE_URL"):
        creados, actualizados = _limites_bulk_upsert_pg(cur, valores)
    else:
        creados, actualizados = _limites_bulk_upsert_sqlite(cur, valores)
    ms = int((time.monotonic() - t0) * 1000)
    log.info(
        "[LIMITES_BULK_DONE] banca_id=%s registros=%s ms=%s creados=%s actualizados=%s",
        int(banca_id),
        n_rows,
        ms,
        creados,
        actualizados,
    )
    _limites_log(
        "aplicar masivo",
        banca_id=banca_id,
        creados=creados,
        actualizados=actualizados,
        pares=len(pairs),
        numeros=len(numeros),
        ms=ms,
    )
    return {
        "creados": creados,
        "actualizados": actualizados,
        "total": creados + actualizados,
        "combinaciones_loteria": len(pairs),
        "numeros": len(numeros),
        "ms": ms,
    }


def _limites_buscar_id_fila(cur, banca_id, lottery_n, draw_n, num, uid=0, fecha_rd="", solo_clave_legacy=False):
    """Busca id de límite por clave exacta o solo banca+lotería+sorteo+número (índice legacy en PG)."""
    if solo_clave_legacy:
        cur.execute(
            _sql(
                """
                SELECT id FROM limites_numeros
                WHERE banca_id = %s AND lottery = %s AND draw = %s AND numero = %s
                ORDER BY id ASC
                LIMIT 1
                """
            ),
            (banca_id, lottery_n, draw_n, num),
        )
    else:
        cur.execute(
            _sql(
                """
                SELECT id FROM limites_numeros
                WHERE banca_id = %s AND lottery = %s AND draw = %s AND numero = %s
                  AND COALESCE(usuario_id, 0) = %s AND COALESCE(fecha_rd, '') = %s
                ORDER BY id ASC
                LIMIT 1
                """
            ),
            (banca_id, lottery_n, draw_n, num, uid, (fecha_rd or "")[:10]),
        )
    ex = cur.fetchone()
    if not ex:
        return 0
    return int(_limites_row_val(ex, "id", 0, 0) or 0)


def _limites_update_fila(cur, eid, limite_f, activo_i, admin_id_i, uid, fecha_rd):
    cur.execute(
        _sql(
            """
            UPDATE limites_numeros
            SET limite=%s, activo=%s, admin_id=%s, usuario_id=%s, fecha_rd=%s, updated_at=CURRENT_TIMESTAMP
            WHERE id=%s
            """
        ),
        (limite_f, activo_i, admin_id_i, uid, (fecha_rd or "")[:10], eid),
    )


def _limites_upsert_fila(cur, banca_id, lottery, draw, numero, limite, admin_id=None, usuario_id=0, fecha_rd="", activo=1):
    """Inserta o actualiza límite (sin duplicar en PG/SQLite). Retorna 'created' o 'updated'."""
    lottery_n, draw_n = _normalizar_clave_limite_loteria(lottery, draw)
    num = normalizar_numero(numero)
    if not re.match(r"^\d{2}$", num or ""):
        raise ValueError("numero_invalido")
    banca_id = int(banca_id)
    limite_f = round(float(limite), 2)
    uid = _limites_usuario_id_int(usuario_id)
    fecha_rd = (fecha_rd or "")[:10]
    activo_i = 1 if str(activo).strip() not in ("0", "false", "False") else 0
    admin_id_i = int(admin_id) if admin_id else None
    is_pg = bool(os.environ.get("DATABASE_URL"))

    eid = _limites_buscar_id_fila(cur, banca_id, lottery_n, draw_n, num, uid, fecha_rd, False)
    if not eid:
        eid = _limites_buscar_id_fila(cur, banca_id, lottery_n, draw_n, num, solo_clave_legacy=True)
    if eid:
        _limites_update_fila(cur, eid, limite_f, activo_i, admin_id_i, uid, fecha_rd)
        return "updated"

    try:
        if is_pg:
            cur.execute(
                """
                INSERT INTO limites_numeros
                (banca_id, admin_id, usuario_id, lottery, draw, numero, limite, fecha_rd, activo, updated_at)
                VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,CURRENT_TIMESTAMP)
                """,
                (banca_id, admin_id_i, uid, lottery_n, draw_n, num, limite_f, fecha_rd, activo_i),
            )
        else:
            cur.execute(
                _sql(
                    """
                    INSERT INTO limites_numeros
                    (banca_id, admin_id, usuario_id, lottery, draw, numero, limite, fecha_rd, activo, updated_at)
                    VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,CURRENT_TIMESTAMP)
                    """
                ),
                (banca_id, admin_id_i, uid, lottery_n, draw_n, num, limite_f, fecha_rd, activo_i),
            )
        return "created"
    except Exception as ex_ins:
        err = str(ex_ins).lower()
        if "unique" not in err and "duplicate" not in err:
            raise
        _rollback_pg_cursor(cur)
        eid = _limites_buscar_id_fila(cur, banca_id, lottery_n, draw_n, num, uid, fecha_rd, False)
        if not eid:
            eid = _limites_buscar_id_fila(cur, banca_id, lottery_n, draw_n, num, solo_clave_legacy=True)
        if eid:
            _limites_update_fila(cur, eid, limite_f, activo_i, admin_id_i, uid, fecha_rd)
            return "updated"
        if is_pg:
            try:
                cur.execute(
                    """
                    INSERT INTO limites_numeros
                    (banca_id, admin_id, usuario_id, lottery, draw, numero, limite, fecha_rd, activo, updated_at)
                    VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,CURRENT_TIMESTAMP)
                    ON CONFLICT (banca_id, lottery, draw, numero)
                    DO UPDATE SET
                        limite = EXCLUDED.limite,
                        activo = EXCLUDED.activo,
                        admin_id = EXCLUDED.admin_id,
                        usuario_id = EXCLUDED.usuario_id,
                        fecha_rd = EXCLUDED.fecha_rd,
                        updated_at = CURRENT_TIMESTAMP
                    """,
                    (banca_id, admin_id_i, uid, lottery_n, draw_n, num, limite_f, fecha_rd, activo_i),
                )
                return "updated"
            except Exception:
                _rollback_pg_cursor(cur)
                eid = _limites_buscar_id_fila(cur, banca_id, lottery_n, draw_n, num, solo_clave_legacy=True)
                if eid:
                    _limites_update_fila(cur, eid, limite_f, activo_i, admin_id_i, uid, fecha_rd)
                    return "updated"
        raise


def _limites_enriquecer_fila(cur, d, fecha_rd):
    """Calcula límite efectivo, vendido y disponible para una fila de listado."""
    ln_id = d.get("id")
    lim_raw = d.get("limite_personalizado")
    if lim_raw is None and ln_id is not None:
        lim_raw = d.get("limite")
    if ln_id is None or lim_raw is None:
        d["tiene_limite_personalizado"] = False
        d["limite_etiqueta"] = "Sin límite personalizado"
        d["limite"] = float(LIMITE_NUMERO_DIARIO_DEFAULT)
    else:
        d["tiene_limite_personalizado"] = True
        d["limite_etiqueta"] = "Personalizado"
        d["limite"] = round(float(lim_raw or 0), 2)
    d["usuario_nombre"] = d.get("usuario_nombre") or d.get("banca_nombre") or ""
    d["banca_nombre"] = d.get("banca_nombre") or d.get("usuario_nombre") or ""
    lot = (d.get("lottery") or "").strip()
    num = (d.get("numero") or "").strip()
    if ln_id and lot and num:
        info = _limites_disponible_numero(
            cur,
            d.get("banca_id") or d.get("usuario_id"),
            lot,
            d.get("draw"),
            num,
            fecha_rd,
            d.get("usuario_id"),
        )
        d.update(info)
        if not d.get("tiene_limite_personalizado"):
            d["disponible"] = max(0.0, float(d["limite"]) - float(d.get("vendido") or 0))
    else:
        d["vendido"] = round(float(d.get("vendido") or 0), 2)
        d["disponible"] = round(float(d["limite"]), 2)
    d["fecha_rd_consulta"] = fecha_rd
    act = d.get("activo")
    if act is None and ln_id is None:
        d["activo"] = 1
        d["estado_texto"] = "Por defecto"
    elif act in (0, "0", False):
        d["estado_texto"] = "Inactivo"
    else:
        d["estado_texto"] = "Activo"
    return d


def _limites_cajero_where_sql(filtros, alias_ln="ln", alias_u="u"):
    """WHERE + params para consultas directas sobre limites_numeros (vista por cajero)."""
    filtros = filtros or {}
    ln_where, params = [], []
    role = (session.get("role") or "").strip().lower()
    uid = int(session.get("uid") or 0)
    if role == ROLE_ADMIN and uid > 0:
        ln_where.append("(%s.banca_id = %s OR %s.created_by = %s)" % (alias_ln, "%s", alias_u, "%s"))
        params.extend([uid, uid])
    bid = filtros.get("banca_id") or filtros.get("cajero_id")
    if bid:
        try:
            ln_where.append("%s.banca_id = %%s" % alias_ln)
            params.append(int(bid))
        except (TypeError, ValueError):
            pass
    if filtros.get("numero"):
        ln_where.append("%s.numero = %%s" % alias_ln)
        params.append(normalizar_numero(filtros["numero"]))
    if filtros.get("lottery"):
        lot_n, _ = _normalizar_clave_limite_loteria(filtros["lottery"], "")
        if lot_n:
            ln_where.append("%s.lottery = %%s" % alias_ln)
            params.append(lot_n)
    if filtros.get("draw") or filtros.get("sorteo"):
        _, dr_n = _normalizar_clave_limite_loteria("", filtros.get("draw") or filtros.get("sorteo"))
        if dr_n:
            ln_where.append("%s.draw = %%s" % alias_ln)
            params.append(dr_n)
    if filtros.get("fecha_rd"):
        ln_where.append("%s.fecha_rd = %%s" % alias_ln)
        params.append(str(filtros["fecha_rd"])[:10])
    if filtros.get("activo") in ("0", "1"):
        ln_where.append("COALESCE(%s.activo, 1) = %%s" % alias_ln)
        params.append(int(filtros["activo"]))
    if filtros.get("q"):
        qtxt = "%%%s%%" % str(filtros["q"]).strip()
        ln_where.append(
            "(%s.numero LIKE %%s OR %s.lottery LIKE %%s OR %s.draw LIKE %%s OR %s.username LIKE %%s)"
            % (alias_ln, alias_ln, alias_ln, alias_u)
        )
        params.extend([qtxt, qtxt, qtxt, qtxt])
    if not ln_where:
        return "1=1", tuple(params)
    return " AND ".join(ln_where), tuple(params)


def _limites_listar_por_cajero(cur, filtros=None):
    """Lista solo filas reales de limites_numeros (rápido, paginado, auditable por cajero)."""
    filtros = filtros or {}
    page = max(1, int(filtros.get("page") or 1))
    per_page = max(10, min(100, int(filtros.get("per_page") or 50)))
    offset = (page - 1) * per_page
    where_sql, params = _limites_cajero_where_sql(filtros)
    base_from = (
        """
        FROM limites_numeros ln
        INNER JOIN users u ON u.id = ln.banca_id
        WHERE """
        + where_sql
    )
    cur.execute(_sql("SELECT COUNT(*) AS c " + base_from), params)
    cr = cur.fetchone()
    total = int(_limites_row_val(cr, "c", 0, 0) or 0)
    cur.execute(
        _sql(
            """
            SELECT
                COUNT(*) AS total_filas,
                COUNT(DISTINCT ln.banca_id) AS cajeros,
                COUNT(DISTINCT ln.lottery) AS loterias,
                COUNT(DISTINCT ln.numero) AS numeros,
                SUM(CASE WHEN COALESCE(ln.activo, 1) = 1 THEN 1 ELSE 0 END) AS activos
            """
            + base_from
        ),
        params,
    )
    sr = cur.fetchone()
    resumen = {
        "total_activos": int(_limites_row_val(sr, "activos", 0, 0) or 0),
        "cajeros_con_limites": int(_limites_row_val(sr, "cajeros", 1, 0) or 0),
        "loterias_configuradas": int(_limites_row_val(sr, "loterias", 2, 0) or 0),
        "numeros_limitados": int(_limites_row_val(sr, "numeros", 3, 0) or 0),
        "total_filas": int(_limites_row_val(sr, "total_filas", 0, 0) or 0),
    }
    cur.execute(
        _sql(
            """
            SELECT
                ln.id,
                ln.banca_id,
                u.username AS cajero_nombre,
                u.role AS cajero_role,
                ln.lottery,
                ln.draw,
                ln.numero,
                ln.limite,
                ln.fecha_rd,
                ln.activo,
                COALESCE(ln.usuario_id, 0) AS usuario_id_limite
            """
            + base_from
            + """
            ORDER BY u.username, ln.lottery, ln.draw, ln.numero
            LIMIT %s OFFSET %s
            """
        ),
        tuple(list(params) + [per_page, offset]),
    )
    items = []
    for r in cur.fetchall() or []:
        d = dict(r) if hasattr(r, "keys") else {}
        activo = d.get("activo")
        items.append(
            {
                "id": d.get("id"),
                "banca_id": d.get("banca_id"),
                "cajero_nombre": d.get("cajero_nombre") or "—",
                "cajero_role": d.get("cajero_role") or "",
                "lottery": d.get("lottery") or "",
                "draw": d.get("draw") or "",
                "numero": d.get("numero") or "",
                "limite": float(d.get("limite") or 0),
                "fecha_rd": (d.get("fecha_rd") or "")[:10],
                "activo": 1 if str(activo).strip() not in ("0", "false", "False") else 0,
                "estado_texto": "Activo" if str(activo).strip() not in ("0", "false", "False") else "Inactivo",
                "usuario_id_limite": d.get("usuario_id_limite") or 0,
            }
        )
    pages = max(1, (total + per_page - 1) // per_page)
    return {
        "items": items,
        "total": total,
        "page": page,
        "per_page": per_page,
        "pages": pages,
        "resumen": resumen,
    }


def _limites_eliminar_masivo(cur, filtros, admin_uid):
    """DELETE masivo con permisos (cajero, fecha, lotería)."""
    where_sql, params = _limites_cajero_where_sql(filtros)
    if where_sql == "1=1" and not params:
        raise ValueError("filtro_requerido")
    cur.execute(
        _sql(
            """
            SELECT DISTINCT ln.banca_id FROM limites_numeros ln
            INNER JOIN users u ON u.id = ln.banca_id
            WHERE """
            + where_sql
        ),
        params,
    )
    for r in cur.fetchall() or []:
        bid = int(_limites_row_val(r, "banca_id", 0, 0) or 0)
        if bid and not _limites_banca_permitida(cur, bid):
            raise ValueError("sin_permiso")
    cur.execute(
        _sql(
            """
            DELETE FROM limites_numeros
            WHERE id IN (
                SELECT ln.id FROM limites_numeros ln
                INNER JOIN users u ON u.id = ln.banca_id
                WHERE """
            + where_sql
            + """
            )
            """
        ),
        params,
    )
    borrados = int(cur.rowcount or 0) if hasattr(cur, "rowcount") else 0
    _limites_log("eliminar masivo", admin_id=admin_uid, borrados=borrados, filtros=str(filtros)[:120])
    return borrados


def _limites_listar_filas(cur, filtros=None, limit=500):
    """
    Lista usuarios del sistema con LEFT JOIN a limites_numeros.
    Incluye usuarios sin límites configurados (una fila con valores por defecto).
    """
    filtros = filtros or {}
    fecha_rd = (filtros.get("fecha_rd") or ahora_rd().strftime("%Y-%m-%d"))[:10]
    page = max(1, int(filtros.get("page") or 1))
    per_page = max(10, min(200, int(filtros.get("per_page") or 50)))
    lim_cap = max(1, min(5000, int(limit or 500)))
    per_page = min(per_page, lim_cap)
    offset = (page - 1) * per_page

    vista = (filtros.get("vista") or "completo").strip().lower()
    solo_con_limite = str(filtros.get("solo_con_limite") or "").strip().lower() in ("1", "true", "yes")

    u_where, u_params = [_limites_sql_not_blocked("u")], []
    ln_on_extra, ln_params = [], []
    post_where, post_params = [], []

    role = (session.get("role") or "").strip().lower()
    uid = int(session.get("uid") or 0)
    if role == ROLE_ADMIN and uid > 0:
        u_where.append("(u.id = %s OR u.created_by = %s)")
        u_params.extend([uid, uid])
    if filtros.get("admin_id"):
        try:
            aid = int(filtros["admin_id"])
            u_where.append("(u.created_by = %s OR u.id = %s)")
            u_params.extend([aid, aid])
        except (TypeError, ValueError):
            pass
    if filtros.get("banca_id"):
        try:
            u_where.append("u.id = %s")
            u_params.append(int(filtros["banca_id"]))
        except (TypeError, ValueError):
            pass
    if filtros.get("usuario_id") or filtros.get("cajero_id"):
        try:
            u_where.append("u.id = %s")
            u_params.append(int(filtros.get("usuario_id") or filtros.get("cajero_id")))
        except (TypeError, ValueError):
            pass
    if filtros.get("role"):
        u_where.append("LOWER(COALESCE(u.role,'')) = %s")
        u_params.append(str(filtros["role"]).strip().lower())
    if filtros.get("q"):
        q = "%%%s%%" % str(filtros["q"]).strip()
        u_where.append(
            "(u.username LIKE %s OR COALESCE(adm.username,'') LIKE %s OR COALESCE(u.role,'') LIKE %s "
            "OR COALESCE(ln.numero,'') LIKE %s OR COALESCE(ln.lottery,'') LIKE %s)"
        )
        u_params.extend([q, q, q, q, q])

    if filtros.get("lottery"):
        ln_lot, _ = _normalizar_clave_limite_loteria(filtros["lottery"], "")
        ln_on_extra.append("(ln.lottery = %s OR ln.id IS NULL)")
        ln_params.append(ln_lot)
    if filtros.get("draw") or filtros.get("sorteo"):
        _, ln_dr = _normalizar_clave_limite_loteria("", filtros.get("draw") or filtros.get("sorteo"))
        ln_on_extra.append("(ln.draw = %s OR ln.id IS NULL)")
        ln_params.append(ln_dr)
    if filtros.get("numero"):
        ln_on_extra.append("(ln.numero = %s OR ln.id IS NULL)")
        ln_params.append(normalizar_numero(filtros["numero"]))
    if filtros.get("activo") in ("0", "1"):
        post_where.append("(ln.id IS NULL OR COALESCE(ln.activo, 1) = %s)")
        post_params.append(int(filtros["activo"]))

    join_ln = "INNER JOIN" if solo_con_limite else "LEFT JOIN"
    ln_on_sql = "ln.banca_id = u.id"
    if ln_on_extra:
        ln_on_sql += " AND " + " AND ".join(ln_on_extra)

    base_from = (
        """
        FROM users u
        LEFT JOIN users adm ON adm.id = u.created_by
        """
        + join_ln
        + " limites_numeros ln ON "
        + ln_on_sql
        + """
        LEFT JOIN users uc ON uc.id = ln.usuario_id AND COALESCE(ln.usuario_id, 0) > 0
        WHERE """
        + " AND ".join(u_where)
    )
    if post_where:
        base_from += " AND " + " AND ".join(post_where)

    count_params = tuple(ln_params + u_params + post_params)
    if vista == "usuarios":
        cur.execute(
            _sql("SELECT COUNT(DISTINCT u.id) AS c " + base_from),
            count_params,
        )
    else:
        cur.execute(
            _sql("SELECT COUNT(*) AS c " + base_from),
            count_params,
        )
    cr = cur.fetchone()
    total = int(_limites_row_val(cr, "c", 0, 0) or 0)

    select_sql = (
        """
        SELECT
            ln.id,
            u.id AS usuario_id,
            u.username AS usuario_nombre,
            u.role AS usuario_role,
            COALESCE(adm.id, 0) AS admin_id,
            COALESCE(adm.username, '') AS admin_nombre,
            ln.banca_id,
            COALESCE(ln.usuario_id, 0) AS usuario_id_limite,
            COALESCE(uc.username, '') AS cajero_nombre,
            ln.lottery,
            ln.draw,
            ln.numero,
            ln.limite AS limite_personalizado,
            ln.fecha_rd,
            ln.activo,
            u.username AS banca_nombre
        """
        + base_from
        + """
        ORDER BY
            COALESCE(adm.username, ''),
            CASE COALESCE(u.role, '')
                WHEN 'super_admin' THEN 0
                WHEN 'admin' THEN 1
                WHEN 'banca' THEN 2
                WHEN 'supervisor' THEN 3
                WHEN 'cajero' THEN 4
                ELSE 5
            END,
            u.username,
            COALESCE(ln.lottery, ''),
            COALESCE(ln.draw, ''),
            COALESCE(ln.numero, '')
        LIMIT %s OFFSET %s
        """
    )
    list_params = tuple(ln_params + u_params + post_params + [per_page, offset])
    cur.execute(_sql(select_sql), list_params)

    out = []
    for r in cur.fetchall() or []:
        d = dict(r) if hasattr(r, "keys") else {}
        out.append(_limites_enriquecer_fila(cur, d, fecha_rd))

    pages = max(1, (total + per_page - 1) // per_page)
    return {
        "items": out,
        "total": total,
        "page": page,
        "per_page": per_page,
        "pages": pages,
        "fecha_rd": fecha_rd,
    }


def _limites_set_config_flag(cur, usar_limites=None, meta_diaria=None):
    if usar_limites is not None:
        if isinstance(usar_limites, str):
            usar_limites = str(usar_limites).strip().lower() in ("1", "true", "yes", "on", "si", "sí")
        v = "1" if usar_limites else "0"
        cur.execute(_sql("UPDATE config SET value=%s WHERE key=%s"), (v, "usar_limites"))
        if cur.rowcount == 0:
            cur.execute(_sql("INSERT INTO config (key,value) VALUES (%s,%s)"), ("usar_limites", v))
    if meta_diaria is not None:
        cur.execute(_sql("UPDATE config SET value=%s WHERE key=%s"), (str(meta_diaria), "meta_diaria"))
        if cur.rowcount == 0:
            cur.execute(_sql("INSERT INTO config (key,value) VALUES (%s,%s)"), ("meta_diaria", str(meta_diaria)))


def _limites_bulk_upsert_legacy(cur, banca_id, numeros, limite_f):
    """Upsert masivo en tabla legacy limites (banca_id, numero)."""
    banca_id = int(banca_id)
    limite_f = round(float(limite_f), 2)
    nums = []
    for n in numeros or []:
        nn = normalizar_numero(n)
        if re.match(r"^\d{2}$", nn or "") and nn not in nums:
            nums.append(nn)
    if not nums:
        return 0
    valores = [(banca_id, nn, limite_f) for nn in nums]
    is_pg = bool(os.environ.get("DATABASE_URL"))
    if is_pg:
        from psycopg2.extras import execute_values

        execute_values(
            cur,
            """
            INSERT INTO limites (banca_id, numero, limite)
            VALUES %s
            ON CONFLICT (banca_id, numero)
            DO UPDATE SET limite = EXCLUDED.limite
            """,
            valores,
            template="(%s::integer, %s::text, %s::numeric)",
            page_size=len(valores),
        )
    else:
        cur.executemany(
            """
            INSERT INTO limites (banca_id, numero, limite)
            VALUES (?, ?, ?)
            ON CONFLICT (banca_id, numero)
            DO UPDATE SET limite = excluded.limite
            """,
            valores,
        )
    return len(valores)


def _limites_guardar_admin_form(
    cur,
    *,
    banca_id,
    numeros_norm,
    limite_f,
    activar_limites,
    meta_diaria,
    admin_uid,
):
    """
    Guardado rápido para POST /admin/limites: config + legacy limites + bulk limites_numeros.
    Sin loops con upsert fila a fila.
    """
    t0 = time.monotonic()
    banca_id = int(banca_id)
    n_nums = len(numeros_norm or [])
    log.info(
        "[LIMITES_SAVE_START] banca_id=%s numeros=%s limite=%s admin_uid=%s",
        banca_id,
        n_nums,
        limite_f,
        admin_uid,
    )
    try:
        _limites_set_config_flag(cur, usar_limites=bool(activar_limites), meta_diaria=meta_diaria)
        _limites_bulk_upsert_legacy(cur, banca_id, numeros_norm, limite_f)
        bulk = _limites_aplicar_masivo(
            cur,
            banca_id,
            numeros_norm,
            limite_f,
            admin_id=admin_uid,
            usuario_id=0,
            fecha_rd="",
            activo=1,
            all_lotteries=True,
            all_draws=True,
        )
        ms = int((time.monotonic() - t0) * 1000)
        log.info(
            "[LIMITES_SAVE_OK] banca_id=%s numeros=%s combinaciones=%s registros=%s tiempo_ms=%s",
            banca_id,
            n_nums,
            bulk.get("combinaciones_loteria"),
            bulk.get("creados", 0) + bulk.get("actualizados", 0),
            ms,
        )
        return {"ok": True, "ms": ms, "bulk": bulk}
    except Exception as ex:
        ms = int((time.monotonic() - t0) * 1000)
        log.exception(
            "[LIMITES_SAVE_ERROR] banca_id=%s numeros=%s tiempo_ms=%s error=%s",
            banca_id,
            n_nums,
            ms,
            ex,
        )
        return {"ok": False, "ms": ms, "error": str(ex)}


def _limites_listar_admin_page(cur, limit=80):
    """
    Listado ligero para GET /admin/limites (sin N+1 de vendido/disponible por fila).
    """
    lim = max(20, min(200, int(limit or 80)))
    where, params = [], []
    role = (session.get("role") or "").strip().lower()
    uid = int(session.get("uid") or 0)
    if role == ROLE_ADMIN and uid > 0:
        where.append("(ln.banca_id = %s OR u.created_by = %s)")
        params.extend([uid, uid])
    where_sql = (" AND ".join(where)) if where else "1=1"
    cur.execute(
        _sql(
            """
            SELECT
                ln.id,
                u.id AS usuario_id,
                u.username AS usuario_nombre,
                u.role AS usuario_role,
                COALESCE(adm.username, '') AS admin_nombre,
                ln.lottery,
                ln.draw,
                ln.numero,
                ln.limite AS limite_personalizado,
                ln.activo,
                u.username AS banca_nombre
            FROM limites_numeros ln
            INNER JOIN users u ON u.id = ln.banca_id
            LEFT JOIN users adm ON adm.id = u.created_by
            WHERE """
            + where_sql
            + """
            ORDER BY
                COALESCE(adm.username, ''),
                u.username,
                ln.lottery,
                ln.draw,
                ln.numero
            LIMIT %s
            """
        ),
        tuple(list(params) + [lim]),
    )
    items = []
    for r in cur.fetchall() or []:
        d = dict(r) if hasattr(r, "keys") else {}
        limite = round(float(d.get("limite_personalizado") or 0), 2)
        items.append(
            {
                "id": d.get("id"),
                "usuario_id": d.get("usuario_id"),
                "usuario_nombre": d.get("usuario_nombre") or "",
                "usuario_role": d.get("usuario_role") or "",
                "admin_nombre": d.get("admin_nombre") or "",
                "banca_nombre": d.get("banca_nombre") or "",
                "lottery": d.get("lottery") or "",
                "draw": d.get("draw") or "",
                "numero": d.get("numero") or "",
                "limite": limite,
                "limite_personalizado": limite,
                "tiene_limite_personalizado": True,
                "disponible": limite,
            }
        )
    return items


@app.route("/api/riesgo/alerta", methods=["GET"])
def api_riesgo_alerta():
    if not session.get("uid"):
        return jsonify({"ok": False, "error": "No autenticado"}), 401
    lottery_raw = (request.args.get("lottery") or "").strip()
    draw_raw = (request.args.get("draw") or request.args.get("sorteo") or "").strip()
    numero_raw = (request.args.get("numero") or "").strip()
    if not lottery_raw or not draw_raw or not numero_raw:
        return jsonify({"ok": False, "error": "lottery, draw y numero son obligatorios"}), 400
    c = db()
    if not c:
        return jsonify({"ok": False, "error": "DB"}), 500
    cur = None
    try:
        cur = c.cursor()
        banca_id = _banca_id_para_usuario_actual(cur, session.get("uid"))
        alerta = _centro_riesgo_alerta_numero(cur, banca_id, lottery_raw, draw_raw, numero_raw)
        if not alerta:
            return jsonify({"ok": True, "mostrar_alerta": False, "mensaje": ""})
        return jsonify({"ok": True, **alerta})
    finally:
        _db_close(c, cur)


