# LOGIN PRO MAX (BANCA DOMINICANA PREMIUM)
_SUPER_ADMIN_PROBE_CACHE_SEC = float(os.environ.get("LOGIN_SUPER_ADMIN_PROBE_CACHE_SECONDS", "120"))
_SUPER_ADMIN_PROBE_CACHE = {"expires": 0.0, "exists": False}


def _cached_super_admin_existe(force_refresh=False):
    """
    Evita un round-trip pesado contra la BD en cada GET /. TTL corto (~2 min configurable).
    No bloquea GET login mientras init_db corre en db-warmup (migraciones SQLite).
    """
    _req_trace("_super_admin_existe inicio", force_refresh=force_refresh, schema_ready=_DB_SCHEMA_READY)
    now_ts = time.time()
    if not force_refresh:
        exp = float(_SUPER_ADMIN_PROBE_CACHE.get("expires") or 0)
        if now_ts < exp:
            _req_trace("_super_admin_existe cache_hit", exists=_SUPER_ADMIN_PROBE_CACHE.get("exists"))
            return bool(_SUPER_ADMIN_PROBE_CACHE.get("exists"))
    if not _DB_SCHEMA_READY and _initializing_db and not force_refresh:
        _req_trace(
            "_super_admin_existe defer (init_db en curso — no bloquear login GET)",
            initializing=True,
        )
        return bool(_SUPER_ADMIN_PROBE_CACHE.get("exists", True))
    t_db = time.perf_counter()
    conn = db()
    _req_trace("_super_admin_existe después db()", ms=round((time.perf_counter() - t_db) * 1000, 2))
    if not conn:
        return False
    try:
        cur = conn.cursor()
        exists = bool(_super_admin_existe_cur(cur))
        _SUPER_ADMIN_PROBE_CACHE["exists"] = exists
        _SUPER_ADMIN_PROBE_CACHE["expires"] = now_ts + max(15.0, _SUPER_ADMIN_PROBE_CACHE_SEC)
        _req_trace("_super_admin_existe query_ok", exists=exists)
        return exists
    except Exception:
        return False
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _invalidate_super_admin_probe_cache():
    _SUPER_ADMIN_PROBE_CACHE["expires"] = 0.0


# =====================================================
def _super_admin_existe():
    return _cached_super_admin_existe()


def _super_admin_existe_cur(cur):
    try:
        cur.execute(_sql("SELECT 1 FROM users WHERE role=%s LIMIT 1"), (ROLE_SUPER_ADMIN,))
        return cur.fetchone() is not None
    except Exception:
        _rollback_pg_cursor(cur)
        return False


def _render_login_error(error, cur=None):
    existe = _super_admin_existe_cur(cur) if cur is not None else _super_admin_existe()
    return render_template_string(
        IOS + LOGIN_HTML,
        error=error,
        mostrar_crear_super_admin=(not existe),
        db_warming=(not _DB_SCHEMA_READY and _initializing_db),
    )


@app.route("/", methods=["GET"])
def login():
    _req_trace("login() inicio")
    t0 = time.perf_counter()
    super_admin_existe = _super_admin_existe()
    _req_trace("login() después _super_admin_existe", ms=round((time.perf_counter() - t0) * 1000, 2))
    t1 = time.perf_counter()
    html = render_template_string(
        IOS + LOGIN_HTML,
        error=None,
        mostrar_crear_super_admin=(not super_admin_existe),
        db_warming=(not _DB_SCHEMA_READY and _initializing_db),
    )
    _req_trace("login() después render", ms=round((time.perf_counter() - t1) * 1000, 2))
    return html


