@app.route("/login", methods=["GET", "POST"])
def do_login():
    if request.method == "GET":
        _req_trace("do_login GET inicio")
        t0 = time.perf_counter()
        super_admin_existe = _super_admin_existe()
        _req_trace("do_login GET después _super_admin_existe", ms=round((time.perf_counter() - t0) * 1000, 2))
        t1 = time.perf_counter()
        html = render_template_string(
            IOS + LOGIN_HTML,
            error=None,
            mostrar_crear_super_admin=(not super_admin_existe),
            db_warming=(not _DB_SCHEMA_READY and _initializing_db),
        )
        _req_trace("do_login GET después render", ms=round((time.perf_counter() - t1) * 1000, 2))
        return html

    _req_trace("do_login POST inicio")
    total_t = time.perf_counter()
    profile = {}
    username = (request.form.get("username") or request.form.get("u") or "").strip()
    password = (request.form.get("password") or request.form.get("p") or "")

    if not username or not password:
        return _render_login_error("Usuario y contraseña son obligatorios")

    t_db = time.perf_counter()
    conn = db()
    _req_trace("do_login POST después db()", ms=round((time.perf_counter() - t_db) * 1000, 2))
    profile["db_connect_ms"] = round((time.perf_counter() - t_db) * 1000, 2)
    if not conn:
        log.warning("login_db_error user=%s profile=%s", username, profile)
        return render_template_string(IOS + LOGIN_HTML, error="Error conectando base de datos", mostrar_crear_super_admin=False)
    try:
        cur = conn.cursor()
        t = time.perf_counter()
        cur.execute(_sql("""
            SELECT id, username, password_hash, role, approved, is_approved, is_blocked,
                   pago_activo, fecha_vencimiento, created_by, telefono
            FROM users
            WHERE username=%s
            LIMIT 1
        """), (username,))
        user = cur.fetchone()
        profile["user_query_ms"] = round((time.perf_counter() - t) * 1000, 2)
        if user is not None and not isinstance(user, dict):
            user = dict(user)

        if not user:
            log.info("login_failed reason=user_not_found user=%s profile=%s total_ms=%s", username, profile, round((time.perf_counter() - total_t) * 1000, 2))
            return _render_login_error("Usuario no existe", cur=cur)

        t = time.perf_counter()
        if not check_password_hash(user.get("password_hash") or "", password):
            profile["password_check_ms"] = round((time.perf_counter() - t) * 1000, 2)
            log.info("login_failed reason=bad_password user=%s profile=%s total_ms=%s", username, profile, round((time.perf_counter() - total_t) * 1000, 2))
            return _render_login_error("Contraseña incorrecta", cur=cur)
        profile["password_check_ms"] = round((time.perf_counter() - t) * 1000, 2)

        aprobado = _to_bool(user.get("is_approved")) if user.get("is_approved") is not None else _to_bool(user.get("approved", False))
        bloqueado = _to_bool(user.get("is_blocked")) if user.get("is_blocked") is not None else False

        if not aprobado:
            log.info("login_failed reason=not_approved user=%s profile=%s", username, profile)
            return _render_login_error("Usuario pendiente de aprobación", cur=cur)

        if bloqueado:
            log.info("login_failed reason=blocked user=%s profile=%s", username, profile)
            return _render_login_error("Usuario bloqueado", cur=cur)

        if (user.get("role") or "").strip().lower() == ROLE_ADMIN:
            if user.get("pago_activo") is not None and (not _to_bool(user.get("pago_activo"))):
                log.info("login_failed reason=pago_inactivo user=%s profile=%s", username, profile)
                return _render_login_error("Pago inactivo", cur=cur)

        t = time.perf_counter()
        ok, msg = validar_estado_usuario(user, cur=cur, conn=conn)
        profile["validaciones_ms"] = round((time.perf_counter() - t) * 1000, 2)
        if not ok:
            log.info("login_failed reason=estado user=%s msg=%s profile=%s", username, msg, profile)
            return _render_login_error(msg, cur=cur)

        session.permanent = True
        session["u"] = user.get("username")
        session["uid"] = user.get("id")
        session["role"] = (user.get("role") or "").strip().lower()
        session["last_activity"] = time.time()
        session["last_activity_touch"] = session["last_activity"]
        session["user_state_checked_at"] = session["last_activity"]

        try:
            if (os.environ.get("LOGIN_SKIP_SESION_LOG") or "").strip().lower() not in ("1", "true", "yes"):
                t = time.perf_counter()
                _registrar_sesion_usuario(cur, user.get("id"))
                conn.commit()
                profile["registrar_sesion_ms"] = round((time.perf_counter() - t) * 1000, 2)
            else:
                profile["registrar_sesion_ms"] = 0.0
        except Exception as e:
            log.warning("sesiones_usuario (login): %s", e, exc_info=True)
            try:
                conn.rollback()
            except Exception:
                pass

        log.info(
            "PERF ruta=/login login_ok user=%s role=%s total_ms=%s profile=%s",
            username,
            session["role"],
            round((time.perf_counter() - total_t) * 1000, 2),
            profile,
        )
        if session["role"] in (ROLE_SUPER_ADMIN, ROLE_ADMIN):
            return redirect("/admin")
        return redirect("/venta")
    finally:
        try:
            conn.close()
        except Exception:
            pass


