# =====================================================
# ENDPOINTS NUEVO SISTEMA DE USUARIOS (Jerarquía + aprobación + bloqueo + pagos)
# =====================================================
def _get_user_id_from_session():
    uid = session.get("uid")
    if uid:
        return uid
    uname = session.get("u") or session.get("user") or ""
    conn = db()
    if not conn:
        return None
    try:
        cur = conn.cursor()
        cur.execute(_sql("SELECT id FROM users WHERE username=%s"), (uname,))
        row = cur.fetchone()
        return row["id"] if row and isinstance(row, dict) else (row[0] if row else None)
    finally:
        try:
            conn.close()
        except Exception:
            pass


@app.route("/superadmin/create-admin", methods=["POST"])
@super_admin_required
def superadmin_create_admin():
    data = request.get_json(silent=True) or request.form or {}
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""
    telefono = (data.get("telefono") or "").strip() or None
    fecha_vencimiento = (data.get("fecha_vencimiento") or "").strip() or None

    if not username or not password:
        return jsonify({"ok": False, "error": "username y password son obligatorios"}), 400

    admin_super_id = _get_user_id_from_session()
    if not admin_super_id:
        return jsonify({"ok": False, "error": "No se pudo identificar el usuario"}), 403

    conn = db()
    if not conn:
        return jsonify({"ok": False, "error": "Error de base de datos"}), 500
    try:
        cur = conn.cursor()
        cur.execute(_sql("SELECT 1 FROM users WHERE username=%s"), (username,))
        if cur.fetchone():
            return jsonify({"ok": False, "error": "Ese username ya existe"}), 409

        cur.execute(
            _sql("""
                INSERT INTO users
                    (username, password_hash, role, created_by, approved, is_approved, is_blocked, pago_activo, fecha_vencimiento, telefono, created_at)
                VALUES (%s, %s, %s, %s, true, true, false, true, %s, %s, CURRENT_TIMESTAMP)
            """),
            (username, generate_password_hash(password), ROLE_ADMIN, admin_super_id, fecha_vencimiento, telefono),
        )
        conn.commit()

        # Notificación: admin creado/aprobado
        send_whatsapp(telefono, "Tu cuenta ha sido aprobada")
        return jsonify({"ok": True, "message": "Admin creado"}), 201
    finally:
        try:
            conn.close()
        except Exception:
            pass


