@app.route("/superadmin/cambiar-contrasena/<int:user_id>", methods=["GET", "POST"])
def superadmin_cambiar_contrasena(user_id):
    """Solo super_admin puede cambiar contraseña de admin/cajero (y otros super_admin)."""
    super_name = session.get("u") or session.get("user") or "?"
    wants_json = request.method == "POST" and (
        request.is_json or (request.content_type or "").startswith("application/json")
    )

    if not session.get("u") and not session.get("user"):
        log.info(
            "[CAMBIAR_PASSWORD] super_admin=%s user_id=%s resultado=no_sesion",
            super_name,
            user_id,
        )
        if wants_json:
            return jsonify({"ok": False, "error": "No autorizado"}), 401
        return redirect("/")

    if not is_super_admin():
        log.info(
            "[CAMBIAR_PASSWORD] super_admin=%s user_id=%s resultado=no_autorizado",
            super_name,
            user_id,
        )
        if wants_json:
            return jsonify({"ok": False, "error": "No autorizado"}), 403
        return "Forbidden", 403

    conn = db()
    if not conn:
        log.info(
            "[CAMBIAR_PASSWORD] super_admin=%s user_id=%s resultado=error_db",
            super_name,
            user_id,
        )
        if wants_json:
            return jsonify({"ok": False, "error": "Error de base de datos"}), 500
        return "Error de base de datos", 500

    try:
        cur = conn.cursor()
        cur.execute(
            _sql("SELECT id, username, role FROM users WHERE id=%s"),
            (user_id,),
        )
        row = cur.fetchone()
        if not row:
            log.info(
                "[CAMBIAR_PASSWORD] super_admin=%s user_id=%s resultado=no_encontrado",
                super_name,
                user_id,
            )
            if wants_json:
                return jsonify({"ok": False, "error": "Usuario no encontrado"}), 404
            flash("Usuario no encontrado.", "warning")
            return redirect("/superadmin/control-usuarios")

        u = dict(row) if hasattr(row, "keys") else {"id": row[0], "username": row[1], "role": row[2]}
        if (u.get("role") or "").strip() not in (ROLE_SUPER_ADMIN, ROLE_ADMIN, ROLE_CAJERO):
            log.info(
                "[CAMBIAR_PASSWORD] super_admin=%s user_id=%s resultado=rol_no_permitido",
                super_name,
                user_id,
            )
            if wants_json:
                return jsonify({"ok": False, "error": "Rol no permitido"}), 400
            flash("Rol no permitido.", "warning")
            return redirect("/superadmin/control-usuarios")

        if request.method == "GET":
            error = (request.args.get("error") or "").strip()
            return render_template_string(
                IOS
                + """
    <a href="/superadmin/control-usuarios" class="admin-btn">⬅ Volver</a>
    <div class="card" style="max-width:480px;margin:26px auto;">
      <h2 style="margin-top:0;">🔑 Cambiar contraseña</h2>
      <p style="color:#64748b;margin-bottom:16px;">Usuario: <strong>{{ u.username }}</strong> ({{ u.role }})</p>
      {% if error %}
      <p style="background:#fee2e2;color:#991b1b;padding:10px;border-radius:8px;margin-bottom:12px;">{{ error }}</p>
      {% endif %}
      <form method="post" action="/superadmin/cambiar-contrasena/{{ u.id }}">
        <label style="display:block;font-size:12px;font-weight:700;color:#334155;margin-bottom:6px;">Nueva contraseña</label>
        <input type="password" name="password" required autocomplete="new-password"
          style="width:100%;padding:10px 12px;border:1px solid #cbd5e1;border-radius:8px;margin-bottom:12px;box-sizing:border-box;" />
        <label style="display:block;font-size:12px;font-weight:700;color:#334155;margin-bottom:6px;">Confirmar contraseña</label>
        <input type="password" name="password_confirm" required autocomplete="new-password"
          style="width:100%;padding:10px 12px;border:1px solid #cbd5e1;border-radius:8px;margin-bottom:16px;box-sizing:border-box;" />
        <button type="submit"
          style="width:100%;padding:12px;border:none;border-radius:8px;background:#7c3aed;color:#fff;font-weight:800;cursor:pointer;">
          Guardar contraseña
        </button>
      </form>
    </div>
    """,
                u=u,
                error=error,
            )

        data = request.get_json(silent=True) if wants_json else (request.form or {})
        nueva = (data.get("password") or data.get("nueva_password") or "").strip()
        confirmar = (data.get("password_confirm") or data.get("confirmar_password") or "").strip()

        if not nueva:
            log.info(
                "[CAMBIAR_PASSWORD] super_admin=%s user_id=%s resultado=vacia",
                super_name,
                user_id,
            )
            if wants_json:
                return jsonify({"ok": False, "error": "La nueva contraseña es obligatoria."}), 400
            return redirect(f"/superadmin/cambiar-contrasena/{user_id}?error=La+nueva+contrase%C3%B1a+es+obligatoria.")

        if nueva != confirmar:
            log.info(
                "[CAMBIAR_PASSWORD] super_admin=%s user_id=%s resultado=no_coincide",
                super_name,
                user_id,
            )
            if wants_json:
                return jsonify({"ok": False, "error": "Las contraseñas no coinciden."}), 400
            return redirect(f"/superadmin/cambiar-contrasena/{user_id}?error=Las+contrase%C3%B1as+no+coinciden.")

        pwd_hash = generate_password_hash(nueva)
        cur.execute(_sql("UPDATE users SET password_hash=%s WHERE id=%s"), (pwd_hash, user_id))
        conn.commit()
        log.info(
            "[CAMBIAR_PASSWORD] super_admin=%s user_id=%s resultado=ok",
            super_name,
            user_id,
        )
        if wants_json:
            return jsonify({"ok": True, "message": "Contraseña actualizada correctamente"}), 200
        flash("Contraseña actualizada correctamente", "success")
        return redirect("/superadmin/control-usuarios")
    finally:
        try:
            conn.close()
        except Exception:
            pass


