    if not conn:
        return jsonify({"ok": False, "error": "Error de base de datos"}), 500
    try:
        cur = conn.cursor()
        cur.execute(_sql("SELECT 1 FROM users WHERE username=%s"), (username,))
        if cur.fetchone():
            return jsonify({"ok": False, "error": "Ese username ya existe"}), 409

        cur.execute(
            _sql("""
                INSERT INTO users
                    (username, password_hash, role, created_by, approved, is_approved, is_blocked, pago_activo, fecha_vencimiento, telefono, created_at)
                VALUES (%s, %s, %s, %s, false, false, false, true, NULL, %s, CURRENT_TIMESTAMP)
            """),
            (username, generate_password_hash(password), ROLE_CAJERO, admin_id, telefono),
        )
        conn.commit()
        return jsonify({"ok": True, "message": "Cajero creado"}), 201
    finally:
        try:
            conn.close()
        except Exception:
            pass


