# =====================================================
# CONTROL COMPLETO DE USUARIOS (super_admin)
# =====================================================
@app.route("/superadmin/control-usuarios", methods=["GET"])
def superadmin_control_usuarios():
    if not session.get("u") and not session.get("user"):
        return redirect("/")
    if not is_super_admin():
        return "Forbidden", 403

    conn = db()
    if not conn:
        return "Error conectando base de datos", 500

    try:
        # Asegurar columnas nuevas (si el esquema ya existe, no pasa nada)
        try:
            if os.environ.get("DATABASE_URL"):
                conn.autocommit = True
        except Exception:
            pass
        cur_m = conn.cursor()
        for col_sql in [
            "ALTER TABLE users ADD COLUMN created_by INTEGER",
            "ALTER TABLE users ADD COLUMN is_approved BOOLEAN DEFAULT FALSE",
            "ALTER TABLE users ADD COLUMN is_blocked BOOLEAN DEFAULT FALSE",
            "ALTER TABLE users ADD COLUMN pago_activo BOOLEAN DEFAULT TRUE",
            "ALTER TABLE users ADD COLUMN fecha_vencimiento DATE",
            "ALTER TABLE users ADD COLUMN telefono TEXT",
        ]:
            try:
                cur_m.execute(col_sql)
            except Exception:
                pass
        try:
            cur_m.close()
        except Exception:
            pass

        cur = conn.cursor()
        # Mostrar solo roles relevantes
        cur.execute(
            _sql("""
                SELECT
                    id, username, role, created_by,
                    COALESCE(is_approved, CASE WHEN approved IS NULL THEN false ELSE approved END) AS is_approved,
                    COALESCE(is_blocked, false) AS is_blocked,
                    COALESCE(pago_activo, true) AS pago_activo,
                    fecha_vencimiento,
                    telefono
                FROM users
                WHERE role IN (%s, %s, %s)
                ORDER BY role, username
            """),
            (ROLE_SUPER_ADMIN, ROLE_ADMIN, ROLE_CAJERO),
        )
        users = cur.fetchall() or []
    finally:
        try:
            conn.close()
        except Exception:
            pass

    # UI tipo SaaS (sin navegación/JSON en pantalla): acciones via fetch + toast + update en vivo
    return render_template_string(IOS + """
    <a href="/admin" class="admin-btn">⬅ Volver</a>
    <div class="card" style="max-width:980px;margin:26px auto;">
      <h2 style="margin-top:0;">🧑‍💼 Control de Usuarios</h2>
      {% for msg in get_flashed_messages() %}
      <p style="background:#dcfce7;color:#166534;padding:10px;border-radius:8px;margin-bottom:12px;font-weight:700;">{{ msg }}</p>
      {% endfor %}
      <div id="toastHost"></div>
      <table width="100%" style="border-collapse:collapse;">
        <tr style="background:#002D62;color:#fff;">
          <th>ID</th>
          <th>Usuario</th>
          <th>Rol</th>
          <th>Admin dueño</th>
          <th>Aprobado</th>
          <th>Bloqueado</th>
          <th>Pago activo</th>
          <th>Vence</th>
          <th>WhatsApp</th>
          <th>Acciones</th>
        </tr>
        {% for u in users %}
        <tr data-user-id="{{ u.id }}" style="border-bottom:1px solid #eee;">
          <td style="padding:8px;">{{ u.id }}</td>
          <td style="padding:8px;">{{ u.username }}</td>
          <td style="padding:8px;">{{ u.role }}</td>
          <td style="padding:8px;">{{ u.created_by if u.created_by is not none else '-' }}</td>
          <td data-col="approved" style="padding:8px;">{% if u.is_approved %}<span style="color:#16a34a">✓</span>{% else %}<span style="color:#b45309">⏳</span>{% endif %}</td>
          <td data-col="blocked" style="padding:8px;">{% if u.is_blocked %}<span style="color:#b91c1c">Bloq</span>{% else %}<span style="color:#16a34a">OK</span>{% endif %}</td>
          <td data-col="pago" style="padding:8px;">{% if u.pago_activo %}<span style="color:#16a34a">✓</span>{% else %}<span style="color:#b45309">No</span>{% endif %}</td>
          <td data-col="vence" style="padding:8px;">{{ u.fecha_vencimiento if u.fecha_vencimiento else '-' }}</td>
          <td data-col="tel" style="padding:8px;">{{ u.telefono if u.telefono else '-' }}</td>
          <td style="padding:8px;">
            <div style="display:flex;flex-direction:column;gap:6px;">
              <button type="button" data-action="aprobar" onclick="aprobarUsuario({{ u.id }}, this)" style="padding:6px 10px;background:#16a34a;color:#fff;border:none;border-radius:8px;cursor:pointer;width:100%;">Aprobar</button>
              <button type="button" data-action="bloquear" onclick="bloquearUsuario({{ u.id }}, this)" style="padding:6px 10px;background:#dc2626;color:#fff;border:none;border-radius:8px;cursor:pointer;width:100%;">Bloquear</button>
              <button type="button" data-action="desbloquear" onclick="desbloquearUsuario({{ u.id }}, this)" style="padding:6px 10px;background:#0284c7;color:#fff;border:none;border-radius:8px;cursor:pointer;width:100%;">Desbloquear</button>
              <button type="button" data-action="desactivarPago" onclick="desactivarPago({{ u.id }}, this)" style="padding:6px 10px;background:#64748b;color:#fff;border:none;border-radius:8px;cursor:pointer;width:100%;">Desactivar pago</button>
              <a href="/superadmin/cambiar-contrasena/{{ u.id }}" style="display:block;text-align:center;padding:6px 10px;background:#7c3aed;color:#fff;border-radius:8px;cursor:pointer;width:100%;text-decoration:none;font-weight:700;">Cambiar contraseña</a>
              <div style="display:flex;gap:6px;align-items:center;">
                <input type="date" data-action="venceInput" style="flex:1;min-width:140px;padding:8px;border:1px solid #e2e8f0;border-radius:8px;" />
                <button type="button" data-action="activarPago" onclick="activarPago({{ u.id }}, this)" style="padding:8px 10px;background:#f59e0b;color:#000;border:none;border-radius:8px;cursor:pointer;white-space:nowrap;">Activar</button>
              </div>
            </div>
          </td>
        </tr>
        {% endfor %}
      </table>
    </div>

    <script>
    function mostrarToast(msg){
      const toast = document.createElement("div");
      toast.innerText = msg;
      toast.style.position = "fixed";
      toast.style.bottom = "20px";
      toast.style.right = "20px";
      toast.style.background = "#111";
      toast.style.color = "#fff";
      toast.style.padding = "12px 20px";
      toast.style.borderRadius = "10px";
      toast.style.boxShadow = "0 4px 12px rgba(0,0,0,0.3)";
      toast.style.zIndex = "9999";
      toast.style.maxWidth = "360px";
      toast.style.fontWeight = "800";
      document.body.appendChild(toast);
      setTimeout(() => toast.remove(), 2500);
    }

    function setBtnLoading(btn, loading){
      if(!btn) return;
      if(loading){
        btn.dataset._txt = btn.innerText;
        btn.innerText = "Procesando...";
        btn.disabled = true;
        btn.style.opacity = "0.75";
        btn.style.cursor = "not-allowed";
      }else{
        btn.innerText = btn.dataset._txt || btn.innerText;
        btn.disabled = false;
        btn.style.opacity = "1";
        btn.style.cursor = "pointer";
      }
    }

    function actualizarFila(id, estado, extra){
      const tr = document.querySelector(`tr[data-user-id="${id}"]`);
      if(!tr) return;
      const approved = tr.querySelector('[data-col="approved"]');
      const blocked = tr.querySelector('[data-col="blocked"]');
      const pago = tr.querySelector('[data-col="pago"]');
      const vence = tr.querySelector('[data-col="vence"]');
      if(estado === "aprobado"){
        if(approved) approved.innerHTML = '<span style="color:#16a34a">✓</span>';
        if(blocked) blocked.innerHTML = '<span style="color:#16a34a">OK</span>';
      }
      if(estado === "bloqueado"){
        if(blocked) blocked.innerHTML = '<span style="color:#b91c1c">Bloq</span>';
      }
      if(estado === "activo"){
        if(blocked) blocked.innerHTML = '<span style="color:#16a34a">OK</span>';
      }
      if(estado === "pago_off"){
        if(pago) pago.innerHTML = '<span style="color:#b45309">No</span>';
      }
      if(estado === "pago_on"){
        if(pago) pago.innerHTML = '<span style="color:#16a34a">✓</span>';
      }
      if(extra && extra.fecha_vencimiento && vence){
        vence.innerText = extra.fecha_vencimiento;
      }
    }

    async function _postJson(url, body){
      const opts = { method: "POST", credentials: "same-origin" };
      if(body && typeof body === "object"){
        opts.headers = { "Content-Type": "application/x-www-form-urlencoded;charset=UTF-8" };
        opts.body = new URLSearchParams(body).toString();
      }
      const res = await fetch(url, opts);
      const data = await res.json().catch(() => ({}));
      if(!res.ok && !data.error) data.error = "Error";
      return data;
    }

    async function aprobarUsuario(id, btn){
      setBtnLoading(btn, true);
      try{
        const data = await _postJson(`/superadmin/aprobar-usuario/${id}`);
        if(data.ok){
          mostrarToast("Usuario aprobado ✅");
          actualizarFila(id, "aprobado");
        }else{
          mostrarToast((data.error || "Error ❌"));
        }
      }finally{
        setBtnLoading(btn, false);
      }
    }

    async function bloquearUsuario(id, btn){
      setBtnLoading(btn, true);
      try{
        const data = await _postJson(`/superadmin/bloquear-usuario/${id}`);
        if(data.ok){
          mostrarToast("Usuario bloqueado 🚫");
          actualizarFila(id, "bloqueado");
        }else{
          mostrarToast((data.error || "Error ❌"));
        }
      }finally{
        setBtnLoading(btn, false);
      }
    }

    async function desbloquearUsuario(id, btn){
      setBtnLoading(btn, true);
      try{
        const data = await _postJson(`/superadmin/desbloquear-usuario/${id}`);
        if(data.ok){
          mostrarToast("Usuario desbloqueado 🔓");
          actualizarFila(id, "activo");
        }else{
          mostrarToast((data.error || "Error ❌"));
        }
      }finally{
        setBtnLoading(btn, false);
      }
    }

    async function desactivarPago(id, btn){
      setBtnLoading(btn, true);
      try{
        const data = await _postJson(`/superadmin/desactivar-pago/${id}`);
        if(data.ok){
          mostrarToast("Pago desactivado 💸");
          actualizarFila(id, "pago_off");
        }else{
          mostrarToast((data.error || "Error ❌"));
        }
      }finally{
        setBtnLoading(btn, false);
      }
    }

    async function activarPago(id, btn){
      const tr = document.querySelector(`tr[data-user-id="${id}"]`);
      const input = tr ? tr.querySelector('input[data-action="venceInput"]') : null;
      const fecha = input ? (input.value || "") : "";
      setBtnLoading(btn, true);
      try{
        const data = await _postJson(`/superadmin/activar-pago/${id}`, fecha ? { fecha_vencimiento: fecha } : {});
        if(data.ok){
          mostrarToast("Pago activado ✅");
          actualizarFila(id, "pago_on", { fecha_vencimiento: fecha || "-" });
        }else{
          mostrarToast((data.error || "Error ❌"));
        }
      }finally{
        setBtnLoading(btn, false);
      }
    }
    </script>
    """, users=users)


# =====================================================
# RESUMEN LOTERÍA / GANANCIA CAJERO (admin + API JSON)
# =====================================================
def _json_auth_resumen_loteria():
    """Misma audiencia que /admin/resumen_loteria; respuestas JSON (preview)."""
    if _current_role() not in ROLES_RESUMEN_LOTERIA_PAGE:
        return jsonify({"ok": False, "error": "No autorizado"}), 403
    username = (session.get("u") or session.get("user") or "").strip()
    if not username:
        return jsonify({"ok": False, "error": "No autorizado"}), 403
    conn = db()
    if not conn:
        return jsonify({"ok": False, "error": "Base de datos no disponible"}), 500
    try:
        cur = conn.cursor()
        cur.execute(_sql("SELECT * FROM users WHERE username=%s"), (username,))
        row = cur.fetchone()
        if row:
            ok, msg = validar_estado_usuario(dict(row))
            if not ok:
                return jsonify({"ok": False, "error": msg}), 403
    except Exception as e:
        print("_json_auth_resumen_loteria:", e)
        return jsonify({"ok": False, "error": "Error de validación"}), 403
    finally:
        try:
            conn.close()
        except Exception:
            pass
    return None


def _resolver_cajero_id_resumen(cur, body):
    """
    Admin puede enviar cajero_id (JSON) para asignar el resumen a un cajero.
    Si no se envía y el usuario es admin/super_admin → NULL.
    Otros roles (si pudieran guardar) → session uid.
    """
    raw = body.get("cajero_id")
    if raw is not None and str(raw).strip() != "":
        try:
            cid = int(raw)
        except (TypeError, ValueError):
            return None, "cajero_id inválido"
        cur.execute(_sql("SELECT id, role FROM users WHERE id = %s"), (cid,))
        row = cur.fetchone()
        if not row:
            return None, "cajero_id no encontrado"
        d = dict(row) if hasattr(row, "keys") else {}
        rl = (d.get("role") or "").strip().lower()
        if rl not in (ROLE_CAJERO, "user", ROLE_COLLECTOR, ROLE_SUPERVISOR):
            return None, "El usuario seleccionado no es cajero"
        return int(d["id"]), None
    if is_admin_or_super():
        return None, None
    uid = session.get("uid")
    if not uid:
        return None, None
    try:
        uid = int(uid)
    except (TypeError, ValueError):
        return None, None
    cur.execute(_sql("SELECT id FROM users WHERE id = %s"), (uid,))
    if not cur.fetchone():
        return None, None
    return uid, None


def _list_cajeros_para_resumen(cur):
    cur.execute(
        _sql(
            """
            SELECT id, username FROM users
            WHERE LOWER(COALESCE(role,'')) IN (%s, %s, %s, %s)
            ORDER BY username
            """
        ),
        (ROLE_CAJERO, "user", ROLE_COLLECTOR, ROLE_SUPERVISOR),
    )
    out = []
    for row in cur.fetchall() or []:
        d = dict(row) if hasattr(row, "keys") else {}
        if d.get("id") is None:
            continue
        out.append({"id": d["id"], "username": (d.get("username") or "").strip()})
    return out


def _fetch_cajeros_balance_rows(conn):
    """
    Filas para ranking/balance por cajero (fuente de verdad financiera del sistema).

    Reglas:
    - Generado = SUM(tickets.monto) del período actual (post-cierre)
    - Pagado   = SUM(pagos_premios.monto) del período actual (post-cierre)
    - Pendiente= generado - pagado - entregado_admin (entregas_cajero) del período actual (post-cierre)

    Nota: NO usa pagos_cajero/resumen_loteria (legacy) para evitar ceros/inconsistencias.
    """
    cur = conn.cursor()
    is_pg = bool(os.environ.get("DATABASE_URL"))
    try:
        _sync_balances_cajeros(cur, is_pg)
        conn.commit()
    except Exception as e:
        log.warning("_fetch_cajeros_balance_rows sync: %s", e, exc_info=True)
        try:
            conn.rollback()
        except Exception:
            pass

    # 1) Lista de cajeros activos (identificador = username; coincide con tickets.cajero y entregas_cajero.cajero)
    try:
        if is_pg:
            cur.execute(
                _sql(
                    """
                    SELECT id, username
                    FROM users
                    WHERE LOWER(COALESCE(role,'')) IN (%s, %s)
                      AND (COALESCE(activo, true) IS TRUE)
                    ORDER BY username
                    """
                ),
                (ROLE_CAJERO, "user"),
            )
        else:
            cur.execute(
                _sql(
                    """
                    SELECT id, username
                    FROM users
                    WHERE LOWER(COALESCE(role,'')) IN (%s, %s)
                      AND (COALESCE(activo, 1) = 1)
                    ORDER BY username
                    """
                ),
                (ROLE_CAJERO, "user"),
            )
    except Exception:
        # fallback mínimo (si columna activo no existe)
        cur.execute(
            _sql(
                """
                SELECT id, username
                FROM users
                WHERE LOWER(COALESCE(role,'')) IN (%s, %s)
                ORDER BY username
                """
            ),
            (ROLE_CAJERO, "user"),
        )

    user_rows = cur.fetchall() or []
    rows = []
    for r in user_rows:
        d = dict(r) if hasattr(r, "keys") else {"id": r[0], "username": r[1]}
        uid = d.get("id")
        uname = (d.get("username") or "").strip()
        if uid is None or not uname:
            continue
        try:
            ultimo_rank = obtener_fecha_ultimo_cierre(cur)
            v, p, ent, bal = _compute_totales_periodo_cierre(
                cur, is_pg, ultimo_rank, cajero_username=uname
            )
            ventas = float(v or 0)
            premios = float(p or 0)
            entregado = float(ent or 0)
            balance = float(bal or (ventas - premios - entregado))
        except Exception:
            ventas = premios = entregado = balance = 0.0
        rows.append(
            {
                "id": int(uid),
                "nombre": uname,
                "total_generado": float(round(ventas, 2)),
                "total_pagado": float(round(premios, 2)),
                "pendiente": float(round(balance, 2)),
                "balance": float(round(balance, 2)),
                "estado": "DEUDA" if float(balance or 0) < -0.005 else "OK",
            }
        )

    # Orden del ranking: por Generado DESC (como indica la UI)
    rows.sort(key=lambda x: (float(x.get("total_generado") or 0), x.get("nombre") or ""), reverse=True)
    for i, rr in enumerate(rows, start=1):
        rr["ranking"] = i
    return rows


@app.route("/resumen_loteria_preview", methods=["POST"])
def resumen_loteria_preview():
    """Preview JSON: totales del período actual (misma fuente que /reporte) + %% cajero. No guarda nada."""
    deny = _json_auth_resumen_loteria()
    if deny:
        return deny
    body = request.get_json(silent=True)
    if not body or not isinstance(body, dict):
        return jsonify({"ok": False, "error": "JSON requerido"}), 400

    fecha_s = _fecha_consulta_cliente_acotada(body.get("fecha"), default_hoy=True)

    raw_pct = body.get("porcentaje_cajero")
    if raw_pct is None or (isinstance(raw_pct, str) and str(raw_pct).strip() == ""):
        return jsonify({"ok": False, "error": "porcentaje_cajero requerido"}), 400
    try:
        pct = float(raw_pct)
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "porcentaje_cajero inválido"}), 400
    if not (0 <= pct <= 100) or pct != pct:
        return jsonify({"ok": False, "error": "porcentaje_cajero debe estar entre 0 y 100"}), 400

    cid, cid_ok = _cajero_id_para_totales_resumen(body)
    if not cid_ok:
        return jsonify({"ok": False, "error": "No autorizado"}), 403
    r = calcular_resumen_automatico(fecha_s, pct, cajero_id=cid)
    if r is None:
        return jsonify({"ok": False, "error": "Base de datos no disponible"}), 500
    return jsonify({"ok": True, **r})


