@app.route("/resumen_loteria", methods=["POST"])
def resumen_loteria_api():
    """API JSON: totales período actual (_compute_totales_periodo_cierre), guarda en `resumen_loteria` (fecha = hasta). Solo admin/super_admin."""
    if not is_admin_or_super():
        return jsonify({"ok": False, "error": "No autorizado"}), 403
    body = request.get_json(silent=True)
    if not body or not isinstance(body, dict):
        return jsonify({"ok": False, "error": "JSON requerido"}), 400

    desde = _fecha_consulta_cliente_acotada(
        body.get("desde") or body.get("fecha_desde"), default_hoy=False
    )
    hasta = _fecha_consulta_cliente_acotada(
        body.get("hasta") or body.get("fecha_hasta"), default_hoy=False
    )
    if not desde or not hasta:
        return jsonify({"ok": False, "error": "desde y hasta son requeridos (YYYY-MM-DD)"}), 400

    raw_pct = body.get("porcentaje_cajero")
    if raw_pct is None or (isinstance(raw_pct, str) and str(raw_pct).strip() == ""):
        return jsonify({"ok": False, "error": "Falta porcentaje_cajero"}), 400
    try:
        pct = float(raw_pct)
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "porcentaje_cajero inválido"}), 400
    if not (0 <= pct <= 100) or pct != pct:
        return jsonify({"ok": False, "error": "porcentaje_cajero debe estar entre 0 y 100"}), 400

    cid = _cajero_id_opcional_body(body)
    try:
        r = calcular_resumen_rango_fechas(desde, hasta, pct, cajero_id=cid)
    except ValueError as e:
        return jsonify({"ok": False, "error": str(e)}), 400
    if r is None:
        return jsonify({"ok": False, "error": "Base de datos no disponible"}), 500
    conn = db()
    if not conn:
        return jsonify({"ok": False, "error": "Base de datos no disponible"}), 500
    new_id = None
    cajero_id_res = None
    cajero_nombre_flash = None
    try:
        cur = conn.cursor()
        cajero_id_res, cajero_err = _resolver_cajero_id_resumen(cur, body)
        if cajero_err:
            try:
                conn.close()
            except Exception:
                pass
            return jsonify({"ok": False, "error": cajero_err}), 400
        if cajero_id_res is None:
            try:
                conn.close()
            except Exception:
                pass
            return jsonify(
                {
                    "ok": False,
                    "error": "Debe seleccionar un cajero para guardar el resumen.",
                }
            ), 400
        cur.execute(
            _sql(
                """
                SELECT id FROM resumen_loteria
                WHERE cajero_id = %s AND fecha_desde = %s AND fecha_hasta = %s
                LIMIT 1
                """
            ),
            (cajero_id_res, desde, hasta),
        )
        if cur.fetchone():
            try:
                conn.close()
            except Exception:
                pass
            return jsonify(
                {
                    "ok": False,
                    "error": "Ya existe un resumen para este cajero en el mismo período (desde/hasta).",
                }
            ), 400
        fecha_guardar = hasta
        vals = (
            fecha_guardar,
            desde,
            hasta,
            r["venta_bruta"],
            r["comision"],
            r["venta_neta"],
            r["total_ganadores"],
            r["resultado"],
            r["porcentaje_cajero"],
            r["ganancia_cajero"],
            r["ganancia_banca"],
            r["total_pagados"],
            r["estado"],
            cajero_id_res,
        )
        if os.environ.get("DATABASE_URL"):
            cur.execute(
                """
                INSERT INTO resumen_loteria (
                    fecha, fecha_desde, fecha_hasta, venta_bruta, comision, venta_neta, total_ganadores, resultado,
                    porcentaje_cajero, ganancia_cajero, ganancia_banca, total_pagados, estado, cajero_id
                )
                VALUES (%s::date, %s::date, %s::date, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
                RETURNING id
                """,
                vals,
            )
            row = cur.fetchone()
            new_id = row["id"] if hasattr(row, "keys") else (row[0] if row else None)
        else:
            cur.execute(
                """
                INSERT INTO resumen_loteria (
                    fecha, fecha_desde, fecha_hasta, venta_bruta, comision, venta_neta, total_ganadores, resultado,
                    porcentaje_cajero, ganancia_cajero, ganancia_banca, total_pagados, estado, cajero_id
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                vals,
            )
            cur.execute("SELECT last_insert_rowid()")
            new_id = (cur.fetchone() or [None])[0]
        if new_id is not None:
            _gc = float(r["ganancia_cajero"])
            _pc_vals = (
                new_id,
                desde,
                hasta,
                _gc,
                _gc,
                float(r["porcentaje_cajero"]),
                "PENDIENTE",
                cajero_id_res,
            )
            if os.environ.get("DATABASE_URL"):
                cur.execute(
                    """
                    INSERT INTO pagos_cajero (
                        resumen_id, fecha_desde, fecha_hasta, monto_pagado, saldo_pendiente, porcentaje_cajero, estado, cajero_id
                    ) VALUES (%s, %s, %s, %s, %s, %s, %s, %s)
                    """,
                    _pc_vals,
                )
            else:
                cur.execute(
                    """
                    INSERT INTO pagos_cajero (
                        resumen_id, fecha_desde, fecha_hasta, monto_pagado, saldo_pendiente, porcentaje_cajero, estado, cajero_id
                    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                    """,
                    _pc_vals,
                )
        _integrar_resumen_loteria_extras(cur, r, fecha_guardar, cajero_id_res)
        try:
            cur.execute(
                _sql("SELECT username FROM users WHERE id = %s LIMIT 1"),
                (cajero_id_res,),
            )
            ur = cur.fetchone()
            if ur:
                cajero_nombre_flash = (
                    (ur.get("username") if hasattr(ur, "keys") else None)
                    or (ur[0] if ur else None)
                    or ""
                ).strip() or None
        except Exception:
            cajero_nombre_flash = None
        conn.commit()
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        print("resumen_loteria INSERT:", e)
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        try:
            conn.close()
        except Exception:
            pass

    if cajero_nombre_flash and new_id is not None:
        flash(
            "Resumen guardado para %s (ID %s)." % (cajero_nombre_flash, new_id),
            "success",
        )
    elif cajero_nombre_flash:
        flash("Resumen guardado para %s." % cajero_nombre_flash, "success")
    elif new_id is not None:
        flash("Resumen guardado correctamente (ID %s)." % new_id, "success")
    else:
        flash("Resumen guardado correctamente.", "success")

    out = {
        **r,
        "fecha": fecha_guardar,
        "fecha_desde": desde,
        "fecha_hasta": hasta,
        "desde": desde,
        "hasta": hasta,
        "id": new_id,
        "cajero_id": cajero_id_res,
    }
    return jsonify(
        {
            "ok": True,
            "desde": desde,
            "hasta": hasta,
            "venta_bruta": r["venta_bruta"],
            "total_pagados": r["total_pagados"],
            "resultado": r["resultado"],
            "ganancia_cajero": r["ganancia_cajero"],
            "estado": r["estado"],
            "cajero_id": cajero_id_res,
            "resumen": out,
        }
    )


