@app.route("/api/admin/dashboard_kpis", methods=["GET"])
def api_admin_dashboard_kpis():
    if not is_admin_or_super():
        return jsonify({"ok": False, "error": "no autorizado"}), 403
    t0 = time.perf_counter()
    hoy_rd = ahora_rd().strftime("%Y-%m-%d")
    session_role_ad = (session.get("role") or "").strip().lower()
    session_uid_ad = int(session.get("uid") or 0)
    is_pg_ad = bool(os.environ.get("DATABASE_URL"))
    conn = db()
    if not conn:
        return jsonify({"ok": False, "error": "sin base de datos"}), 500
    _rollback_pg_connection(conn)
    cur = conn.cursor()
    try:
        ultimo_ad = obtener_fecha_ultimo_cierre(cur)
        snap = get_dashboard_snapshot(
            conn, cur, hoy_rd, is_pg_ad, ultimo_ad, session_role_ad, session_uid_ad
        )
        try:
            conn.commit()
        except Exception:
            pass
        kp = dict((snap.get("kpis") or {}) if snap.get("ok") else {})
        kp = _admin_kpi_unificar_ventas_hoy_display(
            kp, cur, is_pg_ad, ultimo_ad,
            int(kp.get("banca_scope_bc") or (0 if session_role_ad == ROLE_SUPER_ADMIN else session_uid_ad)),
        )
        try:
            _pdash = _ganadores_pendientes_dashboard_resumen(conn, cur, hoy_rd)
            kp["pendiente_hoy"] = float(_pdash.get("pendiente_hoy") or 0)
            kp["pendiente_total"] = float(_pdash.get("pendiente_total") or 0)
        except Exception as _pf:
            log.warning("api_admin_dashboard_kpis merge pendientes: %s", _pf, exc_info=True)
        out = {
            "ok": True,
            "kpis": kp,
            "from_cache": bool(snap.get("from_cache")),
            "from_warm_snapshot": bool(snap.get("from_warm_snapshot")),
        }
        log.info(
            "PERF ruta=/api/admin/dashboard_kpis ms=%s cached=%s",
            round((time.perf_counter() - t0) * 1000, 2),
            1 if snap.get("from_cache") else 0,
        )
        return jsonify(out), 200
    except Exception as e:
        log.warning("api_admin_dashboard_kpis: %s", e, exc_info=True)
        try:
            conn.rollback()
        except Exception:
            pass
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        try:
            conn.close()
        except Exception:
            pass


@app.route("/api/admin/resumen", methods=["GET"])
def api_admin_resumen():
    """
    Balance del ciclo (post-cierre) + ventas del día RD, sin quincenas ni cómputo de ganadores.
    Complementa GET /api/admin/dashboard_kpis (bundle completo con TTL).
    """
    if not is_admin_or_super():
        return jsonify({"ok": False, "error": "no autorizado"}), 403
    t0 = time.perf_counter()
    hoy_rd = ahora_rd().strftime("%Y-%m-%d")
    session_role_ad = (session.get("role") or "").strip().lower()
    session_uid_ad = int(session.get("uid") or 0)
    banca_scope_bc = 0 if session_role_ad == ROLE_SUPER_ADMIN else session_uid_ad
    conn = db()
    if not conn:
        return jsonify({"ok": False, "error": "sin base de datos"}), 500
    _rollback_pg_connection(conn)
    cur = conn.cursor()
    is_pg = bool(os.environ.get("DATABASE_URL"))
    try:
        ultimo = obtener_fecha_ultimo_cierre(cur)
        bc = _balance_contable_con_ajustes(cur, is_pg, ultimo, banca_scope_bc)
        vdi = _compute_ventas_dia_para_banca(cur, banca_scope_bc)
        try:
            conn.commit()
        except Exception:
            pass
        log.info(
            "PERF ruta=/api/admin/resumen ms=%s",
            round((time.perf_counter() - t0) * 1000, 2),
        )
        return (
            jsonify(
                {
                    "ok": True,
                    "hoy": hoy_rd,
                    "ultimo_cierre": ultimo,
                    "ciclo": {
                        "ventas": float(bc.get("ventas") or 0),
                        "premios": float(bc.get("premios") or 0),
                        "entregado": float(bc.get("entregado") or 0),
                        "balance_real": float(bc.get("balance_real") or 0),
                        "sum_ajustes": float(bc.get("sum_ajustes") or 0),
                        "balance_final": float(bc.get("balance_final") or 0),
                    },
                    "ventas_dia": dict(vdi or {}),
                }
            ),
            200,
        )
    except Exception as e:
        log.exception("api_admin_resumen: %s", e)
        try:
            conn.rollback()
        except Exception:
            pass
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        try:
            conn.close()
        except Exception:
            pass


