@app.route("/admin/banco_cajeros/recibo_entrega_58mm")
def recibo_entrega_58mm():
    """Recibo 58mm para entrega de caja (térmica). Auto-print cuando autoprint=1."""
    if not is_admin_or_super():
        return redirect("/")
    cajero = (request.args.get("cajero") or "").strip()
    vs = request.args.get("ventas")
    ps = request.args.get("premios")
    try:
        ventas = float(vs) if vs not in (None, "") else None
    except (ValueError, TypeError):
        ventas = None
    try:
        premios = float(ps) if ps not in (None, "") else None
    except (ValueError, TypeError):
        premios = None
    try:
        monto = float(request.args.get("monto") or 0)
    except (ValueError, TypeError):
        monto = 0
    admin = (request.args.get("admin") or "").strip() or "—"
    fecha_raw = request.args.get("fecha") or ""
    if fecha_raw and hasattr(fecha_raw, "strftime"):
        fecha = fecha_raw.strftime("%Y-%m-%d %H:%M")
    else:
        fd = _parse_fecha_iso_cliente_o_none(fecha_raw)
        if fd:
            fecha = fd.strftime("%Y-%m-%d") + " " + ahora_rd().strftime("%H:%M")
        else:
            fecha = ahora_rd().strftime("%Y-%m-%d %H:%M")
    ventas = "{:,.2f}".format(ventas) if ventas is not None else "0.00"
    premios = "{:,.2f}".format(premios) if premios is not None else "0.00"
    ganancia = "{:,.2f}".format(monto) if monto is not None else "0.00"
    return render_template_string(
        RECIBO_ENTREGA_58MM_HTML,
        cajero=cajero,
        fecha=fecha,
        ventas=ventas,
        premios=premios,
        ganancia=ganancia,
        admin=admin,
    )


@app.route("/admin/banco_cajeros/historial/<path:cajero_enc>")
def historial_entregas_cajero(cajero_enc):
    """Historial de entregas de un cajero."""
    if not is_admin_or_super():
        return redirect("/")
    from urllib.parse import unquote
    cajero = unquote(cajero_enc)
    conn = db()
    if not conn:
        return "Error conectando base de datos", 500
    entregas = []
    try:
        cur = conn.cursor()
        cur.execute(_sql("""
            SELECT id, cajero, monto, fecha, COALESCE(admin, '') AS admin
            FROM entregas_cajero
            WHERE cajero = %s
            ORDER BY fecha DESC
            LIMIT 100
        """), (cajero,))
        for r in cur.fetchall():
            d = dict(r) if hasattr(r, "keys") else r
            if hasattr(d, "get"):
                f = d.get("fecha") or ""
                monto = float(d.get("monto") or 0)
                admin = d.get("admin") or "—"
            else:
                f = d[3] if len(d) > 3 else ""
                monto = float(d[2] if len(d) > 2 else 0)
                admin = d[4] if len(d) > 4 else "—"
            if hasattr(f, "strftime"):
                f = f.strftime("%Y-%m-%d %H:%M") if f else ""
            entregas.append({"monto": monto, "fecha": str(f) if f else "", "admin": admin})
    finally:
        conn.close()
    return render_template_string(IOS + ADMIN_MENU + """
<div class="card" style="max-width:600px;margin:20px auto">
    <h2>📋 Historial de entregas: {{ cajero }}</h2>
    <table width="100%%" style="border-collapse:collapse">
        <tr style="background:#002D62;color:white">
            <th style="padding:10px;text-align:left">Fecha</th>
            <th style="padding:10px;text-align:right">Monto</th>
            <th style="padding:10px;text-align:left">Admin</th>
            <th style="padding:10px">Acciones</th>
        </tr>
        {% for e in entregas %}
        <tr style="border-bottom:1px solid #e2e8f0">
            <td style="padding:10px">{{ e.fecha }}</td>
            <td style="padding:10px;text-align:right">RD$ {{ "{:,.2f}".format(e.monto) }}</td>
            <td style="padding:10px">{{ e.admin }}</td>
            <td style="padding:10px"><a href="{{ url_for('recibo_entrega_58mm', cajero=cajero, monto=e.monto, fecha=e.fecha, admin=e.admin) }}" style="color:#002D62;font-size:13px">🖨 Imprimir recibo</a></td>
        </tr>
        {% endfor %}
    </table>
    {% if not entregas %}
    <p style="color:#666">No hay entregas registradas.</p>
    {% endif %}
    <br>
    <a href="/admin/banco_cajeros" style="color:#002D62;font-weight:bold">← Volver a Banco Cajeros</a>
</div>
""", cajero=cajero, entregas=entregas)


@app.route("/numeros_populares")
def numeros_populares():
    if not is_admin_or_super():
        return redirect("/venta")
    c = db()
    if not c:
        return "Error conectando base de datos", 500
    try:
        cur = c.cursor()
        if os.environ.get("DATABASE_URL"):
            cur.execute("""
                SELECT
                    tl.number AS number,
                    COUNT(*) AS veces,
                    COALESCE(SUM(tl.amount),0) AS total
                FROM ticket_lines tl
                JOIN tickets t ON t.id = tl.ticket_id
                WHERE COALESCE(tl.estado,'activo') != 'cancelado'
                  AND t.created_at >= (CURRENT_TIMESTAMP AT TIME ZONE 'America/Santo_Domingo') - (%s::int * INTERVAL '1 day')
                GROUP BY tl.number
                ORDER BY veces DESC
                LIMIT 20
            """, (NUMEROS_POPULARES_DIAS,))
        else:
            cur.execute(_sql("""
                SELECT
                    tl.number AS number,
                    COUNT(*) AS veces,
                    COALESCE(SUM(tl.amount),0) AS total
                FROM ticket_lines tl
                JOIN tickets t ON t.id = tl.ticket_id
                WHERE COALESCE(tl.estado,'activo') != 'cancelado'
                  AND datetime(substr(trim(cast(t.created_at as text)), 1, 19)) >= datetime('now', '-' || %s || ' days')
                GROUP BY tl.number
                ORDER BY veces DESC
                LIMIT 20
            """), (NUMEROS_POPULARES_DIAS,))
        rows = cur.fetchall()
        rows = [dict(r) for r in rows] if rows else []
    finally:
        c.close()
    html = IOS + """
    <div style="max-width:600px;margin:80px auto;padding:20px">
    <h2>N&uacute;meros m&aacute;s jugados (Top 20)</h2>
    <p style="color:#64748b;font-size:13px">Calculado sobre los &uacute;ltimos {{ dias }} d&iacute;as para mantener la consulta r&aacute;pida.</p>
    <table style="width:100%;border-collapse:collapse;margin-top:16px">
    <tr style="background:#002D62;color:white"><th style="padding:10px;text-align:left">N&uacute;mero</th><th style="padding:10px;text-align:center">Veces</th><th style="padding:10px;text-align:right">Total RD$</th></tr>
    {% for r in rows %}
    <tr><td style="padding:10px;border:1px solid #e2e8f0">{{ r.number }}</td><td style="padding:10px;border:1px solid #e2e8f0;text-align:center">{{ r.veces }}</td><td style="padding:10px;border:1px solid #e2e8f0;text-align:right">{{ "%.2f"|format(r.total|float) }}</td></tr>
    {% endfor %}
    </table>
    <p style="margin-top:20px"><a href="/admin" style="color:#002D62;font-weight:bold">← Volver al panel</a></p>
    </div>
    """
    return render_template_string(html, rows=rows, dias=NUMEROS_POPULARES_DIAS)


def _ventas_cajeros_cerrados_rows():
    c = db()
    if not c:
        raise RuntimeError("Error conectando base de datos")
    try:
        cur = c.cursor()
        cur.execute(
            _sql(
                """
                SELECT
                    COALESCE(NULLIF(TRIM(cajero), ''), 'Sin cajero') AS cajero,
                    COALESCE(SUM(COALESCE(monto, 0)), 0) AS total
                FROM tickets
                WHERE operativo_estado = %s
                GROUP BY COALESCE(NULLIF(TRIM(cajero), ''), 'Sin cajero')
                ORDER BY total DESC
                """
            ),
            ("cerrado",),
        )
        rows = []
        for r in cur.fetchall() or []:
            d = dict(r) if hasattr(r, "keys") else {"cajero": r[0], "total": r[1]}
            rows.append(
                {
                    "cajero": d.get("cajero") or "Sin cajero",
                    "total": float(d.get("total") or 0),
                }
            )
        return rows
    finally:
        c.close()


@app.route("/reporte/cajeros")
def reporte_cajeros():
    if not is_admin_or_super():
        return redirect("/venta")
    try:
        cajeros = _ventas_cajeros_cerrados_rows()
    except Exception:
        log.exception("reporte_cajeros")
