# RESET SISTEMA (BORRAR TODO)
# ===============================
@app.route("/reset_sistema", methods=["POST"])
def reset_sistema():
    if not is_admin_or_super():
        return redirect("/")

    clave = (request.form.get("clave_reset") or "").strip()
    if clave != PANEL_JUGADAS_CLAVE:
        return "❌ Clave incorrecta", 403

    conn = db()
    if not conn:
        return "Error de conexión", 500

    cur = conn.cursor()
    err_reset = None
    try:
        # Orden: líneas y pagos antes que tickets
        cur.execute("DELETE FROM ticket_lines")
        cur.execute("DELETE FROM pagos")
        cur.execute("DELETE FROM pagos_premios")
        cur.execute("DELETE FROM tickets")
        cur.execute("DELETE FROM cierres_caja")
        cur.execute("DELETE FROM cash_closings")

        if os.environ.get("DATABASE_URL"):
            for seq in (
                "ticket_lines_id_seq",
                "tickets_id_seq",
                "pagos_id_seq",
                "pagos_premios_id_seq",
                "cierres_caja_id_seq",
                "cash_closings_id_seq",
            ):
                try:
                    cur.execute("ALTER SEQUENCE %s RESTART WITH 1" % seq)
                except Exception as seq_e:
                    print("RESET seq %s:" % seq, seq_e)
        else:
            for tbl in (
                "ticket_lines",
                "tickets",
                "pagos",
                "pagos_premios",
                "cierres_caja",
                "cash_closings",
            ):
                try:
                    cur.execute(_sql("DELETE FROM sqlite_sequence WHERE name=%s"), (tbl,))
                except Exception as sq_e:
                    print("RESET sqlite_sequence %s:" % tbl, sq_e)

        conn.commit()
    except Exception as e:
        print("ERROR RESET:", e)
        try:
            conn.rollback()
        except Exception:
            pass
        err_reset = e
    finally:
        try:
            cur.close()
        except Exception:
            pass
        try:
            conn.close()
        except Exception:
            pass

    if err_reset is not None:
        return "Error al resetear", 500
    return "✅ Sistema reiniciado correctamente"


