def _normalizar_sale_key(raw):
    key = re.sub(r"[^A-Za-z0-9_.:-]", "", str(raw or "").strip())
    return key[:120]


def _generar_sale_key():
    return secrets.token_urlsafe(24)


def _fingerprint_venta(cajero_id, cajero, jugadas):
    payload = {
        "cajero_id": cajero_id,
        "cajero": cajero,
        "jugadas": jugadas,
    }
    raw = json.dumps(payload, sort_keys=True, separators=(",", ":"), ensure_ascii=True)
    return "fp:" + hashlib.sha256(raw.encode("utf-8")).hexdigest()


def _reservar_sale_key(cur, sale_key, cajero_id):
    """Reserva una venta. Si ya existe, retorna (False, ticket_id_existente)."""
    key = _normalizar_sale_key(sale_key)
    if not key:
        return True, None
    if os.environ.get("DATABASE_URL"):
        cur.execute(
            """
            INSERT INTO sale_idempotency (sale_key, cajero_id)
            VALUES (%s, %s)
            ON CONFLICT (sale_key) DO NOTHING
            RETURNING id
            """,
            (key, cajero_id),
        )
        row = cur.fetchone()
        if row:
            return True, None
        cur.execute("SELECT ticket_id FROM sale_idempotency WHERE sale_key = %s", (key,))
    else:
        cur.execute(
            "INSERT OR IGNORE INTO sale_idempotency (sale_key, cajero_id) VALUES (?, ?)",
            (key, cajero_id),
        )
        if getattr(cur, "rowcount", 0):
            return True, None
        cur.execute("SELECT ticket_id FROM sale_idempotency WHERE sale_key = ?", (key,))
    row = cur.fetchone()
    ticket_id = (dict(row).get("ticket_id") if hasattr(row, "keys") else (row[0] if row else None))
    return False, ticket_id


def _marcar_sale_key_ticket(cur, sale_key, ticket_id):
    key = _normalizar_sale_key(sale_key)
    if not key or not ticket_id:
        return
        cur.execute(_sql("UPDATE sale_idempotency SET ticket_id = %s WHERE sale_key = %s"), (int(ticket_id), key))


def _log_venta_cajero_ctx(error=None, traceback_txt=None, exc_info=False):
    """Log diagnóstico [VENTA CAJERO] para errores en /venta."""
    role = _current_role()
    if not is_cajero_staff() and role != ROLE_CAJERO:
        return
    banca_id = None
    try:
        uid = session.get("uid")
        if uid:
            c = db()
            if c:
                cur = c.cursor()
                banca_id = _banca_id_para_usuario_actual(cur, uid)
                _db_close(c, cur)
    except Exception:
        pass
    tb = traceback_txt or (traceback.format_exc() if exc_info else "")
    log.error(
        "[VENTA CAJERO] usuario=%s role=%s cajero_id=%s banca_id=%s ruta=/venta error=%s traceback=%s",
        session.get("u") or session.get("user"),
        role,
        session.get("uid"),
        banca_id,
        error,
        tb,
        exc_info=exc_info and not traceback_txt,
    )


