def turno_loteria(draw):

    if not draw:
        return ""

    parsed = _parse_draw_time(draw)
    if not parsed:
        return ""
    hora, _mi = parsed

    if hora < 12:
        return "Día"
    elif hora < 18:
        return "Tarde"
    else:
        return "Noche"


def center(text, width=32):
    return str(text or "").center(width)


def left(text, width=32):
    return str(text or "").ljust(width)


def separator(width=32):
    return "-" * width


def _ticket_line(text, width=32):
    return str(text or "")[:width]


def _ticket_center(text, width=32):
    return _ticket_line(text, width).center(width)


def _ticket_money(value):
    try:
        return "{:.2f}".format(float(value or 0))
    except (TypeError, ValueError):
        return "0.00"


def _ticket_numero(jugada):
    return str(jugada.get("numeros") or jugada.get("numero") or "").strip()


def _ticket_numero_sort_key(numero):
    partes = re.split(r"[-\s]+", str(numero or "").strip())
    nums = []
    for parte in partes:
        try:
            nums.append((0, int(parte)))
        except ValueError:
            nums.append((1, parte))
    return tuple(nums)


