@app.route("/ticket/<int:id>")
def ticket_detail(id):

    conn = db()
    if not conn:
        return "Error conectando base de datos", 500

    try:
        cur = conn.cursor()

        # Monto y detalle viven en `tickets` (sin ticket_lines en este flujo).
        _ticket_queries = (
            """
            SELECT id, cajero, created_at, monto, lottery, numero, tipo_jugada, draw, ticket_group
            FROM tickets WHERE id = %s
            """,
            """
            SELECT id, cajero, created_at, monto, lottery, numero, draw, ticket_group
            FROM tickets WHERE id = %s
            """,
            """
            SELECT id, cajero, created_at, monto, lottery, numero, draw
            FROM tickets WHERE id = %s
            """,
        )
        ticket = None
        for _q in _ticket_queries:
            try:
                cur.execute(_sql(_q), (id,))
                ticket = cur.fetchone()
                break
            except Exception:
                try:
                    conn.rollback()
                except Exception:
                    pass

        if not ticket:
            return "Ticket no encontrado", 404

        ticket = dict(ticket)
        if "tipo_jugada" not in ticket:
            ticket["tipo_jugada"] = None
        if "ticket_group" not in ticket:
            ticket["ticket_group"] = None

        if session.get("role") == "cajero" and (ticket.get("cajero") or "") != (session.get("u") or ""):
            return "No autorizado para ver este ticket", 403

        total = float(ticket.get("monto") or 0)

        cur.execute(
            _sql(
                """
                SELECT lottery, draw, lottery2, number, play, amount
                FROM ticket_lines
                WHERE ticket_id = %s
                AND COALESCE(estado, 'activo') = 'activo'
                ORDER BY id ASC
                """
            ),
            (id,),
        )
        lines = cur.fetchall()
        jugadas = []
        for l in lines:
            if hasattr(l, "keys"):
                d = dict(l)
            else:
                d = {
                    "lottery": l[0] if len(l) > 0 else "",
                    "draw": l[1] if len(l) > 1 else "",
                    "lottery2": l[2] if len(l) > 2 else "",
                    "number": l[3] if len(l) > 3 else "",
                    "play": l[4] if len(l) > 4 else "",
                    "amount": l[5] if len(l) > 5 else 0,
                }
            jugadas.append(
                {
                    "loteria": normalizar_nombre_loteria(d.get("lottery") or ""),
                    "loteria2": normalizar_nombre_loteria(d.get("lottery2") or ""),
                    "draw": d.get("draw") or "",
                    "numero": str(d.get("number") or ""),
                    "tipo": d.get("play") or "",
                    "monto": float(d.get("amount") or 0),
                }
            )

        created = ticket.get("created_at")
        if created is None:
            hora_rd = ""
            hora_venta = ""
            fecha_display = ""
        else:
            try:
                if isinstance(created, datetime):
                    dt_rd = created
                else:
                    cs = str(created).strip()
                    dt_rd = datetime.fromisoformat(cs.replace("Z", "+00:00"))
                if dt_rd.tzinfo is None:
                    dt_rd = dt_rd.replace(tzinfo=TZ_RD)
                else:
                    dt_rd = dt_rd.astimezone(TZ_RD)
                fecha_display = dt_rd.strftime("%Y-%m-%d")
                hora_venta = dt_rd.strftime("%H:%M:%S")
                hora_rd = dt_rd.strftime("%I:%M %p")
            except Exception:
                cs = str(created)
                fecha_display = cs[:10] if len(cs) >= 10 else ""
                hora_venta = cs[11:19] if len(cs) >= 19 else (cs[11:16] if len(cs) >= 16 else "")
                hora_rd = cs[11:16] if len(cs) >= 16 else ""

        tg = ticket.get("ticket_group")
        ticket_public_id = tg if tg is not None else ticket.get("id", "")
        ticket_data = {
            "fecha": fecha_display,
            "hora": hora_rd,
            "hora_venta": hora_venta,
            "ticket": ticket_public_id,
            "id": ticket.get("id", ""),
            "cajero": ticket.get("cajero", ""),
            "jugadas": [
                {
                    "loteria": j.get("loteria") or "",
                    "loteria2": j.get("loteria2") or "",
                    "hora": j.get("draw") or "",
                    "tipo": j.get("tipo") or "Quiniela",
                    "numero": j.get("numero") or "",
                    "monto": "{:.2f}".format(float(j.get("monto") or 0)),
                }
                for j in jugadas
            ],
            "total": "{:.2f}".format(float(total or 0)),
        }
        ticket_text = generar_ticket(ticket_data)
        ticket_html = render_ticket_html(ticket_data)
        escpos_b64 = ticket_escpos_b64(ticket_data)

    except Exception as _ticket_err:
        log.exception("ticket_detail id=%s: %s", id, _ticket_err)
        return "Error al generar el ticket.", 500
    finally:
        conn.close()

    html = r"""
<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1, maximum-scale=1, viewport-fit=cover">
<link rel="stylesheet" href="/static/ticket_thermal.css">
<style>{{ ticket_thermal_css }}</style>
<script src="/static/print_ticket_app.js"></script>
</head>
<body class="ticket-body">

<div class="ticket-container">
<button type="button" id="printBtn" class="no-print btn-print-top" onclick="imprimir()">IMPRIMIR</button>
<div class="ticket-scroll">
<div class="ticket ticket-thermal" data-escpos-b64="{{ ticket_escpos_b64 }}" data-ticket-id="{{ ticket_data.id }}">
{{ ticket_html|safe }}
<pre id="reciboTextoPlano" data-print-text>{{ ticket_text }}</pre>
</div>
</div>
</div>

<script>
window.generarTicket = function () {
  return {{ ticket_text|tojson }};
};
</script>

</body>
</html>
"""

    return render_template_string(
        html,
        ticket=ticket,
        jugadas=jugadas,
        total=total,
        hora_rd=hora_rd,
        fecha_display=fecha_display,
        ticket_public_id=ticket_public_id,
        ticket_text=ticket_text,
        ticket_html=ticket_html,
        ticket_escpos_b64=escpos_b64,
        ticket_data=ticket_data,
        ticket_thermal_css=TICKET_THERMAL_CSS,
    )
# =====================================================
# REPORTE DIARIO + CONTROL DE CAJA POR CAJERO
# =====================================================
def _reporte_fetch_sum_dict(cur, rows, key_col, val_col):
    out = {}
    for r in rows or []:
        if hasattr(r, "keys"):
            d = dict(r)
            k = (d.get(key_col) or "").strip() if d.get(key_col) is not None else ""
        else:
            continue
        try:
            v = float(d.get(val_col) or 0)
        except (TypeError, ValueError):
            v = 0.0
        out[k] = float(out.get(k, 0) or 0) + v
    return out

def _legacy_ganancia_perdida_vista_requested():
    """Permite conservar `/reporte/ganancias/*` basado en cierres cuando `legacy=1` (o true/si)."""
    v = (request.args.get("legacy") or "").strip().lower()
    return v in ("1", "true", "yes", "si", "sí")


@app.route("/reporte/ganancias/mensual")
def reporte_ganancias_mensual():
    if not is_admin_or_super():
        flash("No autorizado.", "error")
        return redirect("/reporte")
    if (request.args.get("format") or "").lower().strip() == "json":
        conn = db()
        if not conn:
            return jsonify({"ok": False, "error": "db"}), 500
        is_pg = bool(os.environ.get("DATABASE_URL"))
        try:
            cur = conn.cursor()
            filas, totales = _ganancias_perdidas_desde_cierres_caja(cur, is_pg, anual=False)
            return jsonify({"ok": True, "vista": "mensual", "filas": filas, "totales": totales})
        except Exception:
            log.exception("reporte_ganancias_mensual json")
            return jsonify({"ok": False, "error": "internal"}), 500
        finally:
            try:
                conn.close()
            except Exception:
                pass
    if not _legacy_ganancia_perdida_vista_requested():
        return redirect("/reporte/finanzas/dashboard?period=monthly")
    conn = db()
    if not conn:
        return "Error conectando base de datos", 500
    is_pg = bool(os.environ.get("DATABASE_URL"))
    filas, totales = [], {}
    try:
        cur = conn.cursor()
        filas, totales = _ganancias_perdidas_desde_cierres_caja(cur, is_pg, anual=False)
    except Exception:
        log.exception("reporte_ganancias_mensual")
        flash("Error al cargar el reporte.", "error")
    finally:
        try:
            conn.close()
        except Exception:
            pass
    filas_chart = list(reversed(filas)) if filas else []
    return render_template(
        "dashboard_financiero.html",
        vista="mensual",
        titulo_corto="Mensual",
        totales=totales,
        filas=filas,
        filas_chart=filas_chart,
    )


