@app.route("/api/finance/dashboard")
def api_finance_dashboard():
    t0 = time.perf_counter()
    payload, err = _finance_dashboard_build_payload()
    if err:
        msg = str(err.get("error") or "error")
        if msg == "unauthorized":
            return jsonify({"ok": False, "error": msg}), 403
        if msg in ("missing_custom_range", "bad_custom_range"):
            return jsonify({"ok": False, "error": msg}), 400
        if msg == "db":
            return jsonify({"ok": False, "error": msg}), 500
        return jsonify({"ok": False, "error": msg}), 400
    log.info(
        "PERF ruta=/api/finance/dashboard ms=%s filas=%s",
        round((time.perf_counter() - t0) * 1000, 2),
        len(payload.get("filas_detalle") or []),
    )
    return jsonify(payload)


