@app.route("/reporte/finanzas/dashboard")
def reporte_finanzas_dashboard():
    if not is_admin_or_super():
        flash("No autorizado.", "error")
        return redirect("/reporte")
    t0 = time.perf_counter()
    payload, err = _finance_dashboard_build_payload()
    if err:
        msg = err.get("error") or ""
        if msg == "unauthorized":
            flash("No autorizado.", "error")
            return redirect("/reporte")
        if msg in ("missing_custom_range", "bad_custom_range"):
            flash("Rango personalizado inválido: use start y end en formato YYYY-MM-DD.", "error")
            return redirect("/reporte/finanzas/dashboard?period=monthly")
        log.warning("reporte_finanzas_dashboard: %s", err)
        flash("Error al cargar el dashboard financiero.", "error")
        return redirect("/reporte")
    log.info(
        "PERF ruta=/reporte/finanzas/dashboard ms=%s filas=%s",
        round((time.perf_counter() - t0) * 1000, 2),
        len(payload.get("filas_detalle") or []),
    )
    return render_template(
        "finanzas_dashboard.html",
        fecha=formatear_fecha_rd(ahora_rd()),
        data=payload,
    )


def _finance_dashboard_redirect_ui():
    base = "/reporte/finanzas/dashboard"
    qs = ""
    try:
        if request.query_string:
            qs = request.query_string.decode("utf-8", errors="ignore")
    except Exception:
        qs = ""
    return base + (("?" + qs) if qs else "")


@app.route("/reporte/finanzas/dashboard/export")
def reporte_finanzas_dashboard_export():
    if not is_admin_or_super():
        flash("No autorizado.", "error")
        return redirect("/reporte")
    fmt = (request.args.get("format") or request.args.get("fmt") or "csv").lower()
    payload, err = _finance_dashboard_build_payload()
    if err:
        flash("No se pudo exportar (verifique filtros o permisos).", "error")
        return redirect(_finance_dashboard_redirect_ui())
    resp = _finance_dashboard_export_response(
        payload.get("filas_detalle") or [],
        payload.get("filters_echo") or {},
        payload.get("totales") or {},
        fmt,
    )
    if resp is None:
        flash("Exportación PDF no disponible (instale fpdf2: pip install fpdf2).", "error")
        return redirect(_finance_dashboard_redirect_ui())
    return resp


