def _ganadores_debug_join_ticket_ids_filter():
    raw = os.environ.get("DEBUG_GANADORES_TICKET_IDS", "").strip()
    if not raw:
        return None
    out = []
    for p in raw.split(","):
        p = p.strip()
        if p.isdigit():
            out.append(int(p))
    return frozenset(out) if out else None


