def _ganadores_debug_diagnostico_ticket(cur, ticket_id: int, hoy_s: str):
    """
    Volcado puntual: líneas del ticket, cabecera tickets, pagos_premios, resultados del día (filas Nacional).
    Activar: DEBUG_GANADORES_DIAG_TICKET=415 (o el id a inspeccionar).
    """
    tid = int(ticket_id)
    h = (hoy_s or "")[:10]
    log.warning("GANADORES_DIAG_TICKET=%s hoy=%s", tid, h)
    try:
        cur.execute(
            _sql("SELECT id, pagado, ganador, cajero, created_at FROM tickets WHERE id = %s"),
            (tid,),
        )
        tk = cur.fetchone()
        print("[DIAG tickets]", dict(tk) if tk and hasattr(tk, "keys") else tk)
    except Exception as _e:
        print("[DIAG tickets] error:", _e)
    try:
        cur.execute(
            _sql(
                """
                SELECT id, lottery, draw, number, play, amount, fecha_sorteo, estado, pagado,
                       premio_linea_pagada
                FROM ticket_lines
                WHERE ticket_id = %s
                ORDER BY id
                """
            ),
            (tid,),
        )
        for row in cur.fetchall() or []:
            print("[DIAG ticket_lines]", dict(row) if hasattr(row, "keys") else row)
    except Exception as _e:
        print("[DIAG ticket_lines] error:", _e)
    try:
        cur.execute(
            _sql(
                """
                SELECT COUNT(*) AS c FROM pagos_premios
                WHERE ticket_id = %s AND COALESCE(revertido, 0) = 0
                """
            ),
            (tid,),
        )
        cr = cur.fetchone()
        cn = (cr.get("c") if cr and hasattr(cr, "get") else (cr[0] if cr else 0))
        print("[DIAG pagos_premios activos (no revertidos)] count =", cn)
    except Exception as _e:
        print("[DIAG pagos_premios] error:", _e)
    try:
        if os.environ.get("DATABASE_URL"):
            _fd = _sql_expr_resultados_fecha_calendario_rd_pg("fecha")
            cur.execute(
                f"""
                SELECT id, lottery, draw, primero, segundo, tercero, fecha, publicado, estado
                FROM resultados
                WHERE {_fd} = %s::date
                ORDER BY lottery, draw
                """,
                (h,),
            )
        else:
            cur.execute(
                _sql(
                    """
                    SELECT id, lottery, draw, primero, segundo, tercero, fecha, publicado, estado
                    FROM resultados
                    WHERE """
                    + _sql_expr_resultados_fecha_calendario_rd_sqlite("fecha")
                    + """ = %s
                    ORDER BY lottery, draw
                    """
                ),
                (h,),
            )
        for row in cur.fetchall() or []:
            d = dict(row) if hasattr(row, "keys") else row
            lot = (d.get("lottery") if isinstance(d, dict) else None) or ""
            if "nacional" in str(lot).lower():
                print("[DIAG resultado día (nacional/*)]", d)
    except Exception as _e:
        print("[DIAG resultados día] error:", _e)


def _ganadores_fetch_lineas_vs_resultados(
    cur, hoy, cajero_username=None, ticket_id=None, modo_recalc_manual=False
):
    """
    Cruza **ticket_lines** (jugadas reales: lottery, draw, number, play, amount) con **resultados**.
    **tickets** (tk) solo aporta: ticket_id, cajero, pagado y created_at (defensa anti-bug: debe coincidir
    con tl.fecha_sorteo en PG). La fecha del cruce es **siempre** tl.fecha_sorteo ↔ r.fecha (calendario RD).

    JOIN a resultados: clave canónica de lotería (expresión SQL alineada con clave_loteria, misma noción
    que comparar valores normalizados de tl.lottery y r.lottery) y **tl.draw = r.draw** (lower(trim)
    vía _sql_expr_draw_column_eq_*), salvo GANADORES_SQL_LOOSE_DRAW_JOIN.
    Solo r.publicado estricto; fecha calendario RD: igualdad estricta tl.fecha_sorteo y r.fecha (vía expresión RD).

    GANADORES_SQL_LOOSE_DRAW_JOIN=1: no igualar draw en SQL; se filtra como antes en Python
    (útil si ticket y resultado guardan formatos distintos que normalizar_hora unificaría).
    Modo DEBUG_JOIN_SQL_SIN_LOTERIA=1: sin igualar lotería en SQL; misma comparación de hora en Python;
      «MATCH FORZADO» sobre resultado_cruce_debug.
    No filtra por la hora real de creación del ticket: una jugada hecha antes del sorteo es válida.
    La anti-duplicación de pagos es por fila en `premios` / `pagos_premios.premio_id`, no se excluye
    el ticket entero cuando existe un pago parcial (varios premios por ticket).
    Solo resultados con estado 'cerrado' (por defecto en BD) entran al cruce.
    No retorna filas evaluables hasta 10 minutos despues de la hora del sorteo (RD).
    Antigüedad máxima opcional (GANADORES_MAX_DIAS_TICKET) sobre fecha_sorteo.
    El acierto numérico (Quiniela/Pale/…) se valida con calcular_premio en Python.
    cajero_username: si se indica, solo líneas cuyo tickets.cajero coincide (case-insensitive).
    ticket_id: si se indica, limita el cruce a un ticket (impresión/pago rápido).
    Variables de entorno (solo diagnóstico):
      DEBUG_AUDIT_GANADORES=1 — traza completa por fila: ticket/resultado, sorteo_key, fechas RD, jugados, match, premio (ver _ganadores_debug_audit_imprimir).
      DEBUG_JOIN_GANADORES=1 — imprime por cada fila SQL: lotería, sorteo_key (compound + canonica 24h), fechas ticket/resultado, publicado, estado, nums p1-p3, sanity numérico.
      DEBUG_JOIN_SIN_ESPERA=1 — no aplica el filtro de 10 minutos post-sorteo (solo diagnóstico; ver si el ticket aparece al cruzar).
      DEBUG_CRUCE_COMPLETO=1 — antes del match numérico, imprime ticket↔resultado en consola.
      DEBUG_CRUCE_SIN_FECHA=1 — omite en SQL (y en parte de la validación Python) la igualdad de fechas.
      DEBUG_GANADORES_CRUCE_NUMEROS=1 — en validación: imprime jugados vs primero/segundo/tercero (zfill).
      DEBUG_AISLAR_GANADORES=1 — activa lo anterior + log de cruce, bypass catálogo, sin cruzar fecha en procesar_filas (solo diagnóstico; no usar en prod).
      DEBUG_SORTEO_DRAW_CRUCE=1 — al filtrar por hora, imprime Ticket sorteo / Resultado draw (columnas draw).
      DEBUG_GANADORES_TICKET_RESULTADO=1 — en validación final: Ticket/Resultado loteria y sorteo/draw (columnas reales).
      GANADORES_SQL_LOOSE_DRAW_JOIN=1 — omite igualdad tl.draw = r.draw en SQL (más lento; compatibilidad legada).
    """
    rows_out = []
    join_sin_loteria = os.environ.get("DEBUG_JOIN_SQL_SIN_LOTERIA") == "1"
    if join_sin_loteria:
        log.warning(
            "ganadores: DEBUG_JOIN_SQL_SIN_LOTERIA=1 — JOIN por fecha sin igualar lotería; "
            "horas se cruzan con normalizar_hora(draw) en Python (diagnóstico; revisar falsos positivos)"
        )
    select_tail_pg = (
        """,
                   tl.lottery AS loteria_ticket,
                   r.lottery AS loteria_resultado,
                   tl.draw AS draw_ticket,
                   r.draw AS draw_resultado,
                   (trim(COALESCE(CAST(r.primero AS TEXT), '')) || '-' || trim(COALESCE(CAST(r.segundo AS TEXT), '')) || '-' || trim(COALESCE(CAST(r.tercero AS TEXT), ''))) AS resultado_cruce_debug"""
        if join_sin_loteria
        else ""
    )
    select_tail_sq = (
        """,
                   tl.lottery AS loteria_ticket,
                   r.lottery AS loteria_resultado,
                   tl.draw AS draw_ticket,
                   r.draw AS draw_resultado,
                   (trim(ifnull(cast(r.primero as text), '')) || '-' || trim(ifnull(cast(r.segundo as text), '')) || '-' || trim(ifnull(cast(r.tercero as text), ''))) AS resultado_cruce_debug"""
        if join_sin_loteria
        else ""
    )
    if join_sin_loteria:
        join_core_pg = "1=1"
        join_sq_on = "1=1"
    else:
        join_core_pg = (
            _sql_expr_clave_loteria_pg("tl.lottery")
            + " = "
            + _sql_expr_clave_loteria_pg("r.lottery")
        )
        join_sq_on = "clave_loteria(tl.lottery) = clave_loteria(r.lottery)"
    _sql_loose_draw = os.environ.get("GANADORES_SQL_LOOSE_DRAW_JOIN", "").strip() == "1"
    if _sql_loose_draw and not join_sin_loteria:
        log.warning(
            "ganadores: GANADORES_SQL_LOOSE_DRAW_JOIN=1 — sin igualar draw en SQL; JOIN más ancho"
        )
    join_draw_pg = ""
    join_draw_sq = ""
    if not join_sin_loteria and not _sql_loose_draw:
        # Hora efectiva: si tl.draw viene vacío, usar la hora embebida en tl.lottery (igual que _draw_efectivo_jugada).
        _tl_draw_eff_pg = _sql_expr_draw_effective_pg("tl.lottery", "tl.draw")
        _tl_draw_eff_sq = _sql_expr_draw_effective_sqlite("tl.lottery", "tl.draw")
        join_draw_pg = (
            "\n             AND " + _sql_expr_draw_column_eq_pg(_tl_draw_eff_pg, "r.draw") + "\n        "
        )
        join_draw_sq = (
            "\n             AND "
            + _sql_expr_draw_column_eq_sqlite(_tl_draw_eff_sq, "r.draw")
            + "\n        "
        )
    max_dias = _ganadores_max_dias_ticket()
    frag_ant_pg = ""
    frag_ant_sq = ""
    extra_params = []
    # Cruce por ticket_id: no acotar antigüedad ni día global (líneas del mismo ticket pueden
    # tener fecha_sorteo distinta; el JOIN ya exige tl.fecha_sorteo = r.fecha por fila).
    if max_dias > 0 and ticket_id is None and not modo_recalc_manual:
        min_fecha = (ahora_rd().date() - timedelta(days=max_dias)).strftime("%Y-%m-%d")
        extra_params = [min_fecha]
        frag_ant_pg = """
             AND to_date(substr(NULLIF(trim(CAST(tl.fecha_sorteo AS text)), ''), 1, 10), 'YYYY-MM-DD') >= (%s::date)
        """
        frag_ant_sq = """
             AND date(substr(trim(COALESCE(tl.fecha_sorteo, '')), 1, 10)) >= date(%s)
        """
    filt_caj = bool((cajero_username or "").strip())
    caj_filter_pg = (
        " AND lower(trim(COALESCE(tk.cajero, ''))) = lower(trim(%s))"
        if filt_caj
        else ""
    )
    caj_filter_sq = (
        " AND lower(trim(COALESCE(tk.cajero, ''))) = lower(trim(%s))"
        if filt_caj
        else ""
    )
    filt_ticket = ticket_id is not None
    ticket_filter_pg = " AND tl.ticket_id = %s" if filt_ticket else ""
    ticket_filter_sq = " AND tl.ticket_id = %s" if filt_ticket else ""
    hoy_arg_s = (hoy or "").strip()[:10]
    if len(hoy_arg_s) != 10:
        log.warning("ganadores: fecha de sorteo inválida; no se usa fecha actual como fallback (%r)", hoy)
        return []
    hoy_s = hoy_arg_s
    _diag_tid = os.environ.get("DEBUG_GANADORES_DIAG_TICKET", "").strip()
    if _diag_tid.isdigit():
        _ganadores_debug_diagnostico_ticket(cur, int(_diag_tid), hoy_s)
    # NUNCA permitir cruces sin fecha en producción por accidente.
    # DEBUG_CRUCE_SIN_FECHA/DEBUG_AISLAR_GANADORES solo se honran si ALLOW_UNSAFE_GANADORES_DEBUG=1.
    _unsafe_ok = os.environ.get("ALLOW_UNSAFE_GANADORES_DEBUG", "").strip().lower() in ("1", "true", "yes")
    sin_fecha_dbg = _unsafe_ok and (
        os.environ.get("DEBUG_CRUCE_SIN_FECHA") == "1"
        or os.environ.get("DEBUG_AISLAR_GANADORES") == "1"
    )
    if not _unsafe_ok and (
        os.environ.get("DEBUG_CRUCE_SIN_FECHA") == "1"
        or os.environ.get("DEBUG_AISLAR_GANADORES") == "1"
    ):
        log.warning(
            "ganadores: debug inseguro solicitado pero bloqueado (set ALLOW_UNSAFE_GANADORES_DEBUG=1 para habilitar)"
        )
    if sin_fecha_dbg:
        log.warning(
            "ganadores: DEBUG_CRUCE_SIN_FECHA o DEBUG_AISLAR_GANADORES — cruces SQL sin igualar fechas ticket/resultado/hoy (solo diagnóstico)"
        )
    # Un ticket puede tener líneas con fecha_sorteo distinta (p. ej. error de captura); no forzar
    # tl.fecha y r.fecha al mismo día «hoy» del parámetro: basta con el JOIN tl.fecha = r.fecha.
    use_wide_ticket_fecha = bool(filt_ticket and not sin_fecha_dbg)
    if sin_fecha_dbg:
        _ph_pg = tuple(extra_params)
        _ph_sq = tuple(extra_params)
    elif use_wide_ticket_fecha:
        _ph_pg = tuple(extra_params)
        _ph_sq = tuple(extra_params)
    else:
        _ph_pg = tuple(extra_params) + (hoy_s, hoy_s, hoy_s, hoy_s)
        _ph_sq = tuple(extra_params) + (hoy_s, hoy_s, hoy_s, hoy_s)
    if filt_ticket:
        _ph_pg = _ph_pg + (int(ticket_id),)
        _ph_sq = _ph_sq + (int(ticket_id),)
    if filt_caj:
        _ph_pg = _ph_pg + ((cajero_username or "").strip(),)
        _ph_sq = _ph_sq + ((cajero_username or "").strip(),)
    if os.environ.get("DATABASE_URL"):
        _rfd = _sql_expr_resultados_fecha_calendario_rd_pg("r.fecha")
        # Fecha del ticket: SOLO tl.fecha_sorteo (RD). Sin fallback a created_at para evitar mezclar días.
        _tfd = "to_date(substr(NULLIF(trim(CAST(tl.fecha_sorteo AS text)), ''), 1, 10), 'YYYY-MM-DD')"
        join_fecha_pg = " AND (1=1) " if sin_fecha_dbg else f" AND {_tfd} = {_rfd} "
        where_fecha_pg = (
            """
            WHERE (1=1)
"""
            if sin_fecha_dbg or use_wide_ticket_fecha
            else f"""
            WHERE {_tfd} >= (%s::date) AND {_tfd} <= (%s::date)
              AND {_rfd} >= (%s::date) AND {_rfd} <= (%s::date)
"""
        )
        cur.execute(
            f"""
            SELECT tl.id AS line_id,
                   tl.ticket_id,
                   tk.cajero,
                   tk.banca_id,
                   tl.number,
                   tl.lottery,
                   tl.draw,
                   tl.play,
                   lower(replace(trim(COALESCE(tl.play, '')), ' ', '')) AS play_norm,
                   tl.amount,
                   r.primero,
                   r.segundo,
                   r.tercero,
                   tl.fecha_sorteo,
                   tk.created_at AS ticket_fecha,
                   r.fecha AS resultado_fecha,
                   r.lottery AS res_lottery,
                   r.draw AS res_draw,
                   r.confirmado AS res_confirmado,
                   r.publicado AS res_publicado,
                   r.estado AS res_estado,
                   tk.pagado AS ticket_pagado,
                   tl.pagado AS linea_pagada,
                   COALESCE(tl.premio_linea_pagada, 0) AS premio_linea_pagada,
                   r.ganador_detectado_en AS res_ganador_detectado_en"""
            + select_tail_pg
            + """
            FROM ticket_lines tl
            INNER JOIN tickets tk ON tk.id = tl.ticket_id
            INNER JOIN resultados r
              ON """
            + join_core_pg
            + join_fecha_pg
            + join_draw_pg
            + """
             AND (r.publicado IS TRUE)
             AND lower(trim(COALESCE(NULLIF(trim(CAST(r.estado AS TEXT)), ''), 'cerrado'))) = 'cerrado'
            """
            + frag_ant_pg
            + where_fecha_pg
            + """
              AND """
            + _sql_bool_not_true("tk.pagado")
            + """
              AND """
            + _sql_bool_not_true("tl.pagado")
            + """
              AND COALESCE(tl.premio_linea_pagada, 0) = 0
              AND length(trim(COALESCE(CAST(tl.fecha_sorteo AS text), ''))) >= 10
              -- Regla de negocio: se permite venta anticipada (ticket creado en día distinto
              -- al fecha_sorteo). La validación temporal real del cruce es tl.fecha_sorteo ↔ r.fecha.
            """
            + _sql_ticket_no_eliminado("tk")
            + ticket_filter_pg
            + caj_filter_pg
            + """
              AND COALESCE(tl.estado, 'activo') <> 'cancelado'
            ORDER BY tl.ticket_id, tl.id
            """,
            _ph_pg,
        )
    else:
        _rfsq = _sql_expr_resultados_fecha_calendario_rd_sqlite("r.fecha")
        _tfsq = "substr(trim(COALESCE(tl.fecha_sorteo, '')), 1, 10)"
        if sin_fecha_dbg:
            join_fecha_sq = "\n             AND 1=1\n"
            where_fecha_sq = "\n            WHERE 1=1\n"
        else:
            join_fecha_sq = "\n             AND date(" + _tfsq + ") = date(" + _rfsq + ")\n"
            if use_wide_ticket_fecha:
                where_fecha_sq = "\n            WHERE 1=1\n"
            else:
                where_fecha_sq = (
                    "\n            WHERE date("
                    + _tfsq
                    + ") >= date(%s) AND date("
                    + _tfsq
                    + ") <= date(%s)\n              AND date("
                    + _rfsq
                    + ") >= date(%s) AND date("
                    + _rfsq
                    + ") <= date(%s)\n"
                )
        cur.execute(
            _sql(
                """
            SELECT tl.id AS line_id,
                   tl.ticket_id,
                   tk.cajero,
                   tk.banca_id,
                   tl.number,
                   tl.lottery,
                   tl.draw,
                   tl.play,
                   lower(replace(trim(ifnull(tl.play, '')), ' ', '')) AS play_norm,
                   tl.amount,
                   r.primero,
                   r.segundo,
                   r.tercero,
                   tl.fecha_sorteo,
                   tk.created_at AS ticket_fecha,
                   r.fecha AS resultado_fecha,
                   r.lottery AS res_lottery,
                   r.draw AS res_draw,
                   r.confirmado AS res_confirmado,
                   r.publicado AS res_publicado,
                   r.estado AS res_estado,
                   tk.pagado AS ticket_pagado,
                   tl.pagado AS linea_pagada,
                   COALESCE(tl.premio_linea_pagada, 0) AS premio_linea_pagada,
                   r.ganador_detectado_en AS res_ganador_detectado_en"""
                + select_tail_sq
                + """
            FROM ticket_lines tl
            INNER JOIN tickets tk ON tk.id = tl.ticket_id
            INNER JOIN resultados r
              ON """
                + join_sq_on
                + join_fecha_sq
                + join_draw_sq
                + """
             AND r.publicado = 1
             AND lower(trim(COALESCE(NULLIF(trim(ifnull(r.estado, '')), ''), 'cerrado'))) = 'cerrado'
            """
                + (frag_ant_sq if frag_ant_sq else "")
                + where_fecha_sq
                + """
              AND COALESCE(tk.pagado, 0) = 0
              AND COALESCE(tl.pagado, 0) = 0
              AND COALESCE(tl.premio_linea_pagada, 0) = 0
              AND length(trim(COALESCE(tl.fecha_sorteo, ''))) >= 10
              -- Regla de negocio: se permite venta anticipada (created_at puede diferir de fecha_sorteo).
            """
                + _sql_ticket_no_eliminado("tk")
                + ticket_filter_sq
                + caj_filter_sq
                + """
              AND COALESCE(tl.estado, 'activo') <> 'cancelado'
            ORDER BY tl.ticket_id, tl.id
                """
            ),
            _ph_sq,
        )
    for row in cur.fetchall() or []:
        if hasattr(row, "keys"):
            rows_out.append(dict(row))
        else:
            drow = {
                "line_id": row[0],
                "ticket_id": row[1],
                "cajero": row[2],
                "banca_id": row[3],
                "number": row[4],
                "lottery": row[5],
                "draw": row[6],
                "play": row[7],
                "play_norm": row[8],
                "amount": row[9],
                "primero": row[10],
                "segundo": row[11],
                "tercero": row[12],
                "fecha_sorteo": row[13],
                "ticket_fecha": row[14],
                "resultado_fecha": row[15],
                "res_lottery": row[16],
                "res_draw": row[17],
                "res_confirmado": row[18],
                "res_publicado": row[19] if len(row) > 19 else None,
                "res_estado": row[20] if len(row) > 20 else None,
                "ticket_pagado": row[21] if len(row) > 21 else None,
                "linea_pagada": row[22] if len(row) > 22 else None,
                "premio_linea_pagada": row[23] if len(row) > 23 else None,
                "res_ganador_detectado_en": row[24] if len(row) > 24 else None,
            }
            if join_sin_loteria and len(row) >= 30:
                drow["loteria_ticket"] = row[25]
                drow["loteria_resultado"] = row[26]
                drow["draw_ticket"] = row[27]
                drow["draw_resultado"] = row[28]
                drow["resultado_cruce_debug"] = row[29]
            rows_out.append(drow)
    _jtrace = _ganadores_debug_join_trace_on()
    _jtidf = _ganadores_debug_join_ticket_ids_filter()
    if _jtrace:
        print(
            "[GANADORES JOIN TRACE] hoy=%s filas SQL (antes filtro hora Python)=%s"
            % (hoy_s, len(rows_out))
        )
        _nprt = 0
        for _d in rows_out:
            if _jtidf is not None and int(_d.get("ticket_id") or 0) not in _jtidf:
                continue
            if _jtidf is None and _nprt >= 100:
                print(
                    "[GANADORES JOIN TRACE] …más de 100 filas; defina DEBUG_GANADORES_TICKET_IDS=415 para filtrar"
                )
                break
            _ganadores_debug_trace_row("SQL_ROW", _d)
            _nprt += 1
        if _jtidf is None:
            if len(rows_out) > 100 and _nprt >= 100:
                pass  # mensaje ya impreso
            elif len(rows_out) == 0:
                print(
                    "[GANADORES JOIN TRACE] 0 filas: revisar fecha_sorteo vs r.fecha, publicado, estado, "
                    "pagado/pagos_premios, draw (use DEBUG_GANADORES_DIAG_TICKET=<id>)"
                )
    rows_pre_hora = list(rows_out)
    rows_out = [d for d in rows_out if _ganadores_fila_coincide_hora_sorteo(d)]
    if not sin_fecha_dbg:
        _n_antes_fecha = len(rows_out)
        rows_out = [d for d in rows_out if _ganadores_row_fecha_linea_eq_resultado_strict(d)]
        _n_desc = _n_antes_fecha - len(rows_out)
        if _n_desc and os.environ.get("DEBUG_CRUCE_TICKET_RESULTADO_FECHA", "").strip().lower() in (
            "1",
            "true",
            "yes",
        ):
            print(
                "CRUCE_FECHA estricto: descartadas",
                _n_desc,
                "filas (ticket_lines.fecha_sorteo != fecha resultado), quedan",
                len(rows_out),
            )
    if _jtrace:
        post_h = {_ganadores_line_id_key(d.get("line_id")) for d in rows_out}
        for _d in rows_pre_hora:
            if _jtidf is not None and int(_d.get("ticket_id") or 0) not in _jtidf:
                continue
            lid = _ganadores_line_id_key(_d.get("line_id"))
            if lid in post_h:
                continue
            t_eff = _draw_efectivo_jugada(_d.get("lottery"), _d.get("draw"))
            r_eff = _draw_efectivo_jugada(_d.get("res_lottery"), _d.get("res_draw"))
            nt = normalizar_hora(str(t_eff or "").strip())
            nr = normalizar_hora(str(r_eff or "").strip())
            _ganadores_debug_trace_row(
                "DESCARTADO_hora_sorteo_py",
                _d,
                "| normalizar_hora tl=%r res=%r" % (nt, nr),
            )
    if join_sin_loteria and os.environ.get("DEBUG_JOIN_GANADORES") == "1":
        for d in rows_out:
            numeros_bd = _numeros_resultado_bd(d.get("primero"), d.get("segundo"), d.get("tercero"))
            rn = d.get("number")
            if rn is None or (isinstance(rn, str) and not str(rn).strip()):
                continue
            numero = str(rn).zfill(2)
            print("Numeros BD:", numeros_bd, "| Numero Jugado:", numero)
            if numero in numeros_bd:
                print(
                    "🔥 MATCH FORZADO (SIN LOTE)",
                    {
                        "ticket_id": d.get("ticket_id"),
                        "line_id": d.get("line_id"),
                        "numero": numero,
                        "primero": d.get("primero"),
                        "segundo": d.get("segundo"),
                        "tercero": d.get("tercero"),
                        "loteria_ticket": d.get("loteria_ticket"),
                        "loteria_resultado": d.get("loteria_resultado"),
                    },
                )
    ahora_eval_rd = ahora_rd()
    _debug_join = os.environ.get("DEBUG_JOIN_GANADORES") == "1"
    _sin_espera_dbg = bool(modo_recalc_manual) or os.environ.get("DEBUG_JOIN_SIN_ESPERA") == "1"
    _log_espera_fila = os.environ.get("DEBUG_GANADORES_SORTEO_ESPERA_LOG", "").strip().lower() in (
        "1",
        "true",
        "yes",
    )
    if _debug_join:
        print(
            "===== DEBUG_JOIN_GANADORES: filas cruzadas en SQL (antes filtro 10 min):",
            len(rows_out),
            "| DEBUG_JOIN_SIN_ESPERA:",
            _sin_espera_dbg,
        )
        for _dj in rows_out:
            _ganadores_debug_imprimir_fila_join(_dj)
    rows_ready = []
    pendientes_espera = 0
    for d in rows_out:
        if _sin_espera_dbg:
            evaluable, habilita_dt = True, None
        else:
            evaluable, habilita_dt = _ganadores_sorteo_evaluable_tras_espera(d, ahora=ahora_eval_rd)
        if _jtrace and _jtidf is not None and int(d.get("ticket_id") or 0) in _jtidf and not evaluable:
            _ganadores_debug_trace_row(
                "DESCARTADO_espera_10min_post_sorteo",
                d,
                "| habilita_en=%r ahora_rd=%r"
                % (
                    habilita_dt.isoformat() if habilita_dt and hasattr(habilita_dt, "isoformat") else habilita_dt,
                    ahora_eval_rd.isoformat() if hasattr(ahora_eval_rd, "isoformat") else ahora_eval_rd,
                ),
            )
        if _debug_join:
            if evaluable:
                print(
                    ">>> JOIN: fila PASA filtro 10min | line_id=",
                    d.get("line_id"),
                    "ticket_id=",
                    d.get("ticket_id"),
                )
            else:
                print(
                    ">>> JOIN: fila DESCARTADA por espera 10min post-sorteo | line_id=",
                    d.get("line_id"),
                    "habilita_en=",
                    habilita_dt.isoformat() if habilita_dt and hasattr(habilita_dt, "isoformat") else habilita_dt,
                )
        if evaluable:
            rows_ready.append(d)
            continue
        pendientes_espera += 1
        if _log_espera_fila:
            log.debug(
                "DEBUG CRUCE pendiente por espera sorteo: %s",
                {
                    "ticket_id": d.get("ticket_id"),
                    "line_id": d.get("line_id"),
                    "lottery": d.get("lottery"),
                    "draw": d.get("draw"),
                    "fecha_sorteo": d.get("fecha_sorteo"),
                    "resultado_fecha": d.get("resultado_fecha"),
                    "habilita_en": habilita_dt.isoformat() if habilita_dt else None,
                    "ahora_rd": ahora_eval_rd.isoformat() if hasattr(ahora_eval_rd, "isoformat") else str(ahora_eval_rd),
                },
            )
    if pendientes_espera and _log_espera_fila:
        log.debug("DEBUG CRUCE filas pendientes por espera 10min: %s", pendientes_espera)
    rows_out = rows_ready
    if os.environ.get("DEBUG_AUDIT_GANADORES") == "1":
        print("===== DEBUG_AUDIT_GANADORES: filas evaluables (SQL + filtro 10 min):", len(rows_out))
        for _ad in rows_out:
            _ganadores_debug_audit_imprimir(_ad, "post_join_sql_y_espera")
    if _ganadores_debug_row_dump_on():
        log.debug("DEBUG CRUCE total filas evaluables: %s", len(rows_out))
        for d in rows_out[:50]:
            log.debug("TICKET LOTERIA: %s", d.get("lottery"))
            log.debug("TICKET FECHA: %s", d.get("ticket_fecha") or d.get("fecha_sorteo"))
            log.debug("RESULTADO FECHA: %s", d.get("resultado_fecha"))
            log.debug("TICKET HORA: %s", d.get("draw"))
            log.debug("RESULTADO LOTERIA: %s", d.get("res_lottery"))
            log.debug("RESULTADO HORA: %s", d.get("res_draw"))
            log.debug(
                "DEBUG CRUCE NORMALIZADO: %s",
                {
                    "ticket_loteria": normalizar_texto(d.get("lottery")),
                    "resultado_loteria": normalizar_texto(d.get("res_lottery")),
                    "ticket_hora": normalizar_texto(d.get("draw")),
                    "resultado_hora": normalizar_texto(d.get("res_draw")),
                    "ticket_id": d.get("ticket_id"),
                    "line_id": d.get("line_id"),
                },
            )
        if not rows_out:
            log.debug("DEBUG CRUCE SIN FILAS: ningún ticket pasó lotería/hora/día/publicado/pagado.")
    return rows_out


def _ganadores_tipo_play(play, numero=None):
    """
    Clasificación de jugada para cruce numérico / UI. Debe coincidir con la normalización de play en
    calcular_premio: si allí play_l.startswith("quiniela"), aquí debe ser "quiniela" (no "otro"),
    o _ganadores_numero_coincide_resultado rechaza líneas que sí tienen premio > 0.
    """
    play_eff = _play_efectivo_cruce(play, numero) if numero is not None else _ganadores_play_canonical_premio(play)
    play_in = (play_eff or "").strip()
    play_l = play_in.lower().replace("_", " ")
    if play_l == "quiniela" or play_l.startswith("quiniela"):
        return "quiniela"
    if play_l == "pale" or play_l.startswith("pale"):
        return "pale"
    if play_l == "tripleta":
        return "tripleta"
    if play_l in ("super pale", "superpale"):
        return "super_pale"
    pl = play_in.lower()
    return pl if pl else "otro"


def _ganadores_resultado_str(p1, p2, p3):
    return "%s-%s-%s" % (
        str(p1).strip() if p1 is not None else "",
        str(p2).strip() if p2 is not None else "",
        str(p3).strip() if p3 is not None else "",
    )


def _ganadores_numero_coincide_resultado(play, numero, r1, r2, r3):
    """Valida la coincidencia numerica jugada vs resultado, sin depender del monto/premio."""
    tipo = _ganadores_tipo_play(play, numero)
    num = normalizar_numero(numero)
    r1s = _norm_sorteo_dos_digitos(r1)
    r2s = _norm_sorteo_dos_digitos(r2)
    r3s = _norm_sorteo_dos_digitos(r3)
    _dbg_nums = os.environ.get("DEBUG_GANADORES_CRUCE_NUMEROS") == "1" or os.environ.get(
        "DEBUG_VALIDACION_PREMIOS"
    ) == "1"

    if tipo == "tripleta":
        res_txt = _ganadores_resultado_str(r1, r2, r3)
        coincidencias, gana = _tripleta_coincidencias_eval(num, r1, r2, r3)
        _tripleta_eval_log("", num, res_txt, coincidencias, gana, play_decl=play)
        return gana

    if tipo == "pale":
        coincidencias, gana = _pale_coincidencias_eval(num, r1, r2, r3)
        if _dbg_nums:
            print("----- DEBUG CRUCE PALE -----")
            print("Ticket (number raw):", repr(numero))
            print("Par jugado:", _parse_pale_par(num))
            print("Resultados:", r1s, r2s, r3s)
            print("Coincidencias parciales:", coincidencias)
            print("Gana (par completo):", gana)
        return gana

    if tipo == "quiniela":
        jugados = _quiniela_jugados_desde_campo(numero) or _quiniela_jugados_desde_campo(num)
        if not jugados:
            ji = _jugada_simple_int(num)
            if ji is not None:
                jugados = [str(int(ji) % 100).zfill(2)]
        res_list = numeros_resultado_bd(r1, r2, r3)
        ok = bool(jugados) and _ganadores_hay_match_numeros(jugados, r1, r2, r3)
        if _dbg_nums:
            print("----- DEBUG CRUCE QUINIELA -----")
            print("Ticket (number raw):", repr(numero))
            print("Jugado (normalizar_numero):", repr(num))
            print("Jugados (tokens):", jugados)
            print("Resultados cols [p1,p2,p3] raw:", r1, r2, r3)
            print("Resultados (lista 3 pos, zfill):", res_list)
            print("Coincidencia (algún jugado en lista):", ok)
        elif os.environ.get("DEBUG_VALIDACION_PREMIOS") == "1":
            print("DEBUG VALIDACION _ganadores_numero_coincide (quiniela)")
            print("Jugados:", jugados)
            print("Resultados:", res_list)
            print("Match:", ok)
        return ok

    if tipo == "super_pale":
        n_int = _jugada_simple_int(num)
        r1_int = _jugada_simple_int(r1s)
        return n_int is not None and r1_int is not None and n_int == r1_int

    return False


def _ganadores_fecha_iso_para_comparar(val):
    """YYYY-MM-DD en calendario RD (misma regla que _parse_iso_date_only)."""
    d = _parse_iso_date_only(val)
    return d.strftime("%Y-%m-%d") if d else None


def _ganadores_row_fecha_linea_eq_resultado_strict(d: dict) -> bool:
    """
    Regla obligatoria del cruce: misma fecha calendario (RD) en ticket_lines.fecha_sorteo
    y en la fila de resultados emparejada. Filtro de seguridad post-SQL (driver/TZ/diagnóstico).
    """
    if not isinstance(d, dict):
        return False
    tl_raw = (str(d.get("fecha_sorteo") or "").strip())[:10]
    tl_d = _parse_iso_date_only(tl_raw) if len(tl_raw) == 10 else _parse_iso_date_only(d.get("fecha_sorteo"))
    r_d = _parse_iso_date_only(d.get("resultado_fecha"))
    return tl_d is not None and r_d is not None and tl_d == r_d


def _ganadores_fecha_sorteo_efectiva_str(d):
    """YYYY-MM-DD del sorteo: SOLO ticket_lines.fecha_sorteo (sin fallback a created_at).

    Regla de negocio: el cruce gana sólo si fecha_sorteo (línea) == fecha del resultado.
    Usar ticket_fecha aquí mezclaba días (ej. línea mal fechada pero ticket de ayer).
    """
    fs = (d.get("fecha_sorteo") or "").strip()
    if len(fs) >= 10:
        return fs[:10]
    return ""


def _ganadores_line_id_key(lid):
    """
    Clave estable para ticket_lines.id al agrupar el cruce ganadores.
    Evita partir la misma línea en varios buckets (int / Decimal / str según driver SQL).
    """
    if lid is None:
        return None
    try:
        return int(lid)
    except (TypeError, ValueError):
        try:
            s = str(lid).strip()
            if s.isdigit() or (s.startswith("-") and s[1:].isdigit()):
                return int(s)
        except (TypeError, ValueError):
            pass
    return None


def _ganadores_linea_pasa_validacion_final(d, premio, hoy_rd_str):
    """
    Validación obligatoria en Python: premio, pagos, publicado estricto, fechas (fecha_sorteo = resultado),
    sorteo unificado (sorteo_key_compound), lotería alineada, acierto numérico.
    El catálogo oficial no bloquea si ya hubo match numérico (evita descartes por formato de sorteo en tabla catálogo).
    Activar DEBUG_GANADOR_COMPLETO=1 para traza detallada (ticket, resultado, SK, jugados, match).
    """
    try:
        premio_f = float(premio or 0)
    except (TypeError, ValueError):
        return False
    if premio_f <= 0:
        return False
    _debug_cruce_imprime(d)
    _unsafe_g_dbg = os.environ.get("ALLOW_UNSAFE_GANADORES_DEBUG", "").strip().lower() in (
        "1",
        "true",
        "yes",
    )
    _sin_fecha_dbg = _unsafe_g_dbg and (
        os.environ.get("DEBUG_CRUCE_SIN_FECHA") == "1"
        or os.environ.get("DEBUG_AISLAR_GANADORES") == "1"
    )
    if not _unsafe_g_dbg and (
        os.environ.get("DEBUG_CRUCE_SIN_FECHA") == "1"
        or os.environ.get("DEBUG_AISLAR_GANADORES") == "1"
    ):
        log.warning(
            "ganadores validacion_final: debug inseguro (DEBUG_CRUCE_SIN_FECHA/DEBUG_AISLAR_GANADORES) "
            "bloqueado; set ALLOW_UNSAFE_GANADORES_DEBUG=1 para habilitar"
        )
    hoy_d = _parse_iso_date_only(hoy_rd_str)
    if not hoy_d:
        return False
    if _pago_premio_es_truthy_pagado(d.get("ticket_pagado")):
        return False
    if _pago_premio_es_truthy_pagado(d.get("linea_pagada")):
        return False
    try:
        if int(d.get("premio_linea_pagada") or 0) != 0:
            return False
    except (TypeError, ValueError):
        return False
    if not _ganadores_strict_publicado(d.get("res_publicado")):
        return False
    if os.environ.get("DEBUG_GANADORES_TICKET_RESULTADO") == "1":
        print("Ticket loteria:", d.get("lottery"))
        print("Resultado loteria:", d.get("res_lottery"))
        print("Ticket sorteo:", d.get("draw"))
        print("Resultado draw:", d.get("res_draw"))
    res_st = str(d.get("res_estado") or "cerrado").strip().lower()
    if res_st not in ("cerrado", ""):
        return False
    res_f = d.get("resultado_fecha")
    r_d = _parse_iso_date_only(res_f)
    if not r_d:
        return False
    eff_s = _ganadores_fecha_sorteo_efectiva_str(d)
    if not _sin_fecha_dbg:
        if not eff_s:
            return False
        t_d = _parse_iso_date_only(eff_s)
        if not t_d:
            return False
        if t_d != r_d:
            return False
        maxd = _ganadores_max_dias_ticket()
        if maxd > 0 and (hoy_d - t_d).days > maxd:
            return False
    lot_t = normalizar_loteria(d.get("lottery"))
    if not lot_t:
        lot_t = normalizar_loteria(
            re.sub(
                r"[0-9]{1,2}:[0-9]{2}\s*(a\.?m\.?|p\.?m\.?)",
                " ",
                str(d.get("lottery") or ""),
                flags=re.I,
            ).strip()
        ) or str(d.get("lottery") or "").strip()
    k_t = clave_loteria(d.get("lottery"))
    k_r = clave_loteria(d.get("res_lottery"))
    r1, r2, r3 = d.get("primero"), d.get("segundo"), d.get("tercero")
    sk_t = sorteo_key_compound(d.get("lottery"), d.get("draw"))
    sk_r = sorteo_key_compound(d.get("res_lottery"), d.get("res_draw"))
    _dbg_fail = (
        os.environ.get("DEBUG_CRUCE_COMPLETO") == "1"
        or os.environ.get("DEBUG_NACIONAL_GANADORES") == "1"
        or (_unsafe_g_dbg and os.environ.get("DEBUG_AISLAR_GANADORES") == "1")
    )
    _dbg_gan = os.environ.get("DEBUG_GANADOR_COMPLETO") == "1"
    _debug_match_sorteo(d.get("lottery"), d.get("draw"), d.get("res_lottery"), d.get("res_draw"))
    if _dbg_fail:
        print("TICKET LOTERIA:", d.get("lottery"))
        print("TICKET FECHA (fecha_sorteo):", d.get("fecha_sorteo"))
        print("RESULTADO FECHA:", d.get("resultado_fecha"))
        print("TICKET HORA:", d.get("draw"))
        print("RESULTADO LOTERIA:", d.get("res_lottery"))
        print("RESULTADO HORA:", d.get("res_draw"))
    if not k_t or k_t != k_r:
        if _dbg_fail or _dbg_gan:
            print("DEBUG validacion_final falla loteria:", k_t, k_r)
        return False
    if not lot_t:
        if _dbg_fail or _dbg_gan:
            print("DEBUG validacion_final falla loteria canonica (normalizar_loteria vacío):", d.get("lottery"))
        return False
    if not sk_t or sk_t != sk_r:
        if not (k_t and k_t == k_r and _ganadores_fila_coincide_hora_sorteo(d)):
            if _dbg_fail or _dbg_gan:
                print("DESCARTADO POR SORTEO:", sk_t, sk_r)
            return False
    if not _ganadores_jugada_numero_plausible(d.get("play"), d.get("number")):
        return False
    coin = _ganadores_numero_coincide_resultado(
        d.get("play"),
        d.get("number"),
        r1,
        r2,
        r3,
    )
    if _dbg_gan:
        jugados_dbg = _quiniela_jugados_desde_campo(d.get("number"))
        print("----- DEBUG GANADOR -----")
        print("Ticket:", d.get("lottery"), d.get("draw"))
        print("Resultado:", d.get("res_lottery"), d.get("res_draw"))
        print("SK_T:", sk_t)
        print("SK_R:", sk_r)
        print("Jugados:", jugados_dbg)
        print("Resultados:", numeros_resultado_bd(r1, r2, r3))
        print("MATCH:", coin)
    if not coin:
        if (
            os.environ.get("DEBUG_GANADOR_COMPLETO") == "1"
            or os.environ.get("DEBUG_AUDIT_GANADORES") == "1"
            or os.environ.get("DEBUG_VALIDACION_PREMIOS") == "1"
        ):
            print(
                "DEBUG validacion_final falla numero:",
                {
                    "play": d.get("play"),
                    "number": d.get("number"),
                    "resultado": [r1, r2, r3],
                },
            )
        return False
    if _unsafe_g_dbg and os.environ.get("DEBUG_AISLAR_GANADORES") == "1":
        print("⚠️ IGNORANDO VALIDACIÓN DE CATÁLOGO")
    elif not _ganadores_loteria_sorteo_en_catalogo(lot_t, d.get("draw")):
        if os.environ.get("DEBUG_NACIONAL_GANADORES") == "1" or _dbg_gan:
            print(
                "NO EN CATALOGO (no bloquea; hay match numérico):",
                lot_t,
                d.get("draw"),
            )
    if os.environ.get("DEBUG_NACIONAL_GANADORES") == "1":
        print("Loteria:", d.get("lottery"), "| res:", d.get("res_lottery"), "| claves:", k_t, "/", k_r)
        print("Jugado:", d.get("number"))
        print("Resultado:", f"{r1}-{r2}-{r3}")
        print("Coincidencias:", coin)
    return True


def _premios_log_registrar(cur, g, procesado_por=None, ip_origen=None, fecha_pago=None):
    """Auditoría de línea procesada como ganadora (detalle JSON + usuario / IP opcionales)."""
    det = {
        "evento": "devengo_linea",
        "loteria": g.get("lottery"),
        "sorteo": g.get("draw"),
        "fecha_ticket": g.get("fecha_sorteo_linea") or "",
        "fecha_resultado": g.get("resultado_fecha_iso") or "",
        "play": g.get("play"),
        "resultado_numeros": g.get("resultado"),
        "line_id": g.get("line_id"),
    }
    js = json.dumps(det, ensure_ascii=False)
    proc = ((procesado_por or "")[:200] or None) if procesado_por else None
    ip_s = ((ip_origen or "")[:64] or None) if ip_origen else None
    is_pg = bool(os.environ.get("DATABASE_URL"))
    if is_pg:
        cur.execute(
            """
            INSERT INTO premios_log (ticket_id, line_id, numero, monto, premio, detalle, procesado_por, ip_origen, fecha_pago)
            VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s)
            """,
            (
                g.get("ticket_id"),
                g.get("line_id"),
                str(g.get("number") or ""),
                float(g.get("monto") or 0),
                float(g.get("premio") or 0),
                js,
                proc,
                ip_s,
                fecha_pago,
            ),
        )
    else:
        cur.execute(
            """
            INSERT INTO premios_log (ticket_id, line_id, numero, monto, premio, detalle, procesado_por, ip_origen, fecha_pago)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                g.get("ticket_id"),
                g.get("line_id"),
                str(g.get("number") or ""),
                float(g.get("monto") or 0),
                float(g.get("premio") or 0),
                js,
                proc,
                ip_s,
                fecha_pago,
            ),
        )


def _premios_log_registrar_pago_ticket(
    cur, ticket_id, monto, usuario, ip_origen, hoy_rd_str, premio_id=None
):
    """Auditoría al registrar pago de premio por ticket o por fila `premios.id` (timestamp = ahora RD)."""
    ev = "pago_premio_linea" if premio_id is not None else "pago_premio_ticket"
    det_obj = {
        "evento": ev,
        "fecha_rd": (hoy_rd_str or "")[:10],
        "ticket_id": int(ticket_id),
    }
    if premio_id is not None:
        try:
            det_obj["premio_id"] = int(premio_id)
        except (TypeError, ValueError):
            det_obj["premio_id"] = premio_id
    det = json.dumps(det_obj, ensure_ascii=False)
    u = str(usuario or "sistema").strip()[:200] or "sistema"
    ip_s = ((ip_origen or "")[:64] or None) if ip_origen else None
    is_pg = bool(os.environ.get("DATABASE_URL"))
    mf = float(monto or 0)
    if is_pg:
        cur.execute(
            """
            INSERT INTO premios_log (ticket_id, line_id, numero, monto, premio, detalle, procesado_por, ip_origen, fecha_pago)
            VALUES (%s, NULL, %s, %s, %s, %s, %s, %s, NOW())
            """,
            (ticket_id, "", 0.0, mf, det, u, ip_s),
        )
    else:
        cur.execute(
            """
            INSERT INTO premios_log (ticket_id, line_id, numero, monto, premio, detalle, procesado_por, ip_origen, fecha_pago)
            VALUES (?, NULL, ?, ?, ?, ?, ?, ?, datetime('now'))
            """,
            (ticket_id, "", 0.0, mf, det, u, ip_s),
        )


PREMIOS_ESTADOS_OCULTOS_GANADORES = frozenset(
    {
        "invalidado",
        "invalidado_pagado",
        "manual_review",
        "eliminated_admin",
        "eliminado_admin",
    }
)

DEFAULT_MOTIVO_INVALIDACION_PREMIO = "Invalidado manualmente por resultado falso"


def _premios_linea_tiene_invalidacion_manual(cur, line_id):
    try:
        lid = int(line_id)
    except (TypeError, ValueError):
        return False
    if lid <= 0:
        return False
    cur.execute(
        _sql("SELECT 1 AS x FROM premios_invalidacion_audit WHERE line_id = %s LIMIT 1"),
        (lid,),
    )
    return bool(cur.fetchone())


def _premios_insert_invalidacion_audit(
    cur,
    premio_id,
    ticket_id,
    line_id,
    monto,
    estado_anterior,
    estado_nuevo,
    admin_user,
    motivo,
    lottery,
    draw,
    fecha_rd,
    jugada,
):
    is_pg = bool(os.environ.get("DATABASE_URL"))
    vals = (
        int(premio_id),
        int(ticket_id) if ticket_id is not None else None,
        int(line_id),
        float(monto or 0),
        str(estado_anterior or ""),
        str(estado_nuevo or ""),
        str(admin_user or "")[:200],
        str(motivo or "")[:500],
        str(lottery or "")[:200],
        str(draw or "")[:120],
        str(fecha_rd or "")[:10],
        str(jugada or "")[:200],
    )
    if is_pg:
        cur.execute(
            """
            INSERT INTO premios_invalidacion_audit (
                premio_id, ticket_id, line_id, monto, estado_anterior, estado_nuevo,
                admin_user, motivo, lottery, draw, fecha_rd, jugada
            )
            VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
            """,
            vals,
        )
    else:
        cur.execute(
            """
            INSERT INTO premios_invalidacion_audit (
                premio_id, ticket_id, line_id, monto, estado_anterior, estado_nuevo,
                admin_user, motivo, lottery, draw, fecha_rd, jugada
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            vals,
        )


def _ejecutar_invalidar_premio_admin(conn, premio_id, admin_user, motivo=None):
    """
    Invalidación admin: oculta el premio de ganadores y bloquea recreación por line_id.
    No modifica caja, pagos_premios ni movimientos_caja.
    """
    motivo_f = (str(motivo or "").strip() or DEFAULT_MOTIVO_INVALIDACION_PREMIO)[:500]
    admin = str(admin_user or "admin").strip()[:200] or "admin"
    is_pg = bool(os.environ.get("DATABASE_URL"))
    cur = conn.cursor()
    try:
        pid = int(premio_id)
    except (TypeError, ValueError):
        return {"ok": False, "message": "premio_id inválido."}
    cur.execute(
        _sql(
            """
            SELECT id, ticket_id, line_id, premio, estado, numero, play, lottery, draw,
                   fecha_dia, fecha_resultado, fecha_sorteo
            FROM premios WHERE id = %s
            """
        ),
        (pid,),
    )
    row = cur.fetchone()
    if not row:
        return {"ok": False, "message": "Premio no encontrado."}
    d = (
        dict(row)
        if hasattr(row, "keys")
        else {
            "id": row[0],
            "ticket_id": row[1],
            "line_id": row[2],
            "premio": row[3],
            "estado": row[4],
            "numero": row[5],
            "play": row[6],
            "lottery": row[7],
            "draw": row[8],
            "fecha_dia": row[9],
            "fecha_resultado": row[10],
            "fecha_sorteo": row[11],
        }
    )
    estado_ant = str(d.get("estado") or "").strip().lower()
    if estado_ant in PREMIOS_ESTADOS_OCULTOS_GANADORES:
        return {"ok": False, "message": "Este premio ya está excluido de la lista.", "already": True}
    lid = d.get("line_id")
    if lid is None:
        return {"ok": False, "message": "Premio sin line_id asociado."}
    try:
        lid = int(lid)
    except (TypeError, ValueError):
        return {"ok": False, "message": "line_id inválido."}
    if _premios_linea_tiene_invalidacion_manual(cur, lid):
        return {"ok": False, "message": "Esta línea ya tiene invalidación manual registrada."}
    monto_f = float(d.get("premio") or 0)
    estado_nuevo = "invalidado_pagado" if estado_ant == "pagado" else "invalidado"
    try:
        if not is_pg:
            try:
                cur.execute("BEGIN IMMEDIATE")
            except Exception:
                pass
        if is_pg:
            cur.execute(
                """
                UPDATE premios
                SET estado = %s, updated_at = CURRENT_TIMESTAMP
                WHERE id = %s AND lower(trim(COALESCE(estado, ''))) = %s
                """,
                (estado_nuevo, pid, estado_ant),
            )
        else:
            cur.execute(
                """
                UPDATE premios
                SET estado = ?, updated_at = datetime('now')
                WHERE id = ? AND lower(trim(COALESCE(estado, ''))) = ?
                """,
                (estado_nuevo, pid, estado_ant),
            )
        rc = int(cur.rowcount or 0)
        if not rc:
            try:
                conn.rollback()
            except Exception:
                pass
            return {"ok": False, "message": "No se pudo actualizar el premio (el estado pudo cambiar)."}
        fe_rd = str(d.get("fecha_dia") or d.get("fecha_resultado") or d.get("fecha_sorteo") or "")[:10]
        jp = str(d.get("play") or "").strip()
        jn = str(d.get("numero") or "").strip()
        jugada = (" ".join(x for x in (jp, jn) if x)).strip() or jn
        _premios_insert_invalidacion_audit(
            cur,
            pid,
            d.get("ticket_id"),
            lid,
            monto_f,
            estado_ant,
            estado_nuevo,
            admin,
            motivo_f,
            d.get("lottery"),
            d.get("draw"),
            fe_rd,
            jugada,
        )
        conn.commit()
    except Exception as ex:
        log.warning("invalidar premio premio_id=%s: %s", premio_id, ex, exc_info=True)
        try:
            conn.rollback()
        except Exception:
            pass
        return {"ok": False, "message": "Error al invalidar: %s" % str(ex)[:200]}
    log.info(
        "premio invalidado premio_id=%s line_id=%s %s→%s admin=%s",
        pid,
        lid,
        estado_ant,
        estado_nuevo,
        admin,
    )
    return {
        "ok": True,
        "message": "Premio invalidado.",
        "estado_nuevo": estado_nuevo,
        "line_id": lid,
    }


def _premios_upsert_pendiente(cur, g):
    """Fuente persistente de premios devengados: pendiente hasta pago explícito.

    Returns True si ejecutó INSERT/UPSERT; False si omitió (datos inválidos o invalidación manual).
    """
    tid = int(g.get("ticket_id") or 0)
    lid = g.get("line_id")
    if tid <= 0 or lid is None:
        return False
    try:
        _lid_i = int(lid)
    except (TypeError, ValueError):
        _lid_i = None
    if _lid_i and _premios_linea_tiene_invalidacion_manual(cur, _lid_i):
        log.info(
            "Premio omitido por invalidación manual (upsert) line_id=%s ticket_id=%s",
            _lid_i,
            tid,
        )
        return False
    if os.environ.get("DEBUG_GANADORES_PREMIO_FLOW", "").strip().lower() in ("1", "true", "yes"):
        print(
            "CREANDO PREMIO (upsert pendiente):",
            "ticket_id=",
            tid,
            "line_id=",
            int(lid),
            "numero=",
            repr(g.get("number")),
            "premio=",
            g.get("premio"),
            "monto=",
            g.get("monto"),
        )
    resultado_txt = g.get("resultado")
    if isinstance(resultado_txt, (list, tuple)):
        resultado_txt = "-".join(str(x or "").strip() for x in resultado_txt)
    fecha_sorteo_txt = str(g.get("fecha_sorteo_linea") or g.get("fecha_sorteo") or "")[:10]
    fecha_resultado_txt = str(g.get("resultado_fecha_iso") or "")[:10]
    # Prioridad: día de sorteo en la línea (debe igualar tl.fecha_sorteo en JOIN de integridad).
    fecha_dia_txt = (fecha_sorteo_txt or fecha_resultado_txt or "")[:10]
    if _lid_i:
        try:
            cur.execute(
                _sql("SELECT fecha_sorteo FROM ticket_lines WHERE id = %s LIMIT 1"),
                (_lid_i,),
            )
            r_fs = cur.fetchone()
            if r_fs is not None:
                fs_raw = (
                    r_fs.get("fecha_sorteo")
                    if hasattr(r_fs, "get")
                    else (r_fs[0] if r_fs else None)
                )
                fs_line = str(fs_raw or "").strip()[:10]
                if len(fs_line) == 10:
                    fecha_sorteo_txt = fs_line
                    fecha_dia_txt = fs_line
        except Exception:
            _rollback_pg_cursor(cur)
    norm_bk = _premios_normalize_business_fields(
        g, fecha_sorteo_txt, fecha_resultado_txt, fecha_dia_txt
    )
    lot_u = norm_bk["lottery"]
    draw_u = norm_bk["draw"]
    num_u = norm_bk["numero"]
    fe_res_u = norm_bk["fecha_resultado"]
    shard_s = norm_bk["premio_shard"]
    play_chk = str(g.get("play") or "")
    plow = play_chk.strip().lower().replace("_", " ")
    is_qui = plow == "quiniela" or plow.startswith("quiniela")
    # Evitar doble devengo: antes había máximo una fila pendiente por line_id (shard '0').
    if is_qui and shard_s != "0" and _lid_i:
        try:
            if os.environ.get("DATABASE_URL"):
                cur.execute(
                    """
                    DELETE FROM premios
                    WHERE line_id = %s
                      AND lower(trim(COALESCE(estado, ''))) = 'pendiente'
                      AND premio_shard = '0'
                      AND lower(replace(trim(COALESCE(play, '')), ' ', '')) LIKE %s
                    """,
                    (_lid_i, "quiniela%"),
                )
            else:
                cur.execute(
                    _sql(
                        """
                        DELETE FROM premios
                        WHERE line_id = ?
                          AND lower(trim(COALESCE(estado, ''))) = 'pendiente'
                          AND premio_shard = '0'
                          AND lower(replace(trim(COALESCE(play, '')), ' ', '')) LIKE ?
                        """
                    ),
                    (_lid_i, "quiniela%"),
                )
        except Exception:
            _rollback_pg_cursor(cur)
    if not fe_res_u:
        fe_res_u = (fecha_resultado_txt or fecha_dia_txt or fecha_sorteo_txt or "")[:10]
    cajero_u = str(g.get("cajero") or "").strip()
    if not cajero_u and tid > 0:
        try:
            cur.execute(_sql("SELECT cajero FROM tickets WHERE id = %s LIMIT 1"), (tid,))
            rr_caj = cur.fetchone()
            if rr_caj is not None:
                cajero_u = str(
                    rr_caj.get("cajero") if hasattr(rr_caj, "get") else (rr_caj[0] if rr_caj else "")
                ).strip()
        except Exception:
            _rollback_pg_cursor(cur)
    vals = (
        tid,
        int(lid),
        num_u,
        float(g.get("monto") or 0),
        float(g.get("premio") or 0),
        lot_u,
        draw_u,
        str(g.get("play") or ""),
        str(resultado_txt or ""),
        fecha_sorteo_txt,
        fe_res_u,
        fecha_dia_txt,
        cajero_u,
        g.get("ganador_detectado_en"),
        shard_s,
    )
    _uq_cols = ", ".join(PREMIOS_UQ_BUSINESS_COLS)
    _uq_set = (
        "monto = EXCLUDED.monto, premio = EXCLUDED.premio, play = EXCLUDED.play, "
        "resultado = EXCLUDED.resultado, fecha_sorteo = EXCLUDED.fecha_sorteo, "
        "fecha_dia = EXCLUDED.fecha_dia, cajero = EXCLUDED.cajero, "
        "ganador_detectado_en = EXCLUDED.ganador_detectado_en, "
        "updated_at = CURRENT_TIMESTAMP"
    )
    dbg_qticket = os.environ.get("DEBUG_QUINIELA_TICKET_PREMIO", "").strip().lower() in (
        "1",
        "true",
        "yes",
    )
    if dbg_qticket:
        print("ticket:", tid)
        print("numero:", repr(g.get("number")))
        print("resultado:", repr(resultado_txt))
        print("premio_shard:", shard_s)
        print("premio detectado:", g.get("premio"))
    _upsert_sql_pg = (
        """
            INSERT INTO premios (
                ticket_id, line_id, numero, monto, premio, lottery, draw, play, resultado,
                fecha_sorteo, fecha_resultado, fecha_dia, cajero, ganador_detectado_en,
                premio_shard, estado
            )
            VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, 'pendiente')
            ON CONFLICT ("""
        + _uq_cols
        + """) DO UPDATE SET """
        + _uq_set
        + """
            WHERE lower(trim(COALESCE(premios.estado, ''))) = 'pendiente'
            """
    )
    _upsert_sql_sq = (
        """
            INSERT INTO premios (
                ticket_id, line_id, numero, monto, premio, lottery, draw, play, resultado,
                fecha_sorteo, fecha_resultado, fecha_dia, cajero, ganador_detectado_en,
                premio_shard, estado
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'pendiente')
            ON CONFLICT("""
        + _uq_cols
        + """) DO UPDATE SET """
        + _uq_set.replace("EXCLUDED.", "excluded.")
        + """
            WHERE lower(trim(COALESCE(premios.estado, ''))) = 'pendiente'
            """
    )
    try:
        if os.environ.get("DATABASE_URL"):
            cur.execute(_upsert_sql_pg, vals)
        else:
            cur.execute(_upsert_sql_sq, vals)
    except Exception as _upe:
        if getattr(_upe, "pgcode", None) == "23505" or "UNIQUE" in str(_upe).upper():
            log.warning(
                "premios upsert conflict (idempotente) ticket_id=%s line_id=%s: %s",
                tid,
                _lid_i,
                _upe,
            )
            _rollback_pg_cursor(cur)
        else:
            raise
    try:
        n_aff = int(cur.rowcount or 0)
    except (TypeError, ValueError):
        n_aff = 0
    if n_aff >= 1:
        return True
    if _lid_i:
        try:
            cur.execute(
                _sql(
                    """
                    SELECT lower(trim(COALESCE(estado, ''))) AS est
                    FROM premios
                    WHERE ticket_id = %s AND line_id = %s AND lottery = %s AND draw = %s
                      AND fecha_resultado = %s AND numero = %s AND premio_shard = %s
                    LIMIT 1
                    """
                ),
                (tid, _lid_i, lot_u, draw_u, fe_res_u, num_u, shard_s),
            )
            row_st = cur.fetchone()
            est_ex = ""
            if row_st is not None:
                est_ex = (
                    str(row_st.get("est") or "")
                    if hasattr(row_st, "get")
                    else str(row_st[0] or "")
                )
            if est_ex and est_ex != "pendiente":
                log.warning(
                    "premios upsert omitido (fila existente estado=%s) line_id=%s ticket_id=%s shard=%s",
                    est_ex,
                    _lid_i,
                    tid,
                    shard_s,
                )
        except Exception:
            _rollback_pg_cursor(cur)
    return False


def _premios_borrar_pendientes_ticket(cur, ticket_id):
    """
    Quita filas pendientes del ticket antes de re-devengar desde el cruce oficial.
    No borra pagado / invalidado; pagos_premios no se tocan.
    """
    try:
        tid = int(ticket_id)
    except (TypeError, ValueError):
        return
    if tid <= 0:
        return
    if os.environ.get("DATABASE_URL"):
        cur.execute(
            """
            DELETE FROM premios
            WHERE ticket_id = %s
              AND lower(trim(COALESCE(estado, ''))) = 'pendiente'
            """,
            (tid,),
        )
    else:
        cur.execute(
            _sql(
                """
                DELETE FROM premios
                WHERE ticket_id = %s
                  AND lower(trim(COALESCE(estado, ''))) = 'pendiente'
                """
            ),
            (tid,),
        )


def _premios_borrar_pendientes_linea(cur, line_id):
    """Elimina premios pendientes asociados a una línea de ticket (p. ej. antes de re-devengar esa línea)."""
    try:
        lid = int(line_id)
    except (TypeError, ValueError):
        return
    if lid <= 0:
        return
    if os.environ.get("DATABASE_URL"):
        cur.execute(
            """
            DELETE FROM premios
            WHERE line_id = %s
              AND lower(trim(COALESCE(estado, ''))) = 'pendiente'
            """,
            (lid,),
        )
    else:
        cur.execute(
            _sql(
                """
                DELETE FROM premios
                WHERE line_id = %s
                  AND lower(trim(COALESCE(estado, ''))) = 'pendiente'
                """
            ),
            (lid,),
        )


def _premios_norm_upsert_stats(st):
    """Normaliza retorno de `_premios_upsert_lista_cruce` (dict o int legado)."""
    if isinstance(st, dict):
        return {
            "insertados": int(st.get("insertados") or 0),
            "errores": int(st.get("errores") or 0),
            "conflict_ignored": int(st.get("conflict_ignored") or 0),
        }
    try:
        return {"insertados": int(st or 0), "errores": 0, "conflict_ignored": 0}
    except (TypeError, ValueError):
        return {"insertados": 0, "errores": 0, "conflict_ignored": 0}


def _premios_upsert_lista_cruce(cur, lista_acc, preclean_tickets=True):
    """UPSERT pendientes desde lista del cruce (idempotente por line_id + premio_shard)."""
    insertados = 0
    errores = 0
    conflict_ignored = 0
    is_pg_sync = bool(os.environ.get("DATABASE_URL"))
    if is_pg_sync:
        _pg_ensure_transaction_for_savepoints(cur)
    if preclean_tickets:
        lids_limpiar = []
        seen_l = set()
        for g in lista_acc or []:
            try:
                lid = int(g.get("line_id") or 0)
            except (TypeError, ValueError):
                continue
            if lid > 0 and lid not in seen_l:
                seen_l.add(lid)
                lids_limpiar.append(lid)
        for lid in lids_limpiar:
            _premios_borrar_pendientes_linea(cur, lid)
    for g in lista_acc or []:
        try:
            prem = float(g.get("premio") or 0)
        except (TypeError, ValueError):
            prem = 0.0
        if prem <= 0:
            continue
        try:
            _lid_sync = int(g.get("line_id"))
        except (TypeError, ValueError):
            _lid_sync = None
        if _lid_sync and _premios_linea_tiene_invalidacion_manual(cur, _lid_sync):
            log.info(
                "Premio omitido por invalidación manual (sync cruce) line_id=%s ticket_id=%s",
                _lid_sync,
                g.get("ticket_id"),
            )
            continue
        try:
            if is_pg_sync:
                cur.execute("SAVEPOINT premios_sync_ups_sp")
            if _premios_upsert_pendiente(cur, g):
                insertados += 1
                if is_pg_sync:
                    cur.execute("RELEASE SAVEPOINT premios_sync_ups_sp")
            elif is_pg_sync:
                cur.execute("RELEASE SAVEPOINT premios_sync_ups_sp")
        except Exception as _ie:
            if getattr(_ie, "pgcode", None) == "23505":
                conflict_ignored += 1
                log.debug("premios_sync duplicate key (ignorado): %s", _ie)
            else:
                errores += 1
                log.warning("premios_sync upsert línea: %s", _ie, exc_info=True)
            if is_pg_sync:
                try:
                    cur.execute("ROLLBACK TO SAVEPOINT premios_sync_ups_sp")
                except Exception:
                    _rollback_pg_cursor(cur)
                    _pg_ensure_transaction_for_savepoints(cur)
    return {
        "insertados": insertados,
        "errores": errores,
        "conflict_ignored": conflict_ignored,
    }


def _premios_quick_sync_day(cur, day_str, cajero_username=None):
    """
    Una sola fecha RD: cruce oficial + UPSERT pendientes.

    No recorre la ventana multi-día (`PREMIOS_SYNC_MULTI_DAY_HTTP`); corrige BD frente al cruce
    vivo sólo para `day_str`.
    """
    hoy_s = (day_str or "").strip()[:10]
    if len(hoy_s) != 10:
        return {"ok": False, "insertados": 0, "message": "fecha día inválida", "lista_cruce_ganadores": []}
    t_perf = time.perf_counter()
    consulta_tickets_ms = 0.0
    consulta_resultados_ms = 0.0
    cruce_ms = 0.0
    crear_premios_ms = 0.0
    try:
        t_ct = time.perf_counter()
        n_tickets = _ganadores_count_tickets_fecha(cur, hoy_s, cajero_username)
        consulta_tickets_ms = round((time.perf_counter() - t_ct) * 1000, 2)
        t_cr = time.perf_counter()
        n_resultados = _ganadores_count_resultados_fecha(cur, hoy_s)
        consulta_resultados_ms = round((time.perf_counter() - t_cr) * 1000, 2)
        cfg = _ganadores_try_load_pagos_config(cur) or {}
        pagos_efectivo = {**PAGOS, **cfg}
        t_cruce = time.perf_counter()
        join_rows = _ganadores_fetch_lineas_vs_resultados(
            cur, hoy_s, cajero_username=cajero_username
        )
        cruce_ms = round((time.perf_counter() - t_cruce) * 1000, 2)
        lista_day = _ganadores_procesar_filas(
            join_rows,
            pagos=pagos_efectivo,
            hoy_rd_str=hoy_s,
            cur=cur,
        )
        t_ups = time.perf_counter()
        ins = _premios_upsert_lista_cruce(cur, lista_day)
        crear_premios_ms = round((time.perf_counter() - t_ups) * 1000, 2)
        ns = _premios_norm_upsert_stats(ins)
        if join_rows or int(ns.get("insertados") or 0) > 0:
            _premios_marcar_sync_hecho(hoy_s)
        _admin_lineas_eval_guardar_per_desde_cruce(join_rows, lista_day, hoy_s)
        log.info(
            "PERF premios_quick_sync día=%s tickets=%s resultados=%s "
            "consulta_tickets_ms=%s consulta_resultados_ms=%s cruce_ms=%s crear_premios_ms=%s total_ms=%s",
            hoy_s,
            n_tickets,
            n_resultados,
            consulta_tickets_ms,
            consulta_resultados_ms,
            cruce_ms,
            crear_premios_ms,
            round((time.perf_counter() - t_perf) * 1000, 2),
        )
        return {
            "ok": True,
            "insertados": ns["insertados"],
            "premios_sync_stats": ns,
            "message": "ok",
            "lista_cruce_ganadores": list(lista_day or []),
            "perf": {
                "consulta_tickets_ms": consulta_tickets_ms,
                "consulta_resultados_ms": consulta_resultados_ms,
                "cruce_ms": cruce_ms,
                "crear_premios_ms": crear_premios_ms,
            },
        }
    except Exception as e:
        log.warning("_premios_quick_sync_day(%s): %s", hoy_s, e, exc_info=True)
        _rollback_pg_cursor(cur)
        return {"ok": False, "insertados": 0, "message": str(e), "lista_cruce_ganadores": []}


def _premios_sync_desde_cruce_hoy(cur, hoy_rd: str, cajero_username: str = None):
    """
    Upsert líneas ganadoras en `premios` cruzando ticket_lines ↔ resultados.

    Para el día RD `hoy_rd` equivale al cruce estricto (fecha línea ↔ fecha resultado ese día).
    Además revisa hasta N días hacia atrás (`_ganadores_pagos_ventana_calendario_dias`) modo que
    al cambiar de día calendario (p. ej. sorteos ayer sin pagar al abrir pantalla mañana) sigan apareciendo
    en lista y eventualmente persistidos en premios como pendiente si faltaban.
    """
    hoy_s = (hoy_rd or "").strip()[:10]
    if len(hoy_s) != 10:
        return {"ok": False, "insertados": 0, "message": "fecha hoy inválida", "lista_cruce_ganadores": []}

    dias = _ganadores_sync_ventana_dias_http_efectivos()
    hoy_d = _parse_iso_date_only(hoy_s) or ahora_rd().date()

    lista_acc = []
    try:
        cfg = _ganadores_try_load_pagos_config(cur) or {}
        pagos_efectivo = {**PAGOS, **cfg}
        for offset in range(dias - 1, -1, -1):
            day_str = (hoy_d - timedelta(days=offset)).strftime("%Y-%m-%d")
            join_rows = _ganadores_fetch_lineas_vs_resultados(
                cur, day_str, cajero_username=cajero_username
            )
            lista_day = _ganadores_procesar_filas(
                join_rows,
                pagos=pagos_efectivo,
                hoy_rd_str=day_str,
                cur=cur,
            )
            lista_acc.extend(lista_day or [])
    except Exception as e:
        log.warning("premios_sync_desde_cruce_hoy: %s", e, exc_info=True)
        _rollback_pg_cursor(cur)
        return {"ok": False, "insertados": 0, "message": str(e), "lista_cruce_ganadores": []}

    st = _premios_upsert_lista_cruce(cur, lista_acc)
    ns = _premios_norm_upsert_stats(st)
    return {
        "ok": True,
        "insertados": ns["insertados"],
        "premios_sync_stats": ns,
        "message": "ok",
        "lista_cruce_ganadores": list(lista_acc or []),
    }


def _premios_triple_desde_columna_resultado(resultado_txt):
    """Parsea premios.resultado 'a-b-c' → triple normalizado (dos dígitos); None si vacío o inválido."""
    if resultado_txt is None or not str(resultado_txt).strip():
        return None
    parts = [x.strip() for x in str(resultado_txt).split("-")]
    while len(parts) < 3:
        parts.append("")
    if not any(parts[:3]):
        return None
    return (
        _norm_sorteo_dos_digitos(parts[0]),
        _norm_sorteo_dos_digitos(parts[1]),
        _norm_sorteo_dos_digitos(parts[2]),
    )


def _premio_evaluar_inconsistencia_resultado(cur, premio_row: dict, pagos=None):
    """
    Compara el triple guardado en premios.resultado con el sorteo oficial estricto en `resultados`
    y reproduce el monto con calcular_premio.

    Retorna (es_inconsistente: bool, resultado_original_str, resultado_correcto_str, motivo|None).
    """
    P = pagos if pagos is not None else PAGOS
    try:
        p_rem = float(premio_row.get("premio") or 0)
    except (TypeError, ValueError):
        p_rem = 0.0
    if p_rem <= 0:
        return False, "", "", None

    lottery = premio_row.get("lottery")
    draw = premio_row.get("draw")
    fe = (
        str(
            premio_row.get("fecha_dia")
            or premio_row.get("fecha_resultado")
            or premio_row.get("fecha_sorteo")
            or ""
        ).strip()[:10]
    )
    orig_s = str(premio_row.get("resultado") or "").strip()
    orig_t = _premios_triple_desde_columna_resultado(orig_s)

    if len(fe) != 10:
        return True, orig_s or "—", "—", "Fecha RD inválida o ausente en premio"

    triple, err, _info = _resultado_sorteo_resolver_estricto(cur, lottery, draw, fe)

    if err == "duplicado_sorteo":
        return (
            True,
            orig_s or "—",
            "—",
            "Sorteo duplicado en tabla resultados; no se puede validar el premio",
        )

    if triple is None or err:
        return (
            True,
            orig_s or "—",
            "—",
            "Sin resultado oficial exacto (lotería/hora/fecha) o error de resolución: %s" % (err or ""),
        )

    cn = (
        _norm_sorteo_dos_digitos(triple[0]),
        _norm_sorteo_dos_digitos(triple[1]),
        _norm_sorteo_dos_digitos(triple[2]),
    )
    corr_fmt = "-".join(x for x in cn if x)

    if orig_t != cn:
        return (
            True,
            orig_s or "—",
            corr_fmt,
            "Premio registrado con triple distinto al oficial en tabla resultados (bug de cruce)",
        )

    try:
        p_recalc = float(
            calcular_premio(
                _play_efectivo_cruce(premio_row.get("play"), premio_row.get("numero")),
                premio_row.get("numero"),
                premio_row.get("monto"),
                triple[0],
                triple[1],
                triple[2],
                pagos=P,
            )
            or 0
        )
    except Exception:
        p_recalc = 0.0
    if abs(p_recalc - p_rem) > 0.02:
        return (
            True,
            orig_s or "—",
            corr_fmt,
            "Monto de premio no reproduce con resultado oficial y jugada guardada",
        )

    return False, orig_s, corr_fmt, None


def _premios_inconsistentes_ya_registrado(cur, premio_id: int) -> bool:
    try:
        pid = int(premio_id)
    except (TypeError, ValueError):
        return False
    cur.execute(
        _sql("SELECT 1 FROM premios_inconsistentes WHERE premio_id = %s LIMIT 1"),
        (pid,),
    )
    return cur.fetchone() is not None


def _premios_inconsistentes_insertar(cur, **kwargs):
    """Inserta fila de auditoría (un premio_id solo una vez por índice único)."""
    is_pg = bool(os.environ.get("DATABASE_URL"))
    premio_id = int(kwargs.get("premio_id") or 0)
    if premio_id <= 0:
        return False
    vals = (
        premio_id,
        kwargs.get("ticket_id"),
        kwargs.get("line_id"),
        str(kwargs.get("lottery") or ""),
        str(kwargs.get("draw") or ""),
        str(kwargs.get("fecha_rd") or "")[:10],
        str(kwargs.get("jugada") or ""),
        str(kwargs.get("resultado_usado_original") or ""),
        str(kwargs.get("resultado_correcto") or ""),
        float(kwargs.get("monto_pagado") or 0),
        str(kwargs.get("motivo") or ""),
    )
    try:
        if is_pg:
            cur.execute(
                """
                INSERT INTO premios_inconsistentes (
                    premio_id, ticket_id, line_id, lottery, draw, fecha_rd, jugada,
                    resultado_usado_original, resultado_correcto, monto_pagado, motivo
                )
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
                ON CONFLICT (premio_id) DO NOTHING
                """,
                vals,
            )
        else:
            cur.execute(
                _sql(
                    """
                INSERT OR IGNORE INTO premios_inconsistentes (
                    premio_id, ticket_id, line_id, lottery, draw, fecha_rd, jugada,
                    resultado_usado_original, resultado_correcto, monto_pagado, motivo
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """
                ),
                vals,
            )
        return True
    except Exception as _e:
        log.warning("premios_inconsistentes_insertar: %s", _e, exc_info=True)
        return False


def recalcular_premios_dia_seguro(conn, fecha_rd: str, dry_run: bool = False, cajero_username: str = None):
    """
    Limpia y recalcula premios **pendientes** del día si el triple guardado no coincide con `resultados`
    (resolutor estricto). Premios **pagados** nunca se borran ni se modifican; solo se registran en
    `premios_inconsistentes` si hay inconsistencia. Premios ya auditados (mismo premio_id) se omiten.

    Retorna dict resumen: eliminados_pendiente, insertados_sync, pagados_inconsistentes,
    omitidos_ya_auditados, monto_total_pagado_afectado, dry_run, fecha, ok.
    """
    fecha_s = (str(fecha_rd or "").strip()[:10])
    summary = {
        "ok": True,
        "fecha": fecha_s,
        "dry_run": bool(dry_run),
        "eliminados_pendiente": 0,
        "insertados_sync": 0,
        "pagados_inconsistentes": 0,
        "omitidos_ya_auditados": 0,
        "consistentes": 0,
        "monto_total_pagado_afectado": 0.0,
        "message": "",
    }
    if len(fecha_s) != 10:
        summary["ok"] = False
        summary["message"] = "fecha inválida (use YYYY-MM-DD)"
        return summary

    if not dry_run:
        db_backup_before_dangerous_op("recalcular_premios_dia_" + fecha_s)

    cur = conn.cursor()
    cfg = _ganadores_try_load_pagos_config(cur) or {}
    pagos_efectivo = {**PAGOS, **cfg}

    caj_filter = ""
    caj_params = ()
    if (cajero_username or "").strip():
        caj_filter = " AND lower(trim(COALESCE(p.cajero, ''))) = lower(trim(%s))"
        caj_params = ((cajero_username or "").strip(),)

    cur.execute(
        _sql(
            """
            SELECT p.id, p.ticket_id, p.line_id, p.numero, p.monto, p.premio, p.lottery, p.draw, p.play,
                   p.resultado, p.fecha_sorteo, p.fecha_resultado, p.fecha_dia, p.estado, p.cajero
            FROM premios p
            WHERE p.line_id IS NOT NULL
              AND (
                substr(trim(COALESCE(p.fecha_dia, '')), 1, 10) = %s
                OR substr(trim(COALESCE(p.fecha_resultado, '')), 1, 10) = %s
                OR substr(trim(COALESCE(p.fecha_sorteo, '')), 1, 10) = %s
              )
            """
            + caj_filter
            + """
            ORDER BY p.id ASC
            """
        ),
        (fecha_s, fecha_s, fecha_s) + caj_params,
    )
    rows = cur.fetchall() or []

    is_pg = bool(os.environ.get("DATABASE_URL"))
    if not dry_run and not is_pg:
        try:
            cur.execute("BEGIN IMMEDIATE")
        except Exception:
            try:
                cur.execute("BEGIN")
            except Exception:
                pass

    for row in rows:
        d = dict(row) if hasattr(row, "keys") else {
            "id": row[0],
            "ticket_id": row[1],
            "line_id": row[2],
            "numero": row[3],
            "monto": row[4],
            "premio": row[5],
            "lottery": row[6],
            "draw": row[7],
            "play": row[8],
            "resultado": row[9],
            "fecha_sorteo": row[10],
            "fecha_resultado": row[11],
            "fecha_dia": row[12],
            "estado": row[13],
            "cajero": row[14],
        }
        pid = int(d.get("id") or 0)
        if pid <= 0:
            continue
        estado_row = str(d.get("estado") or "").strip().lower()
        if estado_row in PREMIOS_ESTADOS_OCULTOS_GANADORES:
            continue
        if _premios_inconsistentes_ya_registrado(cur, pid):
            summary["omitidos_ya_auditados"] += 1
            continue

        inc, orig_s, corr_s, motivo = _premio_evaluar_inconsistencia_resultado(
            cur, d, pagos=pagos_efectivo
        )
        if not inc:
            summary["consistentes"] += 1
            continue

        estado = str(d.get("estado") or "").strip().lower()
        fe_rd = (
            str(d.get("fecha_dia") or d.get("fecha_resultado") or d.get("fecha_sorteo") or "")[:10]
        )
        monto_afect = float(d.get("premio") or 0)

        if estado == "pagado":
            summary["pagados_inconsistentes"] += 1
            summary["monto_total_pagado_afectado"] += monto_afect
            if not dry_run:
                _premios_inconsistentes_insertar(
                    cur,
                    premio_id=pid,
                    ticket_id=d.get("ticket_id"),
                    line_id=d.get("line_id"),
                    lottery=d.get("lottery"),
                    draw=d.get("draw"),
                    fecha_rd=fe_rd,
                    jugada=d.get("numero"),
                    resultado_usado_original=orig_s,
                    resultado_correcto=corr_s,
                    monto_pagado=monto_afect,
                    motivo=motivo
                    or "Premio pagado usando resultado incorrecto por bug de cruce",
                )
        else:
            if not dry_run:
                cur.execute(
                    _sql(
                        "DELETE FROM premios WHERE id = %s AND lower(trim(COALESCE(estado,''))) = 'pendiente'"
                    ),
                    (pid,),
                )
                try:
                    rc = int(cur.rowcount or 0)
                except (TypeError, ValueError):
                    rc = 0
                if rc:
                    summary["eliminados_pendiente"] += rc
            else:
                summary["eliminados_pendiente"] += 1

    if not dry_run:
        try:
            sync = _premios_sync_desde_cruce_hoy(cur, fecha_s, cajero_username=cajero_username)
            summary["insertados_sync"] = int(sync.get("insertados") or 0)
            if not sync.get("ok"):
                summary["ok"] = False
                summary["message"] = str(sync.get("message") or "sync falló")
                raise RuntimeError(summary["message"])
            conn.commit()
        except Exception as _ce:
            log.warning("recalcular_premios_dia_seguro: %s", _ce, exc_info=True)
            try:
                conn.rollback()
            except Exception:
                pass
            summary["ok"] = False
            if not summary.get("message"):
                summary["message"] = str(_ce)
    else:
        try:
            conn.rollback()
        except Exception:
            pass

    return summary


def _premios_sync_por_sorteo(cur, fecha: str, loteria: str, hora_sorteo: str, cajero_username: str = None):
    """
    Sincroniza premios SOLO para un sorteo específico (fecha RD + lotería + draw/hora).
    Solo participan líneas con ticket_lines.fecha_sorteo == fecha del resultado y == parámetro `fecha`.
    Más eficiente que recalcular todo el día.

    - No borra nada.
    - Evita duplicados por `line_id` (upsert existente).
    - Usa el mismo pipeline de cruce que /ganadores.
    """
    fecha_s = (str(fecha or "").strip()[:10])
    if len(fecha_s) != 10:
        return {"ok": False, "insertados": 0, "message": "fecha inválida"}
    lot_s = (normalizar_loteria(loteria) or str(loteria or "").strip())
    draw_s = (formatear_hora_estandar(str(hora_sorteo or "").strip()) or str(hora_sorteo or "").strip())
    draw_s = (normalizar_sorteo(draw_s) or draw_s).strip()
    if not lot_s or not draw_s:
        return {"ok": False, "insertados": 0, "message": "lotería/sorteo inválido"}

    print(">>> Sync por sorteo:", lot_s, draw_s, "| fecha:", fecha_s)
    lot_key = clave_loteria(lot_s)

    params = [fecha_s, fecha_s]  # tl/r fecha
    extra_params = []
    filt_caj = bool((cajero_username or "").strip())
    if filt_caj:
        extra_params.append((cajero_username or "").strip())

    # draw_eq_tl y draw_eq_r usan 2 placeholders %s cada uno (OR con forma compacta).
    draw_bind = [draw_s, draw_s, draw_s, draw_s]
    bind_tail = draw_bind + [lot_key] + params + (extra_params if filt_caj else [])

    rows_out = []
    try:
        if os.environ.get("DATABASE_URL"):
            _rfd = _sql_expr_resultados_fecha_calendario_rd_pg("r.fecha")
            _tfd = "to_date(substr(NULLIF(trim(CAST(tl.fecha_sorteo AS text)), ''), 1, 10), 'YYYY-MM-DD')"
            # filtros por sorteo específico (clave lotería + draw)
            lot_expr_tl = _sql_expr_clave_loteria_pg("tl.lottery")
            lot_expr_r = _sql_expr_clave_loteria_pg("r.lottery")
            draw_eq_tl = _sql_expr_draw_col_eq_param_pg(_sql_expr_draw_effective_pg("tl.lottery", "tl.draw"))
            draw_eq_r = _sql_expr_draw_col_eq_param_pg("r.draw")
            caj_filter_pg = (
                " AND lower(trim(COALESCE(tk.cajero, ''))) = lower(trim(%s))" if filt_caj else ""
            )
            cur.execute(
                f"""
                SELECT tl.id AS line_id,
                       tl.ticket_id,
                       tk.cajero,
                       tl.number,
                       tl.lottery,
                       tl.draw,
                       tl.play,
                       lower(replace(trim(COALESCE(tl.play, '')), ' ', '')) AS play_norm,
                       tl.amount,
                       r.primero,
                       r.segundo,
                       r.tercero,
                       tl.fecha_sorteo,
                       tk.created_at AS ticket_fecha,
                       r.fecha AS resultado_fecha,
                       r.lottery AS res_lottery,
                       r.draw AS res_draw,
                       r.confirmado AS res_confirmado,
                       r.publicado AS res_publicado,
                       r.estado AS res_estado,
                       tk.pagado AS ticket_pagado,
                       tl.pagado AS linea_pagada,
                       COALESCE(tl.premio_linea_pagada, 0) AS premio_linea_pagada,
                       r.ganador_detectado_en AS res_ganador_detectado_en
                FROM ticket_lines tl
                INNER JOIN tickets tk ON tk.id = tl.ticket_id
                INNER JOIN resultados r
                  ON {lot_expr_tl} = {lot_expr_r}
                 AND {_tfd} = {_rfd}
                 AND ({draw_eq_tl})
                 AND ({draw_eq_r})
                 AND ({lot_expr_r} = %s)
                 AND (r.publicado IS TRUE)
                 AND lower(trim(COALESCE(NULLIF(trim(CAST(r.estado AS TEXT)), ''), 'cerrado'))) = 'cerrado'
                WHERE {_tfd} = (%s::date)
                  AND {_rfd} = (%s::date)
                  AND """
                + _sql_bool_not_true("tk.pagado")
                + """
                  AND """
                + _sql_bool_not_true("tl.pagado")
                + """
                  AND COALESCE(tl.premio_linea_pagada, 0) = 0
                  AND length(trim(COALESCE(CAST(tl.fecha_sorteo AS text), ''))) >= 10
                  AND (tk.created_at AT TIME ZONE 'America/Santo_Domingo')::date
                      = to_date(substr(NULLIF(trim(CAST(tl.fecha_sorteo AS text)), ''), 1, 10), 'YYYY-MM-DD')
                  AND COALESCE(tl.estado, 'activo') <> 'cancelado'
                """
                + caj_filter_pg
                + """
                ORDER BY tl.ticket_id, tl.id
                """,
                tuple(bind_tail),
            )
        else:
            _rfsq = _sql_expr_resultados_fecha_calendario_rd_sqlite("r.fecha")
            # IMPORTANT: en cruces, la fecha del ticket SIEMPRE debe venir de ticket_lines.fecha_sorteo.
            _tfsq = "substr(trim(COALESCE(tl.fecha_sorteo, '')), 1, 10)"
            lot_eq = "clave_loteria(tl.lottery) = clave_loteria(r.lottery)"
            draw_eq_tl = _sql_expr_draw_col_eq_param_sqlite("tl.draw")
            draw_eq_r = _sql_expr_draw_col_eq_param_sqlite("r.draw")
            caj_filter_sq = (
                " AND lower(trim(COALESCE(tk.cajero, ''))) = lower(trim(%s))" if filt_caj else ""
            )
            cur.execute(
                _sql(
                    f"""
                SELECT tl.id AS line_id,
                       tl.ticket_id,
                       tk.cajero,
                       tl.number,
                       tl.lottery,
                       tl.draw,
                       tl.play,
                       lower(replace(trim(ifnull(tl.play, '')), ' ', '')) AS play_norm,
                       tl.amount,
                       r.primero,
                       r.segundo,
                       r.tercero,
                       tl.fecha_sorteo,
                       tk.created_at AS ticket_fecha,
                       r.fecha AS resultado_fecha,
                       r.lottery AS res_lottery,
                       r.draw AS res_draw,
                       r.confirmado AS res_confirmado,
                       r.publicado AS res_publicado,
                       r.estado AS res_estado,
                       tk.pagado AS ticket_pagado,
                       tl.pagado AS linea_pagada,
                       COALESCE(tl.premio_linea_pagada, 0) AS premio_linea_pagada,
                       r.ganador_detectado_en AS res_ganador_detectado_en
                FROM ticket_lines tl
                INNER JOIN tickets tk ON tk.id = tl.ticket_id
                INNER JOIN resultados r
                  ON {lot_eq}
                 AND date({_tfsq}) = date({_rfsq})
                 AND ({draw_eq_tl})
                 AND ({draw_eq_r})
                 AND (clave_loteria(r.lottery) = %s)
                 AND r.publicado = 1
                 AND lower(trim(COALESCE(NULLIF(trim(ifnull(r.estado, '')), ''), 'cerrado'))) = 'cerrado'
                WHERE date({_tfsq}) = date(%s)
                  AND date({_rfsq}) = date(%s)
                  AND COALESCE(tk.pagado, 0) = 0
                  AND COALESCE(tl.pagado, 0) = 0
                  AND COALESCE(tl.premio_linea_pagada, 0) = 0
                  AND length(trim(COALESCE(tl.fecha_sorteo, ''))) >= 10
                  AND date(substr(trim(COALESCE(tk.created_at, '')), 1, 10))
                      = date(substr(trim(COALESCE(tl.fecha_sorteo, '')), 1, 10))
                  AND COALESCE(tl.estado, 'activo') <> 'cancelado'
                  {caj_filter_sq}
                ORDER BY tl.ticket_id, tl.id
                """
                ),
                tuple(bind_tail),
            )

        _dbg_fs = os.environ.get("DEBUG_CRUCE_TICKET_RESULTADO_FECHA", "").strip().lower() in (
            "1",
            "true",
            "yes",
        )
        for row in cur.fetchall() or []:
            dd = dict(row) if hasattr(row, "keys") else row
            if isinstance(dd, dict):
                if not _ganadores_row_fecha_linea_eq_resultado_strict(dd):
                    if _dbg_fs:
                        _tl = _parse_iso_date_only((str(dd.get("fecha_sorteo") or "").strip()[:10]))
                        _rf = _parse_iso_date_only(dd.get("resultado_fecha"))
                        print(
                            "_premios_sync_por_sorteo DESCARTO fecha:",
                            "numero",
                            repr(dd.get("number")),
                            "fecha_sorteo",
                            _tl.isoformat() if _tl else None,
                            "resultado",
                            _rf.isoformat() if _rf else None,
                        )
                    continue
                tls = (str(dd.get("fecha_sorteo") or "").strip())[:10]
                if tls != fecha_s:
                    if _dbg_fs:
                        print(
                            "_premios_sync_por_sorteo DESCARTO:",
                            "fecha_sorteo",
                            tls,
                            "!= fecha sync",
                            fecha_s,
                            "line_id",
                            dd.get("line_id"),
                        )
                    continue
            rows_out.append(dd)
    except Exception as e:
        log.warning("premios_sync_por_sorteo query: %s", e, exc_info=True)
        return {"ok": False, "insertados": 0, "message": str(e)}

    cfg = _ganadores_try_load_pagos_config(cur) or {}
    ganadores = _ganadores_procesar_filas(
        rows_out, pagos={**PAGOS, **cfg}, hoy_rd_str=fecha_s, cur=cur
    )
    print("Ganadores detectados:", len(ganadores))

    insertados = 0
    for g in ganadores or []:
        try:
            prem = float(g.get("premio") or 0)
        except (TypeError, ValueError):
            prem = 0.0
        if prem <= 0:
            continue
        print("INSERTANDO GANADOR:", g.get("ticket_id"))
        if _premios_upsert_pendiente(cur, g):
            insertados += 1
            print("guardado OK")

    print(">>> Insertados:", insertados)
    return {"ok": True, "insertados": insertados, "message": "ok"}


def _premios_marcar_ticket_pagado(cur, ticket_id):
    """Único cierre contable del premio: pendiente -> pagado con fecha_pago."""
    _ts_pago_rd = timestamp_rd_iso()
    if os.environ.get("DATABASE_URL"):
        cur.execute(
            """
            UPDATE premios
            SET estado = 'pagado',
                fecha_pago = (NOW() AT TIME ZONE 'America/Santo_Domingo'),
                updated_at = CURRENT_TIMESTAMP
            WHERE ticket_id = %s AND estado = 'pendiente'
            """,
            (int(ticket_id),),
        )
    else:
        cur.execute(
            _sql(
                """
            UPDATE premios
            SET estado = 'pagado', fecha_pago = ?, updated_at = CURRENT_TIMESTAMP
            WHERE ticket_id = ? AND estado = 'pendiente'
            """
            ),
            (_ts_pago_rd, int(ticket_id)),
        )


def _premios_reabrir_ticket_pendiente(cur, ticket_id, premio_ids=None):
    """
    Reversa lógica: premios del ticket vuelven a pendiente (sin DELETE).
    Incluye filas con fecha_pago y premio_id ligados al pago revertido.
    """
    tid = int(ticket_id or 0)
    if tid <= 0:
        return
    cur.execute(
        _sql(
            """
            UPDATE premios
            SET estado = %s, fecha_pago = NULL, updated_at = CURRENT_TIMESTAMP
            WHERE ticket_id = %s AND (
                lower(trim(COALESCE(estado,''))) IN (%s, %s)
                OR (
                    fecha_pago IS NOT NULL
                    AND lower(trim(COALESCE(estado,''))) NOT IN (%s, %s, %s)
                )
            )
            """
        ),
        (
            "pendiente",
            tid,
            "pagado",
            "invalidado_pagado",
            "invalidado",
            "eliminado_admin",
            "manual_review",
        ),
    )
    ids_forzar = []
    for p in premio_ids or []:
        try:
            pid = int(p)
        except (TypeError, ValueError):
            continue
        if pid > 0:
            ids_forzar.append(pid)
    if not ids_forzar:
        cur.execute(
            _sql(
                """
                SELECT DISTINCT premio_id FROM pagos_premios
                WHERE ticket_id = %s AND premio_id IS NOT NULL
                """
            ),
            (tid,),
        )
        for row in cur.fetchall() or []:
            try:
                ids_forzar.append(int(_banco_row_val(row, "premio_id", 0)))
            except (TypeError, ValueError):
                pass
    for pid in sorted(set(ids_forzar)):
        cur.execute(
            _sql(
                """
                UPDATE premios
                SET estado = %s, fecha_pago = NULL, updated_at = CURRENT_TIMESTAMP
                WHERE id = %s AND ticket_id = %s
                  AND lower(trim(COALESCE(estado,''))) NOT IN (%s, %s, %s)
                """
            ),
            ("pendiente", pid, tid, "invalidado", "eliminado_admin", "manual_review"),
        )


def _premios_resync_pendientes_desde_cruce_ticket(cur, ticket_id):
    """
    Tras reabrir un pago, recalcula premios pendientes del ticket igual que `/ganadores`
    y hace UPSERT en `premios`. Evita persistir sólo la mitad correcta cuando la fórmula cambió.
    """
    try:
        tid = int(ticket_id)
    except (TypeError, ValueError):
        return
    if tid <= 0:
        return
    fecha_ref = _ticket_fecha_sorteo_para_premio(cur, tid)
    if not fecha_ref or len(str(fecha_ref).strip()) < 10:
        return
    fecha_ref = str(fecha_ref).strip()[:10]
    try:
        cfg = _ganadores_try_load_pagos_config(cur) or {}
        pagos_efectivo = {**PAGOS, **cfg}
        _premios_borrar_pendientes_ticket(cur, tid)
        join_rows = _ganadores_fetch_lineas_vs_resultados(cur, fecha_ref, ticket_id=tid)
        lista = _ganadores_procesar_filas(
            join_rows or [], pagos=pagos_efectivo, hoy_rd_str=fecha_ref, cur=cur
        )
        _premios_upsert_lista_cruce(cur, lista, preclean_tickets=False)
    except Exception as e:
        log.warning(
            "premios resync tras revert ignorado ticket_id=%s: %s",
            tid,
            e,
            exc_info=True,
        )


def _premios_resync_pending_ticket_ids_bounded(cur, max_tickets=400):
    """
    Recalcula `premios` pendientes desde el cruce oficial por ticket_id (todas las fechas).
    Sin esto, filas viejas pueden quedar con monto incompleto pese a que el JOIN ya suma bien.
    """
    try:
        mt = max(50, min(int(max_tickets), 2500))
    except (TypeError, ValueError):
        mt = 400
    is_pg = bool(os.environ.get("DATABASE_URL"))
    try:
        if is_pg:
            cur.execute(
                """
                SELECT DISTINCT p.ticket_id
                FROM premios p
                WHERE p.estado = %s
                ORDER BY p.ticket_id DESC
                LIMIT %s
                """,
                ("pendiente", mt),
            )
        else:
            cur.execute(
                _sql(
                    """
                    SELECT DISTINCT p.ticket_id
                    FROM premios p
                    WHERE p.estado = %s
                    ORDER BY p.ticket_id DESC
                    LIMIT %s
                    """
                ),
                ("pendiente", mt),
            )
        ids = []
        for row in cur.fetchall() or []:
            try:
                ids.append(int(row["ticket_id"] if hasattr(row, "keys") else row[0]))
            except (TypeError, ValueError, KeyError):
                continue
        for tid in ids:
            if tid <= 0:
                continue
            _premios_resync_pendientes_desde_cruce_ticket(cur, tid)
    except Exception as e:
        log.warning("_premios_resync_pending_ticket_ids_bounded: %s", e, exc_info=True)


def _premios_lista_integridad_join_sql():
    """JOIN ticket_lines + tickets: la lista de ganadores solo premios con línea/ticket reales."""
    return """
            INNER JOIN ticket_lines tl ON tl.id = p.line_id
            INNER JOIN tickets tk ON tk.id = p.ticket_id
    """


def _premios_lista_integridad_where_sql_pg():
    """
    Evita «ganadores falsos» persistidos en `premios`:
    - fecha_sorteo de la línea == fecha guardada en premio (fecha_dia / resultado / sorteo)

    No borra filas; solo las excluye de la UI / totales.
    Guardas con to_date sobre cadenas cortas/vacías (evita errores SQL en PG).
    """
    _tls = "trim(COALESCE(CAST(tl.fecha_sorteo AS text), ''))"
    _pcs = (
        "trim(COALESCE(CAST(p.fecha_dia AS text), CAST(p.fecha_resultado AS text), CAST(p.fecha_sorteo AS text), ''))"
    )
    _tlfd = (
        f"CASE WHEN length({_tls}) >= 10 "
        f"THEN to_date(substr({_tls}, 1, 10), 'YYYY-MM-DD') ELSE NULL END"
    )
    _pfd = (
        f"CASE WHEN length({_pcs}) >= 10 "
        f"THEN to_date(substr({_pcs}, 1, 10), 'YYYY-MM-DD') ELSE NULL END"
    )
    return (
        f"""
            AND p.line_id IS NOT NULL
            AND length({_tls}) >= 10
            AND length({_pcs}) >= 10
            AND {_tlfd} IS NOT NULL
            AND {_pfd} IS NOT NULL
            AND {_tlfd} = {_pfd}
            """
        + _sql_ticket_no_eliminado("tk")
    )


def _premios_lista_integridad_where_sql_sqlite():
    return (
        """
            AND p.line_id IS NOT NULL
            AND length(trim(COALESCE(tl.fecha_sorteo, ''))) >= 10
            AND date(substr(trim(COALESCE(tl.fecha_sorteo, '')), 1, 10))
                = date(substr(trim(COALESCE(p.fecha_dia, p.fecha_resultado, p.fecha_sorteo, '')), 1, 10))
    """
        + _sql_ticket_no_eliminado("tk")
    )


def _premios_fetch_por_estado(
    cur,
    estado,
    cajero_username=None,
    limit=None,
    fecha_ref=None,
    restrict_line_ids=None,
    omit_integridad_fecha=False,
    extend_pendiente_ventana=False,
    offset=None,
    order_pendientes_historico=False,
    order_ticket_id_desc=False,
):
    """Obtiene premios por estado.

    `estado` puede ser:
      - una cadena (un solo estado), p.ej. "pendiente".
      - una lista/tupla/set de estados; se aplicará p.estado IN (...).

    Para la "Lista de Ganadores" se debe pasar `["pendiente", "pagado"]` para mostrar
    todos los ganadores del día (pendientes + ya pagados) y NO solo el primero.
    Los estados ocultos (invalidado / invalidado_pagado / manual_review / eliminado_admin)
    nunca deben pasarse aquí.

    Si `fecha_ref` (YYYY-MM-DD) está presente, filtra por fecha_dia / fecha_sorteo / fecha_resultado.

    Si además `extend_pendiente_ventana=True` y el estado incluye «pendiente», también incluye
    premios pendientes con fecha_sorteo de la **línea** en `[hoy − N, fecha_ref]` (ticket no pagado).
    Sirve cuando el día calendario avanzó pero aún debe pagarse un premio del sorteo anterior.

    `restrict_line_ids`: lista de ticket_lines.id; fuerza ese subconjunto (útil cuando el JOIN de
    integridad fecha línea↔premio filtra filas válidas pero con columnas fecha_desfasadas).

    `omit_integridad_fecha`: True omitir solo la igualdad estricta ticket_lines.fecha_sorteo ↔ fecha
    en premios; conserva INNER JOIN línea↔ticket (evita huesos huérfanos).
    """
    _dbg_pf = (
        os.environ.get("DEBUG_PREMIOS_FETCH", "").strip().lower() in ("1", "true", "yes")
        or os.environ.get("DEBUG_GANADORES_OFICIAL") == "1"
    )
    if isinstance(estado, (list, tuple, set)):
        estados_lista = [str(x).strip() for x in estado if str(x or "").strip()]
    else:
        estados_lista = [str(estado or "").strip()] if str(estado or "").strip() else []
    if not estados_lista:
        estados_lista = ["pendiente"]
    placeholders_estado = ", ".join(["%s"] * len(estados_lista))
    estado_in_sql = " p.estado IN (" + placeholders_estado + ")"
    params = list(estados_lista)
    caj_filter = ""
    if (cajero_username or "").strip():
        caj_filter = " AND lower(trim(COALESCE(p.cajero, ''))) = lower(trim(%s))"
        params.append((cajero_username or "").strip())
    fecha_filter = ""
    fr = (str(fecha_ref or "").strip()[:10])
    restrict_line_ids = list(restrict_line_ids or [])
    ids_clean = []
    for x in restrict_line_ids:
        try:
            ids_clean.append(int(x))
        except (TypeError, ValueError):
            continue
    ids_clean = sorted(set(ids_clean))
    line_id_sql = ""
    if ids_clean:
        fecha_filter = ""
        line_id_sql = " AND p.line_id IN (" + ",".join(["%s"] * len(ids_clean)) + ")"
        params.extend(ids_clean)
    elif len(fr) == 10:
        has_pendiente = any(str(x).strip().lower() == "pendiente" for x in estados_lista)
        use_ext = bool(extend_pendiente_ventana and has_pendiente)
        if use_ext:
            h_fr = _parse_iso_date_only(fr) or ahora_rd().date()
            nd_cv = _ganadores_pagos_ventana_calendario_dias()
            f_desde = (h_fr - timedelta(days=nd_cv)).strftime("%Y-%m-%d")
            params.extend([fr, fr, fr, f_desde, fr])
            if os.environ.get("DATABASE_URL"):
                _tls_pg = (
                    "to_date(substr(NULLIF(trim(CAST(tl.fecha_sorteo AS TEXT)), ''), 1, 10), 'YYYY-MM-DD')"
                )
                fecha_filter = (
                    " AND (\n"
                    "     (substr(trim(COALESCE(CAST(p.fecha_dia AS TEXT), '')), 1, 10) = %s\n"
                    "      OR substr(trim(COALESCE(CAST(p.fecha_resultado AS TEXT), '')), 1, 10) = %s\n"
                    "      OR substr(trim(COALESCE(CAST(p.fecha_sorteo AS TEXT), '')), 1, 10) = %s)\n"
                    "     OR (\n"
                    "       lower(trim(COALESCE(p.estado, ''))) = 'pendiente'\n"
                    "       AND "
                    + _sql_bool_not_true("tk.pagado")
                    + "\n"
                    "       AND length(trim(COALESCE(CAST(tl.fecha_sorteo AS TEXT), ''))) >= 10\n"
                    f"       AND {_tls_pg} BETWEEN (%s)::date AND (%s)::date\n"
                    "     )\n"
                    "   )"
                )
            else:
                fecha_filter = (
                    " AND (\n"
                    "     (substr(trim(COALESCE(p.fecha_dia, '')), 1, 10) = %s\n"
                    "      OR substr(trim(COALESCE(p.fecha_resultado, '')), 1, 10) = %s\n"
                    "      OR substr(trim(COALESCE(p.fecha_sorteo, '')), 1, 10) = %s)\n"
                    "     OR (\n"
                    "       lower(trim(COALESCE(p.estado, ''))) = 'pendiente'\n"
                    "       AND COALESCE(tk.pagado, 0) = 0\n"
                    "       AND length(trim(COALESCE(tl.fecha_sorteo, ''))) >= 10\n"
                    "       AND date(substr(trim(COALESCE(tl.fecha_sorteo, '')), 1, 10)) >= date(%s)\n"
                    "       AND date(substr(trim(COALESCE(tl.fecha_sorteo, '')), 1, 10)) <= date(%s)\n"
                    "     )\n"
                    "   )"
                )
        else:
            fecha_filter = _premios_fecha_calendario_match_sql()
            params.extend(_premios_fecha_calendario_match_params(fr))
    lim_sql = ""
    lim_params = []
    if limit is not None:
        try:
            lim_n = int(limit)
            if lim_n > 0:
                lim_sql = " LIMIT %s"
                lim_params.append(lim_n)
        except (TypeError, ValueError):
            pass
    off_sql = ""
    if offset is not None and lim_sql:
        try:
            off_n = int(offset)
            if off_n > 0:
                off_sql = " OFFSET %s"
                lim_params.append(off_n)
        except (TypeError, ValueError):
            pass
    _int_join = _premios_lista_integridad_join_sql()
    if omit_integridad_fecha:
        _int_where = _premios_lista_ticket_activo_where_sql()
    else:
        _int_where = (
            _premios_lista_integridad_where_sql_pg()
            if os.environ.get("DATABASE_URL")
            else _premios_lista_integridad_where_sql_sqlite()
        )
    cur.execute(
        _sql(
            """
            SELECT p.id AS premio_id, p.ticket_id, p.line_id, p.numero, p.monto, p.premio, p.lottery, p.draw, p.play, p.resultado,
                   COALESCE(p.premio_shard, '0') AS premio_shard,
                   p.fecha_sorteo, p.fecha_resultado, p.fecha_dia, p.cajero, p.ganador_detectado_en, p.estado, p.fecha_pago,
                   p.created_at
            FROM premios p
            """
            + _int_join
            + " WHERE "
            + estado_in_sql
            + _int_where
            + caj_filter
            + fecha_filter
            + line_id_sql
            + (
                """
            ORDER BY p.ticket_id DESC, p.id DESC
            """
                if order_ticket_id_desc
                else (
                """
            ORDER BY substr(trim(COALESCE(p.fecha_resultado, p.fecha_sorteo, p.fecha_dia, '')), 1, 10) DESC,
                     COALESCE(p.created_at, p.ganador_detectado_en) DESC,
                     p.ticket_id DESC, p.line_id DESC, p.premio_shard DESC
            """
                if order_pendientes_historico
                else """
            ORDER BY CASE WHEN p.estado = 'pendiente' THEN 0 ELSE 1 END,
                     COALESCE(p.ganador_detectado_en, p.created_at) ASC, p.ticket_id ASC, p.line_id ASC, p.premio_shard ASC
            """
                )
            )
            + lim_sql
            + off_sql
        ),
        tuple(params + lim_params),
    )
    out = []
    for row in cur.fetchall() or []:
        d = dict(row) if hasattr(row, "keys") else {
            "premio_id": row[0],
            "ticket_id": row[1],
            "line_id": row[2],
            "numero": row[3],
            "monto": row[4],
            "premio": row[5],
            "lottery": row[6],
            "draw": row[7],
            "play": row[8],
            "resultado": row[9],
            "premio_shard": row[10],
            "fecha_sorteo": row[11],
            "fecha_resultado": row[12],
            "fecha_dia": row[13],
            "cajero": row[14],
            "ganador_detectado_en": row[15],
            "estado": row[16],
            "fecha_pago": row[17],
            "created_at": row[18] if len(row) > 18 else None,
        }

        if _dbg_pf:
            print(
                "RAW PREMIO:",
                "ticket_id=",
                d.get("ticket_id"),
                "numero=",
                d.get("numero"),
                "play=",
                d.get("play"),
                "resultado=",
                d.get("resultado"),
            )

        resultado = str(d.get("resultado") or "").strip()
        _premio_row = float(d.get("premio") or 0)
        if _dbg_pf:
            if not resultado:
                print("⚠️ PREMIO SIN RESULTADO ASOCIADO:", d.get("ticket_id"))
            if not resultado or "-" not in resultado:
                print("ERROR RESULTADO VACIO O INVALIDO:", repr(resultado))
        elif (not resultado or "-" not in resultado) and _premio_row > 0:
            log.warning(
                "premios fetch: resultado vacío o inválido ticket_id=%s premio=%s",
                d.get("ticket_id"),
                _premio_row,
            )

        resultado_parts = [x.strip() for x in resultado.split("-")] if resultado else []
        while len(resultado_parts) < 3:
            resultado_parts.append("")
        primero, segundo, tercero = (
            resultado_parts[0],
            resultado_parts[1],
            resultado_parts[2],
        )

        raw_num = d.get("numero")
        num_s = str(raw_num if raw_num is not None else "").strip()
        if not num_s:
            numero = ""
        elif "-" in num_s:
            numero = num_s
        elif num_s.isdigit():
            numero = num_s.zfill(2)
        else:
            numero = num_s

        play = (d.get("play") or "").strip().lower()

        premio_f = float(d.get("premio") or 0)
        numero_para_ac = (normalizar_numero(d.get("numero")) or "").strip() or numero

        data = {}
        try:
            data = _ganadores_acierto_presentacion(
                play,
                numero_para_ac,
                primero,
                segundo,
                tercero,
                premio_f,
                None,
            ) or {}
        except Exception as e:
            if _dbg_pf:
                print("ERROR EN PRESENTACION:", e)
            else:
                log.warning("premios fetch presentación acierto: %s", e)
            data = {}

        numero_jugado_display = (data.get("numero_jugado_display") or "").strip() or numero
        if not numero_jugado_display:
            numero_jugado_display = (
                (normalizar_numero(d.get("numero")) or "").strip()
                or str(d.get("numero") or "").strip()
            )
        if not numero_jugado_display:
            numero_jugado_display = "—"

        _ofi_raw = (data.get("numero_oficial_display") or "").strip()
        if not _ofi_raw or _ofi_raw == "—":
            numero_oficial_display = (primero or "").strip()
            if numero_oficial_display:
                numero_oficial_display = (
                    _norm_sorteo_dos_digitos(numero_oficial_display)
                    or numero_oficial_display
                )
            else:
                numero_oficial_display = "—"
        else:
            numero_oficial_display = _ofi_raw
        if not numero_oficial_display:
            numero_oficial_display = "—"

        resultado_sorteo_out = resultado or "-".join(
            p for p in resultado_parts[:3] if p
        )
        acierto_detalle = (data.get("acierto_detalle") or data.get("detalle") or "").strip()
        acierto_ok = bool(data.get("acierto_ok", False))

        if _dbg_pf:
            print(
                "FINAL GANADOR:",
                numero_jugado_display,
                "=>",
                numero_oficial_display,
                "| OK:",
                acierto_ok,
            )

        _estado_raw = (str(d.get("estado") or "").strip().lower())
        if _estado_raw == "pagado":
            _estado_label = "Pagado"
        elif _estado_raw == "pendiente":
            _estado_label = "Pendiente"
        else:
            _estado_label = (str(d.get("estado") or "").strip().capitalize() or "—")
        out.append({
            "premio_id": d.get("premio_id") or d.get("id"),
            "ticket_id": d.get("ticket_id"),
            "line_id": d.get("line_id"),
            "number": d.get("numero"),
            "numero": d.get("numero"),
            "monto": float(d.get("monto") or 0),
            "amount": float(d.get("monto") or 0),
            "premio": premio_f,
            "premio_shard": _premio_shard_norm(d),
            "lottery": d.get("lottery"),
            "draw": d.get("draw"),
            "play": d.get("play"),
            "resultado": "-".join(resultado_parts[:3]),
            "primero": resultado_parts[0],
            "segundo": resultado_parts[1],
            "tercero": resultado_parts[2],
            "fecha_sorteo_linea": (
                d.get("fecha_sorteo")
                or d.get("fecha_resultado")
                or d.get("fecha_dia")
            ),
            "fecha_sorteo_display": (
                str(
                    d.get("fecha_resultado")
                    or d.get("fecha_sorteo")
                    or d.get("fecha_dia")
                    or ""
                ).strip()[:10]
            ),
            "resultado_fecha_iso": (
                d.get("fecha_resultado")
                or d.get("fecha_sorteo")
                or d.get("fecha_dia")
            ),
            "resultado_fecha": (
                d.get("fecha_resultado")
                or d.get("fecha_sorteo")
                or d.get("fecha_dia")
            ),
            "cajero": d.get("cajero"),
            "ganador_detectado_en": d.get("ganador_detectado_en"),
            "estado": _estado_raw,
            "estado_label": _estado_label,
            "fecha_pago": d.get("fecha_pago"),
            "pagado": _estado_raw == "pagado",
            "numero_jugado_display": numero_jugado_display,
            "numero_oficial_display": numero_oficial_display,
            "jugado": numero or numero_jugado_display,
            "oficial": numero_oficial_display,
            "resultado_sorteo": resultado_sorteo_out,
            "acierto_detalle": acierto_detalle,
            "acierto_ok": acierto_ok,
        })
    return out


def _premios_count_por_estado(cur, estado, cajero_username=None):
    params = [estado]
    caj_filter = ""
    if (cajero_username or "").strip():
        caj_filter = " AND lower(trim(COALESCE(cajero, ''))) = lower(trim(%s))"
        params.append((cajero_username or "").strip())
    cur.execute(
        _sql("SELECT COUNT(*) AS c FROM premios WHERE estado = %s" + caj_filter),
        tuple(params),
    )
    row = cur.fetchone()
    return int((row.get("c") if hasattr(row, "get") else (row[0] if row else 0)) or 0)


def _premios_fecha_sorteo_efectiva_expr():
    """Expresión SQL (sin alias) de la fecha del sorteo en premios/línea."""
    return (
        "substr(trim(COALESCE(p.fecha_resultado, p.fecha_sorteo, p.fecha_dia, "
        "tl.fecha_sorteo, '')), 1, 10)"
    )


def _premios_fecha_calendario_match_sql():
    """Filtro por día RD: columnas en premios + fecha_sorteo de ticket_lines (4× mismo %s)."""
    return (
        " AND (substr(trim(COALESCE(p.fecha_dia, '')), 1, 10) = %s "
        "OR substr(trim(COALESCE(p.fecha_resultado, '')), 1, 10) = %s "
        "OR substr(trim(COALESCE(p.fecha_sorteo, '')), 1, 10) = %s "
        "OR substr(trim(COALESCE(tl.fecha_sorteo, '')), 1, 10) = %s)"
    )


def _premios_fecha_calendario_match_params(fr):
    s = str(fr or "").strip()[:10]
    return [s, s, s, s]


def _ganadores_ultima_fecha_con_pendientes(cur, cajero_filtro=None):
    """Última fecha (YYYY-MM-DD) con al menos un premio pendiente (para default tras medianoche)."""
    params = ["pendiente"]
    caj_sql = ""
    if (cajero_filtro or "").strip():
        caj_sql = " AND lower(trim(COALESCE(p.cajero, ''))) = lower(trim(%s))"
        params.append((cajero_filtro or "").strip())
    try:
        cur.execute(
            _sql(
                """
                SELECT MAX(substr(trim(COALESCE(
                    p.fecha_resultado, p.fecha_sorteo, p.fecha_dia, ''
                )), 1, 10)) AS fd
                FROM premios p
                WHERE lower(trim(COALESCE(p.estado, ''))) = %s
                  AND length(substr(trim(COALESCE(
                    p.fecha_resultado, p.fecha_sorteo, p.fecha_dia, ''
                  )), 1, 10)) >= 10
                """
                + caj_sql
            ),
            tuple(params),
        )
        row = cur.fetchone()
        fd = (row.get("fd") if hasattr(row, "get") else (row[0] if row else None)) if row else None
        s = str(fd or "").strip()[:10]
        return s if len(s) == 10 else None
    except Exception as e:
        log.warning("_ganadores_ultima_fecha_con_pendientes: %s", e, exc_info=True)
        return None


def _ganadores_resolver_fecha_premios(hoy_rd, cur, cajero_filtro=None):
    """
    Fecha activa en /ganadores (solo consulta/listado): query `fecha_premios` / `fecha`.
    Sin parámetro → hoy RD del servidor. El parámetro se valida y acota; no se usa reloj del cliente.
    """
    _ = cur, cajero_filtro
    raw = ""
    try:
        raw = (
            request.args.get("fecha_premios")
            or request.args.get("fecha")
            or ""
        ).strip()[:10]
    except Exception:
        raw = ""
    if raw:
        acotada = _fecha_consulta_cliente_acotada(raw, default_hoy=False)
        if acotada:
            return acotada
    hoy_s = str(hoy_rd or "").strip()[:10]
    if len(hoy_s) == 10 and _parse_iso_date_only(hoy_s):
        return hoy_s[:10]
    return fecha_hoy_rd_iso()


def _ganadores_sync_premios_fecha_lista(cur, fecha_rd, cajero_username=None, force=False):
    """
    Cruce tickets↔resultados del día RD y UPSERT en `premios` (pantalla /ganadores).
    Si los premios del día ya están materializados, solo lectura (sin recalcular).
    """
    t_perf = time.perf_counter()
    fr = str(fecha_rd or "").strip()[:10]
    if len(fr) != 10:
        return {"ok": False, "insertados": 0, "lista_cruce_ganadores": [], "message": "fecha inválida"}
    if not _premios_sync_necesario(cur, fr, cajero_username, force=force):
        n_exist = _premios_count_ganadores_lineas_fecha(cur, fr, cajero_username)
        log.info(
            "[GANADORES_FECHA] skip sync fecha=%s premios_existentes=%s sync_hecho=%s ms=%s",
            fr,
            n_exist,
            _premios_sync_hecho_para_fecha(fr),
            round((time.perf_counter() - t_perf) * 1000, 2),
        )
        return {
            "ok": True,
            "insertados": 0,
            "lista_cruce_ganadores": [],
            "message": "skip_materializado",
            "skipped": True,
            "premios_existentes": n_exist,
        }
    log.info("[GANADORES_FECHA] fecha=%s", fr)
    t_ct = time.perf_counter()
    n_tickets = _ganadores_count_tickets_fecha(cur, fr, cajero_username)
    consulta_tickets_ms = round((time.perf_counter() - t_ct) * 1000, 2)
    t_cr = time.perf_counter()
    n_resultados = _ganadores_count_resultados_fecha(cur, fr)
    consulta_resultados_ms = round((time.perf_counter() - t_cr) * 1000, 2)
    log.info(
        "[GANADORES_FECHA] tickets encontrados=%s resultados encontrados=%s "
        "consulta_tickets_ms=%s consulta_resultados_ms=%s",
        n_tickets,
        n_resultados,
        consulta_tickets_ms,
        consulta_resultados_ms,
    )

    sync = _premios_quick_sync_day(cur, fr, cajero_username=cajero_username)
    ins = int(sync.get("insertados") or 0)
    perf = sync.get("perf") or {}
    n_cruce = len(
        [x for x in (sync.get("lista_cruce_ganadores") or []) if float(x.get("premio") or 0) > 0.004]
    )
    log.info(
        "[GANADORES_FECHA] premios creados=%s filas_ganadoras_cruce=%s ok=%s "
        "cruce_ms=%s crear_premios_ms=%s total_ms=%s",
        ins,
        n_cruce,
        bool(sync.get("ok")),
        perf.get("cruce_ms"),
        perf.get("crear_premios_ms"),
        round((time.perf_counter() - t_perf) * 1000, 2),
    )
    return sync


def _premios_id_linea_shard(cur, line_id, premio_shard):
    """Devuelve premios.id para (line_id, premio_shard) o None."""
    try:
        lid = int(line_id)
    except (TypeError, ValueError):
        return None
    if lid <= 0:
        return None
    shard_s = _premio_shard_norm({"premio_shard": premio_shard})
    try:
        cur.execute(
            _sql(
                """
                SELECT id FROM premios
                WHERE line_id = %s AND premio_shard = %s
                LIMIT 1
                """
            ),
            (lid, shard_s),
        )
        row = cur.fetchone()
        if row is None:
            return None
        if hasattr(row, "get"):
            return int(row.get("id") or 0) or None
        return int(row[0]) if row[0] is not None else None
    except Exception:
        _rollback_pg_cursor(cur)
        return None


def _premios_eliminar_pendientes_orfanos_dia(cur, fecha_rd, lista_ganadores, cajero_username=None):
    """
    Quita premios pendientes del día que ya no están en el cruce oficial.
    No toca pagado ni invalidado.
    """
    fr = str(fecha_rd or "").strip()[:10]
    if len(fr) != 10:
        return 0
    live_keys = set()
    for g in lista_ganadores or []:
        try:
            prem = float(g.get("premio") or 0)
        except (TypeError, ValueError):
            prem = 0.0
        if prem <= 0.004:
            continue
        lk = _ganadores_line_id_key(g.get("line_id"))
        if lk is None:
            continue
        live_keys.add((int(lk), _premio_shard_norm(g)))
    try:
        pendientes = premios_pendientes_fetch(
            cur, fr, cajero_username=cajero_username, limit=None, offset=None
        )
    except Exception as e:
        log.warning("_premios_eliminar_pendientes_orfanos_dia fetch: %s", e, exc_info=True)
        _rollback_pg_cursor(cur)
        return 0
    eliminados = 0
    for p in pendientes or []:
        try:
            lid = int(p.get("line_id") or 0)
        except (TypeError, ValueError):
            continue
        if lid <= 0:
            continue
        key = (lid, _premio_shard_norm(p))
        if key in live_keys:
            continue
        pid = p.get("premio_id")
        try:
            if pid:
                cur.execute(
                    _sql(
                        "DELETE FROM premios WHERE id = %s AND lower(trim(COALESCE(estado,''))) = 'pendiente'"
                    ),
                    (int(pid),),
                )
            else:
                cur.execute(
                    _sql(
                        """
                        DELETE FROM premios
                        WHERE line_id = %s AND premio_shard = %s
                          AND lower(trim(COALESCE(estado,''))) = 'pendiente'
                        """
                    ),
                    (lid, _premio_shard_norm(p)),
                )
            rc = int(cur.rowcount or 0)
            if rc:
                eliminados += rc
                log.info(
                    "[RECALC_PREMIO_ORFANO] premio_id=%s line_id=%s ticket_id=%s",
                    pid,
                    lid,
                    p.get("ticket_id"),
                )
        except Exception as e:
            log.warning("_premios_eliminar_pendientes_orfanos_dia delete: %s", e, exc_info=True)
            _rollback_pg_cursor(cur)
    return eliminados


def _purga_premios_tripleta_invalidos(conn, cur, ticket_id=None, pagos=None):
    """
    Elimina premios pendientes o revierte pagos de tripletas que no acertaron los 3 números.
    Corrige falsos positivos donde 41-39-71 se pagó como quiniela parcial.
    """
    P = pagos if pagos is not None else PAGOS
    stats = {"revisados": 0, "eliminados": 0, "revertidos": 0, "ticket_ids": []}
    params = []
    tid_sql = ""
    if ticket_id is not None:
        try:
            tid_sql = " AND p.ticket_id = %s"
            params.append(int(ticket_id))
        except (TypeError, ValueError):
            pass
    cur.execute(
        _sql(
            """
            SELECT p.id, p.ticket_id, p.line_id, p.numero, p.monto, p.premio, p.lottery, p.draw,
                   p.play, p.estado, p.cajero, p.fecha_sorteo, p.fecha_resultado, p.fecha_dia,
                   tl.number AS tl_number, tl.play AS tl_play
            FROM premios p
            LEFT JOIN ticket_lines tl ON tl.id = p.line_id
            WHERE (
                lower(trim(COALESCE(p.play, ''))) = 'tripleta'
                OR lower(trim(COALESCE(tl.play, ''))) = 'tripleta'
                OR trim(COALESCE(tl.number, p.numero, '')) LIKE '%-%-%'
            )
            """
            + tid_sql
        ),
        tuple(params),
    )
    for row in cur.fetchall() or []:
        d = dict(row) if hasattr(row, "keys") else {
            "id": row[0],
            "ticket_id": row[1],
            "line_id": row[2],
            "numero": row[3],
            "monto": row[4],
            "premio": row[5],
            "lottery": row[6],
            "draw": row[7],
            "play": row[8],
            "estado": row[9],
            "cajero": row[10],
            "fecha_sorteo": row[11],
            "fecha_resultado": row[12],
            "fecha_dia": row[13],
            "tl_number": row[14] if len(row) > 14 else None,
            "tl_play": row[15] if len(row) > 15 else None,
        }
        stats["revisados"] += 1
        numero = str(d.get("tl_number") or d.get("numero") or "").strip()
        play_decl = d.get("tl_play") or d.get("play")
        if not _es_formato_tripleta_numero(numero):
            continue
        play_eff = _play_efectivo_cruce(play_decl, numero)
        fe = str(
            d.get("fecha_dia") or d.get("fecha_resultado") or d.get("fecha_sorteo") or ""
        ).strip()[:10]
        if len(fe) != 10:
            continue
        triple, err, _info = _resultado_sorteo_resolver_estricto(
            cur, d.get("lottery"), d.get("draw"), fe
        )
        if not triple or err:
            continue
        coincidencias, gana = _tripleta_coincidencias_eval(numero, *triple)
        try:
            premio_ok = float(
                calcular_premio(
                    play_eff, numero, d.get("monto"), triple[0], triple[1], triple[2], pagos=P
                )
                or 0
            )
        except Exception:
            premio_ok = 0.0
        _tripleta_eval_log(
            d.get("ticket_id"),
            numero,
            _ganadores_resultado_str(*triple),
            coincidencias,
            gana and premio_ok > 0,
            play_decl=play_decl,
        )
        if gana and premio_ok > 0.02:
            continue
        pid = int(d.get("id") or 0)
        tid = int(d.get("ticket_id") or 0)
        estado = str(d.get("estado") or "").strip().lower()
        log.warning(
            "[TRIPLETA_PURGA] ticket=%s premio_id=%s numero=%s coincidencias=%s estado=%s",
            tid,
            pid,
            numero,
            coincidencias,
            estado,
        )
        if estado == "pagado" and tid > 0 and conn is not None:
            try:
                res = _revertir_pago_premio_ticket(
                    conn,
                    tid,
                    str(d.get("cajero") or "sistema"),
                    motivo="Tripleta invalida: deben acertar los 3 numeros",
                    admin_uid=None,
                )
                if res.get("ok"):
                    stats["revertidos"] += 1
                    if tid not in stats["ticket_ids"]:
                        stats["ticket_ids"].append(tid)
            except Exception as _rev_e:
                log.warning("_purga_premios_tripleta_invalidos revert ticket=%s: %s", tid, _rev_e)
        elif pid > 0:
            cur.execute(
                _sql(
                    "DELETE FROM premios WHERE id = %s AND lower(trim(COALESCE(estado,''))) IN ('pendiente', 'invalidado')"
                ),
                (pid,),
            )
            if int(cur.rowcount or 0):
                stats["eliminados"] += 1
                if tid and tid not in stats["ticket_ids"]:
                    stats["ticket_ids"].append(tid)
        try:
            cur.execute(
                _sql(
                    "UPDATE tickets SET ganador = 0 WHERE id = %s AND NOT EXISTS "
                    "(SELECT 1 FROM premios px WHERE px.ticket_id = %s "
                    "AND lower(trim(COALESCE(px.estado,''))) IN ('pendiente','pagado'))"
                ),
                (tid, tid),
            )
        except Exception:
            _rollback_pg_cursor(cur)
    return stats


def _log_recalc_premios_save(
    *,
    ticket_id=None,
    line_id=None,
    premio_id=None,
    banca_id=None,
    monto_jugado=None,
    premio_calculado=None,
    inserted_or_updated=None,
):
    log.info(
        "[RECALC_PREMIOS_SAVE] ticket_id=%s jugada_id=%s premio_id=%s banca_id=%s "
        "monto_jugado=%s premio_calculado=%s estado=pendiente inserted_or_updated=%s",
        ticket_id if ticket_id is not None else "-",
        line_id if line_id is not None else "-",
        premio_id if premio_id is not None else "-",
        banca_id if banca_id is not None else "-",
        round(float(monto_jugado or 0), 2),
        round(float(premio_calculado or 0), 2),
        inserted_or_updated or "-",
    )


def _recalc_linea_directa_a_ganador(cur, ld, pagos, fecha_rd):
    """
    Evalúa una línea sin fila JOIN: resolutor estricto + calcular_premio.
    Cubre lotería compuesta («La Primera 12:00 PM») y tickets que el JOIN SQL no cruzó.
    """
    if not isinstance(ld, dict):
        return None
    fe = str(ld.get("fecha_sorteo") or fecha_rd or "").strip()[:10]
    if len(fe) != 10:
        return None
    try:
        amt = float(ld.get("amount") or 0)
    except (TypeError, ValueError):
        return None
    if amt <= 0:
        return None
    triple, err, _info = _resultado_sorteo_resolver_estricto(
        cur, ld.get("lottery"), ld.get("draw"), fe
    )
    if not triple or err:
        return None
    r1, r2, r3 = triple[0], triple[1], triple[2]
    play_decl = ld.get("play")
    num_raw = ld.get("number")
    play_eff = _play_efectivo_cruce(play_decl, num_raw)
    premio = float(calcular_premio(play_eff, num_raw, amt, r1, r2, r3, pagos=pagos) or 0)
    if premio <= 0.004:
        return None
    Pm = _merge_pagos_calc(pagos)
    if play_eff == "Quiniela":
        fragmentos = _quiniela_premio_fragmentos(num_raw, amt, r1, r2, r3, Pm)
        if not fragmentos:
            return None
        filas_emit = [
            {
                "premio_shard": f["premio_shard"],
                "premio": float(f.get("premio") or 0),
                "jug": f.get("jugado_norm") or "",
            }
            for f in fragmentos
        ]
    else:
        filas_emit = [
            {
                "premio_shard": "0",
                "premio": premio,
                "jug": normalizar_numero(num_raw) or str(num_raw or "").strip(),
            }
        ]
    _draw_eff = _draw_efectivo_jugada(ld.get("lottery"), ld.get("draw"))
    _draw_show = (
        formatear_hora_estandar(str(_draw_eff or "").strip())
        or formatear_hora_estandar(str(ld.get("draw") or "").strip())
        or str(ld.get("draw") or "").strip()
    )
    out = []
    lid = _ganadores_line_id_key(ld.get("line_id"))
    for fe_frag in filas_emit:
        frag_p = float(fe_frag.get("premio") or 0)
        if frag_p <= 0:
            continue
        jug_vis = str(fe_frag.get("jug") or "").strip()
        num_cell = (normalizar_numero(jug_vis) or jug_vis) if jug_vis else (normalizar_numero(num_raw) or "")
        out.append(
            {
                "line_id": lid,
                "ticket_id": ld.get("ticket_id"),
                "number": num_cell,
                "lottery": normalizar_loteria(ld.get("lottery")) or str(ld.get("lottery") or "").strip(),
                "draw": _draw_show,
                "play": play_decl,
                "premio": frag_p,
                "premio_shard": _premio_shard_norm(fe_frag),
                "monto": amt,
                "cajero": ld.get("cajero") or "",
                "banca_id": ld.get("banca_id"),
                "pagado": False,
                "resultado": _ganadores_resultado_str(r1, r2, r3),
                "tipo": _ganadores_tipo_play(play_decl),
                "resultado_fecha_iso": fe,
                "fecha_sorteo_linea": fe,
                "ganador_detectado_en": None,
                "primero": r1,
                "segundo": r2,
                "tercero": r3,
            }
        )
    return out or None


def _recalcular_ganadores_fecha_completo(cur, fecha_rd, cajero_username=None, conn=None, recalc_ctx=None):
    """
    Recálculo explícito del día: recorre tickets/líneas, cruza con resultados publicados,
    sincroniza `premios` pendientes (sin tocar banco ni pagados).
    """
    fr = str(fecha_rd or "").strip()[:10]
    stats = {
        "ok": False,
        "fecha": fr,
        "tickets_evaluados": 0,
        "lineas_evaluadas": 0,
        "premios_creados": 0,
        "premios_actualizados": 0,
        "premios_existentes": 0,
        "premios_orfanos_eliminados": 0,
        "premios_total": 0,
        "filas_cruce": 0,
        "message": "",
        "lista_cruce_ganadores": [],
    }
    if len(fr) != 10:
        stats["message"] = "fecha inválida"
        return stats

    if recalc_ctx is None:
        recalc_ctx = _recalc_premios_session_ctx()

    log.info("[RECALC_INICIO] fecha=%s", fr)
    if conn is not None:
        try:
            purga = _purga_premios_tripleta_invalidos(conn, cur, pagos=PAGOS)
            stats["tripleta_purga"] = purga
            log.info("[RECALC_TRIPLETA_PURGA] %s", purga)
        except Exception as _tp:
            log.warning("[RECALC] purga tripleta invalida: %s", _tp, exc_info=True)
            _rollback_pg_cursor(cur)
    try:
        _premios_migrate_unique_constraints(cur)
    except Exception as _mig_re:
        log.warning("[RECALC] migrate unique constraints: %s", _mig_re, exc_info=True)
        _rollback_pg_cursor(cur)

    tickets_vistos = set()
    lineas_eval = 0
    lineas_dia = []

    try:
        params = [fr]
        caj_sql = ""
        if (cajero_username or "").strip():
            caj_sql = " AND lower(trim(COALESCE(tk.cajero, ''))) = lower(trim(%s))"
            params.append((cajero_username or "").strip())
        cur.execute(
            _sql(
                """
                SELECT tl.ticket_id, tl.id AS line_id, tl.lottery, tl.draw,
                       tl.fecha_sorteo, tl.number, tl.amount, tl.play,
                       tk.banca_id, tk.cajero
                FROM ticket_lines tl
                INNER JOIN tickets tk ON tk.id = tl.ticket_id
                WHERE substr(trim(COALESCE(tl.fecha_sorteo, '')), 1, 10) = %s
                  AND COALESCE(tl.estado, 'activo') <> 'cancelado'
                """
                + _sql_ticket_no_eliminado("tk")
                + caj_sql
                + """
                ORDER BY tl.ticket_id ASC, tl.id ASC
                """
            ),
            tuple(params),
        )
        last_tid_log = None
        for row in cur.fetchall() or []:
            d = (
                dict(row)
                if hasattr(row, "keys")
                else {
                    "ticket_id": row[0],
                    "line_id": row[1],
                    "lottery": row[2],
                    "draw": row[3],
                    "fecha_sorteo": row[4],
                    "number": row[5],
                    "amount": row[6],
                    "play": row[7],
                    "banca_id": row[8] if len(row) > 8 else None,
                    "cajero": row[9] if len(row) > 9 else None,
                }
            )
            lineas_dia.append(d)
            try:
                tid = int(d.get("ticket_id") or 0)
            except (TypeError, ValueError):
                tid = 0
            if tid > 0:
                tickets_vistos.add(tid)
                if tid != last_tid_log:
                    log.info(
                        "[RECALC_TICKET] ticket_id=%s lottery=%s draw=%s fecha=%s",
                        tid,
                        d.get("lottery"),
                        d.get("draw"),
                        str(d.get("fecha_sorteo") or "")[:10],
                    )
                    last_tid_log = tid
            log.info(
                "[RECALC_LINEA] ticket_id=%s line_id=%s jugada=%s monto=%s",
                d.get("ticket_id"),
                d.get("line_id"),
                d.get("number"),
                d.get("amount"),
            )
            lineas_eval += 1
    except Exception as e:
        log.warning("[RECALC] enumerar líneas: %s", e, exc_info=True)
        _rollback_pg_cursor(cur)

    try:
        cfg = _ganadores_try_load_pagos_config(cur) or {}
        pagos_efectivo = {**PAGOS, **cfg}
        join_rows = _ganadores_fetch_lineas_vs_resultados(
            cur, fr, cajero_username=cajero_username, modo_recalc_manual=True
        )
        joined_line_ids = {
            int(_ganadores_line_id_key(jr.get("line_id")))
            for jr in (join_rows or [])
            if _ganadores_line_id_key(jr.get("line_id")) is not None
        }
        for ld in lineas_dia:
            lk = _ganadores_line_id_key(ld.get("line_id"))
            if lk is None or int(lk) in joined_line_ids:
                continue
            _log_recalc_eval_line(
                recalc_ctx=recalc_ctx,
                ticket_id=ld.get("ticket_id"),
                line_id=lk,
                banca_id=ld.get("banca_id"),
                fecha_sorteo_rd=str(ld.get("fecha_sorteo") or "")[:10],
                lottery=ld.get("lottery"),
                draw=ld.get("draw"),
                numero=ld.get("number"),
                play_decl=ld.get("play"),
                premio=0.0,
                motivo_no_ganador="sin_resultado_join",
            )
        lista_live = _ganadores_procesar_filas(
            join_rows or [],
            pagos=pagos_efectivo,
            hoy_rd_str=fr,
            cur=cur,
            recalc_log=True,
            recalc_ctx=recalc_ctx,
        )
        lineas_ganadoras = {
            int(_ganadores_line_id_key(x.get("line_id")))
            for x in (lista_live or [])
            if _ganadores_line_id_key(x.get("line_id")) is not None
            and float(x.get("premio") or 0) > 0.004
        }
        for ld in lineas_dia:
            lk = _ganadores_line_id_key(ld.get("line_id"))
            if lk is None or int(lk) in lineas_ganadoras:
                continue
            direct = _recalc_linea_directa_a_ganador(cur, ld, pagos_efectivo, fr)
            if not direct:
                continue
            lista_live = list(lista_live or []) + list(direct)
            lineas_ganadoras.add(int(lk))
            for dg in direct:
                log.info(
                    "[RECALC_DIRECTO] ticket_id=%s line_id=%s numero=%s premio=%s",
                    dg.get("ticket_id"),
                    dg.get("line_id"),
                    dg.get("number"),
                    dg.get("premio"),
                )
                _log_recalc_eval_line(
                    recalc_ctx=recalc_ctx,
                    ticket_id=dg.get("ticket_id"),
                    line_id=dg.get("line_id"),
                    banca_id=dg.get("banca_id"),
                    fecha_sorteo_rd=fr,
                    lottery=ld.get("lottery"),
                    draw=ld.get("draw"),
                    numero=ld.get("number"),
                    play_decl=ld.get("play"),
                    r1=dg.get("primero"),
                    r2=dg.get("segundo"),
                    r3=dg.get("tercero"),
                    premio=dg.get("premio"),
                    motivo_no_ganador=None,
                )
    except Exception as e:
        log.error("[RECALC] cruce falló: %s", e, exc_info=True)
        _rollback_pg_cursor(cur)
        stats["message"] = str(e)[:220]
        return stats

    winners = []
    join_by_line = {}
    for jr in join_rows or []:
        lk = _ganadores_line_id_key(jr.get("line_id"))
        if lk is not None:
            join_by_line.setdefault(int(lk), []).append(jr)

    for lw in lista_live or []:
        try:
            prem = float(lw.get("premio") or 0)
        except (TypeError, ValueError):
            prem = 0.0
        if prem <= 0.004:
            continue
        winners.append(lw)
        lk = _ganadores_line_id_key(lw.get("line_id"))
        jr0 = (join_by_line.get(int(lk)) or [None])[0] if lk is not None else None
        res_dbg = lw.get("resultado") or ""
        if jr0 is not None:
            res_dbg = (
                "%s-%s-%s"
                % (
                    jr0.get("primero"),
                    jr0.get("segundo"),
                    jr0.get("tercero"),
                )
            )
        log.info(
            "[RECALC_RESULTADO_MATCH] ticket_id=%s line_id=%s lottery=%s draw=%s numeros_resultado=%s",
            lw.get("ticket_id"),
            lw.get("line_id"),
            lw.get("lottery"),
            lw.get("draw"),
            res_dbg,
        )
        log.info(
            "[RECALC_GANADOR] ticket_id=%s line_id=%s numero=%s posicion=%s premio=%s",
            lw.get("ticket_id"),
            lw.get("line_id"),
            lw.get("number"),
            _premio_shard_norm(lw),
            prem,
        )

    stats["filas_cruce"] = len(winners)
    stats["lista_cruce_ganadores"] = list(lista_live or [])

    stats["premios_orfanos_eliminados"] = _premios_eliminar_pendientes_orfanos_dia(
        cur, fr, winners, cajero_username=cajero_username
    )

    for lw in winners:
        try:
            lid = int(lw.get("line_id") or 0)
        except (TypeError, ValueError):
            lid = 0
        if lid <= 0:
            continue
        if _premios_linea_tiene_invalidacion_manual(cur, lid):
            log.info(
                "[RECALC_PREMIO_OMIT] invalidación manual line_id=%s ticket_id=%s",
                lid,
                lw.get("ticket_id"),
            )
            continue
        shard_s = _premio_shard_norm(lw)
        pid_antes = _premios_id_linea_shard(cur, lid, shard_s)
        upserted = _premios_upsert_pendiente(cur, lw)
        pid_despues = _premios_id_linea_shard(cur, lid, shard_s)
        if upserted:
            io = "updated" if pid_antes else "inserted"
            if pid_antes:
                stats["premios_actualizados"] += 1
                log.info(
                    "[RECALC_PREMIO_EXISTE] premio_id=%s ticket_id=%s line_id=%s",
                    pid_despues or pid_antes,
                    lw.get("ticket_id"),
                    lid,
                )
            else:
                stats["premios_creados"] += 1
                log.info(
                    "[RECALC_PREMIO_INSERT] premio_id=%s ticket_id=%s line_id=%s",
                    pid_despues,
                    lw.get("ticket_id"),
                    lid,
                )
            _log_recalc_premios_save(
                ticket_id=lw.get("ticket_id"),
                line_id=lid,
                premio_id=pid_despues or pid_antes,
                banca_id=lw.get("banca_id"),
                monto_jugado=lw.get("monto"),
                premio_calculado=lw.get("premio"),
                inserted_or_updated=io,
            )
        else:
            stats["premios_existentes"] += 1
            log.info(
                "[RECALC_PREMIO_EXISTE] premio_id=%s ticket_id=%s line_id=%s estado=no_pendiente",
                pid_antes,
                lw.get("ticket_id"),
                lid,
            )

    try:
        stats["premios_total"] = len(
            premios_pendientes_fetch(
                cur, fr, cajero_username=cajero_username, limit=None, offset=None
            )
        )
    except Exception:
        stats["premios_total"] = len(winners)

    stats["tickets_evaluados"] = len(tickets_vistos)
    stats["lineas_evaluadas"] = lineas_eval
    stats["ok"] = True
    stats["insertados"] = stats["premios_creados"] + stats["premios_actualizados"]
    _premios_marcar_sync_hecho(fr)
    try:
        _admin_lineas_eval_guardar_per_desde_cruce(join_rows, lista_live, fr)
    except Exception:
        pass
    log.info(
        "[RECALC_FIN] tickets_evaluados=%s lineas_evaluadas=%s premios_creados=%s premios_total=%s filas_cruce=%s",
        stats["tickets_evaluados"],
        stats["lineas_evaluadas"],
        stats["premios_creados"],
        stats["premios_total"],
        stats["filas_cruce"],
    )
    return stats


def premios_pendientes_fetch(
    cur,
    fecha_premios,
    cajero_username=None,
    limit=None,
    offset=None,
):
    """
    Lista de pago: solo `estado=pendiente` del día `fecha_premios` (fecha_resultado o fecha_sorteo).
    """
    fr = str(fecha_premios or "").strip()[:10]
    if len(fr) != 10:
        return []
    return _premios_fetch_por_estado(
        cur,
        ["pendiente"],
        cajero_username=cajero_username,
        limit=limit,
        offset=offset,
        fecha_ref=fr,
        extend_pendiente_ventana=False,
        omit_integridad_fecha=True,
        order_ticket_id_desc=True,
    )


def premios_pagados_historial_fetch(
    cur,
    fecha_premios,
    cajero_username=None,
    limit=None,
):
    """Historial pagados del mismo día (no va en la lista de pago)."""
    fr = str(fecha_premios or "").strip()[:10]
    if len(fr) != 10:
        return []
    try:
        cap = int(limit) if limit is not None else 120
        cap = max(10, min(cap, 400))
    except (TypeError, ValueError):
        cap = 120
    return _premios_fetch_por_estado(
        cur,
        ["pagado"],
        cajero_username=cajero_username,
        limit=cap,
        fecha_ref=fr,
        extend_pendiente_ventana=False,
        omit_integridad_fecha=True,
        order_pendientes_historico=True,
    )


def _ganadores_log_pendientes_historicos(
    cur, cajero_filtro=None, fecha_premios=None, tag=""
):
    """
    Log operativo: [ganadores] pendientes historicos encontrados: X total: RD$Y
    """
    try:
        fr = str(fecha_premios or "").strip()[:10]
        if len(fr) == 10:
            ag = _premios_pendientes_aggregate(
                cur, cajero_filtro, fecha_ref=fr, omit_integridad_fecha=True
            )
        else:
            ag = _premios_pendientes_aggregate(
                cur, cajero_filtro, fecha_ref=None, omit_integridad_fecha=True
            )
        n = int(ag.get("n_lines") or 0)
        total = float(ag.get("sum_premio") or 0)
        suf = (" %s" % tag) if tag else ""
        log.info(
            "[ganadores] fecha_premios=%s pendientes encontrados: %s total: RD$%.2f%s",
            fr or "—",
            n,
            total,
            suf,
        )
        stats = _ganadores_log_pendientes_stats(cur, cajero_filtro, tag=tag)
        return {"n": n, "total_rd": total, "fecha_premios": fr, **stats}
    except Exception as e:
        log.warning("_ganadores_log_pendientes_historicos: %s", e, exc_info=True)
        return {"n": 0, "total_rd": 0.0, "fecha_premios": fecha_premios or ""}


def _ganadores_log_pendientes_stats(cur, cajero_filtro=None, tag=""):
    """
    Diagnóstico: cuántos premios pendientes hay y rango de fechas (sin filtrar por «hoy»).
    """
    params = ["pendiente"]
    caj_sql = ""
    if (cajero_filtro or "").strip():
        caj_sql = " AND lower(trim(COALESCE(p.cajero, ''))) = lower(trim(%s))"
        params.append((cajero_filtro or "").strip())
    _int_join = _premios_lista_integridad_join_sql()
    try:
        cur.execute(
            _sql(
                """
                SELECT COUNT(*) AS n,
                       MIN(substr(trim(COALESCE(
                           p.fecha_sorteo, p.fecha_resultado, p.fecha_dia,
                           tl.fecha_sorteo, ''
                       )), 1, 10)) AS fecha_min,
                       MAX(substr(trim(COALESCE(
                           p.fecha_sorteo, p.fecha_resultado, p.fecha_dia,
                           tl.fecha_sorteo, ''
                       )), 1, 10)) AS fecha_max
                FROM premios p
                """
                + _int_join
                + """
                WHERE lower(trim(COALESCE(p.estado, ''))) = %s
                  AND p.line_id IS NOT NULL
                """
                + caj_sql
            ),
            tuple(params),
        )
        row = cur.fetchone() or {}
        if hasattr(row, "get"):
            n = int(row.get("n") or 0)
            fmin = (row.get("fecha_min") or "") or ""
            fmax = (row.get("fecha_max") or "") or ""
        else:
            n = int(row[0] or 0) if row else 0
            fmin = str(row[1] or "") if row and len(row) > 1 else ""
            fmax = str(row[2] or "") if row and len(row) > 2 else ""
        suf = (" tag=%s" % tag) if tag else ""
        log.info(
            "[GANADORES] pendientes encontrados=%s fecha_min=%s fecha_max=%s%s",
            n,
            fmin or "—",
            fmax or "—",
            suf,
        )
        return {"n": n, "fecha_min": fmin, "fecha_max": fmax}
    except Exception as e:
        log.warning("_ganadores_log_pendientes_stats: %s", e, exc_info=True)
        return {"n": 0, "fecha_min": "", "fecha_max": ""}


def _premios_pendientes_aggregate(
    cur,
    cajero_username=None,
    fecha_ref=None,
    omit_integridad_fecha=None,
    fecha_hasta=None,
):
    """
    Totales de premios pendientes (todas las filas) para métricas de /ganadores sin traer el universo completo.
    Devuelve dict: sum_premio, sum_monto, n_lines, n_tickets.

    - `fecha_ref` (YYYY-MM-DD): solo ese día (legado).
    - `fecha_hasta` (YYYY-MM-DD): sorteos con fecha efectiva <= esa fecha (tarjeta «hasta hoy»).
    - Ambos None: **todos** los pendientes históricos.
    """
    params = []
    caj_filter = ""
    if (cajero_username or "").strip():
        caj_filter = " AND lower(trim(COALESCE(p.cajero, ''))) = lower(trim(%s))"
        params.append((cajero_username or "").strip())
    fecha_filter = ""
    fr = (str(fecha_ref or "").strip()[:10])
    fh = (str(fecha_hasta or "").strip()[:10])
    if len(fr) == 10:
        fecha_filter = _premios_fecha_calendario_match_sql()
        params.extend(_premios_fecha_calendario_match_params(fr))
    elif len(fh) == 10:
        fexpr = _premios_fecha_sorteo_efectiva_expr()
        fecha_filter = (
            " AND (length(" + fexpr + ") < 10 OR " + fexpr + " <= %s)"
        )
        params.append(fh)
    if omit_integridad_fecha is None:
        omit_integridad_fecha = len(fr) != 10
    _int_join = _premios_lista_integridad_join_sql()
    if omit_integridad_fecha:
        _int_where = _premios_lista_ticket_activo_where_sql()
    else:
        _int_where = (
            _premios_lista_integridad_where_sql_pg()
            if os.environ.get("DATABASE_URL")
            else _premios_lista_integridad_where_sql_sqlite()
        )
    cur.execute(
        _sql(
            """
            SELECT COALESCE(SUM(p.premio), 0) AS sum_premio,
                   COALESCE(SUM(p.monto), 0) AS sum_monto,
                   COUNT(*) AS n_lines,
                   COUNT(DISTINCT p.ticket_id) AS n_tickets
            FROM premios p
            """
            + _int_join
            + """
            WHERE p.estado = 'pendiente'
            """
            + _int_where
            + caj_filter
            + fecha_filter
        ),
        tuple(params),
    )
    row = cur.fetchone() or {}
    if hasattr(row, "get"):
        return {
            "sum_premio": float(row.get("sum_premio") or 0),
            "sum_monto": float(row.get("sum_monto") or 0),
            "n_lines": int(row.get("n_lines") or 0),
            "n_tickets": int(row.get("n_tickets") or 0),
        }
    return {
        "sum_premio": float(row[0] or 0) if row else 0.0,
        "sum_monto": float(row[1] or 0) if row and len(row) > 1 else 0.0,
        "n_lines": int(row[2] or 0) if row and len(row) > 2 else 0,
        "n_tickets": int(row[3] or 0) if row and len(row) > 3 else 0,
    }


def _premios_pendientes_premio_por_cajero_clave(cur, cajero_username=None):
    """
    Suma premio pendiente agrupada por cajero (clave minúscula) y etiqueta display.
    Lista de dicts: clave, etiqueta, sum_premio.
    """
    params = []
    caj_filter = ""
    if (cajero_username or "").strip():
        caj_filter = " AND lower(trim(COALESCE(cajero, ''))) = lower(trim(%s))"
        params.append((cajero_username or "").strip())
    cur.execute(
        _sql(
            """
            SELECT
              CASE
                WHEN NULLIF(TRIM(COALESCE(cajero, '')), '') IS NULL THEN '__sin_cajero__'
                ELSE LOWER(TRIM(COALESCE(cajero, '')))
              END AS ck,
              MAX(TRIM(COALESCE(cajero, ''))) AS cajero_label,
              COALESCE(SUM(premio), 0) AS sum_premio
            FROM premios
            WHERE estado = 'pendiente'
            """
            + caj_filter
            + """
            GROUP BY 1
            ORDER BY 1
            """
        ),
        tuple(params),
    )
    out = []
    for row in cur.fetchall() or []:
        if hasattr(row, "get"):
            out.append(
                {
                    "clave": (row.get("ck") or "").strip() or "__sin_cajero__",
                    "etiqueta": (row.get("cajero_label") or "").strip(),
                    "sum_premio": float(row.get("sum_premio") or 0),
                }
            )
        else:
            out.append(
                {
                    "clave": str(row[0] or "").strip() or "__sin_cajero__",
                    "etiqueta": str(row[1] or "").strip(),
                    "sum_premio": float(row[2] or 0) if len(row) > 2 else 0.0,
                }
            )
    return out


def _premios_backfill_pendientes_desde_lineas(
    cur, cajero_username=None, limit=300, fecha_sorteo_dia=None
):
    """
    Candidatos a premios pendientes: **ticket_id** distintos desde **ticket_lines** cuya fecha_sorteo
    coincide con el día dado (RD), ticket no pagado, sin fila premios pendiente.
    No depende de tickets.lottery ni de tickets.ganador (solo tk.cajero / tk.pagado como cabecera).
    Luego recalcula premios con _ganadores_fetch_lineas_vs_resultados (siempre por líneas).
    """
    hoy_s = (fecha_sorteo_dia or ahora_rd().date().strftime("%Y-%m-%d")).strip()[:10]
    if len(hoy_s) != 10:
        return 0
    params = [hoy_s]
    caj_filter_pg = ""
    caj_filter_sq = ""
    if (cajero_username or "").strip():
        caj_filter_pg = " AND lower(trim(COALESCE(tk.cajero, ''))) = lower(trim(%s))"
        caj_filter_sq = " AND lower(trim(COALESCE(tk.cajero, ''))) = lower(trim(%s))"
        params.append((cajero_username or "").strip())
    if os.environ.get("DATABASE_URL"):
        cur.execute(
            """
            SELECT DISTINCT tl.ticket_id
            FROM ticket_lines tl
            INNER JOIN tickets tk ON tk.id = tl.ticket_id
            WHERE COALESCE(tl.estado, 'activo') <> 'cancelado'
              AND substr(trim(COALESCE(CAST(tl.fecha_sorteo AS TEXT), '')), 1, 10) = %s
              AND """
            + _sql_bool_not_true("tk.pagado")
            + """
            """
            + _sql_ticket_no_eliminado("tk")
            + """
              AND NOT EXISTS (
                  SELECT 1 FROM premios p
                  WHERE p.ticket_id = tl.ticket_id AND p.estado = 'pendiente'
              )
            """
            + caj_filter_pg
            + """
            ORDER BY tl.ticket_id DESC
            LIMIT %s
            """,
            tuple(params + [int(limit)]),
        )
    else:
        cur.execute(
            _sql(
                """
            SELECT DISTINCT tl.ticket_id
            FROM ticket_lines tl
            INNER JOIN tickets tk ON tk.id = tl.ticket_id
            WHERE COALESCE(tl.estado, 'activo') <> 'cancelado'
              AND substr(trim(COALESCE(tl.fecha_sorteo, '')), 1, 10) = %s
              AND COALESCE(tk.pagado, 0) = 0
            """
                + _sql_ticket_no_eliminado("tk")
                + """
              AND NOT EXISTS (
                  SELECT 1 FROM premios p
                  WHERE p.ticket_id = tl.ticket_id AND p.estado = 'pendiente'
              )
            """
                + caj_filter_sq
                + """
            ORDER BY tl.ticket_id DESC
            LIMIT %s
                """
            ),
            tuple(params + [int(limit)]),
        )
    rows = cur.fetchall() or []
    inserted = 0
    cfg = _ganadores_try_load_pagos_config(cur) or {}
    pagos_efectivo = {**PAGOS, **cfg}
    for row in rows:
        tid = row.get("ticket_id") if hasattr(row, "get") else (row[0] if row else None)
        if not tid:
            continue
        fecha_ref = hoy_s
        try:
            join_rows = _ganadores_fetch_lineas_vs_resultados(cur, fecha_ref, ticket_id=int(tid))
            lista = _ganadores_procesar_filas(
                join_rows, pagos=pagos_efectivo, hoy_rd_str=fecha_ref, cur=cur
            )
            for g in lista:
                if _premios_upsert_pendiente(cur, g):
                    inserted += 1
        except Exception as e:
            log.warning("premios legacy backfill ticket_id=%s: %s", tid, e, exc_info=True)
            _rollback_pg_cursor(cur)
    if inserted:
        log.info("premios backfill desde ticket_lines pendientes=%s (fecha_sorteo=%s)", inserted, hoy_s)
    return inserted


# Alias legado (nombre antiguo; la lógica ya no usa tickets.ganador como filtro principal).
_premios_backfill_pendientes_desde_tickets = _premios_backfill_pendientes_desde_lineas


def _ganadores_procesar_filas(rows_join, pagos=None, hoy_rd_str=None, cur=None, recalc_log=False, recalc_ctx=None):
    """
    Agrupa por line_id (evita duplicados si hay filas repetidas en JOIN),
    elige la variante con mayor premio, usa calcular_premio (Quiniela, Pale, Tripleta, Super Pale).
    pagos: dict opcional (p. ej. PAGOS fusionado con pagos_config); None usa PAGOS global.
    hoy_rd_str: fecha RD YYYY-MM-DD para validaciones de calendario y antigüedad.
    cur: cursor opcional; si está definido, resuelve el sorteo con `_resultado_sorteo_resolver_estricto`
    (fecha + lotería POS normalizada + hora lógica; sin usar res_lottery del JOIN). Descarta la línea si
    no hay fila única en `resultados` o si el JOIN no coincide con ese triple.
    DEBUG_VALIDACION_SORTEO=1 — imprime líneas [VALIDANDO] con ticket, jugada y triple oficial.
    Omitir validación canónica con GANADORES_SALTAR_CANONICO_RESULTADOS=1 (solo diagnóstico).
    """
    from collections import defaultdict

    _dbg_pfila = os.environ.get("DEBUG_GANADORES_PROCESAR_FILAS", "").strip().lower() in (
        "1",
        "true",
        "yes",
    )
    _dbg_premio_flow = os.environ.get("DEBUG_GANADORES_PREMIO_FLOW", "").strip().lower() in (
        "1",
        "true",
        "yes",
    )
    _saltar_val_final = os.environ.get("DEBUG_GANADORES_SALTAR_VAL_FINAL", "").strip().lower() in (
        "1",
        "true",
        "yes",
    )

    def _pmsg(*args, **kwargs):
        if _dbg_pfila:
            print(*args, **kwargs)

    hoy_rd_use = (hoy_rd_str or ahora_rd().strftime("%Y-%m-%d")).strip()[:10]
    _unsafe_g_dbg = os.environ.get("ALLOW_UNSAFE_GANADORES_DEBUG", "").strip().lower() in (
        "1",
        "true",
        "yes",
    )
    _sin_fecha_sql_dbg = _unsafe_g_dbg and (
        os.environ.get("DEBUG_CRUCE_SIN_FECHA") == "1"
        or os.environ.get("DEBUG_AISLAR_GANADORES") == "1"
    )
    _dbg_cruce_fecha = os.environ.get("DEBUG_CRUCE_FECHA_GANADOR", "").strip().lower() in (
        "1",
        "true",
        "yes",
    )

    by_line = defaultdict(list)
    for d in rows_join:
        lid = _ganadores_line_id_key(d.get("line_id"))
        if lid is None:
            _pmsg(
                "DEBUG _ganadores_procesar_filas descarta fila sin line_id normalizable:",
                d.get("line_id"),
                d.get("ticket_id"),
            )
            continue
        by_line[lid].append(d)

    lista = []
    dup_join = max(0, len(rows_join) - len(by_line))
    _dbg_n = 0
    log.debug(
        "_ganadores_procesar_filas inicio: rows_join=%s line_ids=%s dup_join=%s",
        len(rows_join),
        len(by_line),
        dup_join,
    )

    for lid, variants in by_line.items():
        best = None
        best_premio = 0.0
        _pmsg("DEBUG _ganadores_procesar_filas line_id:", lid, "variantes:", len(variants))
        if (
            cur is not None
            and variants
            and os.environ.get("GANADORES_SALTAR_CANONICO_RESULTADOS", "").strip() != "1"
        ):
            d0 = variants[0]
            fe0 = _ganadores_fecha_iso_para_comparar(d0.get("resultado_fecha"))
            triple_r, err_r, info_r = _resultado_sorteo_resolver_estricto(
                cur,
                d0.get("lottery"),
                d0.get("draw"),
                fe0,
            )
            _draw_disp = (
                formatear_hora_estandar(
                    str(_draw_efectivo_jugada(d0.get("lottery"), d0.get("draw")) or "").strip()
                )
                or str(d0.get("draw") or "").strip()
            )
            fe_dd_mm = ""
            if fe0 and len(fe0) >= 10:
                fe_dd_mm = "%s-%s" % (fe0[5:7], fe0[8:10])
            if _validacion_sorteo_debug_enabled():
                log.info(
                    "[VALIDANDO] estado=%s | ticket: %s %s %s | jugada: %s | resultado usado: %s | line_id=%s ticket_id=%s",
                    err_r or "ok",
                    normalizar_loteria(d0.get("lottery")) or (d0.get("lottery") or ""),
                    _draw_disp,
                    fe_dd_mm or (fe0 or ""),
                    normalizar_numero(d0.get("number")) or (d0.get("number") or ""),
                    (info_r.get("triple_txt") or "—") if isinstance(info_r, dict) else "—",
                    lid,
                    d0.get("ticket_id"),
                )
            if err_r == "duplicado_sorteo":
                log.warning(
                    "ganadores: resultado no encontrado (sorteo duplicado en BD) line_id=%s ticket_id=%s",
                    lid,
                    d0.get("ticket_id"),
                )
                if recalc_log:
                    _log_recalc_eval_line(
                        recalc_ctx=recalc_ctx,
                        ticket_id=d0.get("ticket_id"),
                        line_id=lid,
                        banca_id=d0.get("banca_id"),
                        fecha_sorteo_rd=_ganadores_fecha_sorteo_efectiva_str(d0)[:10],
                        lottery=d0.get("lottery"),
                        draw=d0.get("draw"),
                        numero=d0.get("number"),
                        play_decl=d0.get("play"),
                        premio=0.0,
                        motivo_no_ganador="duplicado_sorteo",
                    )
                continue
            if triple_r is not None and not err_r:
                cn = (
                    _norm_sorteo_dos_digitos(triple_r[0]),
                    _norm_sorteo_dos_digitos(triple_r[1]),
                    _norm_sorteo_dos_digitos(triple_r[2]),
                )
                if all(cn):
                    matched_canon = [d for d in variants if _ganadores_triple_resultado_norm(d) == cn]
                    if matched_canon:
                        variants = matched_canon
                    else:
                        _sorteo_validacion_metrics_inc("premios_incorrectos_detectados")
                        log.warning(
                            "ganadores: JOIN mismatch — resultado usado distinto — line_id=%s ticket_id=%s — triple JOIN %s vs oficial %s",
                            lid,
                            d0.get("ticket_id"),
                            _ganadores_triple_resultado_norm(d0),
                            cn,
                        )
                        if recalc_log:
                            _log_recalc_eval_line(
                                recalc_ctx=recalc_ctx,
                                ticket_id=d0.get("ticket_id"),
                                line_id=lid,
                                banca_id=d0.get("banca_id"),
                                fecha_sorteo_rd=_ganadores_fecha_sorteo_efectiva_str(d0)[:10],
                                lottery=d0.get("lottery"),
                                draw=d0.get("draw"),
                                numero=d0.get("number"),
                                play_decl=d0.get("play"),
                                r1=cn[0],
                                r2=cn[1],
                                r3=cn[2],
                                premio=0.0,
                                motivo_no_ganador="join_mismatch",
                            )
                        continue
                else:
                    log.warning(
                        "ganadores: resultado incompleto en BD line_id=%s ticket_id=%s cn=%s",
                        lid,
                        d0.get("ticket_id"),
                        cn,
                    )
                    if recalc_log:
                        _log_recalc_eval_line(
                            recalc_ctx=recalc_ctx,
                            ticket_id=d0.get("ticket_id"),
                            line_id=lid,
                            banca_id=d0.get("banca_id"),
                            fecha_sorteo_rd=_ganadores_fecha_sorteo_efectiva_str(d0)[:10],
                            lottery=d0.get("lottery"),
                            draw=d0.get("draw"),
                            numero=d0.get("number"),
                            play_decl=d0.get("play"),
                            premio=0.0,
                            motivo_no_ganador="resultado_incompleto",
                        )
                    continue
            elif err_r:
                log.warning(
                    "ganadores: resolutor estricto no disponible (%s) — usando triple del JOIN line_id=%s ticket_id=%s",
                    err_r,
                    lid,
                    d0.get("ticket_id"),
                )
        for d in variants:
            if not _sin_fecha_sql_dbg and not _ganadores_row_fecha_linea_eq_resultado_strict(d):
                if os.environ.get("DEBUG_CRUCE_TICKET_RESULTADO_FECHA", "").strip().lower() in (
                    "1",
                    "true",
                    "yes",
                ):
                    _tl = _parse_iso_date_only((str(d.get("fecha_sorteo") or "").strip()[:10]))
                    _rf = _parse_iso_date_only(d.get("resultado_fecha"))
                    print(
                        "Ticket:",
                        repr(d.get("number")),
                        "fecha_sorteo:",
                        _tl.isoformat() if _tl else None,
                        "| Resultado fecha:",
                        _rf.isoformat() if _rf else None,
                        "| Coinciden:",
                        (_tl == _rf) if (_tl and _rf) else False,
                        "| line_id:",
                        lid,
                    )
                _pmsg("DEBUG _ganadores_procesar_filas descarta fecha linea != resultado (strict):", lid)
                continue
            if os.environ.get("DEBUG_JOIN_GANADORES") == "1":
                _ganadores_debug_imprimir_fila_join(d, prefijo="[premio] ")
            try:
                amt = float(d.get("amount") or 0)
            except (TypeError, ValueError):
                _pmsg("DEBUG _ganadores_procesar_filas descarta amount inválido:", d.get("amount"), "line_id:", lid)
                continue
            if amt <= 0:
                _pmsg("DEBUG _ganadores_procesar_filas descarta amount <= 0:", amt, "line_id:", lid)
                continue
            fsl_raw = _ganadores_fecha_sorteo_efectiva_str(d)
            if len(fsl_raw) < 10:
                _pmsg("DEBUG _ganadores_procesar_filas descarta fecha ticket/sorteo corta:", repr(fsl_raw), "line_id:", lid)
                continue
            rfi = _ganadores_fecha_iso_para_comparar(d.get("resultado_fecha"))
            if _dbg_cruce_fecha:
                _coinc = bool(rfi) and fsl_raw[:10] == rfi
                print(
                    "CRUCE_FECHA ticket_lines.fecha_sorteo:",
                    fsl_raw[:10],
                    "| resultado.fecha:",
                    rfi,
                    "| coinciden:",
                    _coinc,
                    "| line_id:",
                    lid,
                )
            if not _sin_fecha_sql_dbg:
                if not rfi or fsl_raw[:10] != rfi:
                    _pmsg(
                        "DEBUG _ganadores_procesar_filas descarta fecha no coincide:",
                        {"fecha_sorteo": fsl_raw[:10], "resultado_fecha": rfi, "line_id": lid},
                    )
                    continue
            play_decl = d.get("play")
            num_raw = d.get("number")
            play = _play_efectivo_cruce(play_decl, num_raw)
            num = normalizar_numero(num_raw)
            r1, r2, r3 = d.get("primero"), d.get("segundo"), d.get("tercero")
            resultados_norm = [
                _norm_sorteo_dos_digitos(r1),
                _norm_sorteo_dos_digitos(r2),
                _norm_sorteo_dos_digitos(r3),
            ]
            if _dbg_premio_flow:
                n_cmp = _norm_sorteo_dos_digitos(num_raw)
                pool = [x for x in resultados_norm if x]
                print(
                    "EVALUANDO:",
                    d.get("ticket_id"),
                    repr(d.get("number")),
                    "| norm(tl.number)=",
                    repr(n_cmp),
                    "| r1,r2,r3(raw)=",
                    r1,
                    r2,
                    r3,
                    "| norm(res)=",
                    resultados_norm,
                    "| en_pool_simple=",
                    (n_cmp in pool) if n_cmp else False,
                )
            if os.environ.get("DEBUG_GANADORES") == "1" and _dbg_n < 25:
                log.warning(
                    "DEBUG_GANADORES Ticket:%s Resultados:%s raw={jugada:%s, primero:%s, segundo:%s, tercero:%s, play:%s, lottery:%s, draw:%s}",
                    num,
                    resultados_norm,
                    num_raw,
                    r1,
                    r2,
                    r3,
                    play,
                    d.get("lottery"),
                    d.get("draw"),
                )
                print(
                    "DEBUG_GANADORES Ticket:",
                    num,
                    "Resultados:",
                    resultados_norm,
                )
                _dbg_n += 1
            try:
                premio = float(calcular_premio(play, num_raw, amt, r1, r2, r3, pagos=pagos) or 0)
                _tipo_ev, _res_ev, _coin_ev, _gana_ev, _mot_ev = _ganador_eval_detalle(
                    play_decl, num_raw, r1, r2, r3, premio=premio
                )
                _ganador_eval_log(
                    ticket_id=d.get("ticket_id"),
                    line_id=lid,
                    tipo=_tipo_ev,
                    numero=num_raw,
                    resultado=_res_ev,
                    coincidencias=_coin_ev,
                    gana=_gana_ev,
                    motivo=_mot_ev,
                )
                if recalc_log:
                    _log_recalc_eval_line(
                        recalc_ctx=recalc_ctx,
                        ticket_id=d.get("ticket_id"),
                        line_id=lid,
                        banca_id=d.get("banca_id"),
                        fecha_sorteo_rd=fsl_raw[:10],
                        lottery=d.get("lottery"),
                        draw=d.get("draw"),
                        numero=num_raw,
                        play_decl=play_decl,
                        r1=r1,
                        r2=r2,
                        r3=r3,
                        premio=premio,
                        motivo_no_ganador=None if premio > 0.004 else _mot_ev,
                        row_d=d,
                    )
                if play == "Tripleta":
                    _coin, _gana = _tripleta_coincidencias_eval(num_raw, r1, r2, r3)
                    _tripleta_eval_log(
                        d.get("ticket_id"),
                        num_raw,
                        _ganadores_resultado_str(r1, r2, r3),
                        _coin,
                        _gana,
                        play_decl=play_decl,
                    )
                _pmsg("DEBUG _ganadores_procesar_filas premio_calculado:", {"line_id": lid, "numero": num, "play": play, "premio": premio})
                if _dbg_premio_flow and premio > 0:
                    print(
                        "MATCH DETECTADO (premio>0):",
                        "ticket_id=",
                        d.get("ticket_id"),
                        "line_id=",
                        lid,
                        "number=",
                        repr(num_raw),
                        "premio=",
                        premio,
                        "play=",
                        repr(play),
                    )
            except Exception as e:
                _pmsg("DEBUG _ganadores_procesar_filas ERROR calcular_premio:", e, {"line_id": lid, "numero": num, "play": play})
                premio = 0.0
            if premio > best_premio:
                best_premio = premio
                best = (d, premio)
                _pmsg("DEBUG _ganadores_procesar_filas nuevo_best:", {"line_id": lid, "premio": premio})
        if best is None or best_premio <= 0:
            _pmsg("DEBUG _ganadores_procesar_filas SIN GANADOR line_id:", lid, "best_premio:", best_premio)
            continue
        d, premio = best
        play_best = _play_efectivo_cruce(d.get("play"), d.get("number"))
        if os.environ.get("DEBUG_AUDIT_GANADORES") == "1":
            _ganadores_debug_audit_imprimir(d, "mejor_variante_por_linea", premio=premio)
        r1, r2, r3 = d.get("primero"), d.get("segundo"), d.get("tercero")
        if not _ganadores_premio_integridad(
            play_best,
            d.get("number"),
            d.get("amount"),
            r1,
            r2,
            r3,
            premio,
            pagos=pagos,
        ):
            _pmsg("DEBUG _ganadores_procesar_filas descarta por integridad:", {"line_id": lid, "numero": d.get("number"), "premio": premio})
            if os.environ.get("DEBUG_AUDIT_GANADORES") == "1":
                _ganadores_debug_audit_imprimir(d, "falla_integridad_premio", premio=premio, pasa_validacion=False)
            continue
        ok_vf = (
            True
            if recalc_log or _saltar_val_final
            else _ganadores_linea_pasa_validacion_final(d, premio, hoy_rd_use)
        )
        if _saltar_val_final and _dbg_premio_flow:
            print(
                "DEBUG_GANADORES_SALTAR_VAL_FINAL: omitiendo _ganadores_linea_pasa_validacion_final",
                {"ticket_id": d.get("ticket_id"), "line_id": lid, "premio": premio},
            )
        if os.environ.get("DEBUG_AUDIT_GANADORES") == "1":
            _ganadores_debug_audit_imprimir(d, "tras_validacion_final", premio=premio, pasa_validacion=ok_vf)
        if not ok_vf:
            _pmsg("DEBUG _ganadores_procesar_filas descarta por validacion_final:", {"line_id": lid, "ticket_id": d.get("ticket_id"), "numero": d.get("number"), "premio": premio})
            continue
        try:
            amt_f = float(d.get("amount") or 0)
        except (TypeError, ValueError):
            _pmsg("DEBUG _ganadores_procesar_filas descarta amount final inválido:", d.get("amount"), "line_id:", lid)
            continue
        play_c = play_best
        Pm = _merge_pagos_calc(pagos)
        if play_c == "Quiniela":
            fragmentos = _quiniela_premio_fragmentos(d.get("number"), amt_f, r1, r2, r3, Pm)
            if not fragmentos:
                _pmsg("DEBUG _ganadores_procesar_filas Quiniela sin fragmentos pese premio>0:", lid, premio)
                continue
            filas_emit = [
                {"premio_shard": f["premio_shard"], "premio": float(f.get("premio") or 0), "jug": f.get("jugado_norm") or ""}
                for f in fragmentos
            ]
        else:
            filas_emit = [
                {
                    "premio_shard": "0",
                    "premio": float(premio or 0),
                    "jug": (normalizar_numero(d.get("number")) or str(d.get("number") or "").strip()),
                }
            ]
        dbg_ticket_multi = os.environ.get("DEBUG_QUINIELA_TICKET_PREMIO", "").strip().lower() in ("1", "true", "yes")
        tid_dbg = int(d.get("ticket_id") or 0)
        res_txt_dbg = [_norm_sorteo_dos_digitos(r1), _norm_sorteo_dos_digitos(r2), _norm_sorteo_dos_digitos(r3)]
        total_emit_dbg = round(sum(max(0.0, float(x.get("premio") or 0)) for x in filas_emit), 2)
        if dbg_ticket_multi:
            print("ticket:", tid_dbg)
            print("resultado:", res_txt_dbg)
            print("total:", total_emit_dbg)
        _draw_eff = _draw_efectivo_jugada(d.get("lottery"), d.get("draw"))
        _draw_show = (
            formatear_hora_estandar(str(_draw_eff or "").strip())
            or formatear_hora_estandar(str(d.get("draw") or "").strip())
        )
        for fe in filas_emit:
            frag_p = float(fe.get("premio") or 0)
            if frag_p <= 0:
                continue
            jug_vis = str(fe.get("jug") or "").strip()
            num_cell = (normalizar_numero(jug_vis) or jug_vis) if jug_vis else (normalizar_numero(d.get("number")) or "")
            shard_cell = _premio_shard_norm(fe)
            ac = _ganadores_acierto_presentacion(
                play_best,
                jug_vis or num_cell,
                r1,
                r2,
                r3,
                frag_p,
                pagos=pagos,
                premio_shard=shard_cell,
            )
            lista.append({
                "line_id": lid,
                "ticket_id": d.get("ticket_id"),
                "number": num_cell,
                "lottery": normalizar_loteria(d.get("lottery")) or str(d.get("lottery") or "").strip(),
                "draw": _draw_show,
                "play": d.get("play"),
                "premio": frag_p,
                "premio_shard": shard_cell,
                "monto": amt_f,
                "cajero": d.get("cajero") or "",
                "banca_id": d.get("banca_id"),
                "pagado": False,
                "resultado": _ganadores_resultado_str(r1, r2, r3),
                "tipo": _ganadores_tipo_play(d.get("play")),
                "resultado_fecha_iso": _ganadores_fecha_iso_para_comparar(d.get("resultado_fecha")),
                "fecha_sorteo_linea": _ganadores_fecha_sorteo_efectiva_str(d),
                "numero_jugado_display": ac.get("numero_jugado_display") or "",
                "numero_oficial_display": ac.get("numero_oficial_display") or "—",
                "resultado_sorteo": ac.get("resultado_sorteo") or "",
                "acierto_detalle": ac.get("detalle") or "",
                "acierto_ok": ac.get("acierto_ok", False),
                "ganador_detectado_en": d.get("res_ganador_detectado_en"),
            })
            _pmsg(
                "DEBUG _ganadores_procesar_filas AGREGA GANADOR:",
                {
                    "line_id": lid,
                    "ticket_id": d.get("ticket_id"),
                    "premio_shard": shard_cell,
                    "numero": num_cell,
                    "premio": frag_p,
                },
            )
            if dbg_ticket_multi:
                print("numero:", repr(jug_vis or num_cell))
                print("premio detectado:", frag_p)

    tickets_unicos = len({g["ticket_id"] for g in lista})
    log.debug(
        "ganadores: join_rows=%s line_ids=%s dup_join≈%s filas=%s tickets_unicos=%s",
        len(rows_join),
        len(by_line),
        dup_join,
        len(lista),
        tickets_unicos,
    )
    return lista


def _ganadores_agrupar_por_loteria_tipo(lista_ganadores):
    from collections import defaultdict

    agrupado = defaultdict(lambda: defaultdict(list))
    for g in lista_ganadores:
        agrupado[g.get("lottery") or ""][g.get("tipo") or "otro"].append(g)
    return {lot: dict(tipos) for lot, tipos in agrupado.items()}


def _ganadores_agrupar_por_ticket(lista_ganadores):
    """Una fila por ticket: suma premios de todas las líneas ganadoras y conserva el detalle en lineas.

    Calcula `estado_ticket` y `estado_label` a nivel de ticket:
      - "pagado"     → todas las líneas con estado='pagado' (o ticket marcado pagado).
      - "pendiente"  → al menos una línea pendiente.
      - "revertido"  → pendiente pero con pago previo revertido (informativo).
    """
    from collections import OrderedDict

    by_tid = OrderedDict()
    for g in lista_ganadores or []:
        tid = g.get("ticket_id")
        if tid is None:
            continue
        if tid not in by_tid:
            by_tid[tid] = {
                "ticket_id": tid,
                "sorteo": "",
                "cajero": (g.get("cajero") or ""),
                "total_premio": 0.0,
                "pagado": bool(g.get("pagado")),
                "was_revertido": bool(g.get("was_revertido")),
                "any_pendiente": False,
                "any_pagado": False,
                "lineas": [],
            }
        else:
            if g.get("cajero"):
                by_tid[tid]["cajero"] = g.get("cajero") or by_tid[tid]["cajero"]
            by_tid[tid]["pagado"] = bool(by_tid[tid]["pagado"] or g.get("pagado"))
            by_tid[tid]["was_revertido"] = bool(by_tid[tid]["was_revertido"] or g.get("was_revertido"))
        _est = (str(g.get("estado") or "").strip().lower())
        if _est == "pagado":
            by_tid[tid]["any_pagado"] = True
        elif _est == "pendiente":
            by_tid[tid]["any_pendiente"] = True
        by_tid[tid]["total_premio"] += float(g.get("premio") or 0)
        by_tid[tid]["lineas"].append(g)
    out = []
    for tid, ag in by_tid.items():
        draws = []
        for ln in ag["lineas"]:
            d = str(ln.get("draw") or "").strip()
            if d and d not in draws:
                draws.append(d)
        ag["sorteo"] = ", ".join(draws) if draws else "—"
        ag["total_premio"] = round(float(ag["total_premio"]), 2)
        _pend_lines = [
            ln
            for ln in (ag.get("lineas") or [])
            if str(ln.get("estado") or "").strip().lower() == "pendiente"
            and not bool(ln.get("pagado"))
            and float(ln.get("premio") or 0) > 0.004
        ]
        ag["n_lineas_pendientes"] = len(_pend_lines)
        ag["total_pendiente"] = round(
            sum(float(ln.get("premio") or 0) for ln in _pend_lines), 2
        )
        ag_dbg = os.environ.get("DEBUG_PAGO_PREMIO", "").strip().lower() in (
            "1",
            "true",
            "yes",
        )
        pay_info = _premio_ticket_eval_habilitar_pago_ui(
            ag.get("lineas") or [],
            ticket_id=int(tid),
            imprimir_debug=ag_dbg,
        )
        ag["tiene_ganador_premio"] = bool(pay_info.get("tiene_ganador"))
        ag["habilitar_pago"] = bool(pay_info.get("habilitar_pago"))
        ag["pago_habilitar_unix_ms"] = int(pay_info.get("pago_habilitar_unix_ms") or 0)
        # Estado consolidado por ticket para la tabla "Lista de Ganadores".
        if ag["pagado"] or (ag.get("any_pagado") and not ag.get("any_pendiente")):
            ag["estado_ticket"] = "pagado"
            ag["estado_label"] = "Pagado"
            ag["estado_color"] = "#15803d"
            ag["estado_bg"] = "#dcfce7"
        elif ag.get("any_pendiente") and ag.get("was_revertido"):
            ag["estado_ticket"] = "revertido"
            ag["estado_label"] = "Revertido"
            ag["estado_color"] = "#92400e"
            ag["estado_bg"] = "#fef3c7"
        elif ag.get("any_pendiente") and ag.get("any_pagado"):
            ag["estado_ticket"] = "parcial"
            ag["estado_label"] = "Parcial"
            ag["estado_color"] = "#075985"
            ag["estado_bg"] = "#e0f2fe"
        else:
            ag["estado_ticket"] = "pendiente"
            ag["estado_label"] = "Pendiente"
            ag["estado_color"] = "#9a3412"
            ag["estado_bg"] = "#ffedd5"
        out.append(ag)
    return out


def _ganadores_grilla_fila_tiene_numeros(d):
    """True si la fila de resultados trae algún número de sorteo cargado."""
    if not isinstance(d, dict):
        return False

    def _ok(x):
        if x is None:
            return False
        s = str(x).strip()
        return s not in ("", "--", "-", "—")

    return (
        _ok(d.get("primero"))
        or _ok(d.get("segundo"))
        or _ok(d.get("tercero"))
    )


def _ganadores_catalogo_clave_bd(lot, draw):
    """
    Clave estable para clasificar filas BD en el mismo «casillero» del catálogo oficial.
    Alineado con cómo deduplicamos en `clave_unica_resultado_fila` tras normalizar lotería y horario.
    """
    lot0 = normalizar_loteria(lot) or str(lot or "").strip()
    dr_raw = _draw_efectivo_jugada(lot0, draw)
    dr0 = normalizar_sorteo(dr_raw) or str(dr_raw or "").strip()
    return clave_unica_resultado_fila({"lottery": lot0, "draw": dr0})


def _ganadores_resultados_row_dict(r):
    """Convierte fila SQL (dict / sqlite3.Row / tupla) a dict homogéneo."""
    if not r:
        return {}
    if isinstance(r, dict):
        d = dict(r)
    elif hasattr(r, "keys"):
        try:
            d = {k: r[k] for k in r.keys()}
        except Exception:
            d = dict(r)
    else:
        d = {
            "lottery": r[0] if len(r) > 0 else "",
            "draw": r[1] if len(r) > 1 else "",
            "primero": r[2] if len(r) > 2 else "",
            "segundo": r[3] if len(r) > 3 else "",
            "tercero": r[4] if len(r) > 4 else "",
            "fecha": r[5] if len(r) > 5 else None,
        }
    if d.get("fecha") is None and d.get("fecha_rd") is not None:
        d["fecha"] = d.get("fecha_rd")
    return d


def _ganadores_log_resultado_lookup(
    fecha_consultada,
    fecha_rd,
    loteria,
    sorteo,
    resultado_encontrado,
    fuente,
    motivo_si_vacio="",
):
    log.info(
        "[GANADORES RESULTADOS] fecha_consultada=%s fecha_rd=%s loteria=%s sorteo=%s "
        "resultado_encontrado=%s fuente=%s motivo_si_vacio=%s",
        fecha_consultada,
        fecha_rd,
        loteria,
        sorteo,
        resultado_encontrado,
        fuente,
        motivo_si_vacio or "",
    )


def _ganadores_resultados_row_catalog_keys(lot, draw):
    """Claves de casillero del catálogo oficial que puede cubrir una fila cruda de BD."""
    keys = set()
    lot_s = str(lot or "").strip()
    dr_s = str(draw or "").strip()
    nk = _ganadores_catalogo_clave_bd(lot_s, dr_s)
    if nk:
        keys.add(nk)
    lot_norm = normalizar_loteria(lot_s) or lot_s
    if lot_norm != lot_s:
        nk_ln = _ganadores_catalogo_clave_bd(lot_norm, dr_s)
        if nk_ln:
            keys.add(nk_ln)
    combo = f"{lot_s} {dr_s}".strip()
    for internal_key, (lot_db, draw_db) in RESULT_LOTTERY_TO_TICKET.items():
        if (
            lot_s == internal_key
            or dr_s == internal_key
            or combo == internal_key
            or lot_norm == internal_key
        ):
            nk2 = _ganadores_catalogo_clave_bd(lot_db, draw_db)
            if nk2:
                keys.add(nk2)
    return keys


def _ganadores_resultados_loteria_draw_candidates(lottery_cat, draw_raw):
    """Nombres/horas posibles en BD para un casillero del catálogo oficial."""
    lot_cat = normalizar_loteria(lottery_cat) or str(lottery_cat or "").strip()
    dr_eff = _draw_efectivo_jugada(lot_cat, draw_raw)
    dr_norm = normalizar_sorteo(dr_eff) or normalizar_sorteo(draw_raw) or str(draw_raw or "").strip()
    loteria_candidates = {lot_cat}
    draw_candidates = set()
    if dr_norm:
        draw_candidates.add(dr_norm)
        dr_std = formatear_hora_estandar(dr_norm) or ""
        if dr_std:
            draw_candidates.add(dr_std)
        dr_canon = draw_almacen_canonico(dr_norm) or ""
        if dr_canon:
            draw_candidates.add(dr_canon)
    cat_nk = _ganadores_catalogo_clave_bd(lot_cat, dr_norm)
    internal_keys = []
    for internal_key, (lot_db, draw_db) in RESULT_LOTTERY_TO_TICKET.items():
        if _ganadores_catalogo_clave_bd(lot_db, draw_db) == cat_nk:
            internal_keys.append(internal_key)
            loteria_candidates.add(internal_key)
            loteria_candidates.add(lot_db)
            dn = normalizar_sorteo(draw_db) or str(draw_db or "").strip()
            if dn:
                draw_candidates.add(dn)
    return lot_cat, dr_norm, cat_nk, sorted(loteria_candidates), sorted(draw_candidates), internal_keys


def _ganadores_resultados_fetch_latest_para_catalogo(cur, lottery_cat, draw_raw, hoy_str=None):
    """
    Último resultado en BD para un casillero del catálogo (sin límite inferior de ventana).
    Cubre nombres legacy (Florida Día, King Lottery 12:30, etc.).
    """
    hoy_str = str(hoy_str or ahora_rd().date().strftime("%Y-%m-%d"))[:10]
    lot_cat, dr_norm, cat_nk, loteria_candidates, draw_candidates, _ = (
        _ganadores_resultados_loteria_draw_candidates(lottery_cat, draw_raw)
    )
    if not lot_cat or not cat_nk:
        _ganadores_log_resultado_lookup(
            hoy_str, hoy_str, lottery_cat, draw_raw, False, "sql_ultimo", "sin_catalogo"
        )
        return None

    rows = []
    lots = [x for x in loteria_candidates if x]
    if not lots:
        return None
    try:
        if os.environ.get("DATABASE_URL"):
            _fd = _sql_expr_resultados_fecha_calendario_rd_pg("fecha")
            cur.execute(
                f"""
                SELECT lottery, draw, primero, segundo, tercero, {_fd} AS fecha_rd
                FROM resultados
                WHERE lottery = ANY(%s)
                ORDER BY {_fd} DESC NULLS LAST, id DESC
                LIMIT 400
                """,
                (lots,),
            )
            rows = cur.fetchall() or []
        else:
            _fds = _sql_expr_resultados_fecha_calendario_rd_sqlite("fecha")
            ph_lots = ",".join(["%s"] * len(lots))
            cur.execute(
                _sql(
                    f"""
                    SELECT lottery, draw, primero, segundo, tercero, """
                    + _fds
                    + """ AS fecha_rd
                    FROM resultados
                    WHERE lottery IN ("""
                    + ph_lots
                    + """)
                    ORDER BY """
                    + _fds
                    + """ DESC, id DESC
                    LIMIT 400
                    """
                ),
                tuple(lots),
            )
            rows = cur.fetchall() or []
    except Exception as exc:
        log.warning("_ganadores_resultados_fetch_latest_para_catalogo: %s", exc, exc_info=True)
        _ganadores_log_resultado_lookup(
            hoy_str, hoy_str, lottery_cat, draw_raw, False, "sql_ultimo", str(exc)[:120]
        )
        return None

    matches = []
    for r in rows:
        d = _ganadores_resultados_row_dict(r)
        row_keys = _ganadores_resultados_row_catalog_keys(d.get("lottery"), d.get("draw"))
        if cat_nk not in row_keys:
            continue
        dr_row = normalizar_sorteo(d.get("draw") or "") or str(d.get("draw") or "").strip()
        if draw_candidates and dr_row and dr_row not in draw_candidates:
            dr_eff_row = normalizar_sorteo(_draw_efectivo_jugada(d.get("lottery"), d.get("draw")) or "")
            if dr_eff_row and dr_eff_row not in draw_candidates:
                continue
        if not _ganadores_grilla_fila_tiene_numeros(d):
            continue
        matches.append(d)

    if not matches:
        _ganadores_log_resultado_lookup(
            hoy_str, hoy_str, lottery_cat, draw_raw, False, "sql_ultimo", "sin_fila_con_numeros"
        )
        return None

    def _fecha_key(d):
        return _parse_iso_date_only(d.get("fecha")) or date.min

    return max(matches, key=_fecha_key)


def _ganadores_resultados_buckets_ventana(cur, fecha_desde, fecha_hasta):
    """Agrupa filas de `resultados` entre dos fechas (calendario RD) por casillero oficial."""
    from collections import defaultdict

    buckets = defaultdict(list)
    if not cur:
        return buckets

    fecha_desde = str(fecha_desde or "").strip()[:10]
    fecha_hasta = str(fecha_hasta or "").strip()[:10]

    rows = []
    try:
        if os.environ.get("DATABASE_URL"):
            _fd = _sql_expr_resultados_fecha_calendario_rd_pg("fecha")
            cur.execute(
                f"""
                SELECT lottery, draw, primero, segundo, tercero, {_fd} AS fecha_rd
                FROM resultados
                WHERE {_fd} >= CAST(%s AS DATE) AND {_fd} <= CAST(%s AS DATE)
                ORDER BY {_fd} DESC, lottery ASC, draw ASC
                LIMIT 8000
                """,
                (fecha_desde, fecha_hasta),
            )
            rows = cur.fetchall() or []
        else:
            _fds = _sql_expr_resultados_fecha_calendario_rd_sqlite("fecha")
            cur.execute(
                _sql(
                    """
                    SELECT lottery, draw, primero, segundo, tercero, """
                    + _fds
                    + """ AS fecha_rd
                    FROM resultados
                    WHERE date("""
                    + _fds
                    + """) >= date(%s) AND date("""
                    + _fds
                    + """) <= date(%s)
                    ORDER BY """
                    + _fds
                    + """ DESC, lottery ASC, draw ASC
                    LIMIT 8000
                    """
                ),
                (fecha_desde, fecha_hasta),
            )
            rows = cur.fetchall() or []
    except Exception as exc:
        print("_ganadores_resultados_buckets_ventana:", exc)
        return buckets

    for r in rows:
        d = _ganadores_resultados_row_dict(r)
        for nk in _ganadores_resultados_row_catalog_keys(d.get("lottery"), d.get("draw")):
            buckets[nk].append(d)

    return buckets


def _ganadores_catalogo_pick_fila_prioridad(sorted_desc, hoy_d):
    """
    Elige una fila para mostrar el casillero: primero fecha=hoy con números válidos,
    si no hay, el día más reciente anterior con números, luego placeholders recientes.
    """
    parsed = []
    for r in sorted_desc or []:
        fd = _parse_iso_date_only(r.get("fecha") if isinstance(r, dict) else None)
        parsed.append((fd, r))

    tienen_nums = [(fd, r) for fd, r in parsed if isinstance(r, dict) and _ganadores_grilla_fila_tiene_numeros(r)]
    sin_nums = [(fd, r) for fd, r in parsed if isinstance(r, dict) and not _ganadores_grilla_fila_tiene_numeros(r)]

    for fd, r in tienen_nums:
        if fd == hoy_d:
            return r
    for fd, r in tienen_nums:
        if fd is not None and fd < hoy_d:
            return r
    for fd, r in sin_nums:
        if fd == hoy_d:
            return r
    for fd, r in sin_nums:
        if fd is not None and fd < hoy_d:
            return r
    return sorted_desc[0] if sorted_desc else None


def _ganadores_grilla_resultados_catalogo_fallback(cur, hoy_str):
    """
    Lista fija ordenada como SORTEOS_POR_LOTERIA: por casillero, muestra resultado de fecha=hoy RD
    (verde tras finalizar/color) si ya está publicado; si no, el último publicado dentro de ventana (gris).
    """
    hoy_str = str(hoy_str or "").strip()[:10]
    hoy_d = _parse_iso_date_only(hoy_str) or ahora_rd().date()
    try:
        max_days = max(7, min(120, int(os.environ.get("RESULTADOS_FALLBACK_MAX_DIAS", "45"))))
    except (TypeError, ValueError):
        max_days = 45
    fecha_desde = (hoy_d - timedelta(days=max_days)).strftime("%Y-%m-%d")
    fecha_hasta = hoy_d.strftime("%Y-%m-%d")
    buckets = _ganadores_resultados_buckets_ventana(cur, fecha_desde, fecha_hasta)

    ln_clave_chk = clave_loteria("Loteria Nacional")
    ln_930 = normalizar_sorteo("9:00 PM")
    sunday_ln = _ganadores_resultados_fecha_a_date(fecha_hasta, hoy_str).weekday() == 6

    grid = []
    for lottery_cat, draws in SORTEOS_POR_LOTERIA.items():
        cat_loteria_key = clave_loteria(lottery_cat)
        for draw_raw in draws or []:
            nk = _ganadores_catalogo_clave_bd(lottery_cat, draw_raw)

            draw_disp = normalizar_sorteo(draw_raw) or str(draw_raw or "").strip()

            if not draw_disp:
                continue

            skip_ln930_dom = sunday_ln and cat_loteria_key == ln_clave_chk and draw_disp == ln_930
            if skip_ln930_dom:
                continue

            cand = buckets.get(nk, [])
            cand_sorted = sorted(
                cand,
                key=lambda rr: (_parse_iso_date_only(rr.get("fecha") if isinstance(rr, dict) else None) or date.min),
                reverse=True,
            )
            picked = _ganadores_catalogo_pick_fila_prioridad(cand_sorted, hoy_d)
            fuente = "ventana"
            motivo_vacio = ""

            if not picked or not _ganadores_grilla_fila_tiene_numeros(picked):
                motivo_vacio = "sin_match_ventana"
                picked_sql = _ganadores_resultados_fetch_latest_para_catalogo(
                    cur, lottery_cat, draw_raw, hoy_str
                )
                if picked_sql:
                    picked = picked_sql
                    fuente = "sql_ultimo"
                    motivo_vacio = ""

            if picked and isinstance(picked, dict):
                row = dict(picked)
                row["lottery"] = str(lottery_cat).strip()
                row["draw"] = draw_disp
                _normalizar_campos_horario_compacto_fila(row)
                row["lottery_display"] = (row["lottery"] or "") + (
                    (" " + str(row["draw"] or "").strip()) if row.get("draw") else ""
                )
                _ganadores_log_resultado_lookup(
                    hoy_str,
                    str(row.get("fecha") or "")[:10],
                    lottery_cat,
                    draw_disp,
                    True,
                    fuente,
                    "",
                )
            else:
                row = {
                    "lottery": str(lottery_cat).strip(),
                    "draw": draw_disp,
                    "primero": None,
                    "segundo": None,
                    "tercero": None,
                    "fecha": None,
                }
                _normalizar_campos_horario_compacto_fila(row)
                row["lottery_display"] = (row["lottery"] or "") + (
                    (" " + str(row["draw"] or "").strip()) if row.get("draw") else ""
                )
                _ganadores_log_resultado_lookup(
                    hoy_str,
                    hoy_str,
                    lottery_cat,
                    draw_disp,
                    False,
                    fuente,
                    motivo_vacio or "sin_datos_bd",
                )
            grid.append(row)
    return grid


def _ganadores_grilla_alguno_oficial_hoy_con_datos(rows, hoy_str):
    """True si hay al menos un casillero con números cuya fecha BD es el día RD indicado."""
    hoy_d = _parse_iso_date_only(str(hoy_str or "").strip()[:10])
    if not hoy_d:
        return False
    for r in rows or []:
        if not isinstance(r, dict):
            continue
        fd = _parse_iso_date_only(r.get("fecha"))
        if fd == hoy_d and _ganadores_grilla_fila_tiene_numeros(r):
            return True
    return False


def _ganadores_resultados_meta_tarjeta(rows, hoy_str):
    """
    Metadatos solo para la tarjeta «Resultados de Hoy» (visual).
    No altera fechas en BD; distingue verde (fecha=hoy) vs gris (último publicado anterior).
    """
    hoy_d = _parse_iso_date_only(str(hoy_str or "").strip()[:10])
    ultima_d = None
    tiene_alguna_fila = False
    for r in rows or []:
        if not isinstance(r, dict):
            continue
        if not _ganadores_grilla_fila_tiene_numeros(r):
            continue
        tiene_alguna_fila = True
        fd = _parse_iso_date_only(r.get("fecha"))
        if fd and (ultima_d is None or fd > ultima_d):
            ultima_d = fd
    pendiente = not _ganadores_grilla_alguno_oficial_hoy_con_datos(rows, hoy_str)
    ultima_label = ultima_d.strftime("%d-%m-%Y") if ultima_d else ""
    return {
        "resultados_pendientes_hoy": pendiente,
        "resultados_ultima_fecha_display": ultima_label,
        "resultados_grilla_tiene_filas": bool(rows),
        "resultados_grilla_tiene_numeros": tiene_alguna_fila,
    }


def _ganadores_resultados_refresh_grilla_visual(cur, hoy_str):
    """
    Reconstruye la tabla de «Resultados» del dashboard (/ganadores) y /api/resultados_hoy
    compartiendo filtros LN/NY/reordenamiento y color fecha=hoy RD.
  Si falla el armado, devuelve la última grilla cacheada o el fallback desde BD.
    """
    hoy_str = str(hoy_str or "").strip()[:10]
    ttl_sec = _dashboard_cache_ttl_seconds()
    cache_ck = ("grilla_visual", hoy_str)
    cached_rows = None
    if ttl_sec > 0:
        cached_rows = _ttl_cache_peek("resultados", cache_ck)
        if cached_rows is not None:
            if any(
                isinstance(r, dict) and _ganadores_grilla_fila_tiene_numeros(r)
                for r in (cached_rows or [])
            ):
                return cached_rows

    try:
        resultados_hoy = _ganadores_grilla_resultados_catalogo_fallback(cur, hoy_str)
        resultados_fecha = hoy_str
        resultados_hoy = _filtrar_resultados_ny_solo_sorteos_oficiales(resultados_hoy)
        resultados_hoy = _filtrar_excluir_anguila_sin_la(resultados_hoy)
        resultados_hoy = _ganadores_resultados_filtrar_ln_por_dia_semana(
            resultados_hoy, resultados_fecha, hoy_str
        )
        resultados_hoy = _ganadores_resultados_completar_ln_600_si_falta(
            resultados_hoy, resultados_fecha, hoy_str
        )
        resultados_hoy = _ganadores_resultados_completar_ln_930_si_falta(
            resultados_hoy, resultados_fecha, hoy_str
        )
        resultados_hoy = _ganadores_resultados_ln_reordenar_bloque_ln(resultados_hoy)

        for _rf in resultados_hoy or []:
            _resultados_finalizar_display_horario(_rf)
            _resultado_row_set_color_por_sorteo_rd(_rf, hoy_str)
            _fd_rf = _parse_iso_date_only(_rf.get("fecha"))
            hoy_d_rf = _parse_iso_date_only(hoy_str)
            if _fd_rf:
                _rf["fecha_display"] = _fd_rf.strftime("%d-%m-%Y")
                _rf["fecha_visual_iso"] = _fd_rf.strftime("%Y-%m-%d")
                _rf["ultimo_publicado"] = bool(
                    _ganadores_grilla_fila_tiene_numeros(_rf)
                    and hoy_d_rf
                    and _fd_rf < hoy_d_rf
                )
            else:
                _rf["fecha_display"] = "—"
                _rf["fecha_visual_iso"] = ""
                _rf["ultimo_publicado"] = False

        if ttl_sec > 0 and any(
            isinstance(r, dict) and _ganadores_grilla_fila_tiene_numeros(r)
            for r in (resultados_hoy or [])
        ):
            _ttl_cache_store_put("resultados", cache_ck, resultados_hoy, ttl_sec)
        return resultados_hoy
    except Exception as _grilla_ex:
        log.warning(
            "[RESULTADOS_HOY] grilla visual falló hoy=%s: %s",
            hoy_str,
            _grilla_ex,
            exc_info=True,
        )
        if cached_rows is not None:
            return cached_rows
        try:
            return _ganadores_grilla_resultados_catalogo_fallback(cur, hoy_str)
        except Exception:
            return []


def _ganadores_resultados_fecha_a_date(fe, hoy_str):
    """Fecha de calendario RD de la grilla de resultados (misma noción que resultados_fecha / encabezado)."""
    if fe is None:
        return datetime.strptime(str(hoy_str)[:10], "%Y-%m-%d").date()
    if isinstance(fe, datetime):
        return fe.date()
    if isinstance(fe, date):
        return fe
    try:
        return datetime.strptime(str(fe)[:10], "%Y-%m-%d").date()
    except ValueError:
        return ahora_rd().date()


def _ganadores_resultados_filtrar_ln_por_dia_semana(rows, resultados_fecha, hoy_str):
    """
    Solo vista /ganadores: ajuste de calendario para Loteria Nacional.
    Domingo: no se muestra fila 9:00 PM (catálogo local).
    Los resultados reflejan la tabla `resultados` en BD — no se crean sorteos 9:00 PM solo en memoria.
    (Antes: si Conectate guardaba la noche como 6:00 PM, la UI copiaba números a 9:00 PM sin persistir;
    eso impedía que el módulo ganadores cruzara por draw 9:00 PM. Ahora el scraper persiste 9:00 PM y
    existe espejo 6→9 opcional para datos legacy; ver _resultado_espejo_ln_6pm_a_9pm_si_aplica.)
    """
    rows = list(rows or [])
    is_sunday = _ganadores_resultados_fecha_a_date(resultados_fecha, hoy_str).weekday() == 6
    ln_clave = clave_loteria("Loteria Nacional")
    d900 = normalizar_sorteo("9:00 PM")
    out = []
    for r in rows:
        if not isinstance(r, dict):
            out.append(r)
            continue
        if clave_loteria(r.get("lottery") or "") != ln_clave:
            out.append(r)
            continue
        dr = normalizar_sorteo(r.get("draw") or "") or str(r.get("draw") or "").strip()
        if dr == d900 and is_sunday:
            continue
        out.append(r)
    return out


def _ganadores_resultados_completar_ln_600_si_falta(rows, resultados_fecha, hoy):
    """En /ganadores: si hay filas de Loteria Nacional y falta 6:00 PM, agrega fila (pendiente o vacía)."""
    rows = list(rows or [])
    ln = "Loteria Nacional"
    ln_clave = clave_loteria(ln)
    d600 = normalizar_sorteo("6:00 PM")

    def _es_ln(r):
        return isinstance(r, dict) and clave_loteria(r.get("lottery") or "") == ln_clave

    def _draw_norm(r):
        if not isinstance(r, dict):
            return ""
        return normalizar_sorteo(r.get("draw") or "") or str(r.get("draw") or "").strip()

    if not any(_es_ln(r) for r in rows):
        return rows
    if any(_es_ln(r) and _draw_norm(r) == d600 for r in rows):
        return rows

    is_sunday = _ganadores_resultados_fecha_a_date(resultados_fecha, hoy).weekday() == 6
    fecha_val = resultados_fecha if resultados_fecha is not None else hoy
    fecha_res_str = (
        fecha_val.strftime("%Y-%m-%d")
        if hasattr(fecha_val, "strftime")
        else str(fecha_val)[:10]
    )
    display = f"{ln} {d600}" + ("" if is_sunday else " (Pendiente)")
    rows.append(
        {
            "lottery": ln,
            "draw": d600,
            "primero": None,
            "segundo": None,
            "tercero": None,
            "fecha": fecha_val,
            "lottery_display": display,
            "color": "green" if fecha_res_str == str(hoy)[:10] else "gray",
        }
    )
    return rows


def _ganadores_resultados_ln_reordenar_bloque_ln(rows):
    """Ordena filas consecutivas de Loteria Nacional como 2:30 PM, 6:00 PM, 9:00 PM."""
    rows = list(rows or [])
    ln_name = "Loteria Nacional"
    ln_clave = clave_loteria(ln_name)
    order_map = {
        normalizar_sorteo("2:30 PM"): 0,
        normalizar_sorteo("6:00 PM"): 1,
        normalizar_sorteo("9:00 PM"): 2,
    }
    out = []
    i = 0
    n = len(rows)
    while i < n:
        r = rows[i]
        if isinstance(r, dict) and clave_loteria(r.get("lottery") or "") == ln_clave:
            chunk = []
            while (
                i < n
                and isinstance(rows[i], dict)
                and clave_loteria(rows[i].get("lottery") or "") == ln_clave
            ):
                chunk.append(rows[i])
                i += 1

            def _draw_sort_key(r0):
                dr = normalizar_sorteo(r0.get("draw") or "") or str(
                    r0.get("draw") or ""
                ).strip()
                return (order_map.get(dr, 50), dr)

            chunk.sort(key=_draw_sort_key)
            out.extend(chunk)
        else:
            out.append(r)
            i += 1
    return out


def _ganadores_resultados_completar_ln_930_si_falta(rows, resultados_fecha, hoy):
    """
    En /ganadores, si ya hay filas de Loteria Nacional pero falta el sorteo oficial 9:00 PM,
    agrega una fila vacía (--) para alinear con SORTEOS_POR_LOTERIA. Conectate solo publica
    Gana Más + un bloque «Lotería Nacional»; el 9:00 PM no siempre existe en BD.
    No aplica en domingo (ese día no se muestra el 9:00 PM).
    """
    rows = list(rows or [])
    if _ganadores_resultados_fecha_a_date(resultados_fecha, hoy).weekday() == 6:
        return rows
    want_draw = normalizar_sorteo("9:00 PM")
    ln = "Loteria Nacional"
    ln_clave = clave_loteria(ln)

    def _es_ln(r):
        return isinstance(r, dict) and clave_loteria(r.get("lottery") or "") == ln_clave

    def _draw_norm(r):
        if not isinstance(r, dict):
            return ""
        return normalizar_sorteo(r.get("draw") or "") or str(r.get("draw") or "").strip()

    if any(_es_ln(r) and _draw_norm(r) == want_draw for r in rows):
        return rows
    if not any(_es_ln(r) for r in rows):
        return rows

    fecha_val = resultados_fecha if resultados_fecha is not None else hoy
    fecha_res_str = (
        fecha_val.strftime("%Y-%m-%d")
        if hasattr(fecha_val, "strftime")
        else str(fecha_val or "")[:10]
    )
    rows.append(
        {
            "lottery": ln,
            "draw": want_draw,
            "primero": None,
            "segundo": None,
            "tercero": None,
            "fecha": fecha_val,
            "lottery_display": f"{ln} {want_draw}",
            "color": "green" if fecha_res_str == str(hoy)[:10] else "gray",
        }
    )
    return rows



_APP_PKG_DIR = os.path.dirname(os.path.abspath(__file__))
_ganadores_inner_markup_cache = None
_ganadores_page_cache = {"lock": threading.Lock(), "exp": 0.0, "key": None, "html": None}
_admin_lineas_eval_cache = {
    "lock": threading.Lock(),
    "exp": 0.0,
    "key": None,
    "ganador": 0,
    "perdedor": 0,
}


def _admin_lineas_eval_guardar_per_desde_cruce(join_rows, lista_ganadores, hoy_rd):
    """Persiste conteo perdedor tras cruce completo (TTL 24h) para lecturas rápidas."""
    hs = str(hoy_rd or "").strip()[:10]
    if len(hs) != 10:
        return
    wl = set()
    for g in lista_ganadores or []:
        k = _ganadores_line_id_key(g.get("line_id"))
        if k is not None:
            wl.add(k)
    jl = set()
    for rr in join_rows or []:
        k = _ganadores_line_id_key(rr.get("line_id"))
        if k is not None:
            jl.add(k)
    per = len(jl - wl)
    _ttl_cache_store_put("lineas_eval_per", hs, per, ttl_sec=86400)


def _admin_lineas_eval_counts_rapido(cur, hoy_rd):
    """Ganadores desde premios; perdedores desde caché del último cruce (sin JOIN pesado)."""
    t0 = time.perf_counter()
    gan = _premios_count_ganadores_lineas_fecha(cur, hoy_rd)
    per_cached = _ttl_cache_peek("lineas_eval_per", hoy_rd)
    per = int(per_cached) if per_cached is not None else 0
    ms = round((time.perf_counter() - t0) * 1000, 2)
    log.info(
        "PERF lineas_eval_hoy fast gan=%s per=%s consulta_tickets_ms=0 consulta_resultados_ms=0 "
        "cruce_ms=0 crear_premios_ms=0 total_ms=%s",
        gan,
        per,
        ms,
    )
    return gan, per


def _admin_lineas_eval_counts_completo(cur, hoy_rd):
    """Cruce completo líneas↔resultados (solo cuando aún no hay premios materializados)."""
    t0 = time.perf_counter()
    t_cruce = time.perf_counter()
    join_rows = _ganadores_fetch_lineas_vs_resultados(cur, hoy_rd)
    cruce_ms = round((time.perf_counter() - t_cruce) * 1000, 2)
    cfg = _ganadores_try_load_pagos_config(cur) or {}
    lista = _ganadores_procesar_filas(
        join_rows, pagos={**PAGOS, **cfg}, hoy_rd_str=hoy_rd, cur=cur
    )
    wl = set()
    for g in lista:
        k = _ganadores_line_id_key(g.get("line_id"))
        if k is not None:
            wl.add(k)
    jl = set()
    for rr in join_rows:
        k = _ganadores_line_id_key(rr.get("line_id"))
        if k is not None:
            jl.add(k)
    gan = len(wl)
    per = len(jl - wl)
    _admin_lineas_eval_guardar_per_desde_cruce(join_rows, lista, hoy_rd)
    log.info(
        "PERF lineas_eval_hoy full gan=%s per=%s consulta_tickets_ms=0 consulta_resultados_ms=0 "
        "cruce_ms=%s crear_premios_ms=0 total_ms=%s",
        gan,
        per,
        cruce_ms,
        round((time.perf_counter() - t0) * 1000, 2),
    )
    return gan, per


