def _ganadores_page_cache_ttl_seconds():
    try:
        # TTL más alto reduce HTML costoso /ganadores cuando varios usuarios navegan.
        return max(10, min(120, int(os.environ.get("GANADORES_PAGE_CACHE_TTL", "60"))))
    except (TypeError, ValueError):
        return 10


def _ganadores_page_cache_invalidate():
    """Tras pagar/revertir premio: el HTML cacheado deja de reflejar estado del botón «Pagar»."""
    with _ganadores_page_cache["lock"]:
        _ganadores_page_cache["html"] = None
        _ganadores_page_cache["key"] = None
        _ganadores_page_cache["exp"] = 0.0
    _ttl_cache_invalidate_finanzas_ui()


def _resultados_hoy_post_actualizar_cache_clear():
    """Tras scraper manual: grilla de resultados + HTML /api/ganadores (sin tocar cachés financieras)."""
    _ttl_cache_invalidate_bucket("resultados")
    with _ganadores_page_cache["lock"]:
        _ganadores_page_cache["html"] = None
        _ganadores_page_cache["key"] = None
        _ganadores_page_cache["exp"] = 0.0
