def _ganadores_lista_limite():
    """
    Límite de filas para la tabla de ganadores.
    Defensa: no permitir valores demasiado bajos por env (p.ej. 1-3),
    porque generan confusión ("hay 4 ganadores pero solo veo 3 y va rotando").
    """
    try:
        return max(50, min(500, int(os.environ.get("GANADORES_LISTA_LIMITE", "80"))))
    except (TypeError, ValueError):
        return 200


def _ganadores_maps_ventas_y_caja_por_cajero_dia_rd(cur, conn, hoy_str):
    """
    Totales del día por cajero (clave = lower(trim(username))) para panel /ganadores admin.
    Evita N llamadas a _resumen_ventas_y_premios_dia_rd. Misma familia de filtros (post-cierre).
    """
    ventas = {}
    prem = {}
    is_pg = bool(os.environ.get("DATABASE_URL"))
    ultimo = obtener_fecha_ultimo_cierre(cur)
    fci_pg, pci_pg = _frag_ticket_creado_despues_cierre(True, ultimo, "t")
    fci_sq, pci_sq = _frag_ticket_creado_despues_cierre(False, ultimo, "t")
    _rollback_pg_connection(conn)

    def _add_rows(rows, target):
        for row in rows or []:
            if hasattr(row, "get"):
                ck = str(row.get("ck") or "").strip()
                s = float(row.get("s") or 0)
            else:
                ck = str(row[0] or "").strip()
                s = float(row[1] or 0) if row and len(row) > 1 else 0.0
            if not ck:
                continue
            target[ck] = target.get(ck, 0.0) + s

    try:
        if is_pg:
            cur.execute(
                """
                SELECT lower(trim(COALESCE(t.cajero, ''))) AS ck,
                       COALESCE(SUM(tl.amount), 0) AS s
                FROM ticket_lines tl
                JOIN tickets t ON t.id = tl.ticket_id
                WHERE (t.created_at AT TIME ZONE 'America/Santo_Domingo')::date = %s::date
                  AND COALESCE(tl.estado, 'activo') != 'cancelado'
                  AND trim(COALESCE(t.cajero, '')) <> ''
                """
                + fci_pg
                + """
                GROUP BY 1
                """,
                tuple([hoy_str] + pci_pg),
            )
            _add_rows(cur.fetchall(), ventas)
            cur.execute(
                """
                SELECT lower(trim(COALESCE(t.cajero, ''))) AS ck,
                       COALESCE(SUM(pp.monto), 0) AS s
                FROM pagos_premios pp
                INNER JOIN tickets t ON t.id = pp.ticket_id
                WHERE (pp.fecha::date) = (%s::date)
                """
                + fci_pg
                + """
                  AND """
                + _pp_sin_revertir_sql("pp")
                + """
                GROUP BY 1
                """,
                tuple([hoy_str] + pci_pg),
            )
            _add_rows(cur.fetchall(), prem)
            cur.execute(
                """
                SELECT lower(trim(COALESCE(t.cajero, ''))) AS ck,
                       COALESCE(SUM(p.monto), 0) AS s
                FROM pagos p
                INNER JOIN tickets t ON t.id = p.ticket_id
                WHERE left(trim(COALESCE(p.fecha::text, '')), 10) = %s
                """
                + fci_pg
                + """
                GROUP BY 1
                """,
                tuple([hoy_str] + pci_pg),
            )
            _add_rows(cur.fetchall(), prem)
        else:
            cur.execute(
                _sql(
                    """
                SELECT lower(trim(COALESCE(t.cajero, ''))) AS ck,
                       COALESCE(SUM(tl.amount), 0) AS s
                FROM ticket_lines tl
                JOIN tickets t ON t.id = tl.ticket_id
                WHERE substr(trim(cast(t.created_at as text)), 1, 10) = %s
                  AND COALESCE(tl.estado, 'activo') != 'cancelado'
                  AND trim(COALESCE(t.cajero, '')) <> ''
                """
                    + fci_sq
                    + """
                GROUP BY 1
                """
                ),
                tuple([hoy_str] + pci_sq),
            )
            _add_rows(cur.fetchall(), ventas)
            cur.execute(
                _sql(
                    """
                SELECT lower(trim(COALESCE(t.cajero, ''))) AS ck,
                       COALESCE(SUM(pp.monto), 0) AS s
                FROM pagos_premios pp
                INNER JOIN tickets t ON t.id = pp.ticket_id
                WHERE date(pp.fecha) = date(%s)
                """
                    + fci_sq
                    + """
                  AND """
                    + _pp_sin_revertir_sql("pp")
                    + """
                GROUP BY 1
                """
                ),
                tuple([hoy_str] + pci_sq),
            )
            _add_rows(cur.fetchall(), prem)
            cur.execute(
                _sql(
                    """
                SELECT lower(trim(COALESCE(t.cajero, ''))) AS ck,
                       COALESCE(SUM(p.monto), 0) AS s
                FROM pagos p
                INNER JOIN tickets t ON t.id = p.ticket_id
                WHERE date(p.fecha) = date(%s)
                """
                    + fci_sq
                    + """
                GROUP BY 1
                """
                ),
                tuple([hoy_str] + pci_sq),
            )
            _add_rows(cur.fetchall(), prem)
    except Exception as e:
        log.warning("_ganadores_maps_ventas_y_caja_por_cajero_dia_rd: %s", e, exc_info=True)
        try:
            conn.rollback()
        except Exception:
            pass
    return ventas, prem


def _ganadores_fila_live_a_formato_tabla(lw):
    """
    Adapta una fila de `_ganadores_procesar_filas` al formato de `_premios_fetch_por_estado`
    cuando aún no hay registro persistente coherente en `premios`.
    """
    res = str(lw.get("resultado") or "").strip()
    parts = [x.strip() for x in res.split("-")] if res else []
    while len(parts) < 3:
        parts.append("")
    tipo = lw.get("tipo")
    if not tipo:
        try:
            tipo = _ganadores_tipo_play(lw.get("play"))
        except Exception:
            tipo = "otro"
    estado_raw = "pendiente"
    return {
        "premio_id": None,
        "ticket_id": lw.get("ticket_id"),
        "line_id": lw.get("line_id"),
        "premio_shard": _premio_shard_norm(lw),
        "number": lw.get("number"),
        "numero": lw.get("number"),
        "monto": float(lw.get("monto") or 0),
        "amount": float(lw.get("monto") or 0),
        "premio": float(lw.get("premio") or 0),
        "lottery": lw.get("lottery"),
        "draw": lw.get("draw"),
        "play": lw.get("play"),
        "tipo": tipo,
        "resultado": "-".join(parts[:3]),
        "primero": parts[0],
        "segundo": parts[1],
        "tercero": parts[2],
        "fecha_sorteo_linea": lw.get("fecha_sorteo_linea"),
        "fecha_sorteo": lw.get("fecha_sorteo_linea"),
        "resultado_fecha_iso": lw.get("resultado_fecha_iso"),
        "resultado_fecha": lw.get("resultado_fecha_iso"),
        "cajero": lw.get("cajero"),
        "ganador_detectado_en": lw.get("ganador_detectado_en"),
        "estado": estado_raw,
        "estado_label": "Pendiente",
        "fecha_pago": None,
        "pagado": False,
        "numero_jugado_display": (lw.get("numero_jugado_display") or "").strip(),
        "numero_oficial_display": (lw.get("numero_oficial_display") or "").strip() or "—",
        "jugado": lw.get("numero_jugado_display") or lw.get("number") or "",
        "oficial": lw.get("numero_oficial_display") or "",
        "resultado_sorteo": (lw.get("resultado_sorteo") or "").strip() or "-".join(
            p for p in parts[:3] if p
        ),
        "acierto_detalle": (lw.get("acierto_detalle") or "").strip(),
        "acierto_ok": bool(lw.get("acierto_ok", False)),
        "was_revertido": False,
    }


def _ganadores_aplicar_flags_pagado_ticket(cur, lista_ganadores):
    """`pagado` y etiquetas por **fila** según `premios.estado`; `was_revertido` vía `pagos_premios.premio_id`."""
    if not lista_ganadores:
        return
    try:
        premio_ids = []
        for g in lista_ganadores:
            pid = g.get("premio_id")
            if pid is None:
                continue
            try:
                premio_ids.append(int(pid))
            except (TypeError, ValueError):
                pass
        premio_revertido = set()
        if premio_ids:
            ph = ",".join([_ph()] * len(premio_ids))
            try:
                cur.execute(
                    _sql(
                        "SELECT DISTINCT premio_id FROM pagos_premios WHERE premio_id IN ("
                        + ph
                        + ") AND COALESCE(revertido, 0) = 1 AND premio_id IS NOT NULL"
                    ),
                    tuple(premio_ids),
                )
                for row in cur.fetchall() or []:
                    pr = row["premio_id"] if hasattr(row, "keys") else row[0]
                    if pr is not None:
                        premio_revertido.add(int(pr))
            except Exception:
                _rollback_pg_cursor(cur)
                premio_revertido = set()
        for g in lista_ganadores:
            estado_g = str(g.get("estado") or "").strip().lower()
            g["pagado"] = estado_g == "pagado"
            wr = False
            pid = g.get("premio_id")
            if pid is not None:
                try:
                    wr = int(pid) in premio_revertido
                except (TypeError, ValueError):
                    wr = False
            g["was_revertido"] = wr
            if estado_g == "pagado":
                g["estado_label"] = "Pagado"
            elif estado_g == "pendiente" and wr:
                g["estado_label"] = "Revertido"
            elif estado_g == "pendiente":
                g["estado_label"] = "Pendiente"
            else:
                g["estado_label"] = (g.get("estado_label") or estado_g or "—").strip() or "—"
    except Exception:
        for g in lista_ganadores:
            estado_g = str(g.get("estado") or "").strip().lower()
            g["pagado"] = estado_g == "pagado"
            g["was_revertido"] = False
            if estado_g == "pagado":
                g["estado_label"] = "Pagado"
            elif estado_g == "pendiente":
                g["estado_label"] = "Pendiente"


def _ganadores_enriquecer_habilitar_pago_lineas(cur, lista_ganadores):
    """Añade countdown/botón «Pagar» por línea (cada `premios.id` con espera propia)."""
    for g in lista_ganadores or []:
        est = str(g.get("estado") or "").strip().lower()
        if est != "pendiente" or float(g.get("premio") or 0) <= 0.004:
            g["habilitar_pago_linea"] = False
            g["pago_habilitar_unix_ms_linea"] = int(_premio_ticket_far_future_pay_ms())
            g["tiene_ganador_premio_linea"] = False
            continue
        pid = g.get("premio_id")
        if pid:
            info = _premio_eval_habilitar_pago_ui_por_premio_id(cur, int(pid))
        else:
            lineas = [
                {
                    "premio": float(g.get("premio") or 0),
                    "lottery": g.get("lottery"),
                    "draw": g.get("draw"),
                    "fecha_sorteo_linea": g.get("fecha_sorteo_linea") or g.get("fecha_sorteo"),
                    "fecha_sorteo": g.get("fecha_sorteo"),
                    "ganador_detectado_en": g.get("ganador_detectado_en"),
                }
            ]
            info = _premio_ticket_eval_habilitar_pago_ui(lineas, ticket_id=g.get("ticket_id"))
        g["habilitar_pago_linea"] = bool(info.get("habilitar_pago"))
        g["pago_habilitar_unix_ms_linea"] = int(info.get("pago_habilitar_unix_ms") or 0)
        g["tiene_ganador_premio_linea"] = bool(info.get("tiene_ganador"))


def _ganadores_suma_economica_pendiente_visibles(lista_ganadores):
    """Suma premios de líneas aún por pagar (misma norma económica que el recuadro «Total dinero a pagar»)."""
    s = 0.0
    for g in lista_ganadores or []:
        if float(g.get("premio") or 0) <= 0.004:
            continue
        if bool(g.get("pagado")):
            continue
        try:
            s += float(g.get("premio") or 0)
        except (TypeError, ValueError):
            continue
    return round(s, 2)


def _ganadores_premios_pagados_keys(cur, line_ids):
    """Claves (line_id, premio_shard) con premio ya pagado (no re-mostrar en anexar vivo)."""
    ids = []
    for x in line_ids or []:
        k = _ganadores_line_id_key(x)
        if k is not None:
            ids.append(int(k))
    ids = sorted(set(ids))
    if not ids:
        return set()
    ph = ",".join(["%s"] * len(ids))
    try:
        cur.execute(
            _sql(
                """
                SELECT line_id, COALESCE(premio_shard, '0') AS premio_shard
                FROM premios
                WHERE line_id IN ("""
                + ph
                + """)
                  AND lower(trim(COALESCE(estado, ''))) = 'pagado'
                """
            ),
            tuple(ids),
        )
        out = set()
        for row in cur.fetchall() or []:
            try:
                lid = int(row["line_id"] if hasattr(row, "get") else row[0])
                sh = _premio_shard_norm(
                    row.get("premio_shard") if hasattr(row, "get") else row[1]
                )
            except (TypeError, ValueError, KeyError, IndexError):
                continue
            out.add((lid, sh))
        return out
    except Exception as e:
        log.warning("_ganadores_premios_pagados_keys: %s", e, exc_info=True)
        _rollback_pg_cursor(cur)
        return set()


def _ganadores_anexar_cruce_vivo_dia(
    lista_prev,
    cur,
    dia_rd: str,
    cajero_filtro,
    lista_live_cached=None,
):
    """Añade ganadores del cruce del día `dia_rd` que aún no están en `premios`."""
    hs = str(dia_rd or "").strip()[:10]
    if len(hs) != 10:
        return list(lista_prev or [])
    out = list(lista_prev or [])
    seen = set()
    for g in out:
        st = _ganadores_lista_seen_tuple(g)
        if st is not None:
            seen.add(st)
    try:
        if lista_live_cached is not None:
            lista_live = list(lista_live_cached or [])
        else:
            join_rows = _ganadores_fetch_lineas_vs_resultados(
                cur, hs, cajero_username=cajero_filtro
            )
            cfg = _ganadores_try_load_pagos_config(cur) or {}
            lista_live = _ganadores_procesar_filas(
                join_rows or [],
                pagos={**PAGOS, **cfg},
                hoy_rd_str=hs,
                cur=cur,
            )
        live_lids = [
            _ganadores_line_id_key(lw.get("line_id"))
            for lw in (lista_live or [])
        ]
        pagados_keys = _ganadores_premios_pagados_keys(cur, live_lids)
        for lw in lista_live or []:
            if float(lw.get("premio") or 0) <= 0.004:
                continue
            lk = _ganadores_line_id_key(lw.get("line_id"))
            if lk is not None and (int(lk), _premio_shard_norm(lw)) in pagados_keys:
                continue
            row = _ganadores_fila_live_a_formato_tabla(lw)
            st = _ganadores_lista_seen_tuple(row)
            if st is None or st in seen:
                continue
            out.append(row)
            seen.add(st)
    except Exception as e:
        log.warning("_ganadores_anexar_cruce_vivo_dia: %s", e, exc_info=True)
    return out


def _ganadores_lista_cruce_vivo_dia(cur, day_str, cajero_username=None):
    """Cruce tickets↔resultados de un día RD (sin UPSERT masivo en `premios`)."""
    hs = (day_str or "").strip()[:10]
    if len(hs) != 10:
        return []
    try:
        join_rows = _ganadores_fetch_lineas_vs_resultados(
            cur, hs, cajero_username=cajero_username
        )
        cfg = _ganadores_try_load_pagos_config(cur) or {}
        return _ganadores_procesar_filas(
            join_rows or [],
            pagos={**PAGOS, **cfg},
            hoy_rd_str=hs,
            cur=cur,
        )
    except Exception as e:
        log.warning("_ganadores_lista_cruce_vivo_dia(%s): %s", hs, e, exc_info=True)
        _rollback_pg_cursor(cur)
        return []


def _ganadores_materializar_premios_faltantes(cur, lista_live):
    """
    Persiste/actualiza en `premios` TODAS las filas ganadoras del cruce vivo.
    Siempre hace upsert (no omitir por fila pendiente existente con fecha/monto viejos).
    """
    insertados = 0
    for lw in lista_live or []:
        try:
            prem = float(lw.get("premio") or 0)
        except (TypeError, ValueError):
            prem = 0.0
        if prem <= 0.004:
            continue
        try:
            lid = int(lw.get("line_id") or 0)
        except (TypeError, ValueError):
            continue
        if lid <= 0:
            continue
        if _premios_linea_tiene_invalidacion_manual(cur, lid):
            continue
        if _premios_upsert_pendiente(cur, lw):
            insertados += 1
    if insertados:
        log.info(
            "[GANADORES_LOAD] premios materializados desde cruce vivo: %s",
            insertados,
        )
    return insertados


def _premios_log_db_pendientes_fecha(cur, fecha_premios, cajero_filtro=None):
    """Log [PREMIOS_DB_TOTAL] / [PREMIOS_DB_ITEM] para la fecha consultada."""
    fr = str(fecha_premios or "").strip()[:10]
    if len(fr) != 10:
        return 0
    try:
        rows = premios_pendientes_fetch(
            cur, fr, cajero_username=cajero_filtro, limit=None, offset=None
        )
    except Exception as e:
        log.warning("_premios_log_db_pendientes_fecha(%s): %s", fr, e, exc_info=True)
        _rollback_pg_cursor(cur)
        rows = []
    filas = list(rows or [])
    log.info("[PREMIOS_DB_TOTAL] fecha=%s total=%s", fr, len(filas))
    for g in filas:
        log.info(
            "[PREMIOS_DB_ITEM] premio_id=%s ticket_id=%s lottery=%s draw=%s numero=%s estado=%s monto=%s",
            g.get("premio_id"),
            g.get("ticket_id"),
            g.get("lottery"),
            g.get("draw"),
            g.get("numero") or g.get("number"),
            g.get("estado"),
            g.get("premio"),
        )
    return len(filas)


def _ganadores_log_api_items(fecha_premios, lista, total_en_bd=None):
    """Trazas [GANADORES_API_TOTAL] / [GANADORES_API_ITEM]."""
    fr = str(fecha_premios or "").strip()[:10]
    filas = list(lista or [])
    log.info(
        "[GANADORES_API] fecha=%s total=%s total_en_bd=%s",
        fr or "—",
        len(filas),
        total_en_bd if total_en_bd is not None else "—",
    )
    for g in filas:
        log.info(
            "[GANADORES_API_ITEM] ticket_id=%s lottery=%s draw=%s numero=%s estado=%s monto=%s premio_id=%s line_id=%s",
            g.get("ticket_id"),
            g.get("lottery"),
            g.get("draw"),
            g.get("numero") or g.get("number"),
            g.get("estado"),
            g.get("premio"),
            g.get("premio_id"),
            g.get("line_id"),
        )


def _ganadores_lista_pendientes_fecha_alineada(
    cur,
    fecha_premios,
    cajero_filtro=None,
    lista_live_cached=None,
    limit=None,
    offset=None,
):
    """
    Lista de pago = cruce oficial del día (misma fuente que «Evaluación líneas: Ganador»).

    Regla: **cada fila ganadora del cruce** genera una entrada visible (aunque otro ticket
    tenga el mismo número en la misma lotería). No se agrupa por número ni por lotería.
  """
    fr = str(fecha_premios or "").strip()[:10]
    if len(fr) != 10:
        return []

    if lista_live_cached is not None:
        lista_live = list(lista_live_cached or [])
    else:
        lista_live = _ganadores_lista_cruce_vivo_dia(cur, fr, cajero_username=cajero_filtro)

    _premios_log_db_pendientes_fecha(cur, fr, cajero_filtro=cajero_filtro)

    _ganadores_materializar_premios_faltantes(cur, lista_live)

    line_ids = []
    for lw in lista_live or []:
        lk = _ganadores_line_id_key(lw.get("line_id"))
        if lk is not None:
            line_ids.append(int(lk))
    pagados_keys = _ganadores_premios_pagados_keys(cur, line_ids)

    db_by_line_shard = {}
    if line_ids:
        try:
            db_rows = _premios_fetch_por_estado(
                cur,
                ["pendiente"],
                cajero_username=cajero_filtro,
                limit=None,
                fecha_ref=None,
                restrict_line_ids=line_ids,
                omit_integridad_fecha=True,
            )
            for g in db_rows or []:
                try:
                    lid = int(g.get("line_id") or 0)
                except (TypeError, ValueError):
                    continue
                if lid <= 0:
                    continue
                db_by_line_shard[(lid, _premio_shard_norm(g))] = g
        except Exception as e:
            log.warning("_ganadores_lista_pendientes_fecha_alineada fetch: %s", e, exc_info=True)
            _rollback_pg_cursor(cur)

    out = []
    seen = set()

    for lw in lista_live or []:
        try:
            prem = float(lw.get("premio") or 0)
        except (TypeError, ValueError):
            prem = 0.0
        if prem <= 0.004:
            continue
        lk = _ganadores_line_id_key(lw.get("line_id"))
        if lk is None:
            continue
        if (int(lk), _premio_shard_norm(lw)) in pagados_keys:
            log.info(
                "[GANADORES_API] omitido premio ya pagado line_id=%s ticket_id=%s",
                lk,
                lw.get("ticket_id"),
            )
            continue

        row_live = _ganadores_fila_live_a_formato_tabla(lw)
        row_db = db_by_line_shard.get((int(lk), _premio_shard_norm(lw)))
        if row_db is not None:
            row = dict(row_db)
            # El cruce vivo manda sobre snapshot BD (evita ticket_id/lotería desfasados).
            for _fk in (
                "ticket_id",
                "lottery",
                "draw",
                "number",
                "numero",
                "premio",
                "monto",
                "amount",
                "play",
                "resultado",
                "fecha_sorteo_linea",
                "fecha_sorteo",
                "resultado_fecha_iso",
                "premio_shard",
            ):
                _fv = row_live.get(_fk)
                if _fv is not None and _fv != "":
                    row[_fk] = _fv
            if not row.get("numero_jugado_display"):
                row["numero_jugado_display"] = row_live.get("numero_jugado_display")
            if not row.get("numero_oficial_display"):
                row["numero_oficial_display"] = row_live.get("numero_oficial_display")
            if not row.get("acierto_detalle"):
                row["acierto_detalle"] = row_live.get("acierto_detalle")
        else:
            row = row_live

        st = _ganadores_lista_clave_unica(row)
        if st is None or st in seen:
            continue
        if str(row.get("estado") or "").strip().lower() != "pendiente":
            continue
        if bool(row.get("pagado")):
            continue
        seen.add(st)
        out.append(row)

    def _sort_key(g):
        try:
            return (
                int(g.get("ticket_id") or 0),
                int(g.get("line_id") or 0),
                str(_premio_shard_norm(g)),
            )
        except (TypeError, ValueError):
            return (0, 0, "")

    out.sort(key=_sort_key)

    n_live_win = len(
        [x for x in (lista_live or []) if float(x.get("premio") or 0) > 0.004]
    )
    if n_live_win > len(out):
        log.warning(
            "[GANADORES_API] desfase cruce=%s lista=%s fecha=%s — revisar premios/invalidación",
            n_live_win,
            len(out),
            fr,
        )

    off_n = 0
    try:
        off_n = max(0, int(offset or 0))
    except (TypeError, ValueError):
        off_n = 0
    if off_n:
        out = out[off_n:]

    if limit is not None:
        try:
            lim_n = int(limit)
            if lim_n > 0:
                out = out[:lim_n]
        except (TypeError, ValueError):
            pass

    return out


def _ganadores_lista_filas_visibles_fuente_principal(
    cur,
    hoy_rd: str,
    cajero_filtro,
    fecha_premios,
    lista_live_cached=None,
    limit=None,
    offset=None,
):
    """
    Lista de **pago**: solo `estado=pendiente` del día `fecha_premios` (lectura tabla premios).
    """
    fr = str(fecha_premios or "").strip()[:10]
    if len(fr) != 10:
        return []
    _cap = _ganadores_fetch_sql_cap()
    sql_lim = _cap if _cap is not None else limit
    lista = premios_pendientes_fetch(
        cur,
        fr,
        cajero_username=cajero_filtro,
        limit=sql_lim,
        offset=offset,
    )
    if lista_live_cached is not None:
        lista = _ganadores_anexar_cruce_vivo_dia(
            lista, cur, fr, cajero_filtro, lista_live_cached=lista_live_cached
        )
    lista = [
        g
        for g in (lista or [])
        if str(g.get("estado") or "").strip().lower() == "pendiente"
        and float(g.get("premio") or 0) > 0.004
    ]
    _ganadores_aplicar_flags_pagado_ticket(cur, lista)
    _ganadores_enriquecer_habilitar_pago_lineas(cur, lista)
    return lista


def _ganadores_pendientes_dashboard_resumen(cur, conn, hoy_rd, cajero_filtro=None):
    """
    Tarjetas «Pendiente premios» (sorteos con fecha <= hoy RD) y «Pendiente total» (histórico completo).

    Modo rápido (predeterminado): un cruce oficial del día RD con UPSERT ligero (`_premios_quick_sync_day`)
    antes de las agregaciones SQL; el trabajo multi-día en HTTP sólo si PREMIOS_HEAVY_HTTP_RECALC=1 o
    GANADORES_PAGE_PREMIOS_SYNC (ventana efectiva `_ganadores_sync_ventana_dias_http_efectivos`).

    Para el modo antiguo (sync grande + lista detallada + resync bounded) exportar PREMIOS_HEAVY_HTTP_RECALC=1.

    Caché TTL: DASHBOARD_CACHE_TTL segundos (0 = sin caché).

    Hooks de escritura típicos (resultado nuevo / venta ticket / reverso pago) deben disparar también
    `_premios_quick_sync_day`/`_premios_sync_desde_cruce_hoy` cuando aplique.

    Este resumen ejecuta igualmente `_premios_quick_sync_day(hoy_rd)` antes de SUM (solo ese día RD)
    para corregir faltantes o montos viejos frente al cruce vivo sin activar PREMIOS_HEAVY_HTTP_RECALC.
    """
    out = {"pendiente_hoy": 0.0, "pendiente_total": 0.0}
    hs = str(hoy_rd or "").strip()[:10]
    if len(hs) != 10:
        return out

    ttl = _dashboard_cache_ttl_seconds()
    heavy = _premios_heavy_http_recalc_enabled()
    cache_ck = "|".join(
        [
            "pdash_v2hist",
            hs,
            (cajero_filtro or "").strip().lower(),
            "1" if heavy else "0",
        ]
    )
    if ttl > 0:
        hit = _ttl_cache_peek("dashboard_pend", cache_ck)
        if hit is not None:
            return hit

    if not heavy:
        if _dashboard_http_allow_premios_sync():
            try:
                _qsd = _premios_quick_sync_day(cur, hs, cajero_username=cajero_filtro)
                if _qsd.get("ok"):
                    try:
                        conn.commit()
                    except Exception:
                        _rollback_pg_connection(conn)
            except Exception as _qz:
                log.warning("_ganadores_pendientes_dashboard_resumen quick_sync: %s", _qz, exc_info=True)
                _rollback_pg_connection(conn)
        try:
            ag_hasta = _premios_pendientes_aggregate(
                cur, cajero_filtro, fecha_ref=None, fecha_hasta=hs, omit_integridad_fecha=True
            )
            out["pendiente_hoy"] = float(ag_hasta.get("sum_premio") or 0)

            ag_tot = _premios_pendientes_aggregate(
                cur, cajero_filtro, fecha_ref=None, omit_integridad_fecha=True
            )
            sum_lines = float(ag_tot.get("sum_premio") or 0)

            orphan_params = ["pendiente"]
            orphan_sql = ""
            if (cajero_filtro or "").strip():
                orphan_sql = (
                    " AND lower(trim(COALESCE(p.cajero, ''))) = lower(trim(%s))"
                )
                orphan_params.append((cajero_filtro or "").strip())
            orphan_unpaid_sql = ""
            orphan_unpaid_sql = " AND " + _sql_bool_not_true("t.pagado")
            cur.execute(
                _sql(
                    """
                    SELECT COALESCE(SUM(p.premio), 0) AS s
                    FROM premios p
                    INNER JOIN tickets t ON t.id = p.ticket_id
                    WHERE p.estado = %s AND p.line_id IS NULL"""
                    + orphan_unpaid_sql
                    + orphan_sql
                ),
                tuple(orphan_params),
            )
            row_o = cur.fetchone()
            orphan_sum = float(
                ((row_o.get("s") if hasattr(row_o, "get") else (row_o[0] if row_o else 0)) or 0)
            )

            out["pendiente_total"] = round(sum_lines + orphan_sum, 2)
        except Exception as e:
            log.warning("_ganadores_pendientes_dashboard_resumen (rápido): %s", e, exc_info=True)

        try:
            _ganadores_log_pendientes_historicos(cur, cajero_filtro, tag="dashboard")
        except Exception:
            pass
        blob = dict(out)
        _ttl_cache_store_put("dashboard_pend", cache_ck, blob, ttl)
        return blob

    lista_live_cache = []
    try:
        sync = _premios_sync_desde_cruce_hoy(cur, hs, cajero_username=cajero_filtro)
        lista_live_cache = list(sync.get("lista_cruce_ganadores") or [])
        if sync.get("ok"):
            try:
                conn.commit()
            except Exception:
                _rollback_pg_connection(conn)
    except Exception as e:
        log.warning("_ganadores_pendientes_dashboard_resumen sync: %s", e, exc_info=True)
        try:
            conn.rollback()
        except Exception:
            pass

    if _premios_resync_bounded_allowed_http():
        try:
            _premios_resync_pending_ticket_ids_bounded(cur)
            try:
                conn.commit()
            except Exception:
                _rollback_pg_connection(conn)
        except Exception as e:
            log.warning("_ganadores_pendientes_dashboard_resumen resync_pending: %s", e, exc_info=True)

    try:
        ag_hasta = _premios_pendientes_aggregate(
            cur, cajero_filtro, fecha_ref=None, fecha_hasta=hs, omit_integridad_fecha=True
        )
        out["pendiente_hoy"] = float(ag_hasta.get("sum_premio") or 0)
    except Exception as e:
        log.warning("_ganadores_pendientes_dashboard_resumen hasta_hoy: %s", e, exc_info=True)

    try:
        caj_sql = ""
        cq_params = ["pendiente"]
        if (cajero_filtro or "").strip():
            caj_sql = (
                " AND lower(trim(COALESCE(p.cajero, ''))) = lower(trim(%s))"
            )
            cq_params.append((cajero_filtro or "").strip())
        cur.execute(
            _sql(
                """
                SELECT DISTINCT p.line_id
                FROM premios p
                WHERE p.estado = %s AND p.line_id IS NOT NULL
                """
                + caj_sql
            ),
            tuple(cq_params),
        )
        ids = []
        for row in cur.fetchall() or []:
            try:
                lid = row["line_id"]
            except (TypeError, KeyError, IndexError):
                lid = row[0] if row else None
            k = _ganadores_line_id_key(lid)
            if k is not None:
                ids.append(int(k))

        lista_tot = []
        _chunk = 400
        for i in range(0, len(ids), _chunk):
            sub = ids[i : i + _chunk]
            lista_tot.extend(
                _premios_fetch_por_estado(
                    cur,
                    ["pendiente"],
                    cajero_username=cajero_filtro,
                    limit=None,
                    fecha_ref=None,
                    restrict_line_ids=sub,
                    omit_integridad_fecha=True,
                )
            )

        orphan_params = ["pendiente"]
        orphan_sql = ""
        if (cajero_filtro or "").strip():
            orphan_sql = (
                " AND lower(trim(COALESCE(p.cajero, ''))) = lower(trim(%s))"
            )
            orphan_params.append((cajero_filtro or "").strip())
        orphan_unpaid_sql = " AND " + _sql_bool_not_true("t.pagado")
        cur.execute(
            _sql(
                """
                SELECT COALESCE(SUM(p.premio), 0) AS s
                FROM premios p
                INNER JOIN tickets t ON t.id = p.ticket_id
                WHERE p.estado = %s AND p.line_id IS NULL"""
                + orphan_unpaid_sql
                + orphan_sql
            ),
            tuple(orphan_params),
        )
        row_o = cur.fetchone()
        orphan_sum = float(
            ((row_o.get("s") if hasattr(row_o, "get") else (row_o[0] if row_o else 0)) or 0)
        )

        _ganadores_aplicar_flags_pagado_ticket(cur, lista_tot)
        _ganadores_enriquecer_habilitar_pago_lineas(cur, lista_tot)
        s_lines = float(_ganadores_suma_economica_pendiente_visibles(lista_tot))
        if orphan_sum > 0:
            orphan_sum = round(orphan_sum, 2)
        out["pendiente_total"] = round(s_lines + orphan_sum, 2)
    except Exception as e:
        log.warning("_ganadores_pendientes_dashboard_resumen total: %s", e, exc_info=True)

    blob = dict(out)
    _ttl_cache_store_put("dashboard_pend", cache_ck, blob, ttl)
    return blob


def _ganadores_enriquecer_lista_desde_cruce_vivo(
    lista_prev,
    cur,
    hoy_rd: str,
    cajero_filtro,
    fecha_ref_ganadores,
    lista_live_cached=None,
):
    """
    Alinea la tabla «Lista de Ganadores» con el mismo cruce que `lineas_eval_hoy`:
      1) Vuelca premios persistidos del día que el filtro de integridad fecha excluye por datos viejos.
      2) Añade ganadores detectados en vivo si aún no hay fila en `premios` (p. ej. fallo puntual del sync).

    Solo aplica vista «día = hoy» (cuando fecha_ref coincide con hoy_rd). Con `ver_todos_pendientes`
    fecha_ref=None: no altera la lista aquí (universo distinto).

    `lista_live_cached`: resultado de `_ganadores_procesar_filas` del mismo request (p. ej. desde
    `_premios_sync_desde_cruce_hoy`) para evitar repetir el JOIN pesado líneas↔resultados.
    """
    hs = str(hoy_rd or "").strip()[:10]
    fr = str(fecha_ref_ganadores or "").strip()[:10]
    out = list(lista_prev or [])
    if len(hs) != 10 or len(fr) != 10 or fr != hs:
        return out

    seen_tuples = set()
    seen_line_ids_flat = set()
    for g in out:
        st = _ganadores_lista_seen_tuple(g)
        if st is not None:
            seen_tuples.add(st)
        lk = _ganadores_line_id_key(g.get("line_id"))
        if lk is not None:
            seen_line_ids_flat.add(int(lk))

    estados_vis = ["pendiente", "pagado"]
    ph_es = ",".join(["%s"] * len(estados_vis))

    cand_ids = []
    try:
        caj_sql = ""
        params_cq = list(estados_vis)
        if (cajero_filtro or "").strip():
            caj_sql = " AND lower(trim(COALESCE(p.cajero, ''))) = lower(trim(%s))"
            params_cq.append((cajero_filtro or "").strip())
        h_fr = _parse_iso_date_only(fr) or ahora_rd().date()
        f_desde = (
            h_fr - timedelta(days=_ganadores_pagos_ventana_calendario_dias())
        ).strftime("%Y-%m-%d")
        params_cq.extend([fr, fr, fr, f_desde, fr])
        if os.environ.get("DATABASE_URL"):
            _tls_pg = (
                "to_date(substr(NULLIF(trim(CAST(tl.fecha_sorteo AS TEXT)), ''), 1, 10), 'YYYY-MM-DD')"
            )
            filt_fecha_cq = (
                " AND (\n"
                "    (substr(trim(COALESCE(CAST(p.fecha_dia AS TEXT), '')), 1, 10) = %s\n"
                "     OR substr(trim(COALESCE(CAST(p.fecha_resultado AS TEXT), '')), 1, 10) = %s\n"
                "     OR substr(trim(COALESCE(CAST(p.fecha_sorteo AS TEXT), '')), 1, 10) = %s)\n"
                "    OR (\n"
                "      lower(trim(COALESCE(p.estado, ''))) = 'pendiente'\n"
                "      AND "
                + _sql_bool_not_true("tk.pagado")
                + "\n"
                "      AND length(trim(COALESCE(CAST(tl.fecha_sorteo AS TEXT), ''))) >= 10\n"
                f"      AND {_tls_pg} BETWEEN (%s)::date AND (%s)::date\n"
                "    )\n"
                " )"
            )
        else:
            filt_fecha_cq = (
                " AND (\n"
                "    (substr(trim(COALESCE(p.fecha_dia, '')), 1, 10) = %s\n"
                "     OR substr(trim(COALESCE(p.fecha_resultado, '')), 1, 10) = %s\n"
                "     OR substr(trim(COALESCE(p.fecha_sorteo, '')), 1, 10) = %s)\n"
                "    OR (\n"
                "      lower(trim(COALESCE(p.estado, ''))) = 'pendiente'\n"
                "      AND COALESCE(tk.pagado, 0) = 0\n"
                "      AND length(trim(COALESCE(tl.fecha_sorteo, ''))) >= 10\n"
                "      AND date(substr(trim(COALESCE(tl.fecha_sorteo, '')), 1, 10)) >= date(%s)\n"
                "      AND date(substr(trim(COALESCE(tl.fecha_sorteo, '')), 1, 10)) <= date(%s)\n"
                "    )\n"
                " )"
            )
        cur.execute(
            _sql(
                """
                SELECT DISTINCT p.line_id
                FROM premios p
                INNER JOIN ticket_lines tl ON tl.id = p.line_id
                INNER JOIN tickets tk ON tk.id = p.ticket_id
                WHERE p.line_id IS NOT NULL
                  AND p.estado IN ("""
                + ph_es
                + """)"""
                + caj_sql
                + filt_fecha_cq
                + """
                """
            ),
            tuple(params_cq),
        )
        for row in cur.fetchall() or []:
            try:
                lid = row["line_id"]
            except (TypeError, KeyError, IndexError):
                lid = row[0] if row else None
            k = _ganadores_line_id_key(lid)
            if k is not None and k not in seen_line_ids_flat:
                cand_ids.append(int(k))
    except Exception as e:
        log.warning("_ganadores_enriquecer premios día candidatos: %s", e, exc_info=True)
        cand_ids = []

    if cand_ids:
        try:
            extra = _premios_fetch_por_estado(
                cur,
                estados_vis,
                cajero_username=cajero_filtro,
                limit=None,
                fecha_ref=None,
                restrict_line_ids=cand_ids,
                omit_integridad_fecha=True,
            )
            for g in extra or []:
                st_e = _ganadores_lista_seen_tuple(g)
                if st_e is None or st_e in seen_tuples:
                    continue
                out.append(g)
                seen_tuples.add(st_e)
                lk2 = _ganadores_line_id_key(g.get("line_id"))
                if lk2 is not None:
                    seen_line_ids_flat.add(int(lk2))
        except Exception as e:
            log.warning("_ganadores_enriquecer fetch premios omit integridad: %s", e, exc_info=True)

    try:
        if lista_live_cached is not None:
            lista_live = list(lista_live_cached or [])
        else:
            join_rows = _ganadores_fetch_lineas_vs_resultados(
                cur, hs, cajero_username=cajero_filtro
            )
            cfg = _ganadores_try_load_pagos_config(cur) or {}
            lista_live = _ganadores_procesar_filas(
                join_rows or [],
                pagos={**PAGOS, **cfg},
                hoy_rd_str=hs,
                cur=cur,
            )
    except Exception as e:
        log.warning("_ganadores_enriquecer cruce vivo: %s", e, exc_info=True)
        lista_live = []

    live_map = {}
    for lw in lista_live or []:
        lid_k = _ganadores_line_id_key(lw.get("line_id"))
        if lid_k is None:
            continue
        live_map[(int(lid_k), _premio_shard_norm(lw))] = lw

    for row in out:
        krow = _ganadores_line_id_key(row.get("line_id"))
        if krow is None:
            continue
        lw_hit = live_map.get((int(krow), _premio_shard_norm(row)))
        if not lw_hit:
            continue
        if str(row.get("estado") or "").strip().lower() == "pagado":
            continue
        try:
            p_live = float(lw_hit.get("premio") or 0)
        except (TypeError, ValueError):
            p_live = 0.0
        if p_live > 0.004:
            row["premio"] = round(p_live, 2)

    for lw in lista_live or []:
        st_l = _ganadores_lista_seen_tuple(lw)
        if st_l is None or st_l in seen_tuples:
            continue
        out.append(_ganadores_fila_live_a_formato_tabla(lw))
        seen_tuples.add(st_l)
        lk3 = _ganadores_line_id_key(lw.get("line_id"))
        if lk3 is not None:
            seen_line_ids_flat.add(int(lk3))

    def _rk(g):
        try:
            return (
                int(g.get("ticket_id") or 0),
                int(g.get("line_id") or 0),
                str(_premio_shard_norm(g)),
            )
        except (TypeError, ValueError):
            return (0, 0, "")

    out.sort(key=_rk)
    try:
        n_prev = len(lista_prev or [])
        n_live = len(lista_live or [])
        n_out = len(out or [])
        log.info(
            "ganadores_enriquecer día=%s in=%s live_rows=%s out=%s",
            hs,
            n_prev,
            n_live,
            n_out,
        )
    except Exception as _le:
        log.debug("ganadores_enriquecer log: %s", _le)
    return out


def _ganadores_collect_dashboard_context(
    conn,
    cur,
    *,
    hoy,
    cajero_filtro,
    vista_admin,
    mostrar_col_cajero,
    debug_ganadores,
    solo_pendientes=False,
):
    """Contexto para la vista de ganadores. Con solo_pendientes=True: solo lectura `premios` (rápido, sin cruce)."""
    from collections import defaultdict

    resumen_por_cajero = []
    tickets_pagos_admin_recientes = []
    lista_ganadores = []
    lista_ganadores_por_ticket = []
    ganadores_agrupado = {}
    ventas_del_dia = 0.0
    premios_pagados_del_dia = 0.0
    total_premios_ganados = 0.0
    riesgo_pendiente = 0.0
    ganancia_proyectada = 0.0
    ganancia_dia = 0.0
    resultados_hoy = []
    resultados_fecha = hoy
    resultados_pendientes_hoy = False
    total_ganadores = 0
    total_pagar = 0.0
    total_apostado_ganadores = 0.0
    total_riesgo = 0.0
    premios_pagados_count = 0
    ganadores_lista_truncada = False
    lista_limit = _ganadores_lista_limite()

    fecha_premios = _ganadores_resolver_fecha_premios(hoy, cur, cajero_filtro)
    resultados_ultima_fecha_display = ""
    resultados_grilla_tiene_filas = False
    resultados_grilla_tiene_numeros = False
    try:
        if solo_pendientes:
            # Carga rápida /api/ganadores: grilla desde caché TTL; evita trabajo pesado en cada GET.
            _hoy_gr = str(hoy or "").strip()[:10]
            _ttl_gr = _dashboard_cache_ttl_seconds()
            _ck_gr = ("grilla_visual", _hoy_gr)
            resultados_hoy = (
                _ttl_cache_peek("resultados", _ck_gr)
                if _ttl_gr > 0
                else None
            )
            if resultados_hoy is None:
                resultados_hoy = _ganadores_resultados_refresh_grilla_visual(cur, _hoy_gr)
        else:
            resultados_hoy = _ganadores_resultados_refresh_grilla_visual(
                cur, str(hoy or "").strip()[:10]
            )
    except Exception as _gfx:
        log.warning("ganadores resultados refresh grilla: %s", _gfx, exc_info=True)
        resultados_hoy = []
    _meta_res = _ganadores_resultados_meta_tarjeta(resultados_hoy, hoy)
    resultados_pendientes_hoy = bool(_meta_res.get("resultados_pendientes_hoy"))
    resultados_ultima_fecha_display = str(
        _meta_res.get("resultados_ultima_fecha_display") or ""
    )
    resultados_grilla_tiene_filas = bool(_meta_res.get("resultados_grilla_tiene_filas"))
    resultados_grilla_tiene_numeros = bool(_meta_res.get("resultados_grilla_tiene_numeros"))
    if solo_pendientes:
        log.info(
            "[GANADORES_LOAD] fecha=%s solo_pendientes=1 resultados_filas=%s pendiente_hoy=%s ultima=%s",
            fecha_premios,
            len(resultados_hoy or []),
            resultados_pendientes_hoy,
            resultados_ultima_fecha_display,
        )

    fr_sync = str(fecha_premios or "").strip()[:10]

    gnr_page, gnr_limit, gnr_offset = _ganadores_paginacion_params()
    gnr_sql_fetch = int(gnr_limit) + 1

    if len(fr_sync) == 10 and _premios_sync_necesario(cur, fr_sync, cajero_filtro):
        try:
            _ganadores_sync_premios_fecha_lista(cur, fr_sync, cajero_username=cajero_filtro)
        except Exception as _sync_fp:
            log.warning("ganadores sync premios fecha %s: %s", fr_sync, _sync_fp, exc_info=True)
            _rollback_pg_cursor(cur)
    elif len(fr_sync) == 10:
        log.info(
            "[GANADORES_LOAD] skip sync fecha=%s solo_lectura_premios=1",
            fr_sync,
        )
    lista_ganadores = _ganadores_lista_filas_visibles_fuente_principal(
        cur,
        hoy,
        cajero_filtro,
        fecha_premios,
        lista_live_cached=None,
        limit=gnr_sql_fetch,
        offset=gnr_offset,
    )
    try:
        ag_bd = _premios_pendientes_aggregate(
            cur,
            cajero_filtro,
            fecha_ref=fr_sync if len(fr_sync) == 10 else None,
            omit_integridad_fecha=True,
        )
        total_en_bd = int(ag_bd.get("n_lines") or 0)
    except Exception:
        total_en_bd = None
    _ganadores_log_api_items(fr_sync, lista_ganadores, total_en_bd=total_en_bd)
    log.info(
        "[GANADORES_LOAD] día=%s lista_premios=%s tickets=%s total_en_bd=%s",
        fr_sync,
        len(lista_ganadores or []),
        len(
            {
                int(g.get("ticket_id") or 0)
                for g in (lista_ganadores or [])
                if int(g.get("ticket_id") or 0) > 0
            }
        ),
        total_en_bd,
    )
    ganadores_has_more = len(lista_ganadores or []) > gnr_limit
    if ganadores_has_more:
        lista_ganadores = (lista_ganadores or [])[:gnr_limit]
    _ganadores_aplicar_flags_pagado_ticket(cur, lista_ganadores)
    _ganadores_enriquecer_habilitar_pago_lineas(cur, lista_ganadores)
    log.info(
        "[GANADORES_LOAD] premios pendientes mostrados=%s fecha=%s",
        len(lista_ganadores or []),
        fecha_premios,
    )
    if solo_pendientes:
        lista_historial_pagados = []
    else:
        lista_historial_pagados = premios_pagados_historial_fetch(
            cur, fecha_premios, cajero_username=cajero_filtro
        )
        _ganadores_aplicar_flags_pagado_ticket(cur, lista_historial_pagados)
    if debug_ganadores:
        try:
            _ganadores_log_pendientes_historicos(
                cur, cajero_filtro, fecha_premios=fecha_premios, tag="collect"
            )
        except Exception:
            pass
    ganadores_lista_truncada = bool(ganadores_has_more)
    premios_pagados_filas_visibles = 0
    prem_stats_page = None
    try:
        prem_stats_page = _premios_pendientes_aggregate(
            cur,
            cajero_filtro,
            fecha_ref=fecha_premios,
            omit_integridad_fecha=True,
        )
    except Exception:
        prem_stats_page = None

    # Totales = misma lista visible que las tarjetas (nunca desacoplar resumen de filas).
    _vis_pend = [
        g
        for g in (lista_ganadores or [])
        if str(g.get("estado") or "").strip().lower() == "pendiente"
        and float(g.get("premio") or 0) > 0.004
        and not bool(g.get("pagado"))
    ]
    total_ganadores = len(_vis_pend)
    total_ganadores_tickets = len(
        {int(g.get("ticket_id") or 0) for g in _vis_pend if int(g.get("ticket_id") or 0) > 0}
    )
    total_pagar = round(sum(float(g.get("premio") or 0) for g in _vis_pend), 2)
    total_apostado_ganadores = round(
        sum(float(g.get("monto") or g.get("amount") or 0) for g in _vis_pend), 2
    )
    total_premios_ganados = total_pagar
    if prem_stats_page and int(prem_stats_page.get("n_lines") or 0) != total_ganadores:
        log.warning(
            "[GANADORES_DESFASE] fecha=%s aggregate_n=%s lista_n=%s aggregate_rd=%.2f lista_rd=%.2f",
            fecha_premios,
            int(prem_stats_page.get("n_lines") or 0),
            total_ganadores,
            float(prem_stats_page.get("sum_premio") or 0),
            total_pagar,
        )

    total_riesgo = total_pagar
    premios_pagados_count = premios_pagados_filas_visibles
    log.debug(
        "ganadores: filas lista=%s lineas pagadas_visibles=%s",
        len(lista_ganadores),
        premios_pagados_count,
    )

    ganadores_agrupado = _ganadores_agrupar_por_loteria_tipo(lista_ganadores)

    lista_ganadores_por_ticket = _ganadores_agrupar_por_ticket(lista_ganadores)
    print("fecha seleccionada:", fecha_premios)
    print("total resumen:", total_ganadores)
    print("tickets lista:", len(lista_ganadores_por_ticket or []))
    print(
        "ids tickets:",
        [int(t.get("ticket_id") or 0) for t in (lista_ganadores_por_ticket or [])],
    )
    historial_pagados_por_ticket = _ganadores_agrupar_por_ticket(lista_historial_pagados)

    if (not solo_pendientes) and vista_admin and _ganadores_admin_extras_on_load():
        try:
            if os.environ.get("DATABASE_URL"):
                cur.execute(
                    """
                    SELECT t.id AS ticket_id,
                           COALESCE(NULLIF(TRIM(t.cajero), ''), '') AS cajero,
                           t.fecha_pago,
                           COALESCE((
                               SELECT SUM(pp.monto) FROM pagos_premios pp
                               WHERE pp.ticket_id = t.id
                                 AND """
                    + _pp_sin_revertir_sql("pp")
                    + """
                           ), 0) AS monto_registrado
                    FROM tickets t
                    WHERE """
                    + _sql_bool_is_true("t.pagado")
                    + """
                    ORDER BY t.fecha_pago DESC NULLS LAST, t.id DESC
                    LIMIT 50
                    """
                )
            else:
                cur.execute(
                    _sql(
                        """
                    SELECT t.id AS ticket_id,
                           COALESCE(NULLIF(TRIM(t.cajero), ''), '') AS cajero,
                           t.fecha_pago,
                           COALESCE((
                               SELECT SUM(pp.monto) FROM pagos_premios pp
                               WHERE pp.ticket_id = t.id
                                 AND """
                        + _pp_sin_revertir_sql("pp")
                        + """
                           ), 0) AS monto_registrado
                    FROM tickets t
                    WHERE COALESCE(t.pagado, 0) != 0
                    ORDER BY t.fecha_pago IS NULL, t.fecha_pago DESC, t.id DESC
                    LIMIT 50
                    """
                    )
                )
            for rw in cur.fetchall() or []:
                if hasattr(rw, "keys"):
                    tickets_pagos_admin_recientes.append(
                        {
                            "ticket_id": int(rw.get("ticket_id") or 0),
                            "cajero": (rw.get("cajero") or "").strip() or "—",
                            "fecha_pago": rw.get("fecha_pago"),
                            "monto_registrado": float(rw.get("monto_registrado") or 0),
                        }
                    )
                else:
                    tickets_pagos_admin_recientes.append(
                        {
                            "ticket_id": int(rw[0] or 0),
                            "cajero": str(rw[1] or "").strip() or "—",
                            "fecha_pago": rw[2] if len(rw) > 2 else None,
                            "monto_registrado": float(rw[3] or 0) if len(rw) > 3 else 0.0,
                        }
                    )
        except Exception as _trec:
            log.warning(
                "tickets_pagos_admin_recientes /ganadores: %s", _trec, exc_info=True
            )
            tickets_pagos_admin_recientes = []

    try:
        if solo_pendientes:
            ventas_del_dia = 0.0
            premios_pagados_del_dia = 0.0
            ganancia_dia = 0.0
            riesgo_pendiente = float(total_premios_ganados or 0)
            ganancia_proyectada = 0.0 - float(total_premios_ganados or 0)
        else:
            ventas_del_dia, premios_pagados_del_dia, _ = _resumen_ventas_y_premios_dia_rd(
                cur,
                conn,
                hoy,
                cajero_username=cajero_filtro,
                incluir_premios_devengados=False,
            )
            v = float(ventas_del_dia or 0)
            pp = float(premios_pagados_del_dia or 0)
            ganancia_dia = v - pp
            riesgo_pendiente = total_premios_ganados - pp
            ganancia_proyectada = v - total_premios_ganados

        if (not solo_pendientes) and vista_admin and _ganadores_admin_extras_on_load():
            premio_por_clave = defaultdict(float)
            etiqueta_por_clave = {}
            for row in _premios_pendientes_premio_por_cajero_clave(cur, cajero_filtro):
                ck = row["clave"]
                premio_por_clave[ck] = float(row["sum_premio"])
                lb = (row.get("etiqueta") or "").strip()
                if ck != "__sin_cajero__" and lb:
                    etiqueta_por_clave[ck] = lb
            vmap, pmap = _ganadores_maps_ventas_y_caja_por_cajero_dia_rd(cur, conn, hoy)
            claves = set(premio_por_clave.keys())
            if (
                "__sin_cajero__" in claves
                and float(premio_por_clave.get("__sin_cajero__", 0) or 0) <= 0
            ):
                claves.discard("__sin_cajero__")
            ordenadas = sorted(
                claves,
                key=lambda k: (
                    k == "__sin_cajero__",
                    str(etiqueta_por_clave.get(k) or k).lower(),
                ),
            )
            bloques = []
            for clave in ordenadas:
                if clave == "__sin_cajero__":
                    nombre = "(Sin cajero en ticket)"
                    v_c = 0.0
                    pp_c = 0.0
                else:
                    nombre = etiqueta_por_clave.get(clave, clave)
                    ck = str(clave).strip().lower()
                    v_c = float(vmap.get(ck, 0) or 0)
                    pp_c = float(pmap.get(ck, 0) or 0)
                prem_g = float(premio_por_clave.get(clave, 0) or 0)
                v_f = float(v_c or 0)
                pp_f = float(pp_c or 0)
                bloques.append(
                    {
                        "cajero": nombre,
                        "ventas": round(v_f, 2),
                        "premios_ganados": round(prem_g, 2),
                        "premios_pagados": round(pp_f, 2),
                        "ganancia": round(v_f - pp_f, 2),
                    }
                )
            resumen_por_cajero = bloques
    except Exception as _gd:
        print("ERROR resumen ganancia_dia /ganadores:", _gd)
        traceback.print_exc()
        try:
            conn.rollback()
        except Exception:
            pass
        _tp_keep = float(total_premios_ganados or 0)
        _tap_keep = float(total_pagar or 0)
        ventas_del_dia = 0.0
        premios_pagados_del_dia = 0.0
        ganancia_dia = 0.0
        total_premios_ganados = _tp_keep
        total_pagar = _tap_keep
        total_riesgo = _tap_keep
        # Sin lectura confiable de pagos del día: el riesgo mostrado = devengado conocido desde `premios`.
        riesgo_pendiente = _tp_keep
        ganancia_proyectada = 0.0 - _tp_keep
        if vista_admin:
            resumen_por_cajero = []

    aviso_pagos_sorteos_anteriores = None
    try:
        if float(total_premios_ganados or 0) < 0.005 and float(premios_pagados_del_dia or 0) > 0.005:
            aviso_pagos_sorteos_anteriores = (
                "Se pagaron premios hoy por RD$ %.2f correspondientes a tickets de días anteriores."
                % float(premios_pagados_del_dia)
            )
    except Exception:
        aviso_pagos_sorteos_anteriores = None

    debug_resultados_cierre = []
    if debug_ganadores:
        for _d in resultados_hoy or []:
            debug_resultados_cierre.append(
                {
                    "lottery": (_d.get("lottery") or "") if isinstance(_d, dict) else "",
                    "draw": (_d.get("draw") or "") if isinstance(_d, dict) else "",
                    "primero": str((_d.get("primero") if isinstance(_d, dict) else "") or ""),
                    "segundo": str((_d.get("segundo") if isinstance(_d, dict) else "") or ""),
                    "tercero": str((_d.get("tercero") if isinstance(_d, dict) else "") or ""),
                }
            )

    ganancia_dia_fmt = "{:,.2f}".format(ganancia_dia)
    ganancia_proyectada_fmt = "{:,.2f}".format(ganancia_proyectada)
    riesgo_pendiente_fmt = "{:,.2f}".format(riesgo_pendiente)
    total_premios_ganados_fmt = "{:,.2f}".format(total_premios_ganados)

    return {
        "hoy": hoy,
        "fecha_premios": fecha_premios,
        "resultados_fecha": resultados_fecha,
        "resultados_hoy": resultados_hoy,
        "total_ganadores": total_ganadores,
        "total_ganadores_tickets": total_ganadores_tickets,
        "total_pagar": total_pagar,
        "lista_ganadores": lista_ganadores,
        "lista_ganadores_por_ticket": lista_ganadores_por_ticket,
        "historial_pagados_por_ticket": historial_pagados_por_ticket,
        "n_historial_pagados": len(lista_historial_pagados or []),
        "ganancia_dia": ganancia_dia,
        "ganancia_dia_fmt": ganancia_dia_fmt,
        "ganadores_agrupado": ganadores_agrupado,
        "total_apostado_ganadores": total_apostado_ganadores,
        "total_riesgo": total_riesgo,
        "ventas_del_dia": ventas_del_dia,
        "premios_pagados_del_dia": premios_pagados_del_dia,
        "total_premios_ganados": total_premios_ganados,
        "total_premios_ganados_fmt": total_premios_ganados_fmt,
        "riesgo_pendiente": riesgo_pendiente,
        "riesgo_pendiente_fmt": riesgo_pendiente_fmt,
        "ganancia_proyectada": ganancia_proyectada,
        "ganancia_proyectada_fmt": ganancia_proyectada_fmt,
        "debug_ganadores": debug_ganadores,
        "debug_resultados_cierre": debug_resultados_cierre,
        "vista_admin": vista_admin,
        "puede_recalcular_ganadores": puede_recalcular_ganadores(),
        "resumen_por_cajero": resumen_por_cajero,
        "mostrar_col_cajero": mostrar_col_cajero,
        "aviso_pagos_sorteos_anteriores": aviso_pagos_sorteos_anteriores,
        "tickets_pagos_admin_recientes": tickets_pagos_admin_recientes,
        "premio_pago_espera_segundos": PREMIO_PAGO_ESPERA_SEGUNDOS,
        "resultados_pendientes_hoy": resultados_pendientes_hoy,
        "resultados_ultima_fecha_display": resultados_ultima_fecha_display,
        "resultados_grilla_tiene_filas": resultados_grilla_tiene_filas,
        "resultados_grilla_tiene_numeros": resultados_grilla_tiene_numeros,
        "ganadores_lista_truncada": ganadores_lista_truncada,
        "ganadores_lista_limite": gnr_limit,
        "ganadores_page": gnr_page,
        "ganadores_limit": gnr_limit,
        "ganadores_has_more": ganadores_has_more,
        "ganadores_next_page": gnr_page + 1 if ganadores_has_more else gnr_page,
    }


def _ganadores_html_stamp_server_now_ms(html: str) -> str:
    """Reemplaza placeholder en HTML cacheado por epoch ms servidor (America/Santo_Domingo) para alinear countdown sin confiar en hora del navegador."""
    try:
        ms = str(int(ahora_rd().timestamp() * 1000))
    except Exception:
        ms = "0"
    return (html or "").replace("__GNR_SERVER_NOW_MS__", ms)


@app.route("/ganadores")
def ganadores_riesgo():
    t0 = time.perf_counter()
    if session.get("u") is None and session.get("user") is None:
        return redirect("/")
    usuario_sesion = (session.get("u") or session.get("user") or "").strip()
    vista_admin = is_admin_or_super()
    if not vista_admin and not usuario_sesion:
        return redirect("/")
    log.info(
        "PERF ruta=/ganadores shell_ms=%s",
        round((time.perf_counter() - t0) * 1000, 2),
    )
    return render_template_string(
        """
<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1, maximum-scale=1, user-scalable=no">
<title>Ganadores</title>
</head>
<body style="margin:0;font-family:system-ui,-apple-system,sans-serif;background:#f1f5f9">
<div id="ganadores-boot" style="min-height:60vh;display:flex;align-items:center;justify-content:center;padding:24px">
  <div style="text-align:center;max-width:420px">
    <p style="font-size:18px;font-weight:800;color:#0f172a;margin:0 0 8px">Cargando…</p>
    <p style="color:#64748b;font-size:14px;margin:0;line-height:1.5">Cargando premios pendientes guardados…</p>
  </div>
</div>
<script>
(function(){
  var CACHE_KEY = "gnr_html_v2";
  var TIMEOUT_MS = 55000;
  function stripRecalcQs(qs){
    if(!qs) return "";
    return qs.replace(/([?&])recalc=[^&]*/gi, "$1").replace(/[?&]$/, "").replace(/\\?&/, "?");
  }
  function fail(msg, showStale){
    var el = document.getElementById("ganadores-boot");
    if(!el) return;
    var stale = "";
    if(showStale){
      try {
        var prev = sessionStorage.getItem(CACHE_KEY);
        if(prev && prev.length > 200){
          stale = '<p style="margin:12px 0 0 0"><button type="button" id="gnr-use-stale" style="padding:10px 16px;border-radius:8px;background:#64748b;color:#fff;border:none;font-weight:700;cursor:pointer">Ver última versión guardada</button></p>';
          setTimeout(function(){
            var b = document.getElementById("gnr-use-stale");
            if(b) b.onclick = function(){
              document.open();
              document.write(prev);
              document.close();
            };
          }, 0);
        }
      } catch(_e) {}
    }
    el.innerHTML = '<div style="text-align:center;padding:24px"><p style="color:#b91c1c;font-weight:700">'+(msg||"No se pudo cargar. Reintentar")+'</p><p><a href="/ganadores" style="color:#002D62;font-weight:700">Reintentar</a></p>'+stale+'</div>';
  }
  var qs = stripRecalcQs(window.location.search || "");
  var slowTimer = setTimeout(function(){
    fail("La carga está tardando demasiado.", true);
  }, TIMEOUT_MS);
  fetch("/api/ganadores" + qs, {credentials:"same-origin", headers:{"Accept":"application/json"}})
    .then(function(r){
      return r.json().then(function(d){ return { http: r.status, j: d }; });
    })
    .then(function(x){
      clearTimeout(slowTimer);
      var d = x.j;
      if(!d || !d.ok || !d.html){ fail((d&&d.error)||"No se pudo cargar. Reintentar", true); return; }
      try { sessionStorage.setItem(CACHE_KEY, d.html); } catch(_e2) {}
      document.open();
      document.write(d.html);
      document.close();
    })
    .catch(function(){
      clearTimeout(slowTimer);
      fail("No se pudo cargar. Reintentar", true);
    });
})();
</script>
</body>
</html>
        """,
    )


@app.route("/api/premios_pendientes", methods=["GET"])
def api_premios_pendientes():
    """Premios pendientes de una fecha RD (estado=pendiente)."""
    if session.get("u") is None and session.get("user") is None:
        return jsonify({"ok": False, "error": "no autorizado"}), 401
    usuario_sesion = (session.get("u") or session.get("user") or "").strip()
    vista_admin = is_admin_or_super()
    if not vista_admin and not usuario_sesion:
        return jsonify({"ok": False, "error": "no autorizado"}), 401
    hoy = ahora_rd().date().strftime("%Y-%m-%d")
    conn = db()
    if not conn:
        return jsonify({"ok": False, "error": "sin base de datos"}), 500
    _rollback_pg_connection(conn)
    cur = conn.cursor()
    cajero_filtro = None if vista_admin else usuario_sesion
    try:
        fecha = _ganadores_resolver_fecha_premios(hoy, cur, cajero_filtro)
        log.info("[GANADORES_LOAD] fecha=%s solo_pendientes=1", fecha)
        filas = _ganadores_lista_pendientes_fecha_alineada(
            cur,
            fecha,
            cajero_filtro=cajero_filtro,
            limit=100,
        )
        _ganadores_log_api_items(fecha, filas)
        _ganadores_aplicar_flags_pagado_ticket(cur, filas)
        _ganadores_enriquecer_habilitar_pago_lineas(cur, filas)
        items = []
        for g in filas:
            items.append(
                {
                    "premio_id": g.get("premio_id"),
                    "ticket_id": g.get("ticket_id"),
                    "line_id": g.get("line_id"),
                    "cajero": g.get("cajero"),
                    "lottery": g.get("lottery"),
                    "draw": g.get("draw"),
                    "play": g.get("play"),
                    "fecha": (
                        g.get("resultado_fecha_iso")
                        or g.get("fecha_sorteo_linea")
                        or ""
                    ),
                    "numero_jugado": g.get("numero_jugado_display"),
                    "numero_oficial": g.get("numero_oficial_display"),
                    "premio_detalle": g.get("acierto_detalle") or g.get("play"),
                    "monto": float(g.get("premio") or 0),
                    "estado": g.get("estado"),
                }
            )
        return jsonify(
            {
                "ok": True,
                "fecha": fecha,
                "hoy_rd": hoy,
                "total": len(items),
                "items": items,
            }
        )
    except Exception as e:
        log.error("[GANADORES_ERROR] api_premios_pendientes: %s", e, exc_info=True)
        return jsonify({"ok": False, "error": "No se pudo cargar."}), 200
    finally:
        try:
            cur.close()
        except Exception:
            pass
        try:
            conn.close()
        except Exception:
            pass


@app.route("/admin/tickets_eliminados", methods=["GET"])
def admin_tickets_eliminados_history():
    """Historial de tickets eliminados (falso/bajo) — solo administradores."""
    if session.get("u") is None and session.get("user") is None:
        return redirect("/login")
    if not is_admin_or_super():
        return "No autorizado", 403
    desde = (request.args.get("desde") or "").strip()[:12]
    hasta = (request.args.get("hasta") or "").strip()[:12]
    conn = db()
    if not conn:
        return "Error conectando base de datos", 500
    rows = []
    try:
        cur = conn.cursor()
        params = []
        w = ["1=1"]
        if desde:
            w.append("substr(trim(cast(te.fecha_eliminacion as text)), 1, 10) >= %s")
            params.append(desde[:10])
        if hasta:
            w.append("substr(trim(cast(te.fecha_eliminacion as text)), 1, 10) <= %s")
            params.append(hasta[:10])
        sql = (
            """
            SELECT te.id, te.ticket_id, te.eliminado_por, te.motivo,
                   te.fecha_eliminacion, te.monto_ticket, te.serial_ticket
            FROM tickets_eliminados te
            WHERE """
            + " AND ".join(w)
            + " ORDER BY te.id DESC LIMIT 500"
        )
        cur.execute(_sql(sql), tuple(params))
        for r in cur.fetchall() or []:
            if hasattr(r, "keys"):
                rows.append(dict(r))
            else:
                rows.append(
                    {
                        "id": r[0],
                        "ticket_id": r[1],
                        "eliminado_por": r[2],
                        "motivo": r[3],
                        "fecha_eliminacion": r[4],
                        "monto_ticket": r[5],
                        "serial_ticket": r[6],
                    }
                )
    except Exception as e:
        log.exception("admin_tickets_eliminados_history: %s", e)
        rows = []
    finally:
        try:
            conn.close()
        except Exception:
            pass
    html = (
        IOS
        + """
<div class="card" style="max-width:1024px;margin:24px auto;padding:22px">
  <h2 style="margin:0 0 8px">🗑️ Historial de Tickets Eliminados</h2>
  <p style="color:#64748b;font-size:14px;margin:0 0 16px">Tickets marcados como falso o de bajo (soft delete). Solo lectura.</p>
  <form method="get" style="display:flex;flex-wrap:wrap;gap:10px;align-items:flex-end;margin-bottom:18px">
    <div><label style="font-size:12px;color:#64748b">Desde</label><br><input type="date" name="desde" value="{{ desde or '' }}" style="padding:8px;border-radius:8px;border:1px solid #cbd5e1"></div>
    <div><label style="font-size:12px;color:#64748b">Hasta</label><br><input type="date" name="hasta" value="{{ hasta or '' }}" style="padding:8px;border-radius:8px;border:1px solid #cbd5e1"></div>
    <button type="submit" style="padding:10px 16px;background:#b91c1c;color:#fff;border:none;border-radius:8px;font-weight:800;cursor:pointer">Filtrar</button>
    <a href="/admin" style="padding:10px 14px;color:#002D62;font-weight:700">&larr; Admin</a>
    <a href="/ganadores" style="padding:10px 14px;color:#002D62;font-weight:700">Premios pendientes</a>
  </form>
  <div style="overflow-x:auto;border:1px solid #e2e8f0;border-radius:12px">
  <table style="width:100%;border-collapse:collapse;font-size:14px;min-width:640px">
    <thead><tr style="background:linear-gradient(135deg,#7f1d1d,#b91c1c);color:#fff">
      <th style="padding:11px;text-align:left">Ticket</th>
      <th style="padding:11px;text-align:left">Serial</th>
      <th style="padding:11px;text-align:right">Monto</th>
      <th style="padding:11px;text-align:left">Motivo</th>
      <th style="padding:11px;text-align:left">Administrador</th>
      <th style="padding:11px;text-align:left">Fecha eliminación</th>
    </tr></thead>
    <tbody>
    {% for r in rows %}
    <tr style="border-bottom:1px solid #f1f5f9">
      <td style="padding:10px;font-weight:800">#{{ r.ticket_id }}</td>
      <td style="padding:10px;font-family:ui-monospace,monospace;font-size:13px">{{ r.serial_ticket or '—' }}</td>
      <td style="padding:10px;text-align:right;font-weight:700">RD$ {{ "%.2f"|format((r.monto_ticket or 0)|float) }}</td>
      <td style="padding:10px;max-width:280px;word-break:break-word">{{ r.motivo or '—' }}</td>
      <td style="padding:10px">{{ r.eliminado_por or '—' }}</td>
      <td style="padding:10px;white-space:nowrap;font-size:13px">{{ r.fecha_eliminacion }}</td>
    </tr>
    {% else %}
    <tr><td colspan="6" style="padding:24px;text-align:center;color:#64748b">Sin registros.</td></tr>
    {% endfor %}
    </tbody>
  </table>
  </div>
</div>
"""
    )
    return render_template_string(html, rows=rows, desde=desde, hasta=hasta)


@app.route("/api/admin/eliminar_ticket_falso", methods=["POST"])
def api_admin_eliminar_ticket_falso():
    """Soft delete de ticket falso/bajo desde premios pendientes (solo admin)."""
    if session.get("u") is None and session.get("user") is None:
        return jsonify({"ok": False, "error": "no autorizado"}), 401
    if not is_admin_or_super():
        return jsonify({"ok": False, "error": "Solo administradores."}), 403
    body = request.get_json(silent=True) or {}
    ticket_id = body.get("ticket_id")
    motivo = body.get("motivo") or ""
    admin_user = (session.get("u") or session.get("user") or "").strip()
    conn = db()
    if not conn:
        return jsonify({"ok": False, "error": "sin base de datos"}), 500
    _rollback_pg_connection(conn)
    try:
        res = _eliminar_ticket_falso_bajo(conn, ticket_id, motivo, admin_user)
        status = int(res.get("status") or (200 if res.get("ok") else 400))
        if res.get("ok"):
            return jsonify(
                {
                    "ok": True,
                    "message": "✅ Ticket eliminado correctamente",
                    "ticket_id": res.get("ticket_id"),
                }
            )
        return jsonify({"ok": False, "error": res.get("error") or "Error"}), status
    except Exception as e:
        log.error("api_admin_eliminar_ticket_falso: %s", e, exc_info=True)
        try:
            conn.rollback()
        except Exception:
            pass
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        try:
            conn.close()
        except Exception:
            pass


