@app.route("/api/recalcular_ganadores_fecha", methods=["POST"])
def api_recalcular_ganadores_fecha():
    """Cruce manual tickets↔resultados para una fecha RD (solo al pulsar Recalcular)."""
    if session.get("u") is None and session.get("user") is None:
        return jsonify({"ok": False, "error": "no autorizado"}), 401
    if not puede_recalcular_ganadores():
        return jsonify({"ok": False, "error": "Sin permiso para recalcular ganadores."}), 403
    body = request.get_json(silent=True) or {}
    hs = _fecha_consulta_cliente_acotada(
        body.get("fecha") or request.form.get("fecha_premios"),
        default_hoy=True,
    )
    log.info("[GANADORES_RECALC_MANUAL] fecha=%s", hs)
    db_backup_before_dangerous_op("api_recalcular_ganadores_" + hs)
    conn = db()
    if not conn:
        return jsonify({"ok": False, "error": "sin base de datos"}), 500
    _rollback_pg_connection(conn)
    cur = conn.cursor()
    try:
        sync = _recalcular_ganadores_fecha_completo(
            cur, hs, cajero_username=None, conn=conn, recalc_ctx=_recalc_premios_session_ctx()
        )
        if sync.get("ok"):
            try:
                conn.commit()
            except Exception:
                _rollback_pg_connection(conn)
        _ganadores_page_cache_invalidate()
        with _admin_lineas_eval_cache["lock"]:
            _admin_lineas_eval_cache["exp"] = 0.0
        ins = int(sync.get("insertados") or 0)
        n_cruce = int(sync.get("filas_cruce") or 0)
        prem_total = int(sync.get("premios_total") or 0)
        return jsonify(
            {
                "ok": bool(sync.get("ok")),
                "fecha": hs,
                "insertados": ins,
                "filas_cruce": n_cruce,
                "premios_total": prem_total,
                "tickets_evaluados": int(sync.get("tickets_evaluados") or 0),
                "lineas_evaluadas": int(sync.get("lineas_evaluadas") or 0),
                "premios_creados": int(sync.get("premios_creados") or 0),
                "message": sync.get("message") or "",
            }
        )
    except Exception as e:
        log.error("[GANADORES_ERROR] recalc manual: %s", e, exc_info=True)
        try:
            conn.rollback()
        except Exception:
            pass
        return jsonify({"ok": False, "error": str(e)[:220]}), 500
    finally:
        try:
            cur.close()
        except Exception:
            pass
        try:
            conn.close()
        except Exception:
            pass


@app.route("/api/ganadores", methods=["GET"])
def api_ganadores():
    if session.get("u") is None and session.get("user") is None:
        return jsonify({"ok": False, "error": "no autorizado"}), 401
    usuario_sesion = (session.get("u") or session.get("user") or "").strip()
    vista_admin = is_admin_or_super()
    if not vista_admin and not usuario_sesion:
        return jsonify({"ok": False, "error": "no autorizado"}), 401
    t_perf = time.perf_counter()
    cajero_filtro = None if vista_admin else usuario_sesion
    mostrar_col_cajero = vista_admin
    hoy = ahora_rd().date().strftime("%Y-%m-%d")
    debug_ganadores = (request.args.get("debug_ganadores") or "").strip().lower() in (
        "1",
        "true",
        "yes",
    )

    conn = db()
    if not conn:
        return jsonify({"ok": False, "error": "sin base de datos"}), 500
    _rollback_pg_connection(conn)
    cur = conn.cursor()
    fecha_premios_api = _ganadores_resolver_fecha_premios(hoy, cur, cajero_filtro)
    gnr_page_api, gnr_limit_api, _gnr_off_api = _ganadores_paginacion_params()
    cache_key = (
        "gan_fecha_v7_recalc",
        fecha_premios_api,
        bool(vista_admin),
        (cajero_filtro or "").lower(),
        debug_ganadores,
        gnr_page_api,
        gnr_limit_api,
    )
    now = time.time()
    ttl = float(_ganadores_page_cache_ttl_seconds())
    with _ganadores_page_cache["lock"]:
        if (
            _ganadores_page_cache["html"]
            and _ganadores_page_cache["key"] == cache_key
            and now < float(_ganadores_page_cache["exp"] or 0)
        ):
            log.info(
                "PERF ruta=/api/ganadores ms=%s filas=n/a cached=1 fecha_premios=%s",
                round((time.perf_counter() - t_perf) * 1000, 2),
                fecha_premios_api,
            )
            try:
                cur.close()
            except Exception:
                pass
            try:
                conn.close()
            except Exception:
                pass
            return jsonify(
                {
                    "ok": True,
                    "html": _ganadores_html_stamp_server_now_ms(_ganadores_page_cache["html"]),
                    "cached": True,
                    "ttl_seconds": ttl,
                    "fecha_premios": fecha_premios_api,
                }
            )

    try:
        ctx = _ganadores_collect_dashboard_context(
            conn,
            cur,
            hoy=hoy,
            cajero_filtro=cajero_filtro,
            vista_admin=vista_admin,
            mostrar_col_cajero=mostrar_col_cajero,
            debug_ganadores=debug_ganadores,
            solo_pendientes=True,
        )
        html = render_template_string(IOS + _ganadores_dashboard_inner_markup(), **ctx)
        try:
            conn.commit()
        except Exception:
            _rollback_pg_connection(conn)
        with _ganadores_page_cache["lock"]:
            _ganadores_page_cache["key"] = cache_key
            _ganadores_page_cache["html"] = html
            _ganadores_page_cache["exp"] = time.time() + ttl
        n_filas = len(ctx.get("lista_ganadores") or [])
        log.info(
            "PERF ruta=/api/ganadores ms=%s filas=%s cached=0",
            round((time.perf_counter() - t_perf) * 1000, 2),
            n_filas,
        )
        return jsonify({"ok": True, "html": _ganadores_html_stamp_server_now_ms(html), "cached": False, "ttl_seconds": ttl})
    except Exception as e:
        log.error("[GANADORES_ERROR] api_ganadores: %s", e, exc_info=True)
        try:
            conn.rollback()
        except Exception:
            pass
        return jsonify({"ok": False, "error": "No se pudo cargar. Reintentar"}), 200
    finally:
        try:
            cur.close()
        except Exception:
            pass
        try:
            conn.close()
        except Exception:
            pass


@app.route("/admin/ganadores_recalc_hoy", methods=["POST"])
def admin_ganadores_recalc_hoy():
    """Admin: re-ejecuta cruce del día RD + UPSERT pendientes; invalida cache HTML /ganadores."""
    if session.get("u") is None and session.get("user") is None:
        return redirect("/")
    if not puede_recalcular_ganadores():
        flash("Sin permiso.", "danger")
        return redirect("/ganadores")
    hs = _fecha_consulta_cliente_acotada(
        request.form.get("fecha_premios") or request.args.get("fecha_premios"),
        default_hoy=True,
    )
    conn = db()
    if not conn:
        flash("Sin base de datos.", "danger")
        return redirect("/ganadores")
    _rollback_pg_connection(conn)
    cur = conn.cursor()
    try:
        log.info("[GANADORES_RECALC_MANUAL] fecha=%s (form admin)", hs)
        db_backup_before_dangerous_op("admin_recalcular_ganadores_" + hs)
        sync = _recalcular_ganadores_fecha_completo(
            cur, hs, cajero_username=None, conn=conn, recalc_ctx=_recalc_premios_session_ctx()
        )
        ins = int(sync.get("insertados") or 0)
        n_live = int(sync.get("filas_cruce") or 0)
        if sync.get("ok"):
            try:
                conn.commit()
            except Exception:
                _rollback_pg_connection(conn)
        log.info(
            "admin_ganadores_recalc_hoy día=%s ok=%s insertados=%s filas_cruce=%s",
            hs,
            bool(sync.get("ok")),
            ins,
            n_live,
        )
        _ganadores_page_cache_invalidate()
        with _admin_lineas_eval_cache["lock"]:
            _admin_lineas_eval_cache["exp"] = 0.0
        flash(
            "Ganadores recalculados (%s): filas cruce=%s, upsert premios pendientes≈%s."
            % (hs, n_live, ins),
            "success",
        )
    except Exception as e:
        log.warning("admin_ganadores_recalc_hoy: %s", e, exc_info=True)
        try:
            conn.rollback()
        except Exception:
            pass
        flash("Error al recalcular: %s" % str(e)[:220], "danger")
    finally:
        try:
            cur.close()
        except Exception:
            pass
        try:
            conn.close()
        except Exception:
            pass
    return redirect("/ganadores?fecha_premios=" + hs)


@app.route("/api/admin/invalidar_premio", methods=["POST"])
def api_admin_invalidar_premio():
    """
    Admin: marca premio como invalidado / invalidado_pagado, auditoría en premios_invalidacion_audit.
    No toca caja ni pagos_premios. Invalida caché HTML de /ganadores.
    """
    if session.get("u") is None and session.get("user") is None:
        return jsonify({"ok": False, "error": "Sesión inválida."}), 401
    if not is_admin_or_super():
        return jsonify({"ok": False, "error": "Solo administradores."}), 403
    body = request.get_json(silent=True) or {}
    try:
        premio_id = int(body.get("premio_id") or 0)
    except (TypeError, ValueError):
        premio_id = 0
    if premio_id <= 0:
        return jsonify({"ok": False, "error": "premio_id requerido."}), 400
    motivo = (body.get("motivo") or "").strip() or DEFAULT_MOTIVO_INVALIDACION_PREMIO
    admin_u = session.get("u") or session.get("user") or "admin"
    conn = db()
    if not conn:
        return jsonify({"ok": False, "error": "sin base de datos"}), 500
    try:
        res = _ejecutar_invalidar_premio_admin(conn, premio_id, admin_u, motivo=motivo)
    finally:
        try:
            conn.close()
        except Exception:
            pass
    _ganadores_page_cache_invalidate()
    if res.get("ok"):
        return jsonify(res), 200
    code = 409 if res.get("already") else 400
    return jsonify(res), code


@app.route("/api/admin/lineas_eval_hoy", methods=["GET"])
def api_admin_lineas_eval_hoy():
    if not is_admin_or_super():
        return jsonify({"ok": False, "error": "no autorizado"}), 403
    hoy_rd = ahora_rd().strftime("%Y-%m-%d")
    now = time.time()
    ttl = float(_ganadores_page_cache_ttl_seconds())
    cache_key = hoy_rd
    with _admin_lineas_eval_cache["lock"]:
        if (
            _admin_lineas_eval_cache["key"] == cache_key
            and now < float(_admin_lineas_eval_cache.get("exp") or 0)
        ):
            return jsonify(
                {
                    "ok": True,
                    "ganador": int(_admin_lineas_eval_cache["ganador"]),
                    "perdedor": int(_admin_lineas_eval_cache["perdedor"]),
                    "cached": True,
                }
            )

    conn = db()
    if not conn:
        return jsonify({"ok": False, "error": "sin base de datos"}), 500
    _rollback_pg_connection(conn)
    cur = conn.cursor()
    t_perf = time.perf_counter()
    try:
        if not _premios_sync_necesario(cur, hoy_rd):
            gan, per = _admin_lineas_eval_counts_rapido(cur, hoy_rd)
        else:
            gan, per = _admin_lineas_eval_counts_completo(cur, hoy_rd)
        try:
            conn.commit()
        except Exception:
            pass
        with _admin_lineas_eval_cache["lock"]:
            _admin_lineas_eval_cache["key"] = cache_key
            _admin_lineas_eval_cache["ganador"] = gan
            _admin_lineas_eval_cache["perdedor"] = per
            _admin_lineas_eval_cache["exp"] = time.time() + ttl
        log.info(
            "PERF ruta=/api/admin/lineas_eval_hoy ms=%s gan=%s per=%s cached=0",
            round((time.perf_counter() - t_perf) * 1000, 2),
            gan,
            per,
        )
        return jsonify({"ok": True, "ganador": gan, "perdedor": per, "cached": False})
    except Exception as e:
        log.warning("api_admin_lineas_eval_hoy: %s", e, exc_info=True)
        try:
            conn.rollback()
        except Exception:
            pass
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        try:
            cur.close()
        except Exception:
            pass
        try:
            conn.close()
        except Exception:
            pass


