@app.route("/marcar_pagado", methods=["POST"])
def marcar_pagado():

    # 🔒 seguridad admin
    if not is_admin_or_super():
        return redirect("/")

    ticket_id = request.form.get("ticket_id")
    numero = request.form.get("numero")
    jugada = request.form.get("jugada")
    monto = request.form.get("monto")

    # validar datos
    if not ticket_id or not numero or not jugada or not monto:
        return "Datos inválidos"

    c = db()
    if not c:
        return "Error conectando base de datos", 500
    try:
        cur = c.cursor()
        cur.execute(_sql("""
            SELECT 1 FROM pagos
            WHERE ticket_id=%s AND numero=%s AND jugada=%s
        """), (ticket_id, numero, jugada))
        ya_pagado = cur.fetchone()

        if ya_pagado:
            return """
            <h2 style="color:red;text-align:center">
            ESTE PREMIO YA FUE PAGADO
            </h2>
            <a href="/admin/premios">Volver</a>
            """

        cur.execute(_sql("""
            INSERT INTO pagos(ticket_id,numero,jugada,monto,fecha,pagado_por)
            VALUES(%s,%s,%s,%s,%s,%s)
        """), (
            ticket_id,
            numero,
            jugada,
            monto,
            ahora_rd().strftime("%Y-%m-%d"),
            session.get("u")
        ))
        c.commit()
    finally:
        c.close()

    return redirect("/admin/premios")

@app.route("/api/estado_loterias")
def api_estado_loterias():
    """JSON: estado de ventas por sorteo (hora RD). Corte N min antes de cada horario; `estado` sigue abierta/cerrada para compatibilidad."""
    c = db()
    if not c:
        return jsonify({"loterias": [], "apertura_global_display": texto_apertura_global_rd(), "ventas_dia_abiertas": False})
    try:
        cur = c.cursor()
        cur.execute("SELECT lottery, draw FROM lotteries ORDER BY lottery, draw")
        loterias_raw = []
        dia_ok = ventas_loterias_permiso_horario_global()
        sec_apertura = segundos_hasta_apertura_global_rd()
        test_open = _force_loterias_open_enabled()
        for r in cur.fetchall():
            row = dict(r) if hasattr(r, "keys") else {"lottery": r[0], "draw": r[1]}
            lottery = row.get("lottery") or (r[0] if r else "")
            draw = row.get("draw") or (r[1] if r and len(r) > 1 else "")
            loterias_raw.append(_fila_estado_loteria_dict(lottery, draw, endpoint="/api/estado_loterias"))
        loterias, _ = dedupe_sorteos_por_loteria_horario(loterias_raw)
        for row in loterias:
            _st = _fila_estado_loteria_dict(row.get("lottery"), row.get("draw"), endpoint="/api/estado_loterias")
            row.update(_st)
        if test_open:
            dia_ok = True
        return jsonify({
            "loterias": loterias,
            "apertura_global_display": texto_apertura_global_rd(),
            "apertura_global_zona": "America/Santo_Domingo",
            "ventas_dia_abiertas": dia_ok,
            "segundos_hasta_apertura_global": sec_apertura,
            "cerrar_minutos_previo_sorteo": int(CLOSE_BEFORE_DRAW_MINUTES),
            "debug_all_lotteries_open": bool(test_open),
            "force_loterias_open": bool(test_open),
            "test_mode_loterias_abiertas": bool(test_open),
        })
    finally:
        c.close()


@app.route("/api/disponibilidad")
def api_disponibilidad():
    """
    Consulta en tiempo real cuánto se ha jugado hoy (fecha_sorteo RD) por número,
    lotería y sorteo, para la banca del usuario en sesión.
    Query: lottery, draw (sorteo), opcional numero, opcional monto (para probar si cabe la jugada).
    """
    if not session.get("uid"):
        return jsonify({"ok": False, "error": "No autenticado"}), 401
    lottery_raw = (request.args.get("lottery") or "").strip()
    draw_raw = (request.args.get("draw") or request.args.get("sorteo") or "").strip()
    numero_raw = (request.args.get("numero") or "").strip()
    monto_raw = request.args.get("monto")
    try:
        monto_prueba = float(monto_raw) if monto_raw not in (None, "") else 0.0
    except (TypeError, ValueError):
        monto_prueba = 0.0

    if not lottery_raw or not draw_raw:
        return jsonify({"ok": False, "error": "Parámetros lottery y draw (sorteo) son obligatorios"}), 400

    c = db()
    if not c:
        return jsonify({"ok": False, "error": "Base de datos"}), 500
    cur = None
    try:
        cur = c.cursor()
        if not _limites_diarios_activos(cur):
            return jsonify(
                {
                    "ok": True,
                    "limites_activos": False,
                    "fecha_sorteo": ahora_rd().strftime("%Y-%m-%d"),
                    "bloqueado": False,
                    "items": [],
                }
            )
        banca_id = _banca_id_para_usuario_actual(cur, session.get("uid"))
        uid_cajero = _limites_usuario_id_int(session.get("uid"))
        if not banca_id:
            return jsonify(
                {
                    "ok": True,
                    "limites_activos": True,
                    "banca_id": 0,
                    "fecha_sorteo": ahora_rd().strftime("%Y-%m-%d"),
                    "items": [],
                }
            )
        fecha_rd = ahora_rd().strftime("%Y-%m-%d")
        lottery_n, draw_n = _normalizar_clave_limite_loteria(lottery_raw, draw_raw)

        if numero_raw:
            detalles = []
            bloqueado_cualquiera = False
            bloqueado_por_cero = False
            min_disponible = None
            for num in _componentes_limite_numero(numero_raw):
                info = _limites_disponible_numero(cur, banca_id, lottery_n, draw_n, num, fecha_rd, uid_cajero)
                vendido, lim, disponible = info["vendido"], info["limite"], info["disponible"]
                if float(lim or 0) <= 0:
                    bloqueado_por_cero = True
                if min_disponible is None:
                    min_disponible = disponible
                else:
                    min_disponible = min(min_disponible, disponible)
                thr = vendido + (monto_prueba if monto_prueba > 0 else 0)
                bloqueado = thr > lim + 0.005 if monto_prueba > 0 else vendido >= lim - 1e-6
                if bloqueado:
                    bloqueado_cualquiera = True
                detalles.append({
                    "numero": num,
                    "total_jugado": round(float(vendido), 2),
                    "limite": round(float(lim), 2),
                    "disponible": round(float(disponible), 2),
                    "bloqueado": bool(bloqueado),
                })
            riesgo_alerta = None
            try:
                riesgo_alerta = _centro_riesgo_alerta_numero(cur, banca_id, lottery_n, draw_n, numero_raw, fecha_rd)
            except Exception as ex:
                log.warning("api_disponibilidad riesgo_alerta: %s", ex, exc_info=True)
            resp = {
                "ok": True,
                "limites_activos": True,
                "banca_id": banca_id,
                "fecha_sorteo": fecha_rd,
                "lottery": lottery_n,
                "draw": draw_n,
                "numero": numero_raw,
                "numeros": detalles,
                "disponible": round(float(min_disponible or 0), 2) if detalles else 0.0,
                "bloqueado": bool(bloqueado_cualquiera),
                "mensaje": (
                    "Este número está bloqueado para esta lotería/sorteo."
                    if bloqueado_cualquiera and bloqueado_por_cero
                    else (
                        "⚠️ Número limitado. Disponible restante RD$ %.2f" % (min_disponible or 0)
                        if bloqueado_cualquiera
                        else "Disponible restante RD$ %.2f" % (min_disponible or 0)
                    )
                ),
            }
            if riesgo_alerta:
                resp["riesgo"] = riesgo_alerta
                if riesgo_alerta.get("mostrar_alerta") and riesgo_alerta.get("mensaje"):
                    ra = riesgo_alerta.get("alerta") or {}
                    if ra.get("nivel_riesgo") in ("critico", "alto"):
                        resp["mensaje_riesgo"] = riesgo_alerta.get("mensaje")
            return jsonify(resp)

        items = []
        for i in range(100):
            num = f"{i:02d}"
            vendido = _total_jugado_hoy_banca_loteria_numero(cur, banca_id, lottery_n, draw_n, fecha_rd, num)
            lim = _obtener_limite_numero_loteria(cur, banca_id, lottery_n, draw_n, num)
            disponible = max(0.0, lim - vendido)
            thr = vendido + (monto_prueba if monto_prueba > 0 else 0)
            bloqueado = thr > lim + 0.005 if monto_prueba > 0 else vendido >= lim - 1e-6
            items.append({
                "numero": num,
                "total_jugado": round(float(vendido), 2),
                "limite": round(float(lim), 2),
                "disponible": round(float(disponible), 2),
                "bloqueado": bool(bloqueado),
            })
        return jsonify({
            "ok": True,
            "limites_activos": True,
            "banca_id": banca_id,
            "fecha_sorteo": fecha_rd,
            "lottery": lottery_n,
            "draw": draw_n,
            "items": items,
        })
    finally:
        _db_close(c, cur)


@app.route("/api/ventas_cajeros")
def api_ventas_cajeros():
    """Ranking motivacional: ventas post-cierre y metas por cajero (misma banca para todos)."""
    from flask import jsonify
    if not is_staff():
        return jsonify({"error": "unauthorized", "cajeros": []}), 401
    usuario, es_admin = _ventas_scope()
    role_lc = (_current_role() or "").strip().lower()
    try:
        uid_api = int(session.get("uid") or 0)
    except (TypeError, ValueError):
        uid_api = 0
    # Alcance ranking: admin ve su red; super_admin todo; cajero ve peers de su banca.
    banca_api = uid_api if (es_admin and role_lc == ROLE_ADMIN) else 0
    banca_ranking = banca_api
    if banca_ranking <= 0 and not es_admin and uid_api > 0:
        c0 = db()
        if c0:
            cur0 = None
            try:
                cur0 = c0.cursor()
                cur0.execute(
                    _sql("SELECT COALESCE(created_by, 0) AS cb FROM users WHERE id = %s"),
                    (uid_api,),
                )
                r_cb = cur0.fetchone()
                cb = int(
                    (r_cb.get("cb") if r_cb and hasattr(r_cb, "get") else (r_cb[0] if r_cb else 0)) or 0
                )
                if cb > 0:
                    banca_ranking = cb
            except Exception:
                pass
            finally:
                _db_close(c0, cur0)

    meta_global = float(get_config("meta_diaria") or 0)
    nb_users = _limites_sql_not_blocked("users")

    c = db()
    if not c:
        return jsonify({"cajeros": []})
    cur = None
    try:
        cur = c.cursor()

        def _entrada_map(nombre, mt):
            return {
                "cajero": nombre,
                "ventas": 0.0,
                "meta": float(mt if mt else meta_global),
                "pendiente_premios": 0.0,
                "premios_nums": "",
            }

        # 1. Cajeros y su meta (activos, misma banca para ranking motivacional).
        if banca_ranking > 0:
            cur.execute(
                _sql(
                    """
                    SELECT username, COALESCE(meta, 0) AS meta
                    FROM users
                    WHERE role = %s
                      AND (id = %s OR created_by = %s)
                      AND """
                    + nb_users
                    + """
                    ORDER BY username
                    """
                ),
                (ROLE_CAJERO, banca_ranking, banca_ranking),
            )
        elif es_admin:
            cur.execute(
                _sql(
                    """
                    SELECT username, COALESCE(meta, 0) AS meta
                    FROM users
                    WHERE role = %s
                      AND """
                    + nb_users
                    + """
                    ORDER BY username
                    """
                ),
                (ROLE_CAJERO,),
            )
        else:
            cur.execute(
                _sql(
                    """
                    SELECT username, COALESCE(meta, 0) AS meta
                    FROM users
                    WHERE username = %s
                      AND """
                    + nb_users
                    + """
                    ORDER BY username
                    """
                ),
                (usuario,),
            )
        users_rows = cur.fetchall()
        cajeros_map = {}
        for r in users_rows:
            row = dict(r) if hasattr(r, "keys") else {"username": r[0], "meta": float(r[1] or 0)}
            name = (row.get("username") or "") if hasattr(row, "get") else (r[0] or "")
            meta_val = float(row.get("meta", 0) or 0) if hasattr(row, "get") else float(r[1] or 0)
            name = str(name or "").strip()
            if not name:
                continue
            cajeros_map[name] = _entrada_map(name, meta_val)

        # Vendedores en tickets que no están en users (super_admin vendiendo, cajeros huérfanos, etc.)
        if es_admin or banca_ranking > 0:
            try:
                fb_o, pb_o = ("", [])
                scope_banca = banca_ranking if banca_ranking > 0 else banca_api
                if scope_banca > 0:
                    fb_o, pb_o = _filtro_sql_ticket_banca_admin_scope("t", scope_banca)
                cur.execute(
                    _sql("""
                        SELECT DISTINCT trim(COALESCE(t.cajero, '')) AS c
                        FROM tickets t
                        WHERE trim(COALESCE(t.cajero, '')) <> ''
                    """
                    + fb_o),
                    tuple(pb_o),
                )
                exist_low = {k.lower() for k in cajeros_map}
                for rr in cur.fetchall() or []:
                    rn = rr["c"] if hasattr(rr, "keys") else rr[0]
                    caj = str(rn or "").strip()
                    if not caj or caj.lower() in exist_low:
                        continue
                    exist_low.add(caj.lower())
                    cajeros_map[caj] = _entrada_map(caj, meta_global)
            except Exception as e:
                log.warning("api_ventas_cajeros cajeros tickets: %s", e)
                _rollback_pg_cursor(cur)

        is_pg = bool(os.environ.get("DATABASE_URL"))
        f_tkt, p_tkt = _frag_post_cierre_coalesce(cur, is_pg, "t.created_at")
        ventas_params = list(p_tkt)
        filtro_cajero = ""
        filt_banca = ""
        filt_banca_p = []
        scope_ventas = banca_ranking if banca_ranking > 0 else banca_api
        if scope_ventas > 0:
            filt_banca, filt_banca_p = _filtro_sql_ticket_banca_admin_scope("t", scope_ventas)
            ventas_params.extend(filt_banca_p)
        elif not es_admin:
            filtro_cajero = " AND lower(trim(COALESCE(t.cajero, ''))) = lower(trim(%s))"
            ventas_params.append(usuario)

        if is_pg:
            cur.execute(
                """
                SELECT lower(trim(COALESCE(t.cajero, ''))) AS cajero_norm,
                       COALESCE(SUM(t.monto), 0) AS ventas
                FROM tickets t
                WHERE COALESCE(t.monto, 0) > 0
                """
                + f_tkt
                + filtro_cajero
                + filt_banca
                + """
                GROUP BY lower(trim(COALESCE(t.cajero, '')))
                """,
                tuple(ventas_params),
            )
        else:
            cur.execute(
                _sql(
                    """
                SELECT lower(trim(COALESCE(t.cajero, ''))) AS cajero_norm,
                       COALESCE(SUM(t.monto), 0) AS ventas
                FROM tickets t
                WHERE COALESCE(t.monto, 0) > 0
                """
                    + f_tkt
                    + filtro_cajero
                    + filt_banca
                    + """
                GROUP BY lower(trim(COALESCE(t.cajero, '')))
                """
                ),
                tuple(ventas_params),
            )

        # Incluye filas por cajero aunque no estuviera en users (primer ticket con nombre nuevo).
        def _nombre_canon(norm_key):
            key = str(norm_key or "").strip().lower()
            if not key:
                return None
            for k in list(cajeros_map.keys()):
                if k.lower() == key:
                    return k
            return norm_key.strip() if norm_key and norm_key.strip() else None

        by_norm = {str(k or "").strip().lower(): k for k in cajeros_map.keys()}
        for r in cur.fetchall() or []:
            row = dict(r) if hasattr(r, "keys") else {"cajero_norm": r[0], "ventas": r[1]}
            lk = str(row.get("cajero_norm") or "").strip().lower()
            canon = _nombre_canon(lk)
            if not canon and lk:
                canon = lk
                cajeros_map[canon] = _entrada_map(canon, meta_global)
                by_norm[lk] = canon
            key = canon or by_norm.get(lk)
            if key:
                if key not in cajeros_map:
                    cajeros_map[key] = _entrada_map(key, meta_global)
                    if lk:
                        by_norm[lk] = key
                cajeros_map[key]["ventas"] = round(float(row.get("ventas") or 0), 2)

        # Premios pendientes: todos los históricos sin pagar (no filtrar por post-cierre del ticket).
        filt_pend = filtro_cajero + filt_banca
        filt_extra_p = []
        if not es_admin:
            filt_extra_p.append(usuario)
        filt_extra_p.extend(filt_banca_p)
        estado_pend_where = "lower(trim(COALESCE(p.estado, ''))) = lower(trim(%s))"
        pend_run = tuple(filt_extra_p + ["pendiente"])

        pend_where_rest = """
                  AND p.line_id IS NOT NULL
                  AND COALESCE(p.premio, 0) > 0
                """

        try:
            if is_pg:
                cur.execute(
                    """
                    SELECT lower(trim(COALESCE(t.cajero, ''))) AS cajero_norm,
                           COALESCE(SUM(p.premio), 0) AS pendiente_premios,
                           string_agg(
                             trim(coalesce(p.numero, '')) || '(' || ROUND(p.premio::numeric, 0)::text || ')',
                             ' · ' ORDER BY COALESCE(p.id, 0)
                           ) AS premios_nums
                    FROM premios p
                    INNER JOIN tickets t ON t.id = p.ticket_id
                    WHERE 1=1
                    """
                    + filt_pend
                    + pend_where_rest
                    + """ AND """
                    + estado_pend_where
                    + """
                    GROUP BY lower(trim(COALESCE(t.cajero, '')))
                    """,
                    pend_run,
                )
            else:
                cur.execute(
                    _sql(
                        """
                    SELECT lower(trim(COALESCE(t.cajero, ''))) AS cajero_norm,
                           COALESCE(SUM(p.premio), 0) AS pendiente_premios,
                           group_concat(
                             trim(coalesce(p.numero, '')) || '(' || cast(round(cast(coalesce(p.premio, 0) as real), 0) as integer) || ')',
                             ' · '
                           ) AS premios_nums
                    FROM premios p
                    INNER JOIN tickets t ON t.id = p.ticket_id
                    WHERE 1=1
                    """
                        + filt_pend
                        + pend_where_rest
                        + """ AND """
                        + estado_pend_where
                        + """
                    GROUP BY lower(trim(COALESCE(t.cajero, '')))
                    """
                    ),
                    pend_run,
                )
            for rr in cur.fetchall() or []:
                prow = dict(rr) if hasattr(rr, "keys") else (
                    {"cajero_norm": rr[0], "pendiente_premios": rr[1], "premios_nums": rr[2]}
                )
                lk2 = str(prow.get("cajero_norm") or "").strip().lower()
                cn2 = _nombre_canon(lk2)
                if not cn2 and lk2:
                    cn2 = lk2
                    cajeros_map[cn2] = _entrada_map(cn2, meta_global)
                    by_norm[lk2] = cn2
                kk = cn2 or by_norm.get(lk2)
                if not kk:
                    continue
                if kk not in cajeros_map:
                    cajeros_map[kk] = _entrada_map(kk, meta_global)
                    if lk2:
                        by_norm[lk2] = kk
                ps = prow.get("premios_nums") or ""
                txt = str(ps).strip()
                if len(txt) > 220:
                    txt = txt[:217] + "..."
                cajeros_map[kk]["pendiente_premios"] = round(
                    float(prow.get("pendiente_premios") or 0), 2
                )
                if txt:
                    cajeros_map[kk]["premios_nums"] = txt
        except Exception as e:
            log.warning("api_ventas_cajeros pendientes: %s", e, exc_info=True)
            _rollback_pg_cursor(cur)

        cajeros = list(cajeros_map.values())

        def _pct_ranking(entry):
            m = float(entry.get("meta") or 0)
            v = float(entry.get("ventas") or 0)
            return (v / m * 100.0) if m > 0 else 0.0

        cajeros.sort(
            key=lambda x: (
                -float(x.get("ventas") or 0),
                -_pct_ranking(x),
                str(x.get("cajero") or "").lower(),
            )
        )
        return jsonify({"cajeros": cajeros})
    finally:
        _db_close(c, cur)


@app.route("/api/ganancia")
def api_ganancia():
    if not is_staff():
        return {"ventas": 0, "pagado": 0, "ganancia": 0}
    usuario, es_admin = _ventas_scope()
    c = db()
    if not c:
        return {"ventas": 0, "pagado": 0, "ganancia": 0}
    try:
        cur = c.cursor()
        if es_admin:
            cur.execute("""
                SELECT COALESCE(SUM(tl.amount),0)
                FROM ticket_lines tl
                JOIN tickets t ON t.id = tl.ticket_id
                WHERE tl.estado!='cancelado' OR tl.estado IS NULL
            """)
        else:
            cur.execute(_sql("""
                SELECT COALESCE(SUM(tl.amount),0)
                FROM ticket_lines tl
                JOIN tickets t ON t.id = tl.ticket_id
                WHERE (tl.estado!='cancelado' OR tl.estado IS NULL)
                AND t.cajero = %s
            """), (usuario,))
        row = cur.fetchone()
        ventas = list(row.values())[0] if row and hasattr(row, "values") else (row[0] if row else 0)
        if es_admin:
            cur.execute("""
                SELECT COALESCE(SUM(monto),0)
                FROM pagos
            """)
        else:
            cur.execute(_sql("""
                SELECT COALESCE(SUM(monto),0)
                FROM pagos
                WHERE pagado_por = %s
            """), (usuario,))
        row2 = cur.fetchone()
        pagado = list(row2.values())[0] if row2 and hasattr(row2, "values") else (row2[0] if row2 else 0)
        return {
            "ventas": ventas,
            "pagado": pagado,
            "ganancia": ventas - pagado
        }
    finally:
        c.close()


@app.route("/api/whoami")
def api_whoami():
    """Diagnóstico: rol en sesión vs rol en BD (no expone password)."""
    username = session.get("u") or session.get("user")
    if not username:
        return jsonify({"ok": False, "error": "Sin sesión"}), 401
    conn = db()
    if not conn:
        return jsonify({"ok": False, "error": "Error de base de datos"}), 500
    try:
        cur = conn.cursor()
        cur.execute(
            _sql("SELECT id, username, role, is_approved, is_blocked, pago_activo, fecha_vencimiento FROM users WHERE username=%s"),
            (username,),
        )
        row = cur.fetchone()
        u = dict(row) if row and not isinstance(row, dict) else (row or {})
    finally:
        try:
            conn.close()
        except Exception:
            pass
    return jsonify({
        "ok": True,
        "session": {"u": username, "role": session.get("role"), "uid": session.get("uid")},
        "db": u,
    })

# ===============================
# ANULAR TICKET (ADMIN)
# ===============================
@app.route("/anular_ticket/<int:ticket_id>", methods=["POST"])
def anular_ticket(ticket_id):

    # 🔒 SEGURIDAD → solo admin
    if not is_admin_or_super():
        return redirect("/")

    c = db()
    if not c:
        return "Error conectando base de datos", 500
    try:
        cur = c.cursor()
        cur.execute(
            _sql("SELECT id, COALESCE(monto,0) AS monto, cajero_id, cajero FROM tickets WHERE id=%s"),
            (ticket_id,),
        )
        ticket = cur.fetchone()

        if not ticket:
            return "Ticket no encontrado"

        t_monto = float(_banco_row_val(ticket, "monto", 1, 0) or 0)
        t_cajero_id = _banco_row_val(ticket, "cajero_id", 2)
        t_cajero = _banco_row_val(ticket, "cajero", 3)

        try:
            banco_revertir_pagos_ticket(
                cur,
                ticket_id,
                nota="Anulación ticket — reversión premios",
                usuario_admin_id=session.get("uid"),
            )
        except Exception as _bnc_pr:
            log.warning("banco revertir premios anular ticket %s: %s", ticket_id, _bnc_pr, exc_info=True)

        if t_monto > 0:
            try:
                banco_revertir_venta_ticket(
                    cur,
                    ticket_id,
                    nota="Anulación ticket #%s" % int(ticket_id),
                    usuario_admin_id=session.get("uid"),
                )
            except Exception as _bnc_v:
                log.warning("banco revertir venta anular ticket %s: %s", ticket_id, _bnc_v, exc_info=True)

        cur.execute(
            _sql("DELETE FROM ticket_lines WHERE ticket_id=%s"),
            (ticket_id,)
        )
        cur.execute(
            _sql("DELETE FROM tickets WHERE id=%s"),
            (ticket_id,)
        )
        c.commit()
    finally:
        c.close()

    session.pop("ticket_id", None)
    return redirect("/venta")

