# ===============================
# VER HISTORIAL DE PAGOS
# ===============================
@app.route("/admin/pagos")
def ver_pagos():
    # Admin/super_admin: ven todos los pagos (filtro opcional por cajero).
    # Cajero / user / supervisor / collector: solo pagos registrados a nombre de su sesión (forzado en servidor).
    if not is_admin_or_super():
        r_rol = (session.get("role") or "").strip().lower()
        if not (is_staff() or r_rol == "user"):
            return redirect("/")
        if not (session.get("u") or session.get("user")):
            return redirect("/")

    es_admin = is_admin_or_super()
    usuario_sesion = (session.get("u") or session.get("user") or "").strip()

    desde = (request.args.get("desde") or "").strip()[:10]
    hasta = (request.args.get("hasta") or "").strip()[:10]
    cajero_arg = (request.args.get("cajero") or "").strip()
    hoy_rd = ahora_rd().strftime("%Y-%m-%d")
    if not desde:
        desde = hoy_rd
    if not hasta:
        hasta = hoy_rd

    c = db()
    if not c:
        return "Error conectando base de datos", 500
    try:
        cur = c.cursor()
        # Historial unificado:
        # - pagos (flujo antiguo /admin/pagar_premio)
        # - pagos_premios (flujo actual /pagar_premio/<ticket_id>)
        # Se muestran ambos para que el total no salga en 0 cuando hay pagos recientes.
        where_parts = ["fecha_txt >= %s", "fecha_txt <= %s"]
        params = [desde, hasta]
        if es_admin:
            cajero = cajero_arg
            if cajero and cajero.lower() != "todos":
                where_parts.append("lower(trim(COALESCE(usuario,''))) = lower(trim(%s))")
                params.append(cajero)
        else:
            # Cajero (u otro staff no admin): ignorar ?cajero= en URL (seguridad)
            cajero = usuario_sesion
            where_parts.append("lower(trim(COALESCE(usuario,''))) = lower(trim(%s))")
            params.append(usuario_sesion)

        where_sql = " AND ".join(where_parts)
        if os.environ.get("DATABASE_URL"):
            union_sql = """
            SELECT *
            FROM (
                SELECT
                    id,
                    ticket_id,
                    numero,
                    jugada,
                    monto,
                    fecha::text AS fecha,
                    SUBSTRING(fecha::text, 1, 10) AS fecha_txt,
                    pagado_por AS usuario,
                    'pagos' AS origen,
                    COALESCE(revertido, 0) AS revertido
                FROM pagos
                UNION ALL
                SELECT
                    id,
                    ticket_id,
                    NULL::text AS numero,
                    NULL::text AS jugada,
                    monto,
                    fecha::text AS fecha,
                    SUBSTRING(fecha::text, 1, 10) AS fecha_txt,
                    cajero AS usuario,
                    'pagos_premios' AS origen,
                    COALESCE(revertido, 0) AS revertido
                FROM pagos_premios
            ) t
            WHERE """ + where_sql + """
            ORDER BY fecha_txt DESC, id DESC
            LIMIT 500
            """
            cur.execute(union_sql, tuple(params))
        else:
            union_sql = """
            SELECT *
            FROM (
                SELECT
                    id,
                    ticket_id,
                    numero,
                    jugada,
                    monto,
                    CAST(fecha AS TEXT) AS fecha,
                    substr(CAST(fecha AS TEXT), 1, 10) AS fecha_txt,
                    pagado_por AS usuario,
                    'pagos' AS origen,
                    COALESCE(revertido, 0) AS revertido
                FROM pagos
                UNION ALL
                SELECT
                    id,
                    ticket_id,
                    NULL AS numero,
                    NULL AS jugada,
                    monto,
                    CAST(fecha AS TEXT) AS fecha,
                    substr(CAST(fecha AS TEXT), 1, 10) AS fecha_txt,
                    cajero AS usuario,
                    'pagos_premios' AS origen,
                    COALESCE(revertido, 0) AS revertido
                FROM pagos_premios
            ) t
            WHERE """ + where_sql + """
            ORDER BY fecha_txt DESC, id DESC
            LIMIT 500
            """
            cur.execute(_sql(union_sql), tuple(params))
        rows = cur.fetchall() or []
        pagos = []
        total = 0.0
        cajeros_set = set()
        for r in rows:
            d = dict(r) if hasattr(r, "keys") else {
                "id": r[0] if len(r) > 0 else None,
                "ticket_id": r[1] if len(r) > 1 else None,
                "numero": r[2] if len(r) > 2 else "",
                "jugada": r[3] if len(r) > 3 else "",
                "monto": r[4] if len(r) > 4 else 0,
                "fecha": r[5] if len(r) > 5 else "",
                "fecha_txt": r[6] if len(r) > 6 else "",
                "usuario": r[7] if len(r) > 7 else "",
                "origen": r[8] if len(r) > 8 else "",
                "revertido": r[9] if len(r) > 9 else 0,
            }
            d["usuario"] = d.get("usuario") or d.get("pagado_por") or d.get("cajero") or "-"
            if d["usuario"] and d["usuario"] != "-":
                cajeros_set.add(d["usuario"])
            try:
                m = float(d.get("monto") or 0)
            except (TypeError, ValueError):
                m = 0.0
            d["revertido"] = int(d.get("revertido") or 0)
            if d["revertido"] == 0:
                total += m
            d["monto"] = m
            pagos.append(d)
        from collections import defaultdict

        tids = []
        for d in pagos:
            tid = d.get("ticket_id")
            if tid is not None:
                try:
                    tids.append(int(tid))
                except (TypeError, ValueError):
                    pass
        tids = sorted(set(tids))
        meta_by_tid = {}
        if tids:
            ph = ",".join([_ph()] * len(tids))
            q = (
                "SELECT ticket_id, id, number, play, fecha_sorteo, lottery, draw "
                "FROM ticket_lines WHERE ticket_id IN (" + ph + ") ORDER BY ticket_id, id"
            )
            if os.environ.get("DATABASE_URL"):
                cur.execute(q, tuple(tids))
            else:
                cur.execute(_sql(q), tuple(tids))
            by_tid = defaultdict(list)
            for row in cur.fetchall() or []:
                if hasattr(row, "keys"):
                    rd = dict(row)
                else:
                    rd = {
                        "ticket_id": row[0] if len(row) > 0 else None,
                        "id": row[1] if len(row) > 1 else 0,
                        "number": row[2] if len(row) > 2 else "",
                        "play": row[3] if len(row) > 3 else "",
                        "fecha_sorteo": row[4] if len(row) > 4 else "",
                        "lottery": row[5] if len(row) > 5 else "",
                        "draw": row[6] if len(row) > 6 else "",
                    }
                try:
                    tid_k = int(rd.get("ticket_id"))
                except (TypeError, ValueError):
                    continue
                by_tid[tid_k].append(rd)
            for tid_k, lines in by_tid.items():
                lines.sort(key=lambda x: int(x.get("id") or 0))
                first = lines[0]
                fechas_ok = sorted(
                    {
                        str(L.get("fecha_sorteo") or "").strip()[:10]
                        for L in lines
                        if str(L.get("fecha_sorteo") or "").strip()
                    }
                )
                fs_disp = fechas_ok[0] if fechas_ok else "—"
                meta_by_tid[tid_k] = {
                    "numero": (str(first.get("number") or "").strip() or "—"),
                    "tipo": (str(first.get("play") or "").strip() or "—"),
                    "fecha_sorteo": fs_disp,
                }

        pagado_por_tid = {}
        if es_admin and tids:
            ph2 = ",".join([_ph()] * len(tids))
            if os.environ.get("DATABASE_URL"):
                cur.execute(
                    "SELECT id, COALESCE(pagado, false) AS pagado FROM tickets WHERE id IN ("
                    + ph2
                    + ")",
                    tuple(tids),
                )
            else:
                cur.execute(
                    _sql(
                        "SELECT id, COALESCE(pagado, 0) AS pagado FROM tickets WHERE id IN ("
                        + ph2
                        + ")"
                    ),
                    tuple(tids),
                )
            for tr in cur.fetchall() or []:
                if hasattr(tr, "keys"):
                    try:
                        pagado_por_tid[int(tr.get("id") or 0)] = tr.get("pagado")
                    except (TypeError, ValueError):
                        pass
                else:
                    try:
                        pagado_por_tid[int(tr[0])] = tr[1] if len(tr) > 1 else 0
                    except (TypeError, ValueError):
                        pass

        for d in pagos:
            tid = d.get("ticket_id")
            meta = None
            if tid is not None:
                try:
                    meta = meta_by_tid.get(int(tid))
                except (TypeError, ValueError):
                    meta = None
            try:
                tid_int = int(tid) if tid is not None else None
            except (TypeError, ValueError):
                tid_int = None
            d["ticket_show"] = ("#%s" % tid_int) if tid_int is not None else "—"
            ns = d.get("numero")
            if ns is not None and str(ns).strip():
                d["numero_show"] = str(ns).strip()
            else:
                d["numero_show"] = (meta["numero"] if meta else "—")
            js = d.get("jugada")
            if js is not None and str(js).strip():
                d["tipo_show"] = str(js).strip()
            else:
                d["tipo_show"] = (meta["tipo"] if meta else "—")
            d["fecha_sorteo_show"] = (meta["fecha_sorteo"] if meta else "—")
            fp = d.get("fecha")
            if hasattr(fp, "strftime"):
                d["fecha_pago_show"] = fp.strftime("%Y-%m-%d %H:%M")
            else:
                d["fecha_pago_show"] = (str(fp) if fp is not None else "")[:19] or "—"
            d["origen_show"] = (
                "pagos_premios"
                if d.get("origen") == "pagos_premios"
                else (d.get("origen") or "—")
            )
            rpv = int(d.get("revertido") or 0)
            d["revertido_label"] = "Eliminado" if rpv else ""
            d["es_vigente"] = rpv == 0
            d["puede_eliminar_pago"] = bool(
                es_admin
                and rpv == 0
                and tid_int is not None
                and (
                    _pago_premio_es_truthy_pagado(pagado_por_tid.get(tid_int))
                    or _ticket_tiene_pagos_premios_activos(cur, tid_int)
                    or _ticket_tiene_pagos_legacy_activos(cur, tid_int)
                )
            )
        cajeros = sorted(cajeros_set)
    finally:
        c.close()

    return render_template_string(IOS + """
    <div class="card">
        <h2>💰 Historial de Pagos</h2>
        <h3 class="danger">Total efectivo pagado: RD$ {{ "%.2f"|format(total) }}</h3>
        <p style="font-size:12px;color:#64748b;margin:-6px 0 10px 0">El total solo suma pagos <b>vigentes</b> (excluye filas marcadas como eliminadas/revertidas).</p>
        <form method="get" action="/admin/pagos" style="display:flex;flex-wrap:wrap;gap:10px;align-items:end;margin-top:14px">
            <div>
                <label style="display:block;font-size:12px;color:#64748b;margin-bottom:4px;">Desde</label>
                <input type="date" name="desde" value="{{ desde }}" style="padding:8px;border-radius:8px;border:1px solid #94a3b8">
            </div>
            <div>
                <label style="display:block;font-size:12px;color:#64748b;margin-bottom:4px;">Hasta</label>
                <input type="date" name="hasta" value="{{ hasta }}" style="padding:8px;border-radius:8px;border:1px solid #94a3b8">
            </div>
            {% if es_admin %}
            <div>
                <label style="display:block;font-size:12px;color:#64748b;margin-bottom:4px;">Cajero</label>
                <select name="cajero" style="padding:8px;border-radius:8px;border:1px solid #94a3b8;min-width:180px">
                    <option value="Todos" {% if (cajero_sel|lower) in ["", "todos"] %}selected{% endif %}>Todos</option>
                    {% for u in cajeros %}
                    <option value="{{ u }}" {% if cajero_sel == u %}selected{% endif %}>{{ u }}</option>
                    {% endfor %}
                </select>
            </div>
            {% else %}
            <div style="padding:8px 12px;background:#f1f5f9;border-radius:8px;border:1px solid #cbd5e1;font-size:13px;color:#0f172a">
                <span style="display:block;font-size:11px;color:#64748b;margin-bottom:4px;font-weight:700">Cajero (solo tus pagos)</span>
                <strong>{{ usuario_sesion }}</strong>
            </div>
            {% endif %}
            <button type="submit" style="padding:10px 14px;background:#002D62;color:#fff;border:none;border-radius:10px;font-weight:800;cursor:pointer">Buscar</button>
        </form>
    </div>

    <div class="card" style="overflow-x:auto">
        <p style="font-size:12px;color:#64748b;margin:0 0 10px 0;line-height:1.4">Cada fila enlaza al ticket cuando aplica. <b>Sorteo</b> = fecha en la línea (<code>fecha_sorteo</code>) si existe.</p>
        <table width="100%" style="border-collapse:collapse;font-size:13px;min-width:980px">
            <tr style="background:#f1f5f9">
                <th style="padding:8px;text-align:left">Ticket</th>
                <th style="padding:8px;text-align:left">Número</th>
                <th style="padding:8px;text-align:left">Tipo</th>
                <th style="padding:8px;text-align:right">Monto</th>
                <th style="padding:8px;text-align:left">Sorteo</th>
                <th style="padding:8px;text-align:left">Pago</th>
                <th style="padding:8px;text-align:left">Cajero</th>
                <th style="padding:8px;text-align:left">Origen</th>
                <th style="padding:8px;text-align:center">Estado</th>
                <th style="padding:8px;text-align:center">Recibo</th>
                {% if es_admin %}<th style="padding:8px;text-align:center">Acción</th>{% endif %}
            </tr>

            {% for p in pagos %}
            <tr style="border-bottom:1px solid #e2e8f0{% if p.revertido_label %};opacity:0.65;background:#f8fafc{% endif %}">
                <td style="padding:8px;white-space:nowrap{% if p.revertido_label %};text-decoration:line-through;color:#64748b{% endif %}">{{ p.ticket_show }}</td>
                <td style="padding:8px{% if p.revertido_label %};text-decoration:line-through;color:#64748b{% endif %}">{{ p.numero_show }}</td>
                <td style="padding:8px{% if p.revertido_label %};text-decoration:line-through;color:#64748b{% endif %}">{{ p.tipo_show }}</td>
                <td style="padding:8px;text-align:right;font-weight:700;color:{% if p.revertido_label %}#64748b{% else %}#15803d{% endif %}{% if p.revertido_label %};text-decoration:line-through{% endif %}">RD$ {{ "%.2f"|format(p.monto) }}</td>
                <td style="padding:8px;white-space:nowrap{% if p.revertido_label %};text-decoration:line-through;color:#64748b{% endif %}">{{ p.fecha_sorteo_show }}</td>
                <td style="padding:8px;white-space:nowrap{% if p.revertido_label %};text-decoration:line-through;color:#64748b{% endif %}">{{ p.fecha_pago_show }}</td>
                <td style="padding:8px{% if p.revertido_label %};text-decoration:line-through;color:#64748b{% endif %}">{{ p.usuario }}</td>
                <td style="padding:8px;font-size:12px;color:#475569{% if p.revertido_label %};text-decoration:line-through{% endif %}">{{ p.origen_show }}</td>
                <td style="padding:8px;text-align:center;font-size:12px;font-weight:700">{% if p.revertido_label %}<span style="color:#b45309">{{ p.revertido_label }}</span>{% else %}<span style="color:#15803d">Vigente</span>{% endif %}</td>
                <td style="padding:8px;text-align:center">{% if p.ticket_id %}<a href="/imprimir_pago/{{ p.ticket_id }}" target="_blank" rel="noopener" style="color:#002D62;font-weight:700">Ver</a>{% else %}—{% endif %}</td>
                {% if es_admin %}
                <td style="padding:8px;text-align:center">{% if p.puede_eliminar_pago %}<button type="button" class="btnRevPremio" data-tid="{{ p.ticket_id }}" data-monto="{{ "%.2f"|format(p.monto) }}" style="padding:6px 10px;background:#b91c1c;color:#fff;border:none;border-radius:8px;font-weight:800;cursor:pointer;font-size:12px">Eliminar pago</button>{% else %}—{% endif %}</td>
                {% endif %}
            </tr>
            {% endfor %}
            {% if not pagos %}
            <tr>
                <td colspan="{% if es_admin %}11{% else %}10{% endif %}" style="text-align:center;color:#64748b;padding:14px">No hay pagos registrados.</td>
            </tr>
            {% endif %}
        </table>
    </div>
    {% if es_admin %}
    <div id="modalRevPremio" style="display:none;position:fixed;z-index:10000;left:0;top:0;width:100%;height:100%;background:rgba(0,0,0,0.5);align-items:center;justify-content:center;padding:16px">
      <div style="background:#fff;border-radius:16px;max-width:420px;width:100%;padding:22px;border:1px solid #e2e8f0">
        <h3 style="margin:0 0 8px">Eliminar pago de premio</h3>
        <p style="margin:0 0 10px;font-size:13px;color:#64748b">Ticket <strong id="mrpTid">—</strong> · Monto <strong id="mrpMonto">—</strong></p>
        <input type="hidden" id="mrpTicketId" value="">
        <label style="font-size:12px;font-weight:700">Motivo (opcional)</label>
        <input id="mrpMotivo" maxlength="500" style="width:100%;padding:10px;margin:4px 0 12px;border-radius:8px;border:1px solid #cbd5e1;box-sizing:border-box">
        <label style="font-size:12px;font-weight:700">Tu contraseña</label>
        <input type="password" id="mrpPw" autocomplete="current-password" style="width:100%;padding:10px;margin:4px 0 12px;border-radius:8px;border:1px solid #cbd5e1;box-sizing:border-box">
        <div id="mrpMsg" style="display:none;padding:10px;border-radius:8px;margin-bottom:10px;font-weight:700;font-size:13px"></div>
        <div style="display:flex;gap:10px">
          <button type="button" id="mrpOk" style="flex:1;padding:12px;background:#b91c1c;color:#fff;border:none;border-radius:10px;font-weight:800">Confirmar reversa</button>
          <button type="button" id="mrpCancel" style="flex:1;padding:12px;background:#94a3b8;color:#fff;border:none;border-radius:10px;font-weight:700">Cancelar</button>
        </div>
        <p style="font-size:11px;color:#94a3b8;margin:12px 0 0;line-height:1.4">No borra el ticket: anula <code>pagado</code> y marca el registro en <code>pagos_premios</code> como revertido.</p>
      </div>
    </div>
    <script>
    (function(){
      var modal = document.getElementById("modalRevPremio");
      if(!modal) return;
      function openM(tid, monto){
        document.getElementById("mrpTicketId").value = String(tid);
        document.getElementById("mrpTid").textContent = "#"+tid;
        document.getElementById("mrpMonto").textContent = "RD$ "+Number(monto||0).toFixed(2);
        document.getElementById("mrpMotivo").value = "";
        document.getElementById("mrpPw").value = "";
        var m = document.getElementById("mrpMsg"); if(m){ m.style.display="none"; m.textContent=""; }
        modal.style.display = "flex";
      }
      document.querySelectorAll(".btnRevPremio").forEach(function(b){
        b.addEventListener("click", function(){
          openM(b.getAttribute("data-tid"), b.getAttribute("data-monto"));
        });
      });
      document.getElementById("mrpCancel").onclick = function(){ modal.style.display = "none"; };
      modal.onclick = function(e){ if(e.target===modal) modal.style.display = "none"; };
      document.getElementById("mrpOk").onclick = function(){
        var tid = document.getElementById("mrpTicketId").value;
        var pw = document.getElementById("mrpPw").value;
        var motivo = document.getElementById("mrpMotivo").value;
        var msg = document.getElementById("mrpMsg");
        if(!pw){ msg.style.display="block"; msg.style.background="#fee2e2"; msg.style.color="#991b1b"; msg.textContent="Contraseña obligatoria"; return; }
        var okBtn = document.getElementById("mrpOk"); okBtn.disabled = true;
        fetch("/admin/revertir_pago_premio/"+encodeURIComponent(tid), { method:"POST", headers:{"Content-Type":"application/json","X-Requested-With":"XMLHttpRequest"}, body: JSON.stringify({ admin_password: pw, motivo: motivo }) })
          .then(function(r){ return r.text().then(function(txt){ var j={}; try{j=JSON.parse(txt);}catch(e){j={ok:r.ok,raw:txt};} return {ok:r.ok, j:j, status:r.status}; }); })
          .then(function(x){
            okBtn.disabled = false;
            if(x.j && x.j.ok){ msg.style.display="block"; msg.style.background="#dcfce7"; msg.style.color="#166534"; msg.textContent=x.j.message||"Pago eliminado."; setTimeout(function(){ location.reload(); }, 700); }
            else { msg.style.display="block"; msg.style.background="#fee2e2"; msg.style.color="#991b1b"; msg.textContent=(x.j&&(x.j.error||x.j.message))||("Error HTTP "+(x.status||""))||"No se pudo eliminar el pago"; }
          }).catch(function(){ okBtn.disabled = false; msg.style.display="block"; msg.style.background="#fee2e2"; msg.style.color="#991b1b"; msg.textContent="Error de red"; });
      };
    })();
    </script>
    {% endif %}
    """,
        pagos=pagos,
        total=total,
        desde=desde,
        hasta=hasta,
        cajeros=cajeros,
        cajero_sel=cajero,
        es_admin=es_admin,
        usuario_sesion=usuario_sesion,
    )

